class _LazyGlobalProxy:
    def __init__(self, global_name: str, loader: Callable[[], None]) -> None:
        self._global_name = str(global_name)
        self._loader = loader

    def _resolve(self) -> Any:
        self._loader()
        resolved = globals().get(self._global_name)
        if resolved is None or resolved is self:
            raise RuntimeError(f"Lazy global {self._global_name} was not initialized")
        return resolved

    def __getattr__(self, item: str) -> Any:
        return getattr(self._resolve(), item)

    def __call__(self, *args: Any, **kwargs: Any) -> Any:
        return self._resolve()(*args, **kwargs)

    def __repr__(self) -> str:
        resolved = globals().get(self._global_name)
        if resolved is self or resolved is None:
            return f"<LazyGlobalProxy {self._global_name}>"
        return repr(resolved)


_MATPLOTLIB_READY = False


def _ensure_matplotlib_imported() -> None:
    global _MATPLOTLIB_READY, matplotlib, plt, mpl_font_manager, mpl_patheffects, FancyBboxPatch, FuncFormatter
    if _MATPLOTLIB_READY:
        return
    import matplotlib as _matplotlib
    from matplotlib import font_manager as _mpl_font_manager
    from matplotlib import patheffects as _mpl_patheffects
    from matplotlib import pyplot as _plt
    from matplotlib.patches import FancyBboxPatch as _FancyBboxPatch
    from matplotlib.ticker import FuncFormatter as _FuncFormatter

    _matplotlib.rcParams["font.sans-serif"] = ["Noto Sans CJK SC", "Noto Sans CJK JP", "DejaVu Sans"]
    _matplotlib.rcParams["axes.unicode_minus"] = False

    matplotlib = _matplotlib
    plt = _plt
    mpl_font_manager = _mpl_font_manager
    mpl_patheffects = _mpl_patheffects
    FancyBboxPatch = _FancyBboxPatch
    FuncFormatter = _FuncFormatter
    _MATPLOTLIB_READY = True


matplotlib = _LazyGlobalProxy("matplotlib", _ensure_matplotlib_imported)
plt = _LazyGlobalProxy("plt", _ensure_matplotlib_imported)
