def _ensure_akshare_imported() -> Any:
    global ak, _AKSHARE_IMPORT_ATTEMPTED
    if _AKSHARE_IMPORT_ATTEMPTED:
        return ak
    _AKSHARE_IMPORT_ATTEMPTED = True
    try:
        import akshare as _ak  # type: ignore
    except Exception:
        ak = None
    else:
        ak = _ak
    return ak


def _is_akshare_installed() -> bool:
    if ak is not None:
        return True
    if _AKSHARE_IMPORT_ATTEMPTED:
        return False
    try:
        import importlib.util

        return importlib.util.find_spec("akshare") is not None
    except Exception:
        return False


def _akshare_version_text() -> str:
    if ak is not None:
        return str(getattr(ak, "__version__", "") or "")
    if not _AKSHARE_IMPORT_ATTEMPTED:
        return "deferred"
    return "not_installed"

