def render_close_detail_filter_panel(close_detail: pd.DataFrame) -> Tuple[str, str, pd.DataFrame, str]:
    quick_close_mode = st.radio(
        "快速筛选",
        ["全部", "仅结构平仓", "期现平仓记录"],
        horizontal=True,
        key="result_close_quick_mode",
    )
    if quick_close_mode == "期现平仓记录":
        close_type_filter = "仅现货对冲平仓"
        st.caption("期现平仓记录：按 close_batch_id 聚合统计（包含纯现货平仓）。")
    elif quick_close_mode == "仅结构平仓":
        close_type_filter = "仅结构平仓"
    else:
        close_type_filter = st.selectbox(
            "平仓类型筛选",
            CLOSE_TYPE_FILTER_OPTIONS,
            key="result_close_type_filter",
        )

    close_date_hint = ""
    close_detail_view = close_detail.copy()
    if not close_detail_view.empty:
        close_detail_view = apply_close_type_filter(close_detail_view, close_type_filter)
        sf1, sf2 = st.columns([2, 1])
        struct_opts = sorted(close_detail_view["结构"].astype(str).dropna().unique().tolist())
        with sf1:
            struct_sel = st.multiselect("结构筛选（可多选）", struct_opts, key="result_close_struct_filter")
        with sf2:
            close_kw_inline = st.text_input("关键词（模糊）", key="result_close_kw_inline")
        if struct_sel:
            close_detail_view = close_detail_view[close_detail_view["结构"].astype(str).isin([str(x) for x in struct_sel])].copy()
        close_detail_view = apply_close_keyword_filter(close_detail_view, close_kw_inline)
        close_date_hint = build_close_date_hint(close_detail_view, close_detail)
        close_detail_view = apply_close_date_range_filter(
            close_detail_view,
            start_key="result_close_start",
            end_key="result_close_end",
        )
        close_detail_view = apply_table_filters(
            close_detail_view,
            "monitor_tab5",
            keyword_cols=[],
            category_cols=["结构状态", "品种", "方向", "平仓类别", "记录类型"],
            date_cols=[],
            title="平仓明细筛选",
            expanded=False,
        )
    return quick_close_mode, close_type_filter, close_detail_view, close_date_hint


def render_close_metrics_row(m: Dict[str, float]) -> None:
    s1, s2, s3, s4, s5 = st.columns(5)
    with s1:
        st.metric("区间结构盈亏", f"{float(m['struct_pnl_sum']):,.2f}")
    with s2:
        st.metric("区间现货盈亏", f"{float(m['spot_pnl_sum']):,.2f}")
    with s3:
        st.metric("区间合计盈亏", f"{float(m['total_pnl_sum']):,.2f}")
    with s4:
        st.metric("平仓数量合计", f"{float(m['qty_sum']):,.2f}")
    with s5:
        st.metric("平仓次数", f"{int(m['batch_cnt'])}")
    long_close_qty = float(pick_first(to_float(m.get("long_close_qty")), 0.0) or 0.0)
    short_close_qty = float(pick_first(to_float(m.get("short_close_qty")), 0.0) or 0.0)
    other_close_qty = float(pick_first(to_float(m.get("other_close_qty")), 0.0) or 0.0)
    qty_note = (
        "数量口径：已剔除熔断补贴平仓；"
        f"区间平多 {long_close_qty:,.2f} 吨，平空 {short_close_qty:,.2f} 吨。"
    )
    if other_close_qty > 1e-12:
        qty_note += f" 另有其他方向记录 {other_close_qty:,.2f} 吨，未计入多/空拆分。"
    st.caption(qty_note)


