CLOSE_RISK_SUM_COLUMNS: List[str] = [
    "已生成",
    "剩余最小",
    "剩余最大",
    "敞口下界",
    "敞口上界",
    "已生成汇总",
    "剩余最小汇总",
    "剩余最大汇总",
    "敞口下界汇总",
    "敞口上界汇总",
]


def normalize_interval_pair_columns(
    df: pd.DataFrame,
    pairs: Sequence[Tuple[str, str]],
) -> pd.DataFrame:
    # 仅适用于真正的数值区间列（如下界/上界）；
    # 不应用于“业务场景最大/最小”这类保留方向语义的字段。
    if df is None or df.empty:
        return df
    out = df.copy()
    for lo_col, hi_col in pairs:
        if lo_col not in out.columns or hi_col not in out.columns:
            continue
        lo_ser = pd.to_numeric(out[lo_col], errors="coerce")
        hi_ser = pd.to_numeric(out[hi_col], errors="coerce")
        valid_mask = lo_ser.notna() & hi_ser.notna()
        if not bool(valid_mask.any()):
            continue
        lo_vals = np.minimum(lo_ser.loc[valid_mask].to_numpy(dtype=float), hi_ser.loc[valid_mask].to_numpy(dtype=float))
        hi_vals = np.maximum(lo_ser.loc[valid_mask].to_numpy(dtype=float), hi_ser.loc[valid_mask].to_numpy(dtype=float))
        out.loc[valid_mask, lo_col] = lo_vals
        out.loc[valid_mask, hi_col] = hi_vals
    return out


def build_active_risk_bounds_view(
    b_base: pd.DataFrame,
    inactive_sid_block: set[str],
    rep_gid: Any,
    rep_und: Any,
) -> pd.DataFrame:
    b_struct_only = b_base[
        (b_base["层级"].astype(str) == "STRUCTURE")
        & (~b_base["结构ID"].astype(str).str.strip().isin(inactive_sid_block))
    ].copy()

    group_template = b_base[b_base["层级"].astype(str) == "GROUP"].head(1)
    if not group_template.empty:
        group_row = group_template.iloc[0].to_dict()
    else:
        group_row = {c: "" for c in b_base.columns}
    group_row["层级"] = "GROUP"
    if "策略组编号" in group_row:
        group_row["策略组编号"] = str(rep_gid)
    if "结构ID" in group_row:
        group_row["结构ID"] = "GROUP_SUM"
    if "结构" in group_row:
        group_row["结构"] = "GROUP_SUM"
    if "风险子" in group_row:
        group_row["风险子"] = ""
    if "品种" in group_row:
        group_row["品种"] = "全部品种" if is_all_underlying_scope(rep_und) else str(rep_und)
    if "方向" in group_row:
        group_row["方向"] = "净额"
    if "策略类型" in group_row:
        group_row["策略类型"] = "汇总"
    for c in ["总交易日", "已观察交易日", "剩余交易日"]:
        if c in group_row:
            group_row[c] = np.nan

    for c in CLOSE_RISK_SUM_COLUMNS:
        if c in b_struct_only.columns and c in group_row:
            group_row[c] = float(pd.to_numeric(b_struct_only[c], errors="coerce").fillna(0.0).sum())

    if {"已生成", "方向"}.issubset(set(b_struct_only.columns)) and "已生成" in group_row:
        group_row["已生成"] = float(
            pd.to_numeric(
                signed_value_series_by_direction(b_struct_only["已生成"], b_struct_only["方向"]),
                errors="coerce",
            ).fillna(0.0).sum()
        )
    if {"敞口下界", "敞口上界"}.issubset(set(group_row)):
        exp_lo = float(pick_first(to_float(group_row.get("敞口下界")), 0.0) or 0.0)
        exp_hi = float(pick_first(to_float(group_row.get("敞口上界")), 0.0) or 0.0)
        group_row["敞口下界"] = min(exp_lo, exp_hi)
        group_row["敞口上界"] = max(exp_lo, exp_hi)
    for base_col, sum_col in [
        ("已生成", "已生成汇总"),
        ("剩余最小", "剩余最小汇总"),
        ("剩余最大", "剩余最大汇总"),
        ("敞口下界", "敞口下界汇总"),
        ("敞口上界", "敞口上界汇总"),
    ]:
        if base_col in group_row and sum_col in group_row:
            group_row[sum_col] = group_row[base_col]

    return normalize_interval_pair_columns(
        pd.concat([b_struct_only, pd.DataFrame([group_row])], ignore_index=True),
        [
            ("敞口下界", "敞口上界"),
            ("敞口下界汇总", "敞口上界汇总"),
        ],
    )


def _fmt_signed_cell(v: Any) -> Any:
    try:
        if v is None or pd.isna(v):
            return ""
    except Exception:
        pass
    if isinstance(v, str):
        sv = v.strip()
        if sv in {"", "-"}:
            return sv
    try:
        return f"{float(v):+,.2f}"
    except Exception:
        return v


def _fmt_int_cell(v: Any) -> Any:
    try:
        if v is None or pd.isna(v):
            return "-"
    except Exception:
        pass
    if isinstance(v, str):
        sv = v.strip()
        if sv in {"", "-"}:
            return sv
    try:
        return str(int(round(float(v))))
    except Exception:
        return v


def build_structure_price_maps(structs_df: pd.DataFrame) -> Tuple[Dict[str, float], Dict[str, float]]:
    cache_key = (
        "build_structure_price_maps",
        _db_file_version_token(),
        _df_runtime_fingerprint(structs_df),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, tuple) and len(cached) == 2:
        return _copy_cached_runtime_value(cached)
    entry_map: Dict[str, float] = {}
    strike_map: Dict[str, float] = {}
    if structs_df.empty:
        return entry_map, strike_map
    for _, rr in structs_df.iterrows():
        sid_rr = str(rr.get("structure_id", "")).strip()
        if not sid_rr:
            continue
        entry_map[sid_rr] = float(
            pick_first(to_float(rr.get("entry_price")), to_float(rr.get("gen_price")), 0.0)
        )
        strike_map[sid_rr] = float(pick_first(to_float(rr.get("strike_price")), 0.0))
    payload = (entry_map, strike_map)
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, payload, limit=48)
    return _copy_cached_runtime_value(payload)


