def direction_sign(direction_val: Any) -> Optional[int]:
    d_raw = str(direction_val).strip()
    d_up = d_raw.upper()
    if d_raw in {"累购", "看涨", "多单", "买入"} or d_up in {"ACC", "LONG", "BUY"}:
        return 1
    if d_raw in {"累沽", "看跌", "空单", "卖出"} or d_up in {"DEC", "SHORT", "SELL"}:
        return -1
    return None


def signed_value_by_direction(raw_val: Any, direction_val: Any) -> Any:
    v = to_float(raw_val)
    if v is None:
        return raw_val
    if abs(float(v)) <= 1e-12:
        return 0.0
    sign = direction_sign(direction_val)
    if sign is None:
        return float(v)
    if sign > 0:
        return abs(float(v))
    if sign < 0:
        return -abs(float(v))
    return float(v)


def signed_value_series_by_direction(raw_series: Any, direction_series: Any) -> pd.Series:
    raw_ser = raw_series if isinstance(raw_series, pd.Series) else pd.Series(raw_series)
    if isinstance(direction_series, pd.Series):
        dir_ser = direction_series.reindex(raw_ser.index)
    else:
        dir_ser = pd.Series(direction_series, index=raw_ser.index)
    return pd.Series(
        [signed_value_by_direction(raw_v, dir_v) for raw_v, dir_v in zip(raw_ser.tolist(), dir_ser.tolist())],
        index=raw_ser.index,
        dtype="object",
    )


def apply_signed_direction_columns(
    df: pd.DataFrame,
    cols: List[str],
    *,
    direction_col: str = "方向",
    level_col: Optional[str] = None,
    structure_level: str = "STRUCTURE",
) -> pd.DataFrame:
    out = df.copy()
    if out.empty or direction_col not in out.columns:
        return out
    direction_ser = out[direction_col]
    level_ser = None
    if level_col and level_col in out.columns:
        level_ser = out[level_col].astype(str).str.upper()
    structure_level_up = str(structure_level).upper()
    for col in cols:
        if col not in out.columns:
            continue
        if level_ser is not None:
            struct_mask = level_ser.eq(structure_level_up)
            converted = out[col].copy()
            if bool((~struct_mask).any()):
                non_struct_num = pd.to_numeric(out.loc[~struct_mask, col], errors="coerce")
                converted.loc[~struct_mask] = non_struct_num.where(
                    non_struct_num.notna(),
                    out.loc[~struct_mask, col],
                )
            if bool(struct_mask.any()):
                converted.loc[struct_mask] = signed_value_series_by_direction(
                    out.loc[struct_mask, col],
                    direction_ser.loc[struct_mask],
                )
            out[col] = converted
        else:
            out[col] = signed_value_series_by_direction(
                out[col],
                direction_ser,
            )
    return out


def apply_signed_direction_range_pairs(
    df: pd.DataFrame,
    pairs: List[Tuple[str, str]],
    *,
    direction_col: str = "方向",
    level_col: Optional[str] = None,
    structure_level: str = "STRUCTURE",
) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out

    for lo_col, hi_col in pairs:
        if lo_col not in out.columns or hi_col not in out.columns:
            continue

        def _convert_row(rr: pd.Series, lo_name: str = lo_col, hi_name: str = hi_col) -> pd.Series:
            lo_raw = to_float(rr.get(lo_name))
            hi_raw = to_float(rr.get(hi_name))
            if lo_raw is None and hi_raw is None:
                return pd.Series([rr.get(lo_name), rr.get(hi_name)])

            lo_v = float(lo_raw) if lo_raw is not None else 0.0
            hi_v = float(hi_raw) if hi_raw is not None else 0.0
            # 仅保证区间顺序，避免“最小/最大”倒置。
            return pd.Series([min(lo_v, hi_v), max(lo_v, hi_v)])

        pair_vals = out.apply(_convert_row, axis=1, result_type="expand")
        if isinstance(pair_vals, pd.DataFrame) and pair_vals.shape[1] >= 2:
            out[lo_col] = pair_vals.iloc[:, 0]
            out[hi_col] = pair_vals.iloc[:, 1]

    return out


def direction_display_cn(v: Any) -> str:
    t = str(v).strip()
    if t in {"ACC", "累购", "看涨"}:
        return "看涨"
    if t in {"DEC", "累沽", "看跌"}:
        return "看跌"
    if t.upper() == "BUY" or t == "买入":
        return "买入"
    if t.upper() == "SELL" or t == "卖出":
        return "卖出"
    return t


def apply_direction_display_mapping(df: pd.DataFrame, direction_col: str = "方向") -> pd.DataFrame:
    out = df.copy()
    if out.empty or direction_col not in out.columns:
        return out
    out[direction_col] = out[direction_col].map(direction_display_cn).fillna(out[direction_col])
    return out


