def render_risk_bounds_table(b_show: pd.DataFrame, height: Optional[int] = None) -> None:
    if "剩余最大" in b_show.columns:
        signed_cols = [c for c in CLOSE_RISK_SUM_COLUMNS if c in b_show.columns]
        day_cols = [c for c in ["总交易日", "已观察交易日", "剩余交易日"] if c in b_show.columns]
        remain_col_idx = list(b_show.columns).index("剩余最大")
        fmt_map: Dict[str, Any] = {c: _fmt_signed_cell for c in signed_cols}
        for c in day_cols:
            fmt_map[c] = _fmt_int_cell
        b_style = (
            b_show.style
            .format(fmt_map)
            .set_properties(subset=["剩余最大"], **{"color": "#ff4d4f", "font-weight": "700"})
            .set_table_styles(
                [
                    {
                        "selector": f"th.col_heading.level0.col{remain_col_idx}",
                        "props": "color:#ff4d4f;font-weight:700;",
                    }
                ],
                overwrite=False,
            )
        )
        st.dataframe(b_style, width="stretch", height=height)
        return

    b_cfg = _risk_bounds_column_config()
    st.dataframe(
        b_show,
        width="stretch",
        height=height,
        column_config=_column_config_for(b_show, b_cfg),
    )


def render_close_detail_raw_export(close_detail_view: pd.DataFrame) -> None:
    show = close_detail_view.drop(columns=["group_id"]) if "group_id" in close_detail_view.columns else close_detail_view
    with st.expander("平仓原始明细（默认隐藏）", expanded=False):
        st.dataframe(show, width="stretch", height=MONITOR_TABLE_HEIGHT)
    download_df_csv("下载平仓明细CSV", show, "平仓明细.csv")


def render_monitor_tab5(close_detail: pd.DataFrame, prices_df: pd.DataFrame, rep_gid: Any, rep_und: Any) -> None:
    quick_close_mode, _close_type_filter, close_detail_view, close_date_hint = render_close_detail_filter_panel(close_detail)

    if not close_detail_view.empty:
        render_close_interactive_kline_panel(close_detail_view, prices_df, rep_gid, rep_und)
    if not close_detail_view.empty:
        m = summarize_close_metrics(close_detail_view)
        render_close_metrics_row(m)

        if quick_close_mode == "期现平仓记录":
            batch_summary, batch_detail_map = build_spot_batch_summary(close_detail_view)
            render_spot_batch_summary_section(batch_summary, batch_detail_map, rep_gid, rep_und)
    elif close_date_hint:
        st.caption(f"当前筛选无结果。{close_date_hint}")
    else:
        st.caption("当前筛选无结果。")

    render_close_detail_raw_export(close_detail_view)


def build_structure_position_timeline_frame(
    s_df: pd.DataFrame,
    close2_df: Optional[pd.DataFrame],
    adjustment_df: Optional[pd.DataFrame],
    *,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
) -> pd.DataFrame:
    columns = [
        "structure_id",
        "date",
        "day_close_qty",
        "current_open_qty",
        "current_open_avg",
        "manual_adjust_increase_qty",
        "manual_adjust_decrease_qty",
        "manual_adjust_net_qty",
        "manual_adjust_cum_qty",
    ]
    if s_df is None or s_df.empty or "structure_id" not in s_df.columns:
        return pd.DataFrame(columns=columns)

    out = s_df.copy()
    out["date"] = out["date"].astype(str)
    out["structure_id"] = out["structure_id"].astype(str).str.strip()
    out = out[out["structure_id"].ne("")].copy()
    if out.empty:
        return pd.DataFrame(columns=columns)
    if "group_id" in out.columns:
        out = out[out["group_id"].astype(str) == str(rep_gid)].copy()
    if out.empty:
        return pd.DataFrame(columns=columns)
    if not is_all_underlying_scope(rep_und) and "underlying" in out.columns:
        out = out[out["underlying"].astype(str) == str(rep_und)].copy()
    if out.empty:
        return pd.DataFrame(columns=columns)
    cutoff_d = parse_date_maybe(rep_date)
    if cutoff_d is not None:
        out_dt = pd.to_datetime(out["date"], errors="coerce").dt.date
        out = out[out_dt <= cutoff_d].copy()
    if out.empty:
        return pd.DataFrame(columns=columns)

    sid_kind_map: Dict[str, str] = (
        out[["structure_id", "kind"]]
        .drop_duplicates(subset=["structure_id"], keep="last")
        .assign(kind=lambda df: df["kind"].astype(str).str.upper().str.strip())
        .set_index("structure_id")["kind"]
        .to_dict()
    )
    sid_list = sorted({sid for sid in out["structure_id"].astype(str).tolist() if sid})
    if not sid_list:
        return pd.DataFrame(columns=columns)

    close_map: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}
    close_work = filter_internal_position_close_rows(
        close2_df if isinstance(close2_df, pd.DataFrame) else pd.DataFrame(),
        group_id=str(rep_gid),
        structure_ids=sid_list,
        as_of_date=cutoff_d,
    )
    if not close_work.empty:
        if not is_all_underlying_scope(rep_und):
            close_work = close_work[close_work["underlying"].astype(str) == str(rep_und)].copy()
        if not close_work.empty:
            sort_cols = ["dt"]
            if "close_id" in close_work.columns:
                sort_cols.append("close_id")
            close_work = close_work.sort_values(sort_cols)
            for _, rr in close_work.iterrows():
                sid = str(rr.get("structure_id", "")).strip()
                dt_s = str(rr.get("dt", "")).strip()
                if not sid or not dt_s:
                    continue
                close_map.setdefault((sid, dt_s), []).append(
                    {
                        "side": str(rr.get("side", "")).upper(),
                        "qty": float(pick_first(to_float(rr.get("qty")), 0.0) or 0.0),
                        "source_gen_date": str(pick_first(rr.get("source_gen_date"), "") or "").strip(),
                    }
                )

    adjust_map: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}
    adj_work = build_structure_position_adjustment_frame(
        adjustment_df if isinstance(adjustment_df, pd.DataFrame) else pd.DataFrame(),
        group_id=str(rep_gid),
        structure_ids=sid_list,
        as_of_date=cutoff_d,
    )
    if not adj_work.empty:
        if not is_all_underlying_scope(rep_und):
            sid_und_map = (
                out[["structure_id", "underlying"]]
                .drop_duplicates(subset=["structure_id"], keep="last")
                .set_index("structure_id")["underlying"]
                .astype(str)
                .to_dict()
            )
            adj_work = adj_work[
                adj_work["structure_id"].astype(str).map(lambda sid: sid_und_map.get(str(sid), "")).astype(str) == str(rep_und)
            ].copy()
        if not adj_work.empty:
            adj_work = adj_work.sort_values(["adjust_dt", "created_at", "adjustment_id"])
            for _, rr in adj_work.iterrows():
                sid = str(rr.get("structure_id", "")).strip()
                dt_s = str(rr.get("adjust_dt", "")).strip()
                if not sid or not dt_s:
                    continue
                adjust_map.setdefault((sid, dt_s), []).append(
                    {
                        "delta_qty": float(pick_first(to_float(rr.get("delta_qty")), 0.0) or 0.0),
                        "basis_open_price": float(pick_first(to_float(rr.get("basis_open_price")), 0.0) or 0.0),
                    }
                )

    eps = 1e-12
    timeline_rows: List[Dict[str, Any]] = []
    for sid in sid_list:
        sid_rows = out[out["structure_id"].astype(str) == sid].copy().sort_values(["date"])
        if sid_rows.empty:
            continue
        sid_dates = set(sid_rows["date"].astype(str).tolist())
        sid_dates |= {dt_s for sid_s, dt_s in close_map.keys() if sid_s == sid}
        sid_dates |= {dt_s for sid_s, dt_s in adjust_map.keys() if sid_s == sid}
        lots: List[Dict[str, Any]] = []
        latest_row = sid_rows.iloc[0].to_dict()
        sid_row_map: Dict[str, Dict[str, Any]] = {
            str(rr.get("date", "")): rr.to_dict()
            for _, rr in sid_rows.iterrows()
        }
        for dt_s in sorted(sid_dates):
            if dt_s in sid_row_map:
                row = sid_row_map[dt_s]
                latest_row = row
                gen_qty = max(float(pick_first(to_float(row.get("generated_qty")), 0.0) or 0.0), 0.0)
                gen_px = float(
                    pick_first(
                        to_float(row.get("gen_price")),
                        to_float(row.get("entry_price")),
                        to_float(row.get("strike_price")),
                        to_float(row.get("settle")),
                        0.0,
                    )
                    or 0.0
                )
                if gen_qty > eps:
                    lots.append({"source_dt": dt_s, "qty": gen_qty, "price": gen_px})

            day_inc = 0.0
            day_dec = 0.0
            for adj_rr in adjust_map.get((sid, dt_s), []):
                delta_v = float(pick_first(to_float(adj_rr.get("delta_qty")), 0.0) or 0.0)
                if delta_v > eps:
                    ref_open_qty = float(sum(float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) for lr in lots))
                    ref_open_val = float(
                        sum(
                            float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0)
                            * float(pick_first(to_float(lr.get("price")), 0.0) or 0.0)
                            for lr in lots
                        )
                    )
                    ref_open_avg = (ref_open_val / ref_open_qty) if ref_open_qty > eps else None
                    basis_px = float(
                        pick_first(
                            to_float(adj_rr.get("basis_open_price")),
                            ref_open_avg,
                            to_float(latest_row.get("gen_price")),
                            to_float(latest_row.get("entry_price")),
                            0.0,
                        )
                        or 0.0
                    )
                    lots.append({"source_dt": dt_s, "qty": delta_v, "price": basis_px})
                    day_inc += delta_v
                elif delta_v < -eps:
                    total_open = float(sum(float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) for lr in lots))
                    need = min(abs(delta_v), total_open)
                    if need > eps and total_open > eps:
                        factor = max((total_open - need) / total_open, 0.0)
                        pos_idx = [idx for idx, lr in enumerate(lots) if float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) > eps]
                        kept = 0.0
                        for i, lot_idx in enumerate(pos_idx):
                            old_qty = float(pick_first(to_float(lots[lot_idx].get("qty")), 0.0) or 0.0)
                            if i < len(pos_idx) - 1:
                                new_qty = max(old_qty * factor, 0.0)
                                kept += new_qty
                            else:
                                new_qty = max(total_open - need - kept, 0.0)
                            lots[lot_idx]["qty"] = new_qty
                        lots = [lr for lr in lots if float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) > eps]
                    day_dec += abs(delta_v)

            day_close_qty = 0.0
            for close_rr in close_map.get((sid, dt_s), []):
                reduce_qty = structure_close_reduce_qty(
                    sid_kind_map.get(sid, "ACC"),
                    close_rr.get("side", ""),
                    float(pick_first(to_float(close_rr.get("qty")), 0.0) or 0.0),
                )
                if reduce_qty <= eps:
                    continue
                day_close_qty += reduce_qty
                remain = reduce_qty
                src_dt = str(close_rr.get("source_gen_date", "")).strip()
                if src_dt:
                    try:
                        src_dt = pd.to_datetime(src_dt).strftime(DATE_FMT)
                    except Exception:
                        src_dt = ""
                if src_dt:
                    for lot_row in lots:
                        if remain <= eps:
                            break
                        if str(lot_row.get("source_dt", "")) != src_dt:
                            continue
                        avail = float(pick_first(to_float(lot_row.get("qty")), 0.0) or 0.0)
                        if avail <= eps:
                            continue
                        take = min(avail, remain)
                        lot_row["qty"] = avail - take
                        remain -= take
                if remain > eps:
                    for lot_row in lots:
                        if remain <= eps:
                            break
                        avail = float(pick_first(to_float(lot_row.get("qty")), 0.0) or 0.0)
                        if avail <= eps:
                            continue
                        take = min(avail, remain)
                        lot_row["qty"] = avail - take
                        remain -= take
                lots = [lr for lr in lots if float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) > eps]

            if dt_s not in sid_row_map:
                continue
            open_qty = float(sum(float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0) for lr in lots))
            open_val = float(
                sum(
                    float(pick_first(to_float(lr.get("qty")), 0.0) or 0.0)
                    * float(pick_first(to_float(lr.get("price")), 0.0) or 0.0)
                    for lr in lots
                )
            )
            open_avg = (open_val / open_qty) if open_qty > eps else None
            timeline_rows.append(
                {
                    "structure_id": sid,
                    "date": dt_s,
                    "day_close_qty": float(day_close_qty),
                    "current_open_qty": float(max(open_qty, 0.0)),
                    "current_open_avg": open_avg,
                    "manual_adjust_increase_qty": float(day_inc),
                    "manual_adjust_decrease_qty": float(day_dec),
                    "manual_adjust_net_qty": float(day_inc - day_dec),
                    "manual_adjust_cum_qty": float(day_inc - day_dec),
                }
            )

    if not timeline_rows:
        return pd.DataFrame(columns=columns)
    timeline = pd.DataFrame(timeline_rows)
    timeline = timeline.sort_values(["structure_id", "date"]).reset_index(drop=True)
    timeline["manual_adjust_cum_qty"] = timeline.groupby("structure_id")["manual_adjust_net_qty"].cumsum()
    return timeline[columns].copy()


def enrich_trs_daily_rows(
    s_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
    position_timeline: Optional[pd.DataFrame] = None,
) -> pd.DataFrame:
    out = s_df.copy()
    if out.empty or "strategy_code" not in out.columns:
        return out
    trs_mask = out["strategy_code"].astype(str).str.upper().eq("TRS")
    if not bool(trs_mask.any()):
        return out

    out["date"] = out["date"].astype(str)
    sid_kind_map: Dict[str, str] = (
        out.loc[trs_mask, ["structure_id", "kind"]]
        .dropna(subset=["structure_id"])
        .assign(
            structure_id=lambda df: df["structure_id"].astype(str).str.strip(),
            kind=lambda df: df["kind"].astype(str).str.upper().str.strip(),
        )
        .drop_duplicates(subset=["structure_id"], keep="last")
        .set_index("structure_id")["kind"]
        .to_dict()
    )
    sid_list = sorted([sid for sid in sid_kind_map.keys() if sid])
    if not sid_list:
        return out
    timeline_work = pd.DataFrame()
    if isinstance(position_timeline, pd.DataFrame) and not position_timeline.empty:
        timeline_work = position_timeline[
            position_timeline["structure_id"].astype(str).str.strip().isin(sid_list)
        ].copy()
        if not timeline_work.empty:
            timeline_work["structure_id"] = timeline_work["structure_id"].astype(str).str.strip()
            timeline_work["date"] = timeline_work["date"].astype(str)

    reduce_map: Dict[Tuple[str, str], float] = {}
    if close2_df is not None and not close2_df.empty:
        c = close2_df.copy()
        c = c[c["group_id"].astype(str) == str(rep_gid)].copy()
        if not is_all_underlying_scope(rep_und):
            c = c[c["underlying"].astype(str) == str(rep_und)].copy()
        c = c[c["structure_id"].astype(str).str.strip().isin(sid_list)].copy()
        if not c.empty:
            c["dt"] = c["dt"].astype(str)
            cutoff_d = parse_date_maybe(rep_date)
            if cutoff_d is not None:
                c_dt = pd.to_datetime(c["dt"], errors="coerce").dt.date
                c = c[c_dt <= cutoff_d].copy()
        if not c.empty:
            if "close_category" in c.columns:
                c["close_category"] = c["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
                c.loc[c["close_category"] == "", "close_category"] = STRUCT_CLOSE_CATEGORY
                c = c[c["close_category"].isin(INTERNAL_POSITION_CLOSE_CATEGORIES)].copy()
            if "is_external" in c.columns:
                c["is_external"] = pd.to_numeric(c["is_external"], errors="coerce").fillna(0).astype(int)
                c = c[c["is_external"] == 0].copy()
            c["side"] = c["side"].astype(str).str.upper()
            c["qty"] = pd.to_numeric(c["qty"], errors="coerce").fillna(0.0)
            c = c[(c["qty"] > 1e-12) & (c["side"].isin(["BUY", "SELL"]))].copy()
            if not c.empty:
                c["structure_id"] = c["structure_id"].astype(str).str.strip()
                c["reduce_qty"] = c.apply(
                    lambda rr: structure_close_reduce_qty(
                        sid_kind_map.get(str(rr.get("structure_id", "")).strip(), "ACC"),
                        rr.get("side"),
                        float(rr.get("qty", 0.0)),
                    ),
                    axis=1,
                )
                c = c[c["reduce_qty"] > 1e-12].copy()
                if not c.empty:
                    grouped = (
                        c.groupby([c["structure_id"].astype(str), c["dt"].astype(str)])["reduce_qty"]
                        .sum()
                        .reset_index()
                    )
                    reduce_map = {
                        (str(rr.get("structure_id", "")).strip(), str(rr.get("dt", "")).strip()): float(
                            pick_first(to_float(rr.get("reduce_qty")), 0.0) or 0.0
                        )
                        for _, rr in grouped.iterrows()
                    }

    for sid in sid_list:
        sid_mask = trs_mask & out["structure_id"].astype(str).str.strip().eq(str(sid))
        if not bool(sid_mask.any()):
            continue
        sid_rows = out[sid_mask].copy().sort_values(["date"])
        sid_idx = sid_rows.index
        dates = sid_rows["date"].astype(str)
        kind = str(sid_kind_map.get(str(sid), "ACC")).upper()
        sid_timeline = timeline_work[timeline_work["structure_id"].astype(str) == str(sid)].copy() if not timeline_work.empty else pd.DataFrame()
        if not sid_timeline.empty:
            sid_timeline = sid_timeline.sort_values(["date"]).drop_duplicates(subset=["date"], keep="last")
            sid_timeline = sid_timeline.set_index("date", drop=False)
            open_qty = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "current_open_qty"] if d in sid_timeline.index else np.nan),
                errors="coerce",
            ).fillna(0.0)
            open_avg = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "current_open_avg"] if d in sid_timeline.index else np.nan),
                errors="coerce",
            )
            day_close = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "day_close_qty"] if d in sid_timeline.index else 0.0),
                errors="coerce",
            ).fillna(0.0)
            prev_open = open_qty.shift(1).fillna(0.0)
            delta_qty = open_qty - prev_open
            settle_s = pd.to_numeric(sid_rows.get("settle"), errors="coerce").fillna(0.0)
            entry_s = open_avg.fillna(pd.to_numeric(sid_rows.get("entry_price"), errors="coerce"))
            entry_s = entry_s.fillna(pd.to_numeric(sid_rows.get("gen_price"), errors="coerce")).fillna(0.0)
            if kind == "DEC":
                day_pnl = open_qty * (entry_s - settle_s)
            else:
                day_pnl = open_qty * (settle_s - entry_s)
            cum_pnl = day_pnl.copy()

            out.loc[sid_idx, "generated_qty"] = delta_qty.values
            out.loc[sid_idx, "cum_qty"] = open_qty.values
            out.loc[sid_idx, "day_close_qty"] = day_close.values
            out.loc[sid_idx, "current_open_qty"] = open_qty.values
            out.loc[sid_idx, "current_open_avg"] = open_avg.values
            out.loc[sid_idx, "day_pnl"] = day_pnl.values
            out.loc[sid_idx, "cum_pnl"] = cum_pnl.values

            if "flags" in out.columns:
                sid_flags = out.loc[sid_idx, "flags"].fillna("").astype(str)
                new_flags = []
                for old_f, dlt in zip(sid_flags.tolist(), delta_qty.tolist()):
                    parts = [x for x in str(old_f).split("|") if str(x).strip()]
                    if float(dlt) < -1e-12 and "TRS_CLOSE_EVENT" not in parts:
                        parts.append("TRS_CLOSE_EVENT")
                    if abs(float(dlt)) <= 1e-12 and "TRS_HOLD" not in parts:
                        parts.append("TRS_HOLD")
                    new_flags.append("|".join(parts))
                out.loc[sid_idx, "flags"] = new_flags
            continue

        cum_gen = pd.to_numeric(sid_rows.get("cum_qty"), errors="coerce").fillna(0.0)
        daily_reduce = dates.map(lambda d: float(pick_first(reduce_map.get((str(sid), str(d))), 0.0) or 0.0)).astype(float)
        cum_reduce = daily_reduce.cumsum()
        open_qty = (cum_gen - cum_reduce).clip(lower=0.0)
        prev_open = open_qty.shift(1).fillna(0.0)
        delta_qty = open_qty - prev_open

        settle_s = pd.to_numeric(sid_rows.get("settle"), errors="coerce").fillna(0.0)
        entry_s = pd.to_numeric(sid_rows.get("entry_price"), errors="coerce")
        entry_s = entry_s.fillna(pd.to_numeric(sid_rows.get("gen_price"), errors="coerce")).fillna(0.0)
        if kind == "DEC":
            day_pnl = open_qty * (entry_s - settle_s)
        else:
            day_pnl = open_qty * (settle_s - entry_s)
        cum_pnl = day_pnl.copy()

        out.loc[sid_idx, "generated_qty"] = delta_qty.values
        out.loc[sid_idx, "cum_qty"] = open_qty.values
        out.loc[sid_idx, "day_close_qty"] = daily_reduce.values
        out.loc[sid_idx, "current_open_qty"] = open_qty.values
        out.loc[sid_idx, "day_pnl"] = day_pnl.values
        out.loc[sid_idx, "cum_pnl"] = cum_pnl.values

        if "flags" in out.columns:
            sid_flags = out.loc[sid_idx, "flags"].fillna("").astype(str)
            new_flags = []
            for old_f, dlt in zip(sid_flags.tolist(), delta_qty.tolist()):
                parts = [x for x in str(old_f).split("|") if str(x).strip()]
                if float(dlt) < -1e-12 and "TRS_CLOSE_EVENT" not in parts:
                    parts.append("TRS_CLOSE_EVENT")
                if abs(float(dlt)) <= 1e-12 and "TRS_HOLD" not in parts:
                    parts.append("TRS_HOLD")
                new_flags.append("|".join(parts))
            out.loc[sid_idx, "flags"] = new_flags

    return out


def enrich_accumulator_daily_rows(
    s_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
    position_timeline: Optional[pd.DataFrame] = None,
) -> pd.DataFrame:
    out = s_df.copy()
    if out.empty or "strategy_code" not in out.columns:
        return out
    acc_mask = out["strategy_code"].astype(str).str.upper().isin(ACCUMULATOR_STRATEGY_CODES)
    if not bool(acc_mask.any()):
        return out

    out["date"] = out["date"].astype(str)
    sid_kind_map: Dict[str, str] = (
        out.loc[acc_mask, ["structure_id", "kind"]]
        .dropna(subset=["structure_id"])
        .assign(
            structure_id=lambda df: df["structure_id"].astype(str).str.strip(),
            kind=lambda df: df["kind"].astype(str).str.upper().str.strip(),
        )
        .drop_duplicates(subset=["structure_id"], keep="last")
        .set_index("structure_id")["kind"]
        .to_dict()
    )
    sid_list = sorted([sid for sid in sid_kind_map.keys() if sid])
    if not sid_list:
        return out
    timeline_work = pd.DataFrame()
    if isinstance(position_timeline, pd.DataFrame) and not position_timeline.empty:
        timeline_work = position_timeline[
            position_timeline["structure_id"].astype(str).str.strip().isin(sid_list)
        ].copy()
        if not timeline_work.empty:
            timeline_work["structure_id"] = timeline_work["structure_id"].astype(str).str.strip()
            timeline_work["date"] = timeline_work["date"].astype(str)

    close_map: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}
    if close2_df is not None and not close2_df.empty:
        c = close2_df.copy()
        c = c[c["group_id"].astype(str) == str(rep_gid)].copy()
        if not is_all_underlying_scope(rep_und):
            c = c[c["underlying"].astype(str) == str(rep_und)].copy()
        c = c[c["structure_id"].astype(str).str.strip().isin(sid_list)].copy()
        if not c.empty:
            c["dt"] = c["dt"].astype(str)
            cutoff_d = parse_date_maybe(rep_date)
            if cutoff_d is not None:
                c_dt = pd.to_datetime(c["dt"], errors="coerce").dt.date
                c = c[c_dt <= cutoff_d].copy()
        if not c.empty:
            if "close_category" in c.columns:
                c["close_category"] = c["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
                c.loc[c["close_category"] == "", "close_category"] = STRUCT_CLOSE_CATEGORY
                c = c[c["close_category"].isin(INTERNAL_POSITION_CLOSE_CATEGORIES)].copy()
            if "is_external" in c.columns:
                c["is_external"] = pd.to_numeric(c["is_external"], errors="coerce").fillna(0).astype(int)
                c = c[c["is_external"] == 0].copy()
            c["qty"] = pd.to_numeric(c["qty"], errors="coerce").fillna(0.0)
            c["side"] = c["side"].astype(str).str.upper()
            c = c[(c["qty"] > 1e-12) & (c["side"].isin(["BUY", "SELL"]))].copy()
            if not c.empty:
                sort_cols = ["dt"]
                if "close_id" in c.columns:
                    sort_cols.append("close_id")
                c = c.sort_values(sort_cols)
                for _, rr in c.iterrows():
                    sid = str(rr.get("structure_id", "")).strip()
                    dt_s = str(rr.get("dt", "")).strip()
                    if not sid or not dt_s:
                        continue
                    close_map.setdefault((sid, dt_s), []).append(
                        {
                            "side": str(rr.get("side", "")).upper(),
                            "qty": float(pick_first(to_float(rr.get("qty")), 0.0) or 0.0),
                            "source_gen_date": str(pick_first(rr.get("source_gen_date"), "") or "").strip(),
                        }
                    )

    eps = 1e-12
    for sid in sid_list:
        sid_mask = acc_mask & out["structure_id"].astype(str).str.strip().eq(str(sid))
        if not bool(sid_mask.any()):
            continue
        sid_rows = out[sid_mask].copy().sort_values(["date"])
        sid_idx = sid_rows.index
        kind = str(sid_kind_map.get(str(sid), "ACC")).upper()
        sid_timeline = timeline_work[timeline_work["structure_id"].astype(str) == str(sid)].copy() if not timeline_work.empty else pd.DataFrame()
        if not sid_timeline.empty:
            sid_timeline = sid_timeline.sort_values(["date"]).drop_duplicates(subset=["date"], keep="last")
            sid_timeline = sid_timeline.set_index("date", drop=False)
            dates = sid_rows["date"].astype(str)
            day_close_vals = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "day_close_qty"] if d in sid_timeline.index else 0.0),
                errors="coerce",
            ).fillna(0.0)
            open_qty_vals = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "current_open_qty"] if d in sid_timeline.index else 0.0),
                errors="coerce",
            ).fillna(0.0)
            open_avg_vals = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "current_open_avg"] if d in sid_timeline.index else np.nan),
                errors="coerce",
            )
            settle_s = pd.to_numeric(sid_rows.get("settle"), errors="coerce").fillna(0.0)
            current_float_vals = [
                structure_day_pnl(kind, qty_v, float(pick_first(avg_v, 0.0) or 0.0), settle_v)
                if qty_v > 1e-12 and pd.notna(avg_v)
                else 0.0
                for qty_v, avg_v, settle_v in zip(
                    open_qty_vals.tolist(),
                    open_avg_vals.tolist(),
                    settle_s.tolist(),
                )
            ]
            current_float_s = pd.Series(current_float_vals, index=sid_rows.index, dtype=float)
            day_float_s = current_float_s - current_float_s.shift(1).fillna(0.0)
            out.loc[sid_idx, "day_close_qty"] = day_close_vals.values
            out.loc[sid_idx, "current_open_qty"] = open_qty_vals.values
            out.loc[sid_idx, "current_open_avg"] = open_avg_vals.values
            out.loc[sid_idx, "day_pnl"] = day_float_s.values
            out.loc[sid_idx, "cum_pnl"] = current_float_s.values
            continue
        lots: List[Dict[str, Any]] = []
        prev_float = 0.0
        day_close_vals: List[float] = []
        open_qty_vals: List[float] = []
        open_avg_vals: List[Optional[float]] = []
        day_float_vals: List[float] = []
        current_float_vals: List[float] = []

        for _, rr in sid_rows.iterrows():
            dt_s = str(rr.get("date", "")).strip()
            gen_qty = max(float(pick_first(to_float(rr.get("generated_qty")), 0.0) or 0.0), 0.0)
            gen_px = float(
                pick_first(
                    to_float(rr.get("gen_price")),
                    to_float(rr.get("entry_price")),
                    to_float(rr.get("strike_price")),
                    to_float(rr.get("settle")),
                    0.0,
                )
                or 0.0
            )
            if gen_qty > eps:
                lots.append({"source_dt": dt_s, "qty": gen_qty, "price": gen_px})

            day_close_qty = 0.0
            for close_rr in close_map.get((str(sid), dt_s), []):
                reduce_qty = structure_close_reduce_qty(
                    kind,
                    close_rr.get("side", ""),
                    float(pick_first(to_float(close_rr.get("qty")), 0.0) or 0.0),
                )
                if reduce_qty <= eps:
                    continue
                day_close_qty += reduce_qty
                remain = reduce_qty
                src_dt = str(close_rr.get("source_gen_date", "")).strip()
                if src_dt:
                    try:
                        src_dt = pd.to_datetime(src_dt).strftime(DATE_FMT)
                    except Exception:
                        src_dt = ""
                if src_dt:
                    for lot in lots:
                        if remain <= eps:
                            break
                        if str(lot.get("source_dt", "")) != src_dt:
                            continue
                        avail = float(pick_first(to_float(lot.get("qty")), 0.0) or 0.0)
                        if avail <= eps:
                            continue
                        take = min(avail, remain)
                        lot["qty"] = avail - take
                        remain -= take
                if remain > eps:
                    for lot in lots:
                        if remain <= eps:
                            break
                        avail = float(pick_first(to_float(lot.get("qty")), 0.0) or 0.0)
                        if avail <= eps:
                            continue
                        take = min(avail, remain)
                        lot["qty"] = avail - take
                        remain -= take
                lots = [lot for lot in lots if float(pick_first(to_float(lot.get("qty")), 0.0) or 0.0) > eps]

            open_qty = float(sum(float(pick_first(to_float(lot.get("qty")), 0.0) or 0.0) for lot in lots))
            open_val = float(
                sum(
                    float(pick_first(to_float(lot.get("qty")), 0.0) or 0.0)
                    * float(pick_first(to_float(lot.get("price")), 0.0) or 0.0)
                    for lot in lots
                )
            )
            open_avg = (open_val / open_qty) if open_qty > eps else None
            settle_v = float(pick_first(to_float(rr.get("settle")), 0.0) or 0.0)
            current_float = (
                structure_day_pnl(kind, open_qty, float(pick_first(open_avg, 0.0)), settle_v)
                if open_qty > eps and open_avg is not None
                else 0.0
            )
            day_float = current_float - prev_float
            prev_float = current_float

            day_close_vals.append(day_close_qty)
            open_qty_vals.append(open_qty)
            open_avg_vals.append(open_avg)
            day_float_vals.append(day_float)
            current_float_vals.append(current_float)

        out.loc[sid_idx, "day_close_qty"] = day_close_vals
        out.loc[sid_idx, "current_open_qty"] = open_qty_vals
        out.loc[sid_idx, "current_open_avg"] = open_avg_vals
        out.loc[sid_idx, "day_pnl"] = day_float_vals
        out.loc[sid_idx, "cum_pnl"] = current_float_vals

    return out


def enrich_vanilla_option_daily_rows(
    s_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
    position_timeline: Optional[pd.DataFrame] = None,
) -> pd.DataFrame:
    out = s_df.copy()
    if out.empty or "strategy_code" not in out.columns:
        return out
    vanilla_mask = out["strategy_code"].astype(str).str.upper().eq(VANILLA_OPTION_CODE)
    if not bool(vanilla_mask.any()):
        return out

    out["date"] = out["date"].astype(str)
    sid_kind_map: Dict[str, str] = (
        out.loc[vanilla_mask, ["structure_id", "kind"]]
        .dropna(subset=["structure_id"])
        .assign(
            structure_id=lambda df: df["structure_id"].astype(str).str.strip(),
            kind=lambda df: df["kind"].astype(str).str.upper().str.strip(),
        )
        .drop_duplicates(subset=["structure_id"], keep="last")
        .set_index("structure_id")["kind"]
        .to_dict()
    )
    sid_list = sorted([sid for sid in sid_kind_map.keys() if sid])
    if not sid_list:
        return out
    timeline_work = pd.DataFrame()
    if isinstance(position_timeline, pd.DataFrame) and not position_timeline.empty:
        timeline_work = position_timeline[
            position_timeline["structure_id"].astype(str).str.strip().isin(sid_list)
        ].copy()
        if not timeline_work.empty:
            timeline_work["structure_id"] = timeline_work["structure_id"].astype(str).str.strip()
            timeline_work["date"] = timeline_work["date"].astype(str)

    reduce_map: Dict[Tuple[str, str], float] = {}
    if close2_df is not None and not close2_df.empty:
        c = close2_df.copy()
        c = c[c["group_id"].astype(str) == str(rep_gid)].copy()
        if not is_all_underlying_scope(rep_und):
            c = c[c["underlying"].astype(str) == str(rep_und)].copy()
        c = c[c["structure_id"].astype(str).str.strip().isin(sid_list)].copy()
        if not c.empty:
            c["dt"] = c["dt"].astype(str)
            cutoff_d = parse_date_maybe(rep_date)
            if cutoff_d is not None:
                c_dt = pd.to_datetime(c["dt"], errors="coerce").dt.date
                c = c[c_dt <= cutoff_d].copy()
        if not c.empty:
            if "close_category" in c.columns:
                c["close_category"] = c["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
                c.loc[c["close_category"] == "", "close_category"] = STRUCT_CLOSE_CATEGORY
                c = c[c["close_category"].isin(INTERNAL_POSITION_CLOSE_CATEGORIES)].copy()
            if "is_external" in c.columns:
                c["is_external"] = pd.to_numeric(c["is_external"], errors="coerce").fillna(0).astype(int)
                c = c[c["is_external"] == 0].copy()
            c["side"] = c["side"].astype(str).str.upper()
            c["qty"] = pd.to_numeric(c["qty"], errors="coerce").fillna(0.0)
            c = c[(c["qty"] > 1e-12) & (c["side"].isin(["BUY", "SELL"]))].copy()
            if not c.empty:
                c["structure_id"] = c["structure_id"].astype(str).str.strip()
                c["reduce_qty"] = c.apply(
                    lambda rr: structure_close_reduce_qty(
                        sid_kind_map.get(str(rr.get("structure_id", "")).strip(), "ACC"),
                        rr.get("side"),
                        float(rr.get("qty", 0.0)),
                    ),
                    axis=1,
                )
                c = c[c["reduce_qty"] > 1e-12].copy()
                if not c.empty:
                    grouped = (
                        c.groupby([c["structure_id"].astype(str), c["dt"].astype(str)])["reduce_qty"]
                        .sum()
                        .reset_index()
                    )
                    reduce_map = {
                        (str(rr.get("structure_id", "")).strip(), str(rr.get("dt", "")).strip()): float(
                            pick_first(to_float(rr.get("reduce_qty")), 0.0) or 0.0
                        )
                        for _, rr in grouped.iterrows()
                    }

    for sid in sid_list:
        sid_mask = vanilla_mask & out["structure_id"].astype(str).str.strip().eq(str(sid))
        if not bool(sid_mask.any()):
            continue
        sid_rows = out[sid_mask].copy().sort_values(["date"])
        sid_idx = sid_rows.index
        sid_last = sid_rows.iloc[-1] if not sid_rows.empty else pd.Series(dtype="object")
        sid_timeline = timeline_work[timeline_work["structure_id"].astype(str) == str(sid)].copy() if not timeline_work.empty else pd.DataFrame()
        base_qty = max(
            float(
                pick_first(
                    to_float(sid_last.get("base_qty_per_day")),
                    to_float(sid_last.get("base_qty")),
                    to_float(sid_last.get("qty")),
                    to_float(sid_last.get("current_open_qty")),
                    0.0,
                )
                or 0.0
            ),
            0.0,
        )
        premium = max(float(pick_first(to_float(sid_last.get("premium")), 0.0) or 0.0), 0.0)
        option_type = normalize_vanilla_option_type(
            pick_first(sid_last.get("option_type"), "put")
        )
        if not sid_timeline.empty:
            sid_timeline = sid_timeline.sort_values(["date"]).drop_duplicates(subset=["date"], keep="last")
            sid_timeline = sid_timeline.set_index("date", drop=False)
            dates = sid_rows["date"].astype(str)
            open_qty = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "current_open_qty"] if d in sid_timeline.index else 0.0),
                errors="coerce",
            ).fillna(0.0)
            day_close_qty = pd.to_numeric(
                dates.map(lambda d: sid_timeline.at[d, "day_close_qty"] if d in sid_timeline.index else 0.0),
                errors="coerce",
            ).fillna(0.0)
        else:
            cum_reduce = sid_rows["date"].astype(str).map(
                lambda d: float(pick_first(to_float(reduce_map.get((str(sid), str(d)))), 0.0) or 0.0)
            ).astype(float).cumsum()
            open_qty = (base_qty - cum_reduce).clip(lower=0.0)
            day_close_qty = sid_rows["date"].astype(str).map(
                lambda d: float(pick_first(to_float(reduce_map.get((str(sid), str(d)))), 0.0) or 0.0)
            ).astype(float)
        cum_reduce = sid_rows["date"].astype(str).map(
            lambda d: float(pick_first(to_float(reduce_map.get((str(sid), str(d)))), 0.0) or 0.0)
        ).astype(float).cumsum()
        settle_s = pd.to_numeric(sid_rows.get("settle"), errors="coerce").fillna(0.0)
        strike_s = pd.to_numeric(sid_rows.get("strike_price"), errors="coerce").fillna(0.0)
        intrinsic_s = np.where(
            np.full(len(sid_rows), option_type == "call", dtype=bool),
            np.maximum(settle_s.to_numpy(dtype=float) - strike_s.to_numpy(dtype=float), 0.0),
            np.maximum(strike_s.to_numpy(dtype=float) - settle_s.to_numpy(dtype=float), 0.0),
        )
        side = vanilla_side_from_kind(sid_kind_map.get(str(sid), "DEC"))
        if side == "buy":
            current_float = open_qty.to_numpy(dtype=float) * (intrinsic_s - premium)
        else:
            current_float = open_qty.to_numpy(dtype=float) * (premium - intrinsic_s)
        current_float_s = pd.Series(current_float, index=sid_rows.index, dtype=float)
        day_float_s = current_float_s - current_float_s.shift(1).fillna(0.0)

        out.loc[sid_idx, "generated_qty"] = 0.0
        out.loc[sid_idx, "cum_qty"] = 0.0
        out.loc[sid_idx, "day_close_qty"] = day_close_qty.values
        out.loc[sid_idx, "current_open_qty"] = open_qty.values
        out.loc[sid_idx, "day_pnl"] = day_float_s.values
        out.loc[sid_idx, "cum_pnl"] = current_float_s.values

    return out


def adjust_structure_daily_view_columns(s_view: pd.DataFrame) -> pd.DataFrame:
    s_view = s_view.copy()
    if not s_view.empty and "策略类型" in s_view.columns and "熔断行权价" in s_view.columns:
        melt_mask = s_view["策略类型"].astype(str).apply(
            lambda x: resolve_strategy_code_for_display(x) in MELT_TRIGGER_PRICE_STRATEGY_CODES
        )
        s_view.loc[~melt_mask, "熔断行权价"] = np.nan
    if not s_view.empty and "策略类型" in s_view.columns:
        strat_s = s_view["策略类型"].astype(str)
        only_airbag = bool(strat_s.eq("安全气囊").all())
        has_airbag = bool(strat_s.eq("安全气囊").any())
        has_snowball = bool(strat_s.eq("雪球结构").any())
        if only_airbag:
            s_view = s_view.drop(columns=["参与倍数"], errors="ignore")
            s_view = s_view.drop(
                columns=["累计浮盈亏", "累计生成量", "当日平仓量", "当前持仓量", "当日补贴盈亏", "累计补贴盈亏"],
                errors="ignore",
            )
        if not has_airbag:
            s_view = s_view.drop(columns=["参与率"], errors="ignore")
            s_view = s_view.drop(columns=["盈亏计算"], errors="ignore")
        if not has_snowball:
            s_view = s_view.drop(
                columns=[
                    "雪球阶段",
                    "雪球当前票息(%)",
                    "雪球当前敲出线",
                    "雪球当前浮盈亏",
                    "雪球已敲入",
                    "雪球首次敲入日",
                    "雪球折价触发日",
                    "雪球转期货数量",
                    "雪球转期货开仓价",
                    "雪球当前期货浮盈亏",
                ],
                errors="ignore",
            )
    if "参与率" in s_view.columns and "参与率（%）" not in s_view.columns:
        s_view = s_view.rename(columns={"参与率": "参与率（%）"})
    return s_view


def phoenix_knock_in_qty_mode_cn(value: Any) -> str:
    mode = str(value or "").strip().lower()
    return {
        "all": "全部数量",
        "remaining": "剩余数量",
    }.get(mode, str(value or "").strip() or "-")


def phoenix_knock_out_settlement_mode_cn(value: Any) -> str:
    mode = str(value or "").strip().lower()
    return {
        "subsidy": "补贴金额",
        "delivery": "头寸",
    }.get(mode, str(value or "").strip() or "-")


def phoenix_participation_rate_display(value: Any) -> str:
    rate = to_float(value)
    if rate is None:
        return "-"
    return f"{int(round(float(rate)))}倍"


def merge_vanilla_editor_params(
    old_params_value: Any,
    *,
    option_type: Any,
    side: Any,
    premium: Any,
    trade_date: Any,
    expiry_date: Any,
    customer_name: Any = "",
    counterparty: Any = "",
    contract_month: Any = "",
    note: Any = "",
) -> Dict[str, Any]:
    params_json = parse_json_obj(old_params_value, {})
    if not isinstance(params_json, dict):
        params_json = {}
    params_json = dict(params_json)
    params_json.update(
        {
            "multiplier": 1.0,
            "subsidy_per_ton": 0.0,
            "option_type": normalize_vanilla_option_type(option_type, "put"),
            "side": normalize_vanilla_side(side, "sell"),
            "premium": max(float(pick_first(premium, 0.0) or 0.0), 0.0),
            "trade_date": str(pick_first(trade_date, "") or "").strip(),
            "expiry_date": str(pick_first(expiry_date, "") or "").strip(),
        }
    )
    for key, value in {
        "customer_name": customer_name,
        "counterparty": counterparty,
        "contract_month": contract_month,
        "note": note,
    }.items():
        text = str(pick_first(value, "") or "").strip()
        if text:
            params_json[key] = text
        else:
            params_json.pop(key, None)
    return params_json


def special_snapshot_range_text(candidate: Mapping[str, Any], *, as_of_date: Any = None) -> str:
    rec = dict(candidate) if isinstance(candidate, Mapping) else {}
    start_text = str(pick_first(rec.get("start_date"), "") or "").strip() or "-"
    end_text = str(pick_first(rec.get("end_date"), "") or "").strip() or "-"
    remaining_days_raw = pick_first(rec.get("remaining_trading_days"), rec.get("remaining_days"))
    remaining_days_num = to_float(remaining_days_raw)
    if remaining_days_num is None:
        remaining_days_num = float(
            remaining_trading_days_excl_today(
                pick_first(as_of_date, rec.get("as_of_date"), rec.get("rep_date")),
                rec.get("end_date"),
                start_date_v=rec.get("start_date"),
            )
        )
    remaining_days = max(int(round(float(pick_first(remaining_days_num, 0.0) or 0.0))), 0)
    return f"{start_text} -> {end_text} / 剩余{remaining_days}天"


def special_page_candidate_display_id(candidate: Mapping[str, Any]) -> str:
    rec = dict(candidate) if isinstance(candidate, Mapping) else {}
    resolved = rec.get("resolved", {}) if isinstance(rec.get("resolved", {}), Mapping) else {}
    return str(
        pick_first(
            rec.get("structure_display_id"),
            rec.get("structure_code"),
            resolved.get("structure_code") if isinstance(resolved, Mapping) else "",
            rec.get("structure_id"),
            resolved.get("structure_id") if isinstance(resolved, Mapping) else "",
            "",
        )
    ).strip()


def special_page_candidate_option_label(candidate: Mapping[str, Any]) -> str:
    rec = dict(candidate) if isinstance(candidate, Mapping) else {}
    detail_label = str(
        pick_first(
            rec.get("detail_label"),
            rec.get("label"),
            special_page_candidate_display_id(rec),
            "",
        )
    ).strip()
    status_text = str(
        pick_first(
            rec.get("status_cn"),
            rec.get("lifecycle"),
            "",
        )
    ).strip()
    remaining_days = max(
        int(
            round(
                float(
                    pick_first(
                        to_float(rec.get("remaining_days")),
                        to_float(rec.get("remaining_trading_days")),
                        0.0,
                    )
                    or 0.0
                )
            )
        ),
        0,
    )
    parts = [detail_label]
    if status_text:
        parts.append(status_text)
    parts.append(f"剩余 {remaining_days} 天")
    return " | ".join([str(x).strip() for x in parts if str(x).strip()])


def merge_phoenix_acc_editor_payload(
    old_params_value: Any,
    old_meta_value: Any,
    *,
    phoenix_terms: Mapping[str, Any],
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    params_json = parse_json_obj(old_params_value, {})
    if not isinstance(params_json, dict):
        params_json = {}
    params_json = dict(params_json)
    meta_json = parse_json_obj(old_meta_value, {})
    if not isinstance(meta_json, dict):
        meta_json = {}
    meta_json = dict(meta_json)

    multiple = float(pick_first(phoenix_terms.get("participation_rate"), 0.0) or 0.0)
    subsidy_per_ton = float(pick_first(phoenix_terms.get("subsidy_per_ton"), 0.0) or 0.0)
    knock_out_exercise_price = to_float(phoenix_terms.get("knock_out_exercise_price"))

    params_json["multiplier"] = multiple
    params_json["participation_rate"] = multiple
    params_json["subsidy_per_ton"] = subsidy_per_ton
    params_json["knock_in_exercise_price"] = float(
        pick_first(phoenix_terms.get("knock_in_exercise_price"), phoenix_terms.get("entry_price"), 0.0) or 0.0
    )
    params_json["knock_in_qty_mode"] = str(pick_first(phoenix_terms.get("knock_in_qty_mode"), "all"))
    params_json["knock_out_settlement_mode"] = str(pick_first(phoenix_terms.get("knock_out_settlement_mode"), "subsidy"))
    if knock_out_exercise_price is None:
        params_json.pop("knock_out_exercise_price", None)
    else:
        params_json["knock_out_exercise_price"] = float(knock_out_exercise_price)
    meta_json["ko_terminate"] = True
    return params_json, meta_json


def build_phoenix_detail_card_frame(
    struct_row: Mapping[str, Any],
    latest_daily_row: Optional[Mapping[str, Any]] = None,
) -> pd.DataFrame:
    resolved = dict(struct_row) if isinstance(struct_row, Mapping) else {}
    strategy_code = resolve_strategy_code_for_display(resolved.get("strategy_code", resolved.get("strategy", "")))
    if strategy_code not in PHOENIX_ACC_STRATEGY_CODES:
        return pd.DataFrame(columns=["项目", "内容"])

    detail_rows: List[Tuple[str, str]] = [
        (
            "结构名称",
            default_structure_name(
                resolved.get("strategy_code"),
                resolved.get("kind"),
                fallback_name=str(pick_first(resolved.get("name"), "")),
            ),
        ),
        ("方向", direction_display_cn(resolved.get("kind"))),
        ("入场价", _fmt_price_for_detail_label(resolved.get("entry_price"))),
        ("敲入价", _fmt_price_for_detail_label(resolved.get("barrier_in"))),
        (
            "敲出价",
            _fmt_price_for_detail_label(pick_first(resolved.get("knock_out_price"), resolved.get("barrier_out"))),
        ),
        ("敲入熔断行权价", _fmt_price_for_detail_label(resolved.get("knock_in_exercise_price"))),
        ("区间补贴", _fmt_price_for_detail_label(resolved.get("subsidy_per_ton"))),
        ("参与率", phoenix_participation_rate_display(resolved.get("multiple"))),
        ("敲入给量模式", phoenix_knock_in_qty_mode_cn(resolved.get("knock_in_qty_mode"))),
        ("敲出结算模式", phoenix_knock_out_settlement_mode_cn(resolved.get("knock_out_settlement_mode"))),
    ]
    if str(resolved.get("knock_out_settlement_mode", "")).strip().lower() == "delivery":
        detail_rows.append(("敲出行权价", _fmt_price_for_detail_label(resolved.get("knock_out_exercise_price"))))

    latest = dict(latest_daily_row) if isinstance(latest_daily_row, Mapping) else {}
    if latest:
        current_status = (
            override_finished_status_display(
                pick_first(
                    latest.get("状态"),
                    latest.get("status"),
                    "",
                ),
                pick_first(
                    latest.get("剩余交易日"),
                    latest.get("remaining_trading_days"),
                    latest.get("remaining_days"),
                    latest.get("剩余天数"),
                    latest.get("剩余天"),
                ),
            )
            or "-"
        )
        detail_rows.extend(
            [
                ("当前状态", current_status),
                ("当前事件类型", str(pick_first(latest.get("事件类型"), latest.get("event_type"), "")).strip() or "-"),
                ("当前给量方向", str(pick_first(latest.get("给量方向"), latest.get("delivered_side"), "")).strip() or "-"),
                ("当前终止原因", str(pick_first(latest.get("终止原因"), latest.get("terminate_reason"), "")).strip() or "-"),
            ]
        )

    return pd.DataFrame(
        [{"项目": label, "内容": value} for label, value in detail_rows],
        columns=["项目", "内容"],
    )


def build_vanilla_option_detail_card_frame(
    struct_row: Mapping[str, Any],
    latest_daily_row: Optional[Mapping[str, Any]] = None,
) -> pd.DataFrame:
    resolved = dict(struct_row) if isinstance(struct_row, Mapping) else {}
    strategy_code = resolve_strategy_code_for_display(resolved.get("strategy_code", resolved.get("strategy", "")))
    if strategy_code != VANILLA_OPTION_CODE:
        return pd.DataFrame(columns=["项目", "内容"])

    detail_rows: List[Tuple[str, str]] = [
        ("结构类型", "香草期权"),
        ("结构名称", build_vanilla_option_name(resolved.get("option_type"), resolved.get("side"))),
        ("方向", vanilla_option_type_cn(resolved.get("option_type"))),
        ("买卖方向", vanilla_side_cn(resolved.get("side"))),
        ("标的", str(pick_first(resolved.get("underlying"), "")).strip() or "-"),
        ("到期日", pick_first_text(resolved.get("expiry_date"), resolved.get("end_date"), default="-") or "-"),
        ("开始日期", pick_first_text(resolved.get("start_date"), resolved.get("trade_date"), default="-") or "-"),
        ("入场价", _fmt_price_for_detail_label(resolved.get("entry_price"))),
        ("行权价", _fmt_price_for_detail_label(resolved.get("strike_price"))),
        ("期权费", _fmt_price_for_detail_label(resolved.get("premium"))),
    ]
    for label, value in [
        ("客户名称", resolved.get("customer_name")),
        ("交易对手", resolved.get("counterparty")),
        ("合约/月份", resolved.get("contract_month")),
        ("备注", resolved.get("note")),
    ]:
        text = str(pick_first(value, "") or "").strip()
        if text:
            detail_rows.append((label, text))

    latest = dict(latest_daily_row) if isinstance(latest_daily_row, Mapping) else {}
    if latest:
        current_status = (
            override_finished_status_display(
                pick_first(latest.get("状态"), latest.get("status"), ""),
                pick_first(
                    latest.get("剩余交易日"),
                    latest.get("remaining_trading_days"),
                    latest.get("remaining_days"),
                    latest.get("剩余天数"),
                    latest.get("剩余天"),
                ),
            )
            or "-"
        )
        detail_rows.extend(
            [
                ("当前状态", current_status),
                ("当前浮盈亏", _fmt_price_for_detail_label(pick_first(latest.get("累计浮盈亏"), latest.get("cum_pnl")))),
                ("当前持仓量", _fmt_price_for_detail_label(pick_first(latest.get("当前持仓量"), latest.get("current_open_qty")))),
            ]
        )

    return pd.DataFrame(
        [{"项目": label, "内容": value} for label, value in detail_rows],
        columns=["项目", "内容"],
    )


def build_structure_daily_export_view(s_view: pd.DataFrame) -> pd.DataFrame:
    out = s_view.copy() if isinstance(s_view, pd.DataFrame) else pd.DataFrame()
    if out.empty:
        return out
    alias_map = {
        "date": "日期",
        "structure_id": "结构ID",
        "structure_name": "结构名称",
        "direction": "方向",
        "buy_sell_side": "买卖方向",
        "expiry_date": "到期日",
        "premium": "期权费",
        "status": "状态",
        "remaining_trading_days": "剩余交易日",
        "close": "收盘价",
        "day_index": "观察日序号",
        "daily_qty": "每日基准量",
        "event_type": "事件类型",
        "terminate_reason": "终止原因",
        "generated_qty": "当日生成量",
        "gen_price": "生成价",
        "day_subsidy_pnl": "当日补贴盈亏",
        "cum_subsidy_pnl": "累计补贴盈亏",
        "delivered_side": "给量方向",
    }
    for alias_col, src_col in alias_map.items():
        if alias_col not in out.columns and src_col in out.columns:
            out[alias_col] = out[src_col]
    for status_col in ["status", "状态"]:
        if status_col not in out.columns:
            continue
        out[status_col] = out.apply(
            lambda r: override_finished_status_display(
                r.get(status_col),
                pick_first(
                    r.get("remaining_trading_days"),
                    r.get("remaining_days"),
                    r.get("剩余交易日"),
                    r.get("剩余天数"),
                    r.get("剩余天"),
                ),
            ),
            axis=1,
        )
    preferred_cols = [
        "date",
        "structure_id",
        "structure_name",
        "direction",
        "status",
        "remaining_trading_days",
        "close",
        "day_index",
        "daily_qty",
        "event_type",
        "terminate_reason",
        "generated_qty",
        "gen_price",
        "day_subsidy_pnl",
        "cum_subsidy_pnl",
        "delivered_side",
        "日期",
        "结构ID",
        "结构",
        "结构名称",
        "风险子",
        "方向",
        "买卖方向",
        "策略类型",
        "到期日",
        "期权费",
        "剩余交易日",
        "收盘价",
        "观察日序号",
        "每日基准量",
        "状态",
        "事件类型",
        "终止原因",
        "给量方向",
        "当日补贴盈亏",
        "累计补贴盈亏",
        "当日生成量",
        "生成价",
    ]
    ordered_cols = [c for c in preferred_cols if c in out.columns]
    tail_cols = [c for c in out.columns if c not in ordered_cols]
    return out[ordered_cols + tail_cols].copy()


