def coerce_display_numeric_columns(df: pd.DataFrame, numeric_cols: List[str]) -> pd.DataFrame:
    """表格展示前统一将数值列转为数值/空值，避免 NumberColumn 被空字符串或 'None' 干扰。"""
    if df is None or df.empty:
        return df
    out = df.copy()
    for col in numeric_cols:
        if col in out.columns:
            out[col] = pd.to_numeric(out[col], errors="coerce")
    return out


def build_trs_monitor_frame(s_df: pd.DataFrame) -> pd.DataFrame:
    trs_cols = ["结构", "风险子", "方向", "入场价", "数量", "当日浮盈亏"]
    if s_df is None or s_df.empty or "策略类型" not in s_df.columns:
        return pd.DataFrame(columns=trs_cols)

    out = s_df.copy()
    trs_mask = out["策略类型"].astype(str).str.strip().eq("TRS头寸")
    if not bool(trs_mask.any()):
        return pd.DataFrame(columns=trs_cols)
    out = out.loc[trs_mask].copy()

    qty_s = (
        pd.to_numeric(out["当前持仓量"], errors="coerce")
        if "当前持仓量" in out.columns
        else pd.Series(index=out.index, dtype=float)
    )
    fallback_qty_s = (
        pd.to_numeric(out["累计生成量"], errors="coerce")
        if "累计生成量" in out.columns
        else pd.Series(index=out.index, dtype=float)
    )
    qty_s = qty_s.where(qty_s.notna(), fallback_qty_s)
    qty_s = qty_s.where(qty_s.abs() > 1e-12, fallback_qty_s)
    out["_trs_qty"] = qty_s.fillna(0.0)
    out["_trs_date"] = pd.to_datetime(out["日期"], errors="coerce") if "日期" in out.columns else pd.NaT
    out["_trs_sid"] = (
        out["结构ID"].astype(str).str.strip()
        if "结构ID" in out.columns
        else out["结构"].astype(str).str.strip()
    )

    out = (
        out.sort_values(["_trs_date", "_trs_sid"])
        .groupby("_trs_sid", as_index=False)
        .tail(1)
        .copy()
    )
    out = out[out["_trs_qty"] > 1e-12].copy()
    if out.empty:
        return pd.DataFrame(columns=trs_cols)

    out["数量"] = out["_trs_qty"]
    for col in ["结构", "风险子", "方向"]:
        if col not in out.columns:
            out[col] = ""
    for col in ["入场价", "当日浮盈亏"]:
        if col not in out.columns:
            out[col] = 0.0

    return (
        out[trs_cols]
        .sort_values(["风险子", "结构"], na_position="last")
        .reset_index(drop=True)
    )


