def build_row_map(df: pd.DataFrame, key_col: str) -> Dict[str, Dict[str, Any]]:
    """将 DataFrame 按指定主键列映射为 {key: row_dict}。"""
    if df is None or df.empty or key_col not in df.columns:
        return {}
    out: Dict[str, Dict[str, Any]] = {}
    for _, r in df.iterrows():
        out[str(r.get(key_col))] = dict(r)
    return out


def build_structure_id_maps(structs_df: pd.DataFrame, fields: List[str]) -> Dict[str, Dict[str, Any]]:
    """按 structure_id 构建多字段映射字典，缺列自动返回空映射。"""
    field_keys = tuple(str(f) for f in fields)
    cache_key = (
        "build_structure_id_maps",
        _db_file_version_token(),
        _df_runtime_fingerprint(structs_df),
        field_keys,
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return _copy_cached_runtime_value(cached)
    out: Dict[str, Dict[str, Any]] = {str(f): {} for f in field_keys}
    if structs_df is None or structs_df.empty or "structure_id" not in structs_df.columns:
        return out
    sid_series = structs_df["structure_id"].astype(str)
    sid_vals = sid_series.tolist()
    for f in field_keys:
        f_s = str(f)
        if f_s not in structs_df.columns:
            continue
        col_vals = structs_df[f_s].tolist()
        out[f_s] = {str(sid): v for sid, v in zip(sid_vals, col_vals)}
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, out, limit=48)
    return _copy_cached_runtime_value(out)


def is_all_underlying_scope(v: Any) -> bool:
    s = str(pick_first(v, "")).strip()
    return s in {"全部", "ALL", "全品种", "*"}


def build_close_detail_maps(structs_df: pd.DataFrame, groups_df: pd.DataFrame) -> Dict[str, Dict[str, Any]]:
    cache_key = (
        "build_close_detail_maps",
        _db_file_version_token(),
        _df_runtime_fingerprint(structs_df),
        _df_runtime_fingerprint(groups_df),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return _copy_cached_runtime_value(cached)
    sid_maps = build_structure_id_maps(
        structs_df,
        [
            "name",
            "risk_party",
            "kind",
            "underlying",
            "strike_price",
            "barrier_in",
            "barrier_out",
            "strategy_code",
            "strategy",
            "structure_code",
        ],
    )
    struct_name_map = sid_maps.get("name", {})
    struct_risk_map = sid_maps.get("risk_party", {})
    struct_kind_map = sid_maps.get("kind", {})
    struct_und_map = sid_maps.get("underlying", {})
    struct_strike_map = sid_maps.get("strike_price", {})
    struct_barrier_in_map = sid_maps.get("barrier_in", {})
    struct_barrier_out_map = sid_maps.get("barrier_out", {})
    struct_strategy_code_map = sid_maps.get("strategy_code", {})
    struct_strategy_raw_map = sid_maps.get("strategy", {})
    struct_code_map = {
        str(sid): resolve_structure_display_code(sid, code)
        for sid, code in sid_maps.get("structure_code", {}).items()
    }
    group_und_map = groups_df.set_index("group_id")["underlying"].to_dict() if not groups_df.empty else {}
    struct_open_px_map: Dict[str, float] = {}
    if not structs_df.empty:
        for _, r in structs_df.iterrows():
            sid = str(r.get("structure_id"))
            struct_open_px_map[sid] = float(pick_first(to_float(r.get("entry_price")), to_float(r.get("gen_price")), 0.0))
    payload = {
        "struct_name_map": struct_name_map,
        "struct_risk_map": struct_risk_map,
        "struct_kind_map": struct_kind_map,
        "struct_und_map": struct_und_map,
        "struct_strike_map": struct_strike_map,
        "struct_barrier_in_map": struct_barrier_in_map,
        "struct_barrier_out_map": struct_barrier_out_map,
        "struct_strategy_code_map": struct_strategy_code_map,
        "struct_strategy_raw_map": struct_strategy_raw_map,
        "struct_code_map": struct_code_map,
        "struct_open_px_map": struct_open_px_map,
        "group_und_map": group_und_map,
    }
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, payload, limit=48)
    return _copy_cached_runtime_value(payload)


def build_structure_close_detail_frame(
    close2_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    cutoff_d: Optional[date],
    group_name_map: Dict[str, str],
    maps: Dict[str, Dict[str, Any]],
) -> pd.DataFrame:
    if close2_df.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)
    struct_name_map = maps.get("struct_name_map", {})
    struct_risk_map = maps.get("struct_risk_map", {})
    struct_kind_map = maps.get("struct_kind_map", {})
    struct_und_map = maps.get("struct_und_map", {})
    struct_strike_map = maps.get("struct_strike_map", {})
    struct_barrier_in_map = maps.get("struct_barrier_in_map", {})
    struct_barrier_out_map = maps.get("struct_barrier_out_map", {})
    struct_strategy_code_map = maps.get("struct_strategy_code_map", {})
    struct_strategy_raw_map = maps.get("struct_strategy_raw_map", {})
    struct_code_map = maps.get("struct_code_map", {})
    struct_open_px_map = maps.get("struct_open_px_map", {})

    tmp = close2_df.copy()
    tmp = tmp[tmp["group_id"].astype(str) == str(rep_gid)].copy()
    if not is_all_underlying_scope(rep_und):
        tmp = tmp[tmp["underlying"].astype(str) == str(rep_und)].copy()
    if cutoff_d is not None:
        dt_s = pd.to_datetime(tmp["dt"], errors="coerce").dt.date
        tmp = tmp[dt_s <= cutoff_d].copy()
    if tmp.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    tmp["策略组"] = tmp["group_id"].map(lambda x: f"{x} - {group_name_map.get(x, '')}")
    tmp["结构"] = tmp["structure_id"].map(
        lambda x: (
            "外部-外部平仓"
            if str(x) == "外部"
            else structure_verbose_label(
                struct_code_map.get(str(x), str(x)),
                struct_name_map.get(x, ""),
                struct_risk_map.get(x, ""),
                struct_kind_map.get(x, ""),
                struct_und_map.get(x, ""),
                struct_open_px_map.get(str(x), None),
                to_float(struct_strike_map.get(x, None)),
                strategy_value=pick_first(struct_strategy_code_map.get(x, ""), struct_strategy_raw_map.get(x, "")),
                knock_in_price=to_float(struct_barrier_in_map.get(x, None)),
                barrier_price=resolve_display_barrier_price(
                    pick_first(struct_strategy_code_map.get(x, ""), struct_strategy_raw_map.get(x, "")),
                    barrier_out=to_float(struct_barrier_out_map.get(x, None)),
                    barrier_in=to_float(struct_barrier_in_map.get(x, None)),
                    strike_price=to_float(struct_strike_map.get(x, None)),
                ),
            )
        )
    )
    if "close_category" in tmp.columns:
        tmp["平仓类别"] = tmp["close_category"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
        tmp.loc[tmp["平仓类别"] == "", "平仓类别"] = STRUCT_CLOSE_CATEGORY
    else:
        tmp["平仓类别"] = STRUCT_CLOSE_CATEGORY
    manual_closed_structs = set(tmp[tmp["平仓类别"].astype(str) == MANUAL_STRUCT_CLOSE_CATEGORY]["structure_id"].astype(str).tolist())
    manual_reduced_structs = set(tmp[tmp["平仓类别"].astype(str) == MANUAL_STRUCT_REDUCTION_CATEGORY]["structure_id"].astype(str).tolist())
    tmp["结构状态"] = tmp["structure_id"].astype(str).apply(
        lambda x: "已手动平仓" if (str(x) in manual_closed_structs and str(x) != "外部") else ""
    )
    if manual_reduced_structs:
        reduced_mask = (
            tmp["structure_id"].astype(str).isin(manual_reduced_structs)
            & ~tmp["structure_id"].astype(str).isin(manual_closed_structs)
            & tmp["structure_id"].astype(str).ne("外部")
        )
        if bool(reduced_mask.any()):
            tmp.loc[reduced_mask, "结构状态"] = "整体减仓"
    tmp["方向"] = tmp["side"].map({"BUY": close_side_to_cn("BUY"), "SELL": close_side_to_cn("SELL"), "平仓": "平仓"}).fillna(tmp["side"])
    if "underlying" not in tmp.columns:
        tmp["underlying"] = ""
    tmp["品种"] = tmp["underlying"].astype(str)
    tmp["头寸价格"] = pd.to_numeric(tmp.get("open_price"), errors="coerce")
    tmp["头寸价格"] = tmp["头寸价格"].fillna(tmp["structure_id"].astype(str).map(struct_open_px_map))
    tmp["换月盈亏"] = pd.to_numeric(tmp.get("roll_spread_pnl"), errors="coerce")
    if "quick_batch_id" in tmp.columns:
        roll_mask = tmp["quick_batch_id"].fillna("").astype(str).str.startswith("TRS_ROLL_")
        tmp.loc[~roll_mask, "换月盈亏"] = np.nan
    else:
        tmp["换月盈亏"] = np.nan
    tmp = tmp.rename(columns={"dt": "日期", "qty": "数量", "close_price": "平仓价", "pnl": "平仓盈亏"})
    tmp["现货盈亏"] = 0.0
    tmp["合计盈亏"] = numeric_col(tmp, "平仓盈亏")
    tmp["平仓批次号"] = tmp.get("quick_batch_id", "").fillna("").astype(str)
    tmp["记录类型"] = "结构记录"
    return tmp[CLOSE_DETAIL_COLUMNS].copy()


def build_spot_close_detail_frame(
    spot_match_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    cutoff_d: Optional[date],
    group_name_map: Dict[str, str],
    maps: Dict[str, Dict[str, Any]],
) -> pd.DataFrame:
    if spot_match_df.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)
    struct_code_map = maps.get("struct_code_map", {})
    struct_name_map = maps.get("struct_name_map", {})
    struct_risk_map = maps.get("struct_risk_map", {})
    struct_kind_map = maps.get("struct_kind_map", {})
    struct_und_map = maps.get("struct_und_map", {})
    struct_strike_map = maps.get("struct_strike_map", {})
    struct_barrier_in_map = maps.get("struct_barrier_in_map", {})
    struct_barrier_out_map = maps.get("struct_barrier_out_map", {})
    struct_strategy_code_map = maps.get("struct_strategy_code_map", {})
    struct_strategy_raw_map = maps.get("struct_strategy_raw_map", {})
    struct_open_px_map = maps.get("struct_open_px_map", {})
    group_und_map = maps.get("group_und_map", {})

    sm = spot_match_df.copy()
    sm = sm[sm["group_id"].astype(str) == str(rep_gid)].copy()
    if cutoff_d is not None:
        sm_dt = pd.to_datetime(sm.get("match_dt"), errors="coerce").dt.date
        sm = sm[sm_dt <= cutoff_d].copy()
    if sm.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    if "structure_id" not in sm.columns:
        sm["structure_id"] = ""
    sid_sm = sm["structure_id"].fillna("").astype(str).str.strip()
    sid_und = sid_sm.map(lambda x: str(pick_first(struct_und_map.get(str(x)), ""))).astype(str)
    gid_und = sm["group_id"].astype(str).map(lambda x: str(pick_first(group_und_map.get(str(x)), ""))).astype(str)
    if not is_all_underlying_scope(rep_und):
        mask_rep_und = ((sid_sm != "") & (sid_und == str(rep_und))) | ((sid_sm == "") & (gid_und == str(rep_und)))
        sm = sm[mask_rep_und].copy()
    if sm.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)

    sm["策略组"] = sm["group_id"].map(lambda x: f"{x} - {group_name_map.get(x, '')}")

    def _spot_struct_label(sid_val: Any, spot_name_val: Any) -> str:
        sid_s = str(pick_first(sid_val, "")).strip()
        spot_name_s = str(pick_first(spot_name_val, "")).strip()
        if not sid_s:
            return f"现货:{spot_name_s}" if spot_name_s else "纯现货"
        struct_label = structure_verbose_label(
            struct_code_map.get(sid_s, sid_s),
            struct_name_map.get(sid_s, sid_s),
            struct_risk_map.get(sid_s, ""),
            struct_kind_map.get(sid_s, ""),
            struct_und_map.get(sid_s, ""),
            struct_open_px_map.get(sid_s, None),
            to_float(struct_strike_map.get(sid_s, None)),
            strategy_value=pick_first(struct_strategy_code_map.get(sid_s, ""), struct_strategy_raw_map.get(sid_s, "")),
            knock_in_price=to_float(struct_barrier_in_map.get(sid_s, None)),
            barrier_price=resolve_display_barrier_price(
                pick_first(struct_strategy_code_map.get(sid_s, ""), struct_strategy_raw_map.get(sid_s, "")),
                barrier_out=to_float(struct_barrier_out_map.get(sid_s, None)),
                barrier_in=to_float(struct_barrier_in_map.get(sid_s, None)),
                strike_price=to_float(struct_strike_map.get(sid_s, None)),
            ),
        )
        return f"{spot_name_s}-{struct_label}" if spot_name_s else struct_label

    sm["结构"] = sm.apply(lambda r: _spot_struct_label(r.get("structure_id", ""), r.get("spot_name", "")), axis=1)
    sm["结构状态"] = ""
    sm["平仓类别"] = SPOT_HEDGE_CLOSE_CATEGORY
    sid_sm2 = sm["structure_id"].fillna("").astype(str).str.strip()
    sm["品种"] = sid_sm2.map(lambda x: str(pick_first(struct_und_map.get(str(x)), ""))).astype(str)
    sm.loc[sm["品种"].astype(str).str.strip() == "", "品种"] = sm["group_id"].astype(str).map(
        lambda x: str(pick_first(group_und_map.get(str(x)), ""))
    )
    sm["方向"] = "现货平仓"
    if "match_dt" not in sm.columns:
        sm["match_dt"] = ""
    sm["日期"] = sm["match_dt"].fillna("").astype(str)
    sm["数量"] = numeric_col(sm, "matched_qty")
    sm["头寸价格"] = numeric_col(sm, "spot_buy_avg_price")
    sm["平仓价"] = numeric_col(sm, "spot_sell_price")
    sm["换月盈亏"] = np.nan
    sm["平仓盈亏"] = 0.0
    sm["现货盈亏"] = numeric_col(sm, "spot_pnl")
    sm["合计盈亏"] = sm["现货盈亏"]
    if "close_batch_id" not in sm.columns:
        sm["close_batch_id"] = ""
    sm["平仓批次号"] = sm["close_batch_id"].fillna("").astype(str)
    sm["记录类型"] = "现货记录"
    return sm[CLOSE_DETAIL_COLUMNS].copy()


def build_close_detail_table(
    close2_df: pd.DataFrame,
    spot_match_df: pd.DataFrame,
    rep_gid: Any,
    rep_und: Any,
    rep_date: Any,
    group_name_map: Dict[str, str],
    structs_df: pd.DataFrame,
    groups_df: pd.DataFrame,
) -> pd.DataFrame:
    maps = build_close_detail_maps(structs_df, groups_df)
    try:
        cutoff_d = datetime.strptime(str(rep_date), DATE_FMT).date()
    except Exception:
        cutoff_d = None

    close_frames: List[pd.DataFrame] = []
    struct_frame = build_structure_close_detail_frame(close2_df, rep_gid, rep_und, cutoff_d, group_name_map, maps)
    if not struct_frame.empty:
        close_frames.append(struct_frame)
    spot_frame = build_spot_close_detail_frame(spot_match_df, rep_gid, rep_und, cutoff_d, group_name_map, maps)
    if not spot_frame.empty:
        close_frames.append(spot_frame)
    if close_frames:
        return pd.concat(close_frames, ignore_index=True)
    return pd.DataFrame(columns=CLOSE_DETAIL_COLUMNS)


def build_close_detail_editor_view(
    close2_df: pd.DataFrame,
    *,
    group_id: Any,
    main_underlying: Any,
    structs_df: pd.DataFrame,
) -> pd.DataFrame:
    if close2_df is None or close2_df.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_EDITOR_COLUMNS)

    sid_maps = build_structure_id_maps(
        structs_df,
        [
            "name",
            "risk_party",
            "structure_code",
        ],
    )
    name_map = sid_maps.get("name", {})
    risk_map = sid_maps.get("risk_party", {})
    display_code_map = {
        str(sid): resolve_structure_display_code(sid, code)
        for sid, code in sid_maps.get("structure_code", {}).items()
    }
    open_price_map: Dict[str, float] = {}
    if structs_df is not None and not structs_df.empty:
        for _, rr in structs_df.iterrows():
            sid = str(pick_first(rr.get("structure_id"), "")).strip()
            if not sid:
                continue
            open_price_map[sid] = float(
                pick_first(
                    to_float(rr.get("entry_price")),
                    to_float(rr.get("gen_price")),
                    0.0,
                )
                or 0.0
            )

    sdf = close2_df.copy()
    sdf = sdf[sdf["group_id"].astype(str) == str(group_id)].copy()
    if str(pick_first(main_underlying, "")).strip():
        sdf = sdf[sdf["underlying"].astype(str) == str(main_underlying)].copy()
    if sdf.empty:
        return pd.DataFrame(columns=CLOSE_DETAIL_EDITOR_COLUMNS)

    close_category_series = sdf.get("close_category", pd.Series("", index=sdf.index))
    close_category_series = close_category_series.fillna("").astype(str).str.strip()
    if "is_external" in sdf.columns:
        is_external_series = pd.to_numeric(sdf.get("is_external"), errors="coerce").fillna(0).astype(int)
    else:
        is_external_series = pd.Series(0, index=sdf.index, dtype="int64")
    structure_id_series = sdf["structure_id"].fillna("").astype(str).str.strip()
    external_close_mask = (
        is_external_series.eq(1)
        | structure_id_series.eq("外部")
        | close_category_series.isin(EXT_CLOSE_CATEGORY_OPTIONS)
    )
    structure_display_series = structure_id_series.copy()
    structure_display_series.loc[external_close_mask] = "外部"

    sdf["结构编号"] = structure_display_series.map(
        lambda sid: display_code_map.get(str(sid), str(sid))
    )
    sdf["结构名称"] = structure_id_series.map(name_map).fillna(
        structure_id_series.apply(lambda x: EXTERNAL_CLOSE_DISPLAY_LABEL if x == "外部" else "")
    )
    sdf.loc[external_close_mask, "结构名称"] = EXTERNAL_CLOSE_DISPLAY_LABEL
    sdf["风险子"] = structure_id_series.map(risk_map).fillna(
        structure_id_series.apply(lambda x: "" if x == "外部" else "")
    )
    sdf["方向"] = sdf["side"].map(
        {"BUY": close_side_to_cn("BUY"), "SELL": close_side_to_cn("SELL"), "平仓": "平仓"}
    ).fillna(sdf["side"])
    sdf["平仓类别"] = sdf.get("close_category", STRUCT_CLOSE_CATEGORY)
    sdf["平仓类别"] = sdf["平仓类别"].fillna(STRUCT_CLOSE_CATEGORY).astype(str).str.strip()
    sdf.loc[sdf["平仓类别"] == "", "平仓类别"] = STRUCT_CLOSE_CATEGORY
    sdf["头寸价格"] = pd.to_numeric(sdf.get("open_price"), errors="coerce")
    sdf["头寸价格"] = sdf["头寸价格"].fillna(sdf["structure_id"].astype(str).map(open_price_map))
    sdf["换月盈亏"] = pd.to_numeric(sdf.get("roll_spread_pnl"), errors="coerce")
    if "quick_batch_id" in sdf.columns:
        sdf.loc[
            ~sdf["quick_batch_id"].fillna("").astype(str).str.startswith("TRS_ROLL_"),
            "换月盈亏",
        ] = np.nan
    else:
        sdf["换月盈亏"] = np.nan
    show_close = sdf.rename(
        columns={
            "close_id": "记录ID",
            "dt": "日期",
            "group_id": "策略组编号",
            "underlying": "品种",
            "qty": "平仓数量",
            "close_price": "平仓价",
            "pnl": "平仓盈亏",
        }
    )[
        [
            "记录ID",
            "日期",
            "策略组编号",
            "结构编号",
            "结构名称",
            "风险子",
            "平仓类别",
            "品种",
            "方向",
            "平仓数量",
            "头寸价格",
            "平仓价",
            "换月盈亏",
            "平仓盈亏",
        ]
    ]
    show_close = add_structure_label_column(
        show_close,
        id_col="结构编号",
        name_col="结构名称",
        risk_col="风险子",
        out_col="结构",
        kind_col="方向",
    )
    if bool(external_close_mask.any()):
        show_close.loc[external_close_mask, "风险子"] = EXTERNAL_CLOSE_DISPLAY_LABEL
    show_close["撤回"] = False
    show_close["删除"] = False
    ordered_cols = [c for c in CLOSE_DETAIL_EDITOR_COLUMNS if c in show_close.columns]
    remaining_cols = [c for c in show_close.columns if c not in ordered_cols]
    return show_close[ordered_cols + remaining_cols].copy()


def hide_empty_close_detail_editor_columns(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return df
    return hide_empty_display_columns(df, CLOSE_DETAIL_EDITOR_HIDEABLE_COLUMNS)


def pick_first(*vals: Any) -> Any:
    for v in vals:
        if v is None:
            continue
        try:
            if pd.isna(v):
                continue
        except Exception:
            pass
        return v
    return None


def pick_first_text(*vals: Any, default: str = "") -> str:
    for v in vals:
        if v is None:
            continue
        try:
            if pd.isna(v):
                continue
        except Exception:
            pass
        text = str(v).strip()
        if text:
            return text
    return str(default).strip()


def kind_to_signed(kind: str, qty: float) -> float:
    k = str(kind).upper()
    if k == "ACC":
        return +qty
    if k == "DEC":
        return -qty
    raise ValueError(f"Unknown kind: {kind}")


def close_to_signed(side: str, qty: float) -> float:
    s = str(side).upper()
    if s == "BUY":
        return +qty
    if s == "SELL":
        return -qty
    raise ValueError("side must be BUY/SELL")


CLOSE_SIDE_CODE_TO_CN: Dict[str, str] = {"SELL": "卖平仓", "BUY": "买平仓"}
CLOSE_SIDE_CN_TO_CODE: Dict[str, str] = {v: k for k, v in CLOSE_SIDE_CODE_TO_CN.items()}


def default_close_side_code(kind: Any) -> str:
    k = str(kind).upper()
    if k == "ACC":
        return "SELL"
    if k == "DEC":
        return "BUY"
    return "SELL"


def normalize_close_side_code(side_val: Any, default: str = "SELL") -> str:
    dft = str(default).upper()
    if dft not in CLOSE_SIDE_CODE_TO_CN:
        dft = "SELL"
    s = str(side_val or "").strip()
    s_up = s.upper()
    if s_up in CLOSE_SIDE_CODE_TO_CN:
        return s_up
    if s in CLOSE_SIDE_CN_TO_CODE:
        return CLOSE_SIDE_CN_TO_CODE[s]
    return dft


def close_side_to_cn(side_val: Any, default: str = "SELL") -> str:
    code = normalize_close_side_code(side_val, default=default)
    return CLOSE_SIDE_CODE_TO_CN.get(code, CLOSE_SIDE_CODE_TO_CN["SELL"])


def structure_day_pnl(kind: str, qty: float, gen_price: float, settle: float) -> float:
    k = str(kind).upper()
    if k == "ACC":
        return qty * (settle - gen_price)
    if k == "DEC":
        return qty * (gen_price - settle)
    raise ValueError(f"Unknown kind: {kind}")


def calc_close_pnl(kind: str, side: str, qty: float, open_price: float, close_price: float) -> float:
    """
    结构内平仓盈亏计算：
    - ACC（累购）默认平多（SELL）
    - DEC（累沽）默认平空（BUY）
    允许用户手工选反向交易，按对应方向计算。
    """
    k = str(kind).upper()
    s = str(side).upper()
    q = float(qty)
    op = float(open_price)
    cp = float(close_price)
    if k == "ACC":
        return q * (cp - op) if s == "SELL" else q * (op - cp)
    if k == "DEC":
        return q * (op - cp) if s == "BUY" else q * (cp - op)
    raise ValueError(f"Unknown kind: {kind}")


def manual_structure_close_effective_price(
    kind: Any,
    side: Any,
    qty: Any,
    open_price: Any,
    pnl_value: Any,
) -> float:
    qty_v = float(pick_first(to_float(qty), 0.0) or 0.0)
    open_v = float(pick_first(to_float(open_price), 0.0) or 0.0)
    pnl_v = float(pick_first(to_float(pnl_value), 0.0) or 0.0)
    if qty_v <= 1e-12:
        return open_v
    kind_s = str(kind).upper().strip()
    side_s = str(side).upper().strip()
    if kind_s == "ACC":
        if side_s == "SELL":
            return open_v + pnl_v / qty_v
        if side_s == "BUY":
            return open_v - pnl_v / qty_v
    if kind_s == "DEC":
        if side_s == "BUY":
            return open_v - pnl_v / qty_v
        if side_s == "SELL":
            return open_v + pnl_v / qty_v
    raise ValueError("平仓方向与结构方向不匹配（会加仓）")


def build_manual_structure_close_rows(
    open_lots: Sequence[Mapping[str, Any]],
    *,
    kind: Any,
    side: Any,
    qty: Any,
    total_pnl: Any,
    close_dt: Any,
    group_id: Any,
    structure_id: Any,
    underlying: Any,
    quick_batch_id: Any,
    close_category: Any = STRUCT_CLOSE_CATEGORY,
) -> Dict[str, Any]:
    kind_s = str(kind).upper().strip()
    side_s = str(side).upper().strip()
    qty_v = float(pick_first(to_float(qty), 0.0) or 0.0)
    total_pnl_v = float(pick_first(to_float(total_pnl), 0.0) or 0.0)
    reduce_need = float(structure_close_reduce_qty(kind_s, side_s, qty_v))
    if reduce_need <= 1e-12:
        raise ValueError("平仓方向与结构方向不匹配（会加仓）")

    normalized_lots: List[Dict[str, Any]] = []
    for raw in open_lots or []:
        if not isinstance(raw, Mapping):
            continue
        lot_qty = float(pick_first(to_float(raw.get("open_qty")), 0.0) or 0.0)
        if lot_qty <= 1e-12:
            continue
        normalized_lots.append(
            {
                "source_gen_date": str(pick_first(raw.get("date"), raw.get("source_gen_date"), "") or "").strip(),
                "open_qty": lot_qty,
                "open_price": float(pick_first(to_float(raw.get("gen_price")), to_float(raw.get("open_price")), 0.0) or 0.0),
            }
        )
    available_qty = float(sum(float(item.get("open_qty", 0.0)) for item in normalized_lots))
    if available_qty <= 1e-12 or not normalized_lots:
        raise ValueError("当前无可平仓在库头寸")
    if reduce_need - available_qty > 1e-12:
        raise ValueError(f"平仓数量超过当前可平数量（可平 {available_qty:,.2f} 吨）")

    pieces: List[Dict[str, Any]] = []
    remain = float(reduce_need)
    for lot in normalized_lots:
        if remain <= 1e-12:
            break
        take = min(float(lot.get("open_qty", 0.0)), remain)
        if take <= 1e-12:
            continue
        pieces.append(
            {
                "source_gen_date": str(lot.get("source_gen_date", "")),
                "qty": float(take),
                "open_price": float(lot.get("open_price", 0.0)),
            }
        )
        remain -= take
    if remain > 1e-8 or not pieces:
        raise ValueError("平仓拆分失败，请重试")

    total_saved_qty = float(sum(float(item.get("qty", 0.0)) for item in pieces))
    if total_saved_qty <= 1e-12:
        raise ValueError("平仓数量需大于 0")

    rows: List[Dict[str, Any]] = []
    pnl_assigned = 0.0
    close_dt_s = str(close_dt or "").strip()
    for idx, piece in enumerate(pieces):
        take = float(piece.get("qty", 0.0))
        open_price_v = float(piece.get("open_price", 0.0))
        if idx == len(pieces) - 1:
            pnl_piece = total_pnl_v - pnl_assigned
        else:
            pnl_piece = total_pnl_v * (take / total_saved_qty)
            pnl_assigned += pnl_piece
        close_price_v = manual_structure_close_effective_price(
            kind_s,
            side_s,
            take,
            open_price_v,
            pnl_piece,
        )
        rows.append(
            {
                "close_id": uuid4().hex,
                "dt": close_dt_s,
                "group_id": str(group_id),
                "structure_id": str(structure_id),
                "underlying": str(underlying),
                "side": side_s,
                "qty": float(take),
                "open_price": float(open_price_v),
                "close_price": float(close_price_v),
                "pnl": float(pnl_piece),
                "close_category": str(close_category),
                "quick_batch_id": str(quick_batch_id),
                "source_gen_date": str(piece.get("source_gen_date", "")),
                "is_external": 0,
            }
        )
    remaining_open_qty_after = max(float(available_qty) - float(total_saved_qty), 0.0)
    return {
        "rows": rows,
        "saved_qty": float(total_saved_qty),
        "available_qty_before": float(available_qty),
        "remaining_open_qty_after": float(remaining_open_qty_after),
        "total_pnl": float(total_pnl_v),
        "auto_manual_close": bool(remaining_open_qty_after <= 1e-8),
    }


def calc_roll_spread_pnl(kind: str, qty: float, near_price: float, far_price: float) -> float:
    """
    换月价差盈亏口径：
    - 看涨（多头）= 平近开远后的换月成本 = 近月价格 - 远月价格；
    - 看跌（空头）= 平近开远后的换月收益/成本 = 远月价格 - 近月价格。
    """
    k = str(kind).upper()
    q = float(pick_first(to_float(qty), 0.0) or 0.0)
    near_v = float(pick_first(to_float(near_price), 0.0) or 0.0)
    far_v = float(pick_first(to_float(far_price), 0.0) or 0.0)
    if q <= 1e-12:
        return 0.0
    if k == "ACC":
        return q * (near_v - far_v)
    if k == "DEC":
        return q * (far_v - near_v)
    return 0.0


def plan_sym_close_pairs(
    long_items: List[Dict[str, Any]],
    short_items: List[Dict[str, Any]],
) -> Dict[str, Any]:
    long_ready: List[Dict[str, Any]] = []
    short_ready: List[Dict[str, Any]] = []
    for raw in long_items or []:
        item = dict(raw or {})
        item["sid"] = pick_first_text(item.get("sid"))
        item["label"] = pick_first_text(item.get("label"), item.get("sid"))
        item["can_qty"] = float(pick_first(to_float(item.get("can_qty")), 0.0) or 0.0)
        long_ready.append(item)
    for raw in short_items or []:
        item = dict(raw or {})
        item["sid"] = pick_first_text(item.get("sid"))
        item["label"] = pick_first_text(item.get("label"), item.get("sid"))
        item["can_qty"] = float(pick_first(to_float(item.get("can_qty")), 0.0) or 0.0)
        short_ready.append(item)
    if not long_ready or not short_ready:
        raise ValueError("请至少选择一个多头结构和一个空头结构")
    if len(long_ready) > 1 and len(short_ready) > 1:
        raise ValueError("多空对称平仓仅支持单边多选，另一边需单选")

    plan: Dict[str, Any] = {
        "selection_mode": "single",
        "shared_side": "",
        "shared_sid": "",
        "shared_label": "",
        "shared_total_qty": 0.0,
        "default_total_qty": 0.0,
        "pairs": [],
    }
    pair_rows: List[Dict[str, Any]] = []
    if len(long_ready) > 1:
        shared_short = short_ready[0]
        remain_short = float(shared_short["can_qty"])
        plan["selection_mode"] = "long_multi"
        plan["shared_side"] = "short"
        plan["shared_sid"] = str(shared_short["sid"])
        plan["shared_label"] = str(shared_short["label"])
        plan["shared_total_qty"] = float(shared_short["can_qty"])
        for idx, long_item in enumerate(long_ready, start=1):
            default_qty = max(0.0, min(float(long_item["can_qty"]), remain_short))
            pair_rows.append(
                {
                    "seq": idx,
                    "long_sid": str(long_item["sid"]),
                    "long_label": str(long_item["label"]),
                    "long_can": float(long_item["can_qty"]),
                    "long_avg_price": float(pick_first(to_float(long_item.get("avg_price")), 0.0) or 0.0),
                    "long_strike_price": to_float(long_item.get("strike_price")),
                    "long_profit_basis_price": to_float(long_item.get("profit_basis_price")),
                    "long_underlying": pick_first_text(long_item.get("underlying")),
                    "long_risk_party": pick_first_text(long_item.get("risk_party")),
                    "short_sid": str(shared_short["sid"]),
                    "short_label": str(shared_short["label"]),
                    "short_can": float(shared_short["can_qty"]),
                    "short_avg_price": float(pick_first(to_float(shared_short.get("avg_price")), 0.0) or 0.0),
                    "short_strike_price": to_float(shared_short.get("strike_price")),
                    "short_profit_basis_price": to_float(shared_short.get("profit_basis_price")),
                    "short_underlying": pick_first_text(shared_short.get("underlying")),
                    "short_risk_party": pick_first_text(shared_short.get("risk_party")),
                    "default_qty": float(default_qty),
                }
            )
            remain_short = max(0.0, remain_short - float(default_qty))
    elif len(short_ready) > 1:
        shared_long = long_ready[0]
        remain_long = float(shared_long["can_qty"])
        plan["selection_mode"] = "short_multi"
        plan["shared_side"] = "long"
        plan["shared_sid"] = str(shared_long["sid"])
        plan["shared_label"] = str(shared_long["label"])
        plan["shared_total_qty"] = float(shared_long["can_qty"])
        for idx, short_item in enumerate(short_ready, start=1):
            default_qty = max(0.0, min(float(short_item["can_qty"]), remain_long))
            pair_rows.append(
                {
                    "seq": idx,
                    "long_sid": str(shared_long["sid"]),
                    "long_label": str(shared_long["label"]),
                    "long_can": float(shared_long["can_qty"]),
                    "long_avg_price": float(pick_first(to_float(shared_long.get("avg_price")), 0.0) or 0.0),
                    "long_strike_price": to_float(shared_long.get("strike_price")),
                    "long_profit_basis_price": to_float(shared_long.get("profit_basis_price")),
                    "long_underlying": pick_first_text(shared_long.get("underlying")),
                    "long_risk_party": pick_first_text(shared_long.get("risk_party")),
                    "short_sid": str(short_item["sid"]),
                    "short_label": str(short_item["label"]),
                    "short_can": float(short_item["can_qty"]),
                    "short_avg_price": float(pick_first(to_float(short_item.get("avg_price")), 0.0) or 0.0),
                    "short_strike_price": to_float(short_item.get("strike_price")),
                    "short_profit_basis_price": to_float(short_item.get("profit_basis_price")),
                    "short_underlying": pick_first_text(short_item.get("underlying")),
                    "short_risk_party": pick_first_text(short_item.get("risk_party")),
                    "default_qty": float(default_qty),
                }
            )
            remain_long = max(0.0, remain_long - float(default_qty))
    else:
        long_item = long_ready[0]
        short_item = short_ready[0]
        default_qty = max(0.0, min(float(long_item["can_qty"]), float(short_item["can_qty"])))
        plan["shared_total_qty"] = float(default_qty)
        pair_rows.append(
            {
                "seq": 1,
                "long_sid": str(long_item["sid"]),
                "long_label": str(long_item["label"]),
                "long_can": float(long_item["can_qty"]),
                "long_avg_price": float(pick_first(to_float(long_item.get("avg_price")), 0.0) or 0.0),
                "long_strike_price": to_float(long_item.get("strike_price")),
                "long_profit_basis_price": to_float(long_item.get("profit_basis_price")),
                "long_underlying": pick_first_text(long_item.get("underlying")),
                "long_risk_party": pick_first_text(long_item.get("risk_party")),
                "short_sid": str(short_item["sid"]),
                "short_label": str(short_item["label"]),
                "short_can": float(short_item["can_qty"]),
                "short_avg_price": float(pick_first(to_float(short_item.get("avg_price")), 0.0) or 0.0),
                "short_strike_price": to_float(short_item.get("strike_price")),
                "short_profit_basis_price": to_float(short_item.get("profit_basis_price")),
                "short_underlying": pick_first_text(short_item.get("underlying")),
                "short_risk_party": pick_first_text(short_item.get("risk_party")),
                "default_qty": float(default_qty),
            }
        )
    plan["pairs"] = pair_rows
    plan["default_total_qty"] = float(sum(float(pick_first(to_float(x.get("default_qty")), 0.0) or 0.0) for x in pair_rows))
    return plan


def plan_sym_close_auto_pairs(
    long_items: List[Dict[str, Any]],
    short_items: List[Dict[str, Any]],
) -> Dict[str, Any]:
    long_ready: List[Dict[str, Any]] = []
    short_ready: List[Dict[str, Any]] = []
    for idx, raw in enumerate(long_items or []):
        item = dict(raw or {})
        item["sid"] = pick_first_text(item.get("sid"))
        item["label"] = pick_first_text(item.get("label"), item.get("sid"))
        item["risk_party"] = pick_first_text(item.get("risk_party"))
        item["can_qty"] = float(pick_first(to_float(item.get("can_qty")), 0.0) or 0.0)
        item["avg_price"] = float(pick_first(to_float(item.get("avg_price")), 0.0) or 0.0)
        item["strike_price"] = to_float(item.get("strike_price"))
        item["profit_basis_price"] = to_float(item.get("profit_basis_price"))
        item["remaining_qty"] = float(item["can_qty"])
        item["__order__"] = int(idx)
        if item["sid"] and item["can_qty"] > 1e-12:
            long_ready.append(item)
    for idx, raw in enumerate(short_items or []):
        item = dict(raw or {})
        item["sid"] = pick_first_text(item.get("sid"))
        item["label"] = pick_first_text(item.get("label"), item.get("sid"))
        item["risk_party"] = pick_first_text(item.get("risk_party"))
        item["can_qty"] = float(pick_first(to_float(item.get("can_qty")), 0.0) or 0.0)
        item["avg_price"] = float(pick_first(to_float(item.get("avg_price")), 0.0) or 0.0)
        item["strike_price"] = to_float(item.get("strike_price"))
        item["profit_basis_price"] = to_float(item.get("profit_basis_price"))
        item["remaining_qty"] = float(item["can_qty"])
        item["__order__"] = int(idx)
        if item["sid"] and item["can_qty"] > 1e-12:
            short_ready.append(item)
    if not long_ready or not short_ready:
        raise ValueError("请至少存在一个可平多头结构和一个可平空头结构")

    def _short_sort_key(item: Mapping[str, Any]) -> Tuple[float, int, str]:
        strike_val = to_float(item.get("strike_price"))
        return (
            float(pick_first(to_float(strike_val), float("inf"))),
            int(pick_first(item.get("__order__"), 0) or 0),
            pick_first_text(item.get("sid")),
        )

    pair_rows: List[Dict[str, Any]] = []
    same_risk_qty = 0.0
    cross_risk_qty = 0.0

    def _append_pair(long_item: Dict[str, Any], short_item: Dict[str, Any], match_type: str) -> None:
        nonlocal same_risk_qty, cross_risk_qty
        long_rem = float(pick_first(to_float(long_item.get("remaining_qty")), 0.0) or 0.0)
        short_rem = float(pick_first(to_float(short_item.get("remaining_qty")), 0.0) or 0.0)
        take = max(0.0, min(long_rem, short_rem))
        if take <= 1e-12:
            return
        if match_type == "same_risk":
            match_label = "同风险子优先"
            same_risk_qty += float(take)
        else:
            match_label = "剩余多头补配"
            cross_risk_qty += float(take)
        pair_rows.append(
            {
                "seq": int(len(pair_rows) + 1),
                "long_sid": str(long_item["sid"]),
                "long_label": str(long_item["label"]),
                "long_can": float(long_item["can_qty"]),
                "long_avg_price": float(long_item["avg_price"]),
                "long_strike_price": to_float(long_item.get("strike_price")),
                "long_profit_basis_price": to_float(long_item.get("profit_basis_price")),
                "long_underlying": pick_first_text(long_item.get("underlying")),
                "long_risk_party": pick_first_text(long_item.get("risk_party")),
                "short_sid": str(short_item["sid"]),
                "short_label": str(short_item["label"]),
                "short_can": float(short_item["can_qty"]),
                "short_avg_price": float(short_item["avg_price"]),
                "short_profit_basis_price": to_float(short_item.get("profit_basis_price")),
                "short_underlying": pick_first_text(short_item.get("underlying")),
                "short_risk_party": pick_first_text(short_item.get("risk_party")),
                "short_strike_price": to_float(short_item.get("strike_price")),
                "match_type": str(match_type),
                "match_type_label": match_label,
                "default_qty": float(take),
                "pair_qty": float(take),
            }
        )
        long_item["remaining_qty"] = max(0.0, long_rem - float(take))
        short_item["remaining_qty"] = max(0.0, short_rem - float(take))

    for long_item in long_ready:
        if float(pick_first(to_float(long_item.get("remaining_qty")), 0.0) or 0.0) <= 1e-12:
            continue
        risk_party = pick_first_text(long_item.get("risk_party"))
        if not risk_party:
            continue
        same_risk_shorts = sorted(
            [
                short_item
                for short_item in short_ready
                if float(pick_first(to_float(short_item.get("remaining_qty")), 0.0) or 0.0) > 1e-12
                and pick_first_text(short_item.get("risk_party")) == risk_party
            ],
            key=_short_sort_key,
        )
        for short_item in same_risk_shorts:
            if float(pick_first(to_float(long_item.get("remaining_qty")), 0.0) or 0.0) <= 1e-12:
                break
            _append_pair(long_item, short_item, "same_risk")

    remaining_shorts = sorted(
        [
            short_item
            for short_item in short_ready
            if float(pick_first(to_float(short_item.get("remaining_qty")), 0.0) or 0.0) > 1e-12
        ],
        key=_short_sort_key,
    )
    for long_item in long_ready:
        while float(pick_first(to_float(long_item.get("remaining_qty")), 0.0) or 0.0) > 1e-12:
            next_short = next(
                (
                    short_item
                    for short_item in remaining_shorts
                    if float(pick_first(to_float(short_item.get("remaining_qty")), 0.0) or 0.0) > 1e-12
                ),
                None,
            )
            if next_short is None:
                break
            _append_pair(long_item, next_short, "lowest_strike_fallback")

    unmatched_longs = [
        {
            "sid": str(item["sid"]),
            "label": str(item["label"]),
            "risk_party": pick_first_text(item.get("risk_party")),
            "remaining_qty": float(pick_first(to_float(item.get("remaining_qty")), 0.0) or 0.0),
        }
        for item in long_ready
        if float(pick_first(to_float(item.get("remaining_qty")), 0.0) or 0.0) > 1e-12
    ]
    unmatched_shorts = [
        {
            "sid": str(item["sid"]),
            "label": str(item["label"]),
            "risk_party": pick_first_text(item.get("risk_party")),
            "strike_price": to_float(item.get("strike_price")),
            "remaining_qty": float(pick_first(to_float(item.get("remaining_qty")), 0.0) or 0.0),
        }
        for item in short_ready
        if float(pick_first(to_float(item.get("remaining_qty")), 0.0) or 0.0) > 1e-12
    ]

    return {
        "selection_mode": "auto",
        "shared_side": "",
        "shared_sid": "",
        "shared_label": "",
        "shared_total_qty": 0.0,
        "default_total_qty": float(sum(float(pick_first(to_float(x.get("default_qty")), 0.0) or 0.0) for x in pair_rows)),
        "same_risk_total_qty": float(same_risk_qty),
        "cross_risk_total_qty": float(cross_risk_qty),
        "pairs": pair_rows,
        "unmatched_longs": unmatched_longs,
        "unmatched_shorts": unmatched_shorts,
    }


def calc_sym_close_total_profit(pair_rows: List[Dict[str, Any]]) -> float:
    total_profit = 0.0
    for row in pair_rows or []:
        one_profit = calc_sym_close_row_profit(row)
        if one_profit is None:
            continue
        total_profit += float(one_profit)
    return float(total_profit)


def calc_sym_close_row_profit(row: Optional[Mapping[str, Any]]) -> Optional[float]:
    if not isinstance(row, Mapping):
        return None
    explicit_profit = to_float(pick_first(row.get("expected_profit"), row.get("pair_profit"), row.get("row_profit")))
    if explicit_profit is not None:
        return float(explicit_profit)
    qty = float(pick_first(to_float(row.get("pair_qty")), 0.0) or 0.0)
    if qty <= 1e-12:
        return None
    long_basis = to_float(
        pick_first(
            row.get("long_profit_basis_price"),
            row.get("long_pair_price"),
            row.get("long_strike_price"),
            row.get("long_avg_price"),
        )
    )
    short_basis = to_float(
        pick_first(
            row.get("short_profit_basis_price"),
            row.get("short_pair_price"),
            row.get("short_strike_price"),
            row.get("short_avg_price"),
        )
    )
    if long_basis is None or short_basis is None:
        return None
    return float((float(short_basis) - float(long_basis)) * qty)


def is_sym_close_cross_risk_pair(row: Optional[Mapping[str, Any]]) -> bool:
    if not isinstance(row, Mapping):
        return False
    long_risk = pick_first_text(row.get("long_risk_party"))
    short_risk = pick_first_text(row.get("short_risk_party"))
    if long_risk and short_risk and long_risk != short_risk:
        return True
    match_type = pick_first_text(row.get("match_type"))
    return match_type in {"lowest_strike_fallback", "cross_risk", "cross_risk_fallback"}


def build_sym_close_command_display_rows(pair_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    same_risk_rows: List[Dict[str, Any]] = []
    cross_risk_rows: List[Dict[str, Any]] = []
    for row in pair_rows or []:
        qty = float(pick_first(to_float((row or {}).get("pair_qty")), 0.0) or 0.0)
        if qty <= 1e-12:
            continue
        row_copy = dict(row or {})
        if is_sym_close_cross_risk_pair(row_copy):
            cross_risk_rows.append(row_copy)
        else:
            same_risk_rows.append(row_copy)
    ordered_rows = same_risk_rows + cross_risk_rows
    for idx, row in enumerate(ordered_rows, start=1):
        row["display_seq"] = int(idx)
    return ordered_rows


def build_sym_close_pair_signature(row: Optional[Mapping[str, Any]]) -> str:
    if not isinstance(row, Mapping):
        return ""
    long_sid = pick_first_text(row.get("long_sid"))
    short_sid = pick_first_text(row.get("short_sid"))
    if not long_sid or not short_sid:
        return ""
    match_type = pick_first_text(row.get("match_type"))
    qty = float(pick_first(to_float(row.get("pair_qty")), to_float(row.get("default_qty")), 0.0) or 0.0)
    long_risk = pick_first_text(row.get("long_risk_party"))
    short_risk = pick_first_text(row.get("short_risk_party"))
    return "||".join(
        [
            str(long_sid),
            str(short_sid),
            str(match_type),
            f"{float(qty):.6f}",
            str(long_risk),
            str(short_risk),
        ]
    )


def filter_sym_close_pairs_by_signatures(
    pair_rows: List[Dict[str, Any]],
    selected_signatures: Optional[Sequence[Any]],
) -> List[Dict[str, Any]]:
    selected_set = {str(x).strip() for x in (selected_signatures or []) if str(x).strip()}
    if not selected_set:
        return []
    picked_rows: List[Dict[str, Any]] = []
    for row in build_sym_close_command_display_rows(pair_rows):
        pair_sig = build_sym_close_pair_signature(row)
        if pair_sig and pair_sig in selected_set:
            picked_rows.append(dict(row or {}))
    return picked_rows


def summarize_sym_close_pair_rows(pair_rows: List[Dict[str, Any]]) -> Dict[str, float]:
    display_rows = build_sym_close_command_display_rows(pair_rows)
    same_risk_qty = 0.0
    cross_risk_qty = 0.0
    total_qty = 0.0
    for row in display_rows:
        qty = float(pick_first(to_float((row or {}).get("pair_qty")), 0.0) or 0.0)
        total_qty += float(qty)
        if is_sym_close_cross_risk_pair(row):
            cross_risk_qty += float(qty)
        else:
            same_risk_qty += float(qty)
    return {
        "pair_count": float(len(display_rows)),
        "pair_total_qty": float(total_qty),
        "same_risk_total_qty": float(same_risk_qty),
        "cross_risk_total_qty": float(cross_risk_qty),
        "pair_total_profit": float(calc_sym_close_total_profit(display_rows)),
    }


def build_sym_close_auto_selection_df(
    pair_rows: List[Dict[str, Any]],
    selected_signatures: Optional[Sequence[Any]] = None,
) -> pd.DataFrame:
    selected_set = {str(x).strip() for x in (selected_signatures or []) if str(x).strip()}
    rows: List[Dict[str, Any]] = []
    for idx, detail in enumerate(build_sym_close_command_display_rows(pair_rows), start=1):
        pair_sig = build_sym_close_pair_signature(detail)
        row_profit = calc_sym_close_row_profit(detail)
        rows.append(
            {
                "选择平仓": bool(pair_sig and pair_sig in selected_set),
                "序号": int(pick_first(detail.get("display_seq"), detail.get("seq"), idx) or idx),
                "多头结构": pick_first_text(detail.get("long_label"), detail.get("long_sid")),
                "空头结构": pick_first_text(detail.get("short_label"), detail.get("short_sid")),
                "平仓数量（吨）": float(pick_first(to_float(detail.get("pair_qty")), 0.0) or 0.0),
                "多头风险子": pick_first_text(detail.get("long_risk_party")),
                "空头风险子": pick_first_text(detail.get("short_risk_party")),
                "匹配方式": pick_first_text(detail.get("match_type_label"), detail.get("match_type")),
                "预计利润": None if row_profit is None else float(row_profit),
                "__pair_signature__": pair_sig,
            }
        )
    return pd.DataFrame(rows)


def build_sym_close_command_sections(pair_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    sections: List[Dict[str, Any]] = []
    for idx, row in enumerate(build_sym_close_command_display_rows(pair_rows), start=1):
        long_risk = pick_first_text(row.get("long_risk_party"))
        short_risk = pick_first_text(row.get("short_risk_party"))
        if is_sym_close_cross_risk_pair(row):
            risk_heading = f"多头风险子：{long_risk or '未标注'}；空头风险子：{short_risk or '未标注'}"
        else:
            risk_heading = f"风险子：{long_risk or short_risk or '未标注'}"
        qty = float(pick_first(to_float(row.get("pair_qty")), 0.0) or 0.0)
        row_profit = calc_sym_close_row_profit(row)
        sections.append(
            {
                "seq": int(idx),
                "risk_heading": risk_heading,
                "long_label": pick_first_text(row.get("long_label"), row.get("long_sid")),
                "short_label": pick_first_text(row.get("short_label"), row.get("short_sid")),
                "pair_qty": float(qty),
                "row_profit": row_profit,
                "row": row,
            }
        )
    return sections


def build_sym_close_pair_qty_text(qty: float, row_profit: Optional[float] = None) -> str:
    qty_text = f"数量：平多单{float(qty):,.2f}吨；平空单{float(qty):,.2f}吨"
    if row_profit is None:
        return qty_text
    return f"{qty_text}；预计利润{float(row_profit):,.2f}"


def build_sym_close_preview_qty_text(qty: float) -> str:
    return f"数量：平多单{float(qty):,.2f}吨；平空单{float(qty):,.2f}吨"


def build_sym_close_preview_label_html(label: Any) -> str:
    text = str(label or "")
    if not text:
        return ""
    pattern = re.compile(r"行权价\s*[（(][^）)]*[）)]")
    parts: List[str] = []
    last = 0
    for match in pattern.finditer(text):
        start, end = match.span()
        if start > last:
            parts.append(html.escape(text[last:start]))
        parts.append(f"<span class='sym-close-cmd-strike'>{html.escape(match.group(0))}</span>")
        last = end
    if last < len(text):
        parts.append(html.escape(text[last:]))
    if not parts:
        return html.escape(text)
    return "".join(parts)


def split_sym_close_command_sections(pair_rows: List[Dict[str, Any]]) -> Dict[str, Any]:
    sections = build_sym_close_command_sections(pair_rows)
    same_sections: List[Dict[str, Any]] = []
    cross_sections: List[Dict[str, Any]] = []
    for section in sections:
        if is_sym_close_cross_risk_pair(section.get("row")):
            cross_sections.append(section)
        else:
            same_sections.append(section)
    return {
        "sections": sections,
        "same_sections": same_sections,
        "cross_sections": cross_sections,
        "total_qty": float(sum(float(pick_first(to_float(x.get("pair_qty")), 0.0) or 0.0) for x in sections)),
        "same_qty": float(sum(float(pick_first(to_float(x.get("pair_qty")), 0.0) or 0.0) for x in same_sections)),
        "cross_qty": float(sum(float(pick_first(to_float(x.get("pair_qty")), 0.0) or 0.0) for x in cross_sections)),
    }


