def format_auto_deleted_structure_suffix(structure_ids: List[str]) -> str:
    ids = [str(x).strip() for x in structure_ids if str(x).strip()]
    if not ids:
        return ""
    if len(ids) <= 3:
        return f"；已自动终止空结构：{', '.join(ids)}"
    preview = ", ".join(ids[:3])
    return f"；已自动终止空结构 {len(ids)} 个（{preview} 等）"


def format_auto_deleted_structure_notice(structure_ids: List[str]) -> str:
    ids = [str(x).strip() for x in structure_ids if str(x).strip()]
    if not ids:
        return ""
    if len(ids) <= 3:
        return f"已自动终止空结构：{', '.join(ids)}"
    preview = ", ".join(ids[:3])
    return f"已自动终止空结构 {len(ids)} 个（{preview} 等）"


def _format_accumulator_multiplier_text(mult: Any) -> str:
    mult_v = to_float(mult)
    if mult_v is None:
        return ""
    mult_num = float(mult_v)
    if abs(mult_num) < 1e-12:
        return ""
    rounded = round(mult_num)
    if abs(mult_num - rounded) < 1e-9:
        return f"{int(rounded)}倍"
    return f"{mult_num:.4f}".rstrip("0").rstrip(".") + "倍"


def _is_accumulator_status_with_multiplier(status_text: Any, prefix: str) -> bool:
    s = str(status_text or "").strip()
    if not s.startswith(prefix):
        return False
    if "倍" not in s:
        return False
    return ((f"{prefix}（" in s) and s.endswith("）")) or ((f"{prefix}(" in s) and s.endswith(")"))


def status_to_cn(status_raw: str, qty: float, mult: float) -> str:
    s = str(status_raw or "")
    if s in {"未行权", "行权"}:
        return s
    if _is_accumulator_status_with_multiplier(s, "敲入") or _is_accumulator_status_with_multiplier(s, "震荡"):
        return s
    if s.startswith("存续中-") and ("买入" in s or "卖出" in s):
        if "看涨" in s or "看跌" in s:
            return "未行权"
        return s
    if s.startswith("到期结束-") and ("买入" in s or "卖出" in s):
        if "看涨" in s or "看跌" in s:
            return "行权" if "实值" in s else "未行权"
        return s
    if "TRS持仓" in s:
        return "TRS持仓"
    if "TRS建仓" in s:
        return "TRS建仓"
    if "雪球折价转期货跟踪" in s:
        return "雪球折价转期货跟踪"
    if "雪球折价转期货" in s:
        return "雪球折价转期货"
    if "雪球到期未敲入未敲出" in s:
        return "雪球到期未敲入未敲出"
    if "雪球到期已敲入" in s:
        return "雪球到期已敲入"
    if "雪球敲出" in s:
        return "雪球敲出"
    if "雪球缺价预警" in s:
        return "雪球缺价预警"
    if "雪球已敲入计息中" in s:
        return "雪球已敲入计息中"
    if "雪球已敲入观察" in s:
        return "雪球已敲入计息中"
    if "雪球观察中" in s:
        return "雪球观察中"
    if "敲入转线性" in s:
        return "敲入转线性"
    if "未敲入观察" in s:
        return "未敲入观察"
    if "未敲入到期上涨" in s:
        return "未敲入到期上涨"
    if "未敲入到期下跌" in s:
        return "未敲入到期下跌"
    if "未敲入到期保护" in s:
        return "未敲入到期保护"
    for phoenix_key, phoenix_label in PHOENIX_ACC_STATUS_CN_MAP.items():
        if phoenix_key in s:
            return phoenix_label
    for phoenix_label in PHOENIX_ACC_STATUS_CN_MAP.values():
        if phoenix_label in s:
            return phoenix_label
    if "区间补贴" in s:
        return "区间补贴"
    if "不敲入补贴" in s:
        return "不敲入补贴"
    if "敲出熔断" in s:
        return "敲出熔断"
    if "敲出不熔断" in s:
        return "敲出不熔断"
    if "敲入" in s:
        mult_txt = _format_accumulator_multiplier_text(mult)
        return f"敲入（{mult_txt}）" if mult_txt else "敲入"
    if "震荡" in s:
        return "震荡（1倍）"
    if qty <= 0 or mult <= 0:
        return "当日不生成"
    return "震荡（1倍）"


def remaining_days_mark_finished(remaining_days: Any) -> bool:
    remaining_num = to_float(remaining_days)
    return remaining_num is not None and float(remaining_num) <= 0.0


def override_finished_status_display(
    status_text: Any,
    remaining_days: Any,
    *,
    finished_label: str = "已结束",
) -> str:
    text = str(pick_first(status_text, "")).strip()
    if remaining_days_mark_finished(remaining_days):
        return finished_label
    return text


def override_finished_status_series(
    status_series: Any,
    remaining_days_series: Any,
    *,
    finished_label: str = "已结束",
) -> pd.Series:
    status_ser = status_series if isinstance(status_series, pd.Series) else pd.Series(status_series)
    if isinstance(remaining_days_series, pd.Series):
        remaining_ser = remaining_days_series.reindex(status_ser.index)
    else:
        remaining_ser = pd.Series(remaining_days_series, index=status_ser.index)
    out = status_ser.map(lambda v: str(pick_first(v, "")).strip()).astype("object")
    remaining_num = pd.to_numeric(remaining_ser, errors="coerce")
    finished_mask = remaining_num.notna() & (remaining_num <= 0.0)
    if bool(finished_mask.any()):
        out.loc[finished_mask] = finished_label
    return out


PHOENIX_ACC_RAW_STATUS_TO_NORMALIZED: Dict[str, str] = {
    "normal_subsidy": "phoenix_normal_subsidy",
    "震荡获得补贴": "phoenix_normal_subsidy",
    "凤凰正常补贴": "phoenix_normal_subsidy",
    "knock_in_terminate": "phoenix_knock_in_terminate",
    "敲入熔断": "phoenix_knock_in_terminate",
    "凤凰敲入终止": "phoenix_knock_in_terminate",
    "knock_out_subsidy_terminate": "phoenix_knock_out_subsidy_terminate",
    "敲出熔断-补贴": "phoenix_knock_out_subsidy_terminate",
    "凤凰敲出补贴终止": "phoenix_knock_out_subsidy_terminate",
    "knock_out_delivery_terminate": "phoenix_knock_out_delivery_terminate",
    "敲出熔断-给量": "phoenix_knock_out_delivery_terminate",
    "凤凰敲出给量终止": "phoenix_knock_out_delivery_terminate",
    "maturity_end": "phoenix_maturity_end",
    "到期结束": "phoenix_maturity_end",
    "凤凰到期结束": "phoenix_maturity_end",
}
TERMINAL_NORMALIZED_STATUSES: set[str] = {
    "accumulator_knock_out_terminate",
    "phoenix_knock_in_terminate",
    "phoenix_knock_out_subsidy_terminate",
    "phoenix_knock_out_delivery_terminate",
    "phoenix_maturity_end",
    "airbag_knock_in_linear",
    "airbag_maturity_up",
    "airbag_maturity_down",
    "airbag_maturity_protect",
    "snowball_knock_out",
    "snowball_discount_convert",
    "snowball_discount_track",
    "snowball_maturity_coupon",
    "snowball_maturity_loss",
    "vanilla_expired_itm",
    "vanilla_expired_otm",
}


def normalize_structure_status(status_raw: Any) -> str:
    s = str(pick_first(status_raw, "")).strip()
    if not s:
        return ""
    if s in PHOENIX_ACC_RAW_STATUS_TO_NORMALIZED:
        return PHOENIX_ACC_RAW_STATUS_TO_NORMALIZED[s]
    if s.startswith("存续中-") and ("买入" in s or "卖出" in s):
        return "vanilla_active"
    if s.startswith("到期结束-") and ("买入" in s or "卖出" in s):
        return "vanilla_expired_itm" if "实值" in s else "vanilla_expired_otm"
    if s == "行权":
        return "vanilla_expired_itm"
    if s == "未行权":
        return "vanilla_expired_otm"
    if s in {"敲出熔断", "已熔断终止"}:
        return "accumulator_knock_out_terminate"
    if s == "敲出不熔断":
        return "accumulator_knock_out_non_terminal"
    if s == "敲入" or _is_accumulator_status_with_multiplier(s, "敲入"):
        return "accumulator_knock_in"
    if s == "震荡" or _is_accumulator_status_with_multiplier(s, "震荡"):
        return "accumulator_active"
    if s == "不敲入补贴":
        return "premium_subsidy_active"
    if s == "区间补贴":
        return "range_subsidy_active"
    if s == "未敲入观察":
        return "airbag_observe"
    if s == "敲入转线性":
        return "airbag_knock_in_linear"
    if s == "未敲入到期上涨":
        return "airbag_maturity_up"
    if s == "未敲入到期下跌":
        return "airbag_maturity_down"
    if s == "未敲入到期保护":
        return "airbag_maturity_protect"
    if s == "雪球观察中":
        return "snowball_observe"
    if s == "雪球缺价预警":
        return "snowball_price_gap_warn"
    if s in {"雪球已敲入观察", "雪球已敲入计息中"}:
        return "snowball_knocked_in_observe"
    if s == "雪球敲出":
        return "snowball_knock_out"
    if s == "雪球折价转期货":
        return "snowball_discount_convert"
    if s == "雪球折价转期货跟踪":
        return "snowball_discount_track"
    if s == "雪球到期未敲入未敲出":
        return "snowball_maturity_coupon"
    if s == "雪球到期已敲入":
        return "snowball_maturity_loss"
    if s == "TRS建仓":
        return "trs_open"
    if s == "TRS持仓":
        return "trs_hold"
    return s


def structure_status_is_finished(
    raw_status: Any,
    *,
    normalized_status: Any = None,
    terminated_with_position: bool = False,
) -> bool:
    if bool(terminated_with_position):
        return True
    normalized = str(pick_first(normalized_status, "")).strip() or normalize_structure_status(raw_status)
    return normalized in TERMINAL_NORMALIZED_STATUSES


def _auto_termination_rows(
    struct_rows: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> pd.DataFrame:
    if struct_rows is None or struct_rows.empty:
        return pd.DataFrame()
    need_cols = {"structure_id", "date"}
    if not need_cols.issubset(set(struct_rows.columns)):
        return pd.DataFrame()
    df = struct_rows.copy()
    if group_id is not None and "group_id" in df.columns:
        df = df[df["group_id"].astype(str) == str(group_id)].copy()
    if df.empty:
        return pd.DataFrame()
    if as_of_date is not None:
        dser = pd.to_datetime(df["date"], errors="coerce").dt.date
        df = df[dser <= as_of_date].copy()
    if df.empty:
        return pd.DataFrame()
    if "raw_status" in df.columns:
        raw_status_series = df["raw_status"].fillna("").astype(str)
    elif "status" in df.columns:
        raw_status_series = df["status"].fillna("").astype(str)
    else:
        raw_status_series = pd.Series("", index=df.index, dtype="object")
    if "normalized_status" in df.columns:
        normalized_series = df["normalized_status"].fillna("").astype(str)
    else:
        normalized_series = raw_status_series.apply(normalize_structure_status)
    df["_raw_status"] = raw_status_series
    df["_normalized_status"] = normalized_series
    return df[df["_normalized_status"].isin(TERMINAL_NORMALIZED_STATUSES)].copy()


def parse_date_maybe(v: Any) -> Optional[date]:
    if v is None:
        return None
    try:
        return datetime.strptime(str(v), DATE_FMT).date()
    except Exception:
        pass
    try:
        ts = pd.to_datetime(v, errors="coerce")
        if pd.isna(ts):
            return None
        return ts.date()
    except Exception:
        return None


def pick_recent_trading_date_option(
    options: Sequence[Any],
    *,
    base_day_v: Any = None,
) -> str:
    """在候选日期中优先选择不晚于“最近交易日”的最近一个。"""
    raw_opts: List[str] = []
    parsed_opts: List[Tuple[str, date]] = []
    for raw in options or []:
        text = str(raw).strip()
        if not text:
            continue
        raw_opts.append(text)
        parsed_day = parse_date_maybe(text)
        if parsed_day is not None:
            parsed_opts.append((text, parsed_day))
    if not raw_opts:
        return ""
    if base_day_v is None:
        try:
            now_fn = globals().get("_now_cn")
            if callable(now_fn):
                now_val = now_fn()
                if isinstance(now_val, datetime):
                    base_day_v = now_val.date()
        except Exception:
            base_day_v = None
    base_day = parse_date_maybe(base_day_v)
    if base_day is None:
        base_day = date.today()
    target_day = base_day if is_trading_day(base_day) else previous_trading_day(base_day)
    if parsed_opts:
        parsed_opts.sort(key=lambda item: (item[1], item[0]))
        eligible = [item for item in parsed_opts if item[1] <= target_day]
        if eligible:
            return eligible[-1][0]
        return parsed_opts[0][0]
    return sorted(raw_opts)[-1]


def remaining_natural_days_excl_today(
    as_of_date_v: Any,
    end_date_v: Any,
    *,
    start_date_v: Any = None,
) -> int:
    """剩余自然日口径：不包含 as_of 当天。"""
    as_of_d = parse_date_maybe(as_of_date_v)
    end_d = parse_date_maybe(end_date_v)
    if as_of_d is None or end_d is None:
        return 0
    begin_d = as_of_d + timedelta(days=1)
    start_d = parse_date_maybe(start_date_v)
    if start_d is not None and begin_d < start_d:
        begin_d = start_d
    if end_d < begin_d:
        return 0
    return int((end_d - begin_d).days) + 1


def total_natural_days_inclusive(
    start_date_v: Any,
    end_date_v: Any,
) -> int:
    """总结构自然日口径：起止日都包含在内。"""
    start_d = parse_date_maybe(start_date_v)
    end_d = parse_date_maybe(end_date_v)
    if start_d is None or end_d is None or end_d < start_d:
        return 0
    return int((end_d - start_d).days) + 1


def format_remaining_days_ratio(
    remaining_days_v: Any,
    total_days_v: Any,
) -> str:
    rem_days = to_float(remaining_days_v)
    if rem_days is None or pd.isna(rem_days):
        return "-"
    rem_days_i = max(0, int(round(float(rem_days))))
    total_days = to_float(total_days_v)
    if total_days is None or pd.isna(total_days):
        return str(rem_days_i)
    total_days_i = max(0, int(round(float(total_days))))
    if total_days_i > 0:
        return f"{rem_days_i}/{total_days_i}"
    return str(rem_days_i)


def remaining_trading_days_excl_today(
    as_of_date_v: Any,
    end_date_v: Any,
    *,
    start_date_v: Any = None,
) -> int:
    """剩余交易日口径：不包含 as_of 当天。"""
    as_of_d = parse_date_maybe(as_of_date_v)
    end_d = parse_date_maybe(end_date_v)
    if as_of_d is None or end_d is None:
        return 0
    begin_d = as_of_d + timedelta(days=1)
    start_d = parse_date_maybe(start_date_v)
    if start_d is not None and begin_d < start_d:
        begin_d = start_d
    if end_d < begin_d:
        return 0
    return int(len(trading_days_between(begin_d, end_d)))


def build_manual_close_date_map(
    closes2: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> Dict[str, date]:
    cache_key = (
        "build_manual_close_date_map",
        _db_file_version_token(),
        _df_runtime_fingerprint(closes2),
        str(pick_first(group_id, "")),
        str(pick_first(as_of_date, "")),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return _copy_cached_runtime_value(cached)
    out: Dict[str, date] = {}
    if closes2 is None or closes2.empty or "close_category" not in closes2.columns:
        return out
    cat_s = closes2["close_category"].astype(str).str.strip()
    df = closes2[cat_s == MANUAL_STRUCT_CLOSE_CATEGORY].copy()
    if df.empty:
        return out
    if group_id is not None and "group_id" in df.columns:
        df = df[df["group_id"].astype(str) == str(group_id)].copy()
    if df.empty:
        return out
    if as_of_date is not None and "dt" in df.columns:
        dser = pd.to_datetime(df["dt"], errors="coerce").dt.date
        df = df[dser <= as_of_date].copy()
    for _, r in df.iterrows():
        sid = str(r.get("structure_id", "")).strip()
        if not sid or sid == "外部":
            continue
        d = parse_date_maybe(r.get("dt"))
        if d is None:
            continue
        prev = out.get(sid)
        if prev is None or d < prev:
            out[sid] = d
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, out, limit=96)
    return _copy_cached_runtime_value(out)


def build_manual_structure_reduction_frame(
    closes2: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> pd.DataFrame:
    cache_key = (
        "build_manual_structure_reduction_frame",
        _db_file_version_token(),
        _df_runtime_fingerprint(closes2),
        str(pick_first(group_id, "")),
        str(pick_first(as_of_date, "")),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, pd.DataFrame):
        return cached.copy()
    columns = ["close_id", "dt", "group_id", "structure_id", "qty", "close_category"]
    if closes2 is None or closes2.empty or "close_category" not in closes2.columns:
        return pd.DataFrame(columns=columns)
    cat_s = closes2["close_category"].astype(str).str.strip()
    df = closes2[cat_s == MANUAL_STRUCT_REDUCTION_CATEGORY].copy()
    if df.empty:
        return pd.DataFrame(columns=columns)
    if group_id is not None and "group_id" in df.columns:
        df = df[df["group_id"].astype(str) == str(group_id)].copy()
    if df.empty:
        return pd.DataFrame(columns=columns)
    if as_of_date is not None and "dt" in df.columns:
        dser = pd.to_datetime(df["dt"], errors="coerce").dt.date
        df = df[dser <= as_of_date].copy()
    if df.empty:
        return pd.DataFrame(columns=columns)
    if "structure_id" not in df.columns:
        return pd.DataFrame(columns=columns)
    df["structure_id"] = df["structure_id"].fillna("").astype(str).str.strip()
    df = df[df["structure_id"].ne("") & df["structure_id"].ne("外部")].copy()
    if df.empty:
        return pd.DataFrame(columns=columns)
    df["qty"] = pd.to_numeric(df.get("qty"), errors="coerce").fillna(0.0)
    df = df[df["qty"] > 1e-12].copy()
    if df.empty:
        return pd.DataFrame(columns=columns)
    if "dt" in df.columns:
        dt_parsed = pd.to_datetime(df["dt"], errors="coerce")
        df = df[dt_parsed.notna()].copy()
        df["dt"] = dt_parsed.loc[df.index].dt.strftime(DATE_FMT)
    else:
        df["dt"] = ""
    for col in columns:
        if col not in df.columns:
            df[col] = "" if col != "qty" else 0.0
    out = df[columns].copy()
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, out, limit=96)
    return out.copy()


def build_manual_structure_reduction_qty_map(
    closes2: Optional[pd.DataFrame],
    *,
    group_id: Optional[str] = None,
    as_of_date: Optional[date] = None,
) -> Dict[str, float]:
    cache_key = (
        "build_manual_structure_reduction_qty_map",
        _db_file_version_token(),
        _df_runtime_fingerprint(closes2),
        str(pick_first(group_id, "")),
        str(pick_first(as_of_date, "")),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return _copy_cached_runtime_value(cached)
    df = build_manual_structure_reduction_frame(
        closes2,
        group_id=group_id,
        as_of_date=as_of_date,
    )
    if df.empty:
        return {}
    grouped = (
        df.groupby(df["structure_id"].astype(str).str.strip())["qty"]
        .sum()
        .astype(float)
    )
    out = {
        str(sid).strip(): float(max(pick_first(to_float(qty), 0.0), 0.0) or 0.0)
        for sid, qty in grouped.items()
        if str(sid).strip()
    }
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, out, limit=96)
    return _copy_cached_runtime_value(out)


def apply_manual_structure_reduction_to_resolved_row(
    resolved_row: Mapping[str, Any],
    reduction_qty: Any = None,
) -> Dict[str, Any]:
    out = dict(resolved_row) if isinstance(resolved_row, Mapping) else {}
    if not out:
        return out
    reduce_qty = max(float(pick_first(to_float(reduction_qty), 0.0) or 0.0), 0.0)
    total_scale_qty = max(float(pick_first(to_float(structure_scale_sort_value(out)), 0.0) or 0.0), 0.0)
    if total_scale_qty <= 1e-12:
        out["_manual_reduction_qty"] = float(reduce_qty)
        out["_manual_remaining_scale_qty"] = 0.0
        out["_manual_reduction_factor"] = 0.0
        return out
    applied_reduce_qty = min(float(reduce_qty), float(total_scale_qty))
    remaining_scale_qty = max(float(total_scale_qty) - float(applied_reduce_qty), 0.0)
    if applied_reduce_qty <= 1e-12:
        factor = 1.0
    else:
        factor = max(min(float(remaining_scale_qty) / float(total_scale_qty), 1.0), 0.0)
    strategy_code = resolve_strategy_code_for_display(pick_first(out.get("strategy_code"), out.get("strategy"), ""))
    params = dict(out.get("params", {}) if isinstance(out.get("params", {}), dict) else {})
    meta = dict(out.get("meta", {}) if isinstance(out.get("meta", {}), dict) else {})

    if strategy_code == "SNOWBALL":
        notional_amount = max(float(resolve_snowball_notional_amount(params)), 0.0)
        scaled_notional = float(notional_amount) * float(factor)
        params["sb_notional_amount"] = scaled_notional
        params["sb_notional_wan"] = scaled_notional / 10000.0
    else:
        out["base_qty_per_day"] = float(max(float(pick_first(to_float(out.get("base_qty_per_day")), 0.0) or 0.0) * float(factor), 0.0))
        trs_position_qty = to_float(out.get("trs_position_qty"))
        if trs_position_qty is not None:
            out["trs_position_qty"] = float(max(float(trs_position_qty) * float(factor), 0.0))
        total_cap_qty = to_float(out.get("total_cap_qty"))
        if total_cap_qty is not None:
            out["total_cap_qty"] = float(max(float(total_cap_qty) * float(factor), 0.0))
        daily_cap_qty = to_float(out.get("daily_cap_qty"))
        if daily_cap_qty is not None:
            out["daily_cap_qty"] = float(max(float(daily_cap_qty) * float(factor), 0.0))

    for key in ["trs_position_qty", "total_cap_qty", "daily_cap_qty"]:
        val = pick_first(to_float(params.get(key)), to_float(meta.get(key)))
        if val is not None:
            scaled_val = float(max(float(val) * float(factor), 0.0))
            params[key] = scaled_val
            meta[key] = scaled_val

    out["params"] = params
    out["meta"] = meta
    out["_manual_reduction_qty"] = float(applied_reduce_qty)
    out["_manual_remaining_scale_qty"] = float(remaining_scale_qty)
    out["_manual_reduction_factor"] = float(factor)
    return out


