DEFAULT_SUBSIDY_DISPLAY_LABEL = "每吨补贴金额"
FIXED_SUBSIDY_DISPLAY_LABEL = "熔断赔付金额"
SUBSIDY_DISPLAY_LABEL_CANDIDATES: List[str] = [FIXED_SUBSIDY_DISPLAY_LABEL, DEFAULT_SUBSIDY_DISPLAY_LABEL]


def subsidy_amount_display_label(strategy_value: Any) -> str:
    return (
        FIXED_SUBSIDY_DISPLAY_LABEL
        if resolve_strategy_code_for_display(strategy_value) == "FIXED_SUBSIDY"
        else DEFAULT_SUBSIDY_DISPLAY_LABEL
    )


def price_gap_structure_type_label(strategy_value: Any) -> str:
    strategy_code = str(resolve_strategy_code_for_display(strategy_value)).upper()
    if strategy_code == "SAFETY_AIRBAG":
        return "气囊类"
    if strategy_code == "SNOWBALL":
        return "雪球类"
    if strategy_code == VANILLA_OPTION_CODE:
        return "香草类"
    return "累计类"


def normalize_risk_party_name(value: Any, default: str = "海证资本") -> str:
    text = str(pick_first(value, "") or "").strip()
    if not text:
        return str(default or "").strip()
    return str(RISK_PARTY_ALIAS_MAP.get(text, text)).strip()


def subsidy_amount_display_label_for_frame(frame: Any, strategy_col: str = "策略类型") -> str:
    if not isinstance(frame, pd.DataFrame) or frame.empty or strategy_col not in frame.columns:
        return DEFAULT_SUBSIDY_DISPLAY_LABEL
    strategy_values = [str(v).strip() for v in frame[strategy_col].tolist() if str(v).strip()]
    if not strategy_values:
        return DEFAULT_SUBSIDY_DISPLAY_LABEL
    strategy_codes = {resolve_strategy_code_for_display(v) for v in strategy_values}
    return FIXED_SUBSIDY_DISPLAY_LABEL if strategy_codes == {"FIXED_SUBSIDY"} else DEFAULT_SUBSIDY_DISPLAY_LABEL


def subsidy_display_column_name(frame: Any) -> str:
    if not isinstance(frame, pd.DataFrame):
        return DEFAULT_SUBSIDY_DISPLAY_LABEL
    for col in SUBSIDY_DISPLAY_LABEL_CANDIDATES:
        if col in frame.columns:
            return col
    return DEFAULT_SUBSIDY_DISPLAY_LABEL


def rename_subsidy_display_column(frame: Any, strategy_col: str = "策略类型") -> pd.DataFrame:
    out = frame.copy() if isinstance(frame, pd.DataFrame) else pd.DataFrame()
    src_col = subsidy_display_column_name(out)
    if src_col not in out.columns:
        return out
    target_col = subsidy_amount_display_label_for_frame(out, strategy_col=strategy_col)
    if src_col == target_col:
        return out
    return out.rename(columns={src_col: target_col})


def normalize_strategy_code(value: Any) -> str:
    s = str(value or "").strip().upper()
    if not s:
        return "BASIC_RANGE"
    return STRATEGY_ALIAS_TO_CODE.get(s, s)


def resolve_multiplier_from_legacy(params: Dict[str, Any], row_multiple: Optional[float], default: float = 3.0) -> float:
    val = pick_first(
        row_multiple,
        params.get("multiple"),
        params.get("participation_rate"),
        params.get("participation"),
        params.get("up_mult"),
    )
    try:
        return float(val) if val is not None else float(default)
    except Exception:
        return float(default)


def resolve_subsidy_per_ton_from_legacy(params: Dict[str, Any], meta: Dict[str, Any]) -> float:
    val = pick_first(
        params.get("subsidy_per_ton"),
        params.get("subsidy"),
        params.get("subsidy_amt_per_ton"),
        meta.get("subsidy_per_ton"),
    )
    try:
        out = float(val) if val is not None else 0.0
    except Exception:
        out = 0.0
    return max(out, 0.0)


def resolve_trs_position_qty_from_legacy(
    params: Dict[str, Any],
    meta: Dict[str, Any],
    row_base_qty: Any,
) -> float:
    val = pick_first(
        params.get("trs_position_qty"),
        params.get("trs_qty"),
        meta.get("trs_position_qty"),
        row_base_qty,
        0.0,
    )
    out = float(pick_first(to_float(val), 0.0) or 0.0)
    return max(out, 0.0)


def _bool_from_any(v: Any, default: bool = False) -> bool:
    if v is None:
        return bool(default)
    if isinstance(v, bool):
        return v
    s = str(v).strip().lower()
    if s in {"1", "true", "yes", "y", "on", "是", "开", "开启"}:
        return True
    if s in {"0", "false", "no", "n", "off", "否", "关", "关闭"}:
        return False
    try:
        return bool(int(float(s)))
    except Exception:
        return bool(default)


def _int_from_any(
    v: Any,
    default: int = 0,
    *,
    min_value: Optional[int] = None,
    max_value: Optional[int] = None,
) -> int:
    try:
        out = int(round(float(v)))
    except Exception:
        out = int(default)
    if min_value is not None:
        out = max(out, int(min_value))
    if max_value is not None:
        out = min(out, int(max_value))
    return out


def _float_from_any(v: Any, default: float = 0.0) -> float:
    try:
        return float(v)
    except Exception:
        return float(default)


def _snowball_add_period(base_date: date, unit_code: str, n: int) -> date:
    unit = str(unit_code).strip().upper()
    n_int = max(int(n), 0)
    if unit.startswith("MONTH"):
        try:
            return (pd.Timestamp(base_date) + pd.DateOffset(months=n_int)).date()
        except Exception:
            return base_date
    return base_date + timedelta(weeks=n_int)


def _snowball_shift_to_next_trading_day(d: date) -> date:
    out = d
    guard = 0
    while not is_trading_day(out) and guard < 400:
        out = out + timedelta(days=1)
        guard += 1
    return out


def _snowball_normalize_obs_freq(freq: Any) -> str:
    freq_u = str(freq).strip().upper()
    if freq_u not in {"WEEKLY", "BIWEEKLY", "MONTHLY"}:
        return "WEEKLY"
    return freq_u


def _snowball_auto_step_profile(kind: Any) -> Dict[str, Any]:
    kind_code = normalize_kind_code(kind)
    if kind_code not in {"ACC", "DEC"}:
        kind_code = "ACC"
    is_put = kind_code == "DEC"
    step_word = "敲升" if is_put else "敲降"
    return {
        "kind": kind_code,
        "step_word": step_word,
        "step_sign": 1.0 if is_put else -1.0,
        "toggle_label": f"自动{step_word}敲出线",
        "step_label": f"每期{step_word}比例（%）",
        "step_label_short": f"每期{step_word}比例",
    }


def _snowball_build_observations(
    start_date: date,
    maturity_natural: date,
    ko_freq: Any,
) -> List[Dict[str, Any]]:
    freq_u = _snowball_normalize_obs_freq(ko_freq)
    observations: List[Dict[str, Any]] = []
    prev_obs_date: Optional[date] = None
    serial = 1
    while True:
        if freq_u == "MONTHLY":
            raw_d = _snowball_add_period(start_date, "MONTH", serial)
        elif freq_u == "BIWEEKLY":
            raw_d = _snowball_add_period(start_date, "WEEK", serial * 2)
        else:
            raw_d = _snowball_add_period(start_date, "WEEK", serial)
        if raw_d > maturity_natural:
            break
        obs_d = _snowball_shift_to_next_trading_day(raw_d)
        holiday_shift_days = max((obs_d - raw_d).days, 0)
        dedup_shift_days = 0
        week_roll_weeks = 0
        if isinstance(prev_obs_date, date) and obs_d <= prev_obs_date:
            obs_d2 = _snowball_shift_to_next_trading_day(prev_obs_date + timedelta(days=1))
            dedup_shift_days = max((obs_d2 - obs_d).days, 0)
            obs_d = obs_d2
        if isinstance(prev_obs_date, date) and freq_u == "WEEKLY":
            guard = 0
            prev_iso_year, prev_iso_week, _prev_iso_wd = prev_obs_date.isocalendar()
            cur_iso_year, cur_iso_week, _cur_iso_wd = obs_d.isocalendar()
            while (cur_iso_year, cur_iso_week) == (prev_iso_year, prev_iso_week) and guard < 60:
                week_roll_weeks += 1
                rolled_raw = raw_d + timedelta(weeks=week_roll_weeks)
                obs_roll = _snowball_shift_to_next_trading_day(rolled_raw)
                if obs_roll <= prev_obs_date:
                    obs_roll = _snowball_shift_to_next_trading_day(prev_obs_date + timedelta(days=1))
                obs_d = obs_roll
                cur_iso_year, cur_iso_week, _cur_iso_wd = obs_d.isocalendar()
                guard += 1
        week_roll_shift_days = max((obs_d - raw_d).days - int(holiday_shift_days) - int(dedup_shift_days), 0)
        total_shift_days = int(max(holiday_shift_days + dedup_shift_days, 0))
        total_shift_days = int(max(total_shift_days + week_roll_shift_days, 0))
        observations.append(
            {
                "serial": serial,
                "raw_date": raw_d,
                "obs_date": obs_d,
                "holiday_shift_days": int(max(holiday_shift_days, 0)),
                "dedup_shift_days": int(max(dedup_shift_days, 0)),
                "week_roll_weeks": int(max(week_roll_weeks, 0)),
                "week_roll_shift_days": int(max(week_roll_shift_days, 0)),
                "total_shift_days": total_shift_days,
                "shifted": bool(total_shift_days > 0),
            }
        )
        prev_obs_date = obs_d
        serial += 1
    return observations


def _snowball_base_ko_pct(entry_price: float, ko_base_price: float, ko_pct_from_params: Optional[float]) -> float:
    ko_base_pct = float(pick_first(ko_pct_from_params, -1.0) or -1.0)
    if ko_base_pct <= 0 and entry_price > 1e-12:
        ko_base_pct = (ko_base_price / entry_price) * 100.0
    if ko_base_pct <= 0:
        ko_base_pct = 100.0
    return ko_base_pct


def _snowball_ko_line_for_idx(
    *,
    kind: Any,
    entry_price: float,
    ko_base_pct: float,
    auto_stepdown: bool,
    stepdown_pct: float,
    eligible_obs_idx: int,
    min_ko_price: float,
) -> Tuple[float, float]:
    min_price = max(float(min_ko_price), 0.0001)
    idx = max(int(eligible_obs_idx), 1)
    pct_now = float(ko_base_pct)
    if bool(auto_stepdown):
        step_profile = _snowball_auto_step_profile(kind)
        pct_now = pct_now + float(step_profile.get("step_sign", -1.0)) * float(stepdown_pct) * float(max(idx - 1, 0))
    if float(entry_price) > 1e-12:
        min_pct = (min_price / float(entry_price)) * 100.0
        pct_now = max(float(pct_now), float(min_pct))
        px_now = max(float(entry_price) * float(pct_now) / 100.0, min_price)
    else:
        px_now = min_price
    return float(pct_now), float(px_now)


def _snowball_build_observation_plan(
    *,
    observations: List[Dict[str, Any]],
    lock_ko_obs: int,
    kind: Any,
    entry_price: float,
    ko_base_price: float,
    ko_base_pct: Optional[float],
    auto_stepdown: bool,
    stepdown_pct: float,
    min_ko_price: float,
) -> List[Dict[str, Any]]:
    lock_n = max(int(lock_ko_obs), 0)
    base_pct = _snowball_base_ko_pct(float(entry_price), float(ko_base_price), ko_base_pct)
    plan: List[Dict[str, Any]] = []
    eligible_idx = 0
    for obs in observations:
        serial = _int_from_any(obs.get("serial"), 0, min_value=0)
        is_locked = serial <= lock_n
        display_eligible_idx = max(int(eligible_idx) + 1, 1)
        display_ko_pct, display_ko_price = _snowball_ko_line_for_idx(
            kind=kind,
            entry_price=float(entry_price),
            ko_base_pct=float(base_pct),
            auto_stepdown=bool(auto_stepdown),
            stepdown_pct=float(stepdown_pct),
            eligible_obs_idx=int(display_eligible_idx),
            min_ko_price=float(min_ko_price),
        )
        row: Dict[str, Any] = {
            "serial": serial,
            "raw_date": obs.get("raw_date"),
            "obs_date": obs.get("obs_date"),
            "is_locked": bool(is_locked),
            "eligible_idx": 0,
            "ko_pct": None,
            "ko_price": None,
            "display_ko_pct": float(display_ko_pct),
            "display_ko_price": float(display_ko_price),
        }
        if not is_locked:
            eligible_idx += 1
            ko_pct_now, ko_price_now = _snowball_ko_line_for_idx(
                kind=kind,
                entry_price=float(entry_price),
                ko_base_pct=float(base_pct),
                auto_stepdown=bool(auto_stepdown),
                stepdown_pct=float(stepdown_pct),
                eligible_obs_idx=int(eligible_idx),
                min_ko_price=float(min_ko_price),
            )
            row["eligible_idx"] = int(eligible_idx)
            row["ko_pct"] = float(ko_pct_now)
            row["ko_price"] = float(ko_price_now)
        plan.append(row)
    return plan


def _snowball_effective_ko_schedule(
    plan: Sequence[Mapping[str, Any]],
    *,
    price_digits: int = 2,
) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    for item in plan:
        eligible_idx = _int_from_any(pick_first(item.get("eligible_idx"), 0), 0, min_value=0)
        obs_date = item.get("obs_date")
        ko_price = to_float(pick_first(item.get("display_ko_price"), item.get("ko_price")))
        ko_pct = to_float(pick_first(item.get("display_ko_pct"), item.get("ko_pct")))
        if eligible_idx <= 0 or not isinstance(obs_date, date) or ko_price is None:
            continue
        rows.append(
            {
                "eligible_idx": int(eligible_idx),
                "obs_date": obs_date,
                "obs_date_text": obs_date.strftime("%Y/%m/%d"),
                "ko_price": float(ko_price),
                "ko_pct": ko_pct,
                "display_text": f"第{int(eligible_idx)}次 {obs_date.strftime('%Y/%m/%d')}：{float(ko_price):,.{price_digits}f}",
            }
        )
    return rows


def _snowball_all_ko_schedule(
    plan: Sequence[Mapping[str, Any]],
    *,
    price_digits: int = 2,
    start_date_value: Any = None,
    early_mode: bool = False,
    early_a: int = 0,
    coupon_single_pct: Any = None,
    coupon_a_pct: Any = None,
    coupon_b_pct: Any = None,
    notional_amount: Any = None,
) -> List[Dict[str, Any]]:
    rows: List[Dict[str, Any]] = []
    start_d: Optional[date] = None
    try:
        start_d = datetime.strptime(str(start_date_value or "").strip(), DATE_FMT).date()
    except Exception:
        start_d = None
    notional_amount_v = max(float(pick_first(to_float(notional_amount), 0.0) or 0.0), 0.0)
    for item in plan:
        serial = _int_from_any(pick_first(item.get("serial"), 0), 0, min_value=0)
        obs_date = item.get("obs_date")
        ko_price = to_float(pick_first(item.get("display_ko_price"), item.get("ko_price")))
        ko_pct = to_float(pick_first(item.get("display_ko_pct"), item.get("ko_pct")))
        is_locked = bool(item.get("is_locked", False))
        if serial <= 0 or not isinstance(obs_date, date) or ko_price is None:
            continue
        lock_suffix = "（锁定）" if is_locked else ""
        coupon_pct_v = float(pick_first(to_float(coupon_single_pct), 0.0) or 0.0)
        if bool(early_mode):
            coupon_pct_v = (
                float(pick_first(to_float(coupon_a_pct), 0.0) or 0.0)
                if int(serial) <= max(int(early_a), 0)
                else float(
                    pick_first(
                        to_float(coupon_b_pct),
                        to_float(coupon_a_pct),
                        0.0,
                    )
                    or 0.0
                )
            )
        profit_text = "-"
        profit_amt: Optional[float] = None
        if (not is_locked) and isinstance(start_d, date) and notional_amount_v > 1e-12:
            hold_days_v = max((obs_date - start_d).days + 1, 0)
            profit_amt = notional_amount_v * float(coupon_pct_v) / 100.0 * float(hold_days_v) / 365.0
            profit_text = f"{float(profit_amt):,.2f}"
        rows.append(
            {
                "serial": int(serial),
                "obs_date": obs_date,
                "obs_date_text": obs_date.strftime("%Y/%m/%d"),
                "ko_price": float(ko_price),
                "ko_pct": ko_pct,
                "is_locked": is_locked,
                "coupon_pct": float(coupon_pct_v),
                "profit_amt": profit_amt,
                "display_text": (
                    f"第{int(serial)}次 {obs_date.strftime('%Y/%m/%d')}{lock_suffix}："
                    f"{float(ko_price):,.{price_digits}f}，收益 {profit_text}"
                ),
            }
        )
    return rows


def _snowball_build_quote_observation_plan(
    *,
    kind: Any,
    start_date_value: Any,
    maturity_natural_value: Any,
    term_unit: Any,
    term_count: Any,
    ko_freq: Any,
    lock_ko_obs: Any,
    entry_price: Any,
    ko_base_price: Any,
    ko_base_pct: Any,
    auto_stepdown: Any,
    stepdown_pct: Any,
    min_ko_price: float = 0.0001,
) -> List[Dict[str, Any]]:
    try:
        start_d = datetime.strptime(str(start_date_value or "").strip(), DATE_FMT).date()
    except Exception:
        return []
    term_unit_u = str(term_unit or "").strip().upper()
    if term_unit_u not in {"WEEK", "MONTH"}:
        term_unit_u = "WEEK"
    term_count_n = _int_from_any(term_count, 0, min_value=0)
    if term_count_n <= 0:
        return []
    maturity_natural = _snowball_add_period(start_d, term_unit_u, term_count_n)
    maturity_natural_txt = str(maturity_natural_value or "").strip()
    if maturity_natural_txt:
        try:
            maturity_natural = datetime.strptime(maturity_natural_txt, DATE_FMT).date()
        except Exception:
            pass
    observations = _snowball_build_observations(start_d, maturity_natural, ko_freq)
    return _snowball_build_observation_plan(
        observations=observations,
        lock_ko_obs=_int_from_any(lock_ko_obs, 0, min_value=0),
        kind=kind,
        entry_price=float(pick_first(to_float(entry_price), 0.0) or 0.0),
        ko_base_price=float(pick_first(to_float(ko_base_price), to_float(entry_price), 0.0) or 0.0),
        ko_base_pct=to_float(ko_base_pct),
        auto_stepdown=bool(_bool_from_any(auto_stepdown, False)),
        stepdown_pct=max(float(pick_first(to_float(stepdown_pct), 0.0) or 0.0), 0.0),
        min_ko_price=float(max(min_ko_price, 0.0001)),
    )


def _snowball_render_observation_plan_table(map_rows: Sequence[Mapping[str, Any]]) -> None:
    if not map_rows:
        return
    map_df = pd.DataFrame(list(map_rows)).copy()
    for col_name in ["敲出线(%)", "敲出价", "票息(%)", "收益(元)"]:
        if col_name in map_df.columns:
            map_df[col_name] = pd.to_numeric(map_df[col_name], errors="coerce")
    style = (
        map_df.style
        .hide(axis="index")
        .set_table_styles(
            [
                {
                    "selector": "th",
                    "props": [
                        ("text-align", "center"),
                        ("white-space", "nowrap"),
                        ("word-break", "keep-all"),
                    ],
                },
                {
                    "selector": "td",
                    "props": [
                        ("text-align", "center"),
                        ("white-space", "nowrap"),
                        ("word-break", "keep-all"),
                    ],
                },
            ]
        )
        .set_properties(**{"text-align": "center", "white-space": "nowrap"})
        .format(
            {
                "敲出线(%)": "{:.2f}",
                "敲出价": "{:.2f}",
                "票息(%)": "{:.2f}",
                "收益(元)": "{:.2f}",
            },
            na_rep="-",
        )
    )
    st.table(style)


CN_WEEKDAY_LABELS: Tuple[str, ...] = ("周一", "周二", "周三", "周四", "周五", "周六", "周日")


def format_relative_weekday_date_text(target_date: Any, reference_date: Any) -> str:
    target_d = parse_date_maybe(target_date)
    ref_d = parse_date_maybe(reference_date)
    if not isinstance(target_d, date):
        return str(pick_first(target_date, "")).strip()
    if not isinstance(ref_d, date):
        ref_d = target_d
    weekday_txt = CN_WEEKDAY_LABELS[target_d.weekday()]
    weekday_short = weekday_txt[-1]
    ref_week_start = ref_d - timedelta(days=ref_d.weekday())
    target_week_start = target_d - timedelta(days=target_d.weekday())
    week_delta = int((target_week_start - ref_week_start).days // 7)
    if week_delta <= 0:
        relative_txt = f"这周{weekday_short}"
    elif week_delta == 1:
        relative_txt = f"下周{weekday_short}"
    elif week_delta == 2:
        relative_txt = f"下下周{weekday_short}"
    else:
        relative_txt = f"{week_delta}周后{weekday_txt}"
    return f"{relative_txt} {target_d.strftime(DATE_FMT)}"


def resolve_snowball_next_ko_from_plan(
    plan: Sequence[Mapping[str, Any]],
    *,
    as_of_date: Any = None,
) -> Dict[str, Any]:
    ref_d = parse_date_maybe(as_of_date)
    if not isinstance(ref_d, date):
        ref_d = date.today()
    for item in list(plan or []):
        obs_d = item.get("obs_date")
        eligible_idx = _int_from_any(pick_first(item.get("eligible_idx"), 0), 0, min_value=0)
        if eligible_idx <= 0 or not isinstance(obs_d, date):
            continue
        if obs_d < ref_d:
            continue
        return {
            "obs_date": obs_d,
            "serial": _int_from_any(item.get("serial"), 0, min_value=0),
            "eligible_idx": eligible_idx,
            "display_text": format_relative_weekday_date_text(obs_d, ref_d),
            "date_text": obs_d.strftime(DATE_FMT),
        }
    return {}


def build_snowball_observation_plan_for_resolved_row(struct_row: Mapping[str, Any]) -> List[Dict[str, Any]]:
    if not isinstance(struct_row, Mapping):
        return []
    strategy_code = resolve_strategy_code_for_display(
        pick_first(struct_row.get("strategy_code"), struct_row.get("strategy"), "")
    )
    if strategy_code != "SNOWBALL":
        return []
    params_value = struct_row.get("params")
    params = params_value if isinstance(params_value, dict) else parse_json_obj(struct_row.get("params_json"), {})
    start_d = parse_date_maybe(
        pick_first(
            struct_row.get("start_date"),
            struct_row.get("trade_date"),
            params.get("start_date"),
            params.get("trade_date"),
        )
    )
    if not isinstance(start_d, date):
        return []
    maturity_natural = parse_date_maybe(
        pick_first(
            params.get("sb_maturity_natural_date"),
            params.get("maturity_natural_date"),
            "",
        )
    )
    if not isinstance(maturity_natural, date):
        term_unit_u = str(pick_first(params.get("sb_term_unit"), "WEEK")).strip().upper()
        if term_unit_u not in {"WEEK", "MONTH"}:
            term_unit_u = "WEEK"
        term_count_n = _int_from_any(params.get("sb_term_count"), 0, min_value=0)
        if term_count_n > 0:
            maturity_natural = _snowball_add_period(start_d, term_unit_u, term_count_n)
    if not isinstance(maturity_natural, date):
        maturity_natural = parse_date_maybe(
            pick_first(
                struct_row.get("end_date"),
                struct_row.get("expiry_date"),
                params.get("expiry_date"),
            )
        )
    if not isinstance(maturity_natural, date) or maturity_natural < start_d:
        return []
    observations = _snowball_build_observations(
        start_date=start_d,
        maturity_natural=maturity_natural,
        ko_freq=pick_first(params.get("sb_ko_obs_freq"), "WEEKLY"),
    )
    if not observations:
        return []
    lock_n = (
        _int_from_any(params.get("sb_lock_ko_obs"), 0, min_value=0)
        if bool(_bool_from_any(params.get("sb_lock_enabled"), False))
        else 0
    )
    entry_price_v = float(pick_first(to_float(struct_row.get("entry_price")), 0.0) or 0.0)
    ko_base_price_v = float(
        pick_first(
            to_float(struct_row.get("knock_out_price")),
            to_float(params.get("sb_ko_price")),
            to_float(struct_row.get("barrier_out")),
            to_float(struct_row.get("entry_price")),
            0.0,
        )
        or 0.0
    )
    return _snowball_build_observation_plan(
        observations=observations,
        lock_ko_obs=lock_n,
        kind=struct_row.get("kind"),
        entry_price=entry_price_v,
        ko_base_price=ko_base_price_v,
        ko_base_pct=to_float(params.get("sb_ko_pct")),
        auto_stepdown=bool(_bool_from_any(params.get("sb_auto_stepdown"), False)),
        stepdown_pct=max(float(pick_first(to_float(params.get("sb_stepdown_pct")), 0.0) or 0.0), 0.0),
        min_ko_price=0.0001,
    )


def resolve_snowball_next_ko_observation(
    struct_row: Mapping[str, Any],
    *,
    as_of_date: Any = None,
) -> Dict[str, Any]:
    return resolve_snowball_next_ko_from_plan(
        build_snowball_observation_plan_for_resolved_row(struct_row),
        as_of_date=as_of_date,
    )


def _snowball_coupon_pct(runtime: Dict[str, Any], obs_serial: int) -> float:
    if bool(runtime.get("early_mode", False)):
        a_obs = max(int(runtime.get("a_obs", 0)), 0)
        coupon_a = float(runtime.get("coupon_a_pct", 0.0))
        coupon_b = float(runtime.get("coupon_b_pct", coupon_a))
        return coupon_a if int(obs_serial) <= a_obs else coupon_b
    return float(runtime.get("coupon_single_pct", 0.0))


def _snowball_phase(runtime: Dict[str, Any], obs_serial: int) -> str:
    if not bool(runtime.get("early_mode", False)):
        return "单阶段"
    a_obs = max(int(runtime.get("a_obs", 0)), 0)
    return "A阶段" if int(obs_serial) <= a_obs else "B阶段"


def _snowball_ko_price(runtime: Dict[str, Any], eligible_obs_idx: int) -> float:
    _pct_now, price_now = _snowball_ko_line_for_idx(
        kind=runtime.get("kind"),
        entry_price=float(runtime.get("entry_price", 0.0)),
        ko_base_pct=float(runtime.get("ko_base_pct", 100.0)),
        auto_stepdown=bool(runtime.get("auto_stepdown", False)),
        stepdown_pct=max(float(runtime.get("stepdown_pct", 0.0)), 0.0),
        eligible_obs_idx=max(int(eligible_obs_idx), 1),
        min_ko_price=max(float(runtime.get("min_ko_price", 0.0001)), 0.0001),
    )
    return float(price_now)


def _snowball_current_ko_line(runtime: Dict[str, Any], eligible_processed: int) -> Optional[float]:
    eligible_total = max(int(runtime.get("eligible_ko_total", 0)), 0)
    if eligible_total <= 0:
        return None
    next_idx = min(max(int(eligible_processed) + 1, 1), eligible_total)
    return _snowball_ko_price(runtime, next_idx)


def _snowball_date_to_text(v: Any) -> str:
    if isinstance(v, date):
        return v.strftime(DATE_FMT)
    return ""


def _snowball_runtime(struct: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    cached = st_state.get("_snowball_runtime")
    if isinstance(cached, dict):
        return cached

    params = struct.get("params", {}) if isinstance(struct.get("params", {}), dict) else {}
    start_d: date
    try:
        start_d = datetime.strptime(str(struct.get("start_date", "")), DATE_FMT).date()
    except Exception:
        start_d = date.today()
    try:
        end_d = datetime.strptime(str(struct.get("end_date", "")), DATE_FMT).date()
    except Exception:
        end_d = start_d

    term_unit = str(pick_first(params.get("sb_term_unit"), "WEEK")).strip().upper()
    term_count = _int_from_any(pick_first(params.get("sb_term_count"), 1), 1, min_value=1)
    maturity_natural = _snowball_add_period(start_d, term_unit, term_count)
    maturity_natural_txt = str(pick_first(params.get("sb_maturity_natural_date"), "")).strip()
    if maturity_natural_txt:
        try:
            maturity_natural = datetime.strptime(maturity_natural_txt, DATE_FMT).date()
        except Exception:
            pass
    maturity_settle = end_d if end_d >= start_d else _snowball_shift_to_next_trading_day(maturity_natural)

    ko_freq = _snowball_normalize_obs_freq(pick_first(params.get("sb_ko_obs_freq"), "WEEKLY"))
    ko_obs = _snowball_build_observations(start_d, maturity_natural, ko_freq)

    lock_ko_obs = _int_from_any(pick_first(params.get("sb_lock_ko_obs"), 0), 0, min_value=0)
    lock_enabled = _bool_from_any(pick_first(params.get("sb_lock_enabled"), lock_ko_obs > 0), lock_ko_obs > 0)
    if not lock_enabled:
        lock_ko_obs = 0
    notional_amount = max(_float_from_any(pick_first(params.get("sb_notional_amount"), 0.0), 0.0), 0.0)
    if notional_amount <= 1e-12:
        notional_wan = max(_float_from_any(pick_first(params.get("sb_notional_wan"), 0.0), 0.0), 0.0)
        notional_amount = notional_wan * 10000.0

    entry_price = max(_float_from_any(pick_first(struct.get("entry_price"), 0.0), 0.0), 0.0)
    ki_price = _float_from_any(pick_first(struct.get("barrier_in"), entry_price), entry_price)
    ko_base_price = _float_from_any(pick_first(struct.get("knock_out_price"), entry_price), entry_price)
    kind_code = normalize_kind_code(pick_first(struct.get("kind"), params.get("kind"), "ACC"))

    auto_stepdown = _bool_from_any(pick_first(params.get("sb_auto_stepdown"), False), False)
    stepdown_pct = max(_float_from_any(pick_first(params.get("sb_stepdown_pct"), 0.0), 0.0), 0.0)
    min_ko_price = 0.0001
    ko_pct_from_params = to_float(pick_first(params.get("sb_ko_pct"), None))
    ko_base_pct = _snowball_base_ko_pct(entry_price, ko_base_price, ko_pct_from_params)
    ko_obs_plan = _snowball_build_observation_plan(
        observations=ko_obs,
        lock_ko_obs=lock_ko_obs,
        kind=kind_code,
        entry_price=entry_price,
        ko_base_price=ko_base_price,
        ko_base_pct=ko_base_pct,
        auto_stepdown=auto_stepdown,
        stepdown_pct=stepdown_pct,
        min_ko_price=min_ko_price,
    )
    eligible_ko_total = len([r for r in ko_obs_plan if int(pick_first(r.get("eligible_idx"), 0) or 0) > 0])

    runtime = {
        "start_date": start_d,
        "maturity_natural": maturity_natural,
        "maturity_settle_date": maturity_settle,
        "ko_observations": ko_obs,
        "ko_observation_plan": ko_obs_plan,
        "lock_ko_obs": lock_ko_obs,
        "eligible_ko_total": int(max(eligible_ko_total, 0)),
        "kind": kind_code,
        "entry_price": entry_price,
        "ki_price": ki_price,
        "ko_base_pct": ko_base_pct,
        "auto_stepdown": bool(auto_stepdown),
        "stepdown_pct": float(stepdown_pct),
        "min_ko_price": float(min_ko_price),
        "notional_amount": notional_amount,
        "early_mode": _bool_from_any(pick_first(params.get("sb_early_mode"), False), False),
        "a_obs": _int_from_any(pick_first(params.get("sb_early_a"), 0), 0, min_value=0),
        "b_obs": _int_from_any(pick_first(params.get("sb_early_b"), 0), 0, min_value=0),
        "coupon_single_pct": max(_float_from_any(pick_first(params.get("sb_coupon_pct"), 0.0), 0.0), 0.0),
        "coupon_a_pct": max(_float_from_any(pick_first(params.get("sb_coupon_a_pct"), 0.0), 0.0), 0.0),
        "coupon_b_pct": max(_float_from_any(pick_first(params.get("sb_coupon_b_pct"), 0.0), 0.0), 0.0),
        "floor_enabled": _bool_from_any(pick_first(params.get("sb_floor_enabled"), True), True),
        "discount_enabled": _bool_from_any(pick_first(params.get("sb_discount_enabled"), False), False),
        "discount_price": max(_float_from_any(pick_first(params.get("sb_discount_price"), 0.0), 0.0), 0.0),
    }
    if runtime["discount_enabled"]:
        runtime["floor_enabled"] = False
    if runtime["early_mode"] and runtime["a_obs"] <= 0:
        runtime["a_obs"] = 1
    if runtime["early_mode"] and runtime["coupon_b_pct"] <= 0 and runtime["coupon_a_pct"] > 0:
        runtime["coupon_b_pct"] = runtime["coupon_a_pct"]

    st_state.setdefault("sb_knocked_in", False)
    st_state.setdefault("sb_first_ki_date", None)
    st_state.setdefault("sb_obs_processed", 0)
    st_state.setdefault("sb_eligible_processed", 0)
    st_state.setdefault("sb_price_gap_warn_count", 0)
    st_state.setdefault("sb_discount_triggered", False)
    st_state.setdefault("sb_discount_date", None)
    st_state.setdefault("sb_conversion_qty", 0.0)
    st_state.setdefault("sb_conversion_price", 0.0)
    st_state.setdefault("sb_ko_date", None)
    st_state.setdefault("sb_ko_coupon_pct", 0.0)
    st_state["_snowball_runtime"] = runtime
    return runtime


def _sm_snowball(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    runtime = _snowball_runtime(struct, st_state)
    dt = day_ctx["dt"]
    kind = str(struct["kind"]).upper()
    start_d = runtime["start_date"]
    entry = float(runtime["entry_price"])
    ki_price = float(runtime["ki_price"])
    notional = float(runtime["notional_amount"])
    ko_obs = runtime["ko_observations"]
    lock_n = int(runtime["lock_ko_obs"])
    maturity_settle = runtime["maturity_settle_date"]

    knocked_in = bool(st_state.get("sb_knocked_in", False))
    first_ki_d = st_state.get("sb_first_ki_date")
    obs_processed = _int_from_any(st_state.get("sb_obs_processed", 0), 0, min_value=0)
    eligible_processed = _int_from_any(st_state.get("sb_eligible_processed", 0), 0, min_value=0)
    discount_triggered = bool(st_state.get("sb_discount_triggered", False))
    discount_date = st_state.get("sb_discount_date")
    conversion_qty = max(_float_from_any(st_state.get("sb_conversion_qty", 0.0), 0.0), 0.0)
    conversion_price = max(_float_from_any(st_state.get("sb_conversion_price", 0.0), 0.0), 0.0)

    missed_obs = 0
    while obs_processed < len(ko_obs) and ko_obs[obs_processed]["obs_date"] < dt:
        serial_now = int(ko_obs[obs_processed]["serial"])
        if serial_now > lock_n:
            eligible_processed += 1
        obs_processed += 1
        missed_obs += 1
    if missed_obs > 0:
        st_state["sb_price_gap_warn_count"] = _int_from_any(st_state.get("sb_price_gap_warn_count", 0), 0) + missed_obs

    st_state["sb_obs_processed"] = obs_processed
    st_state["sb_eligible_processed"] = eligible_processed

    serial_for_view = min(max(obs_processed + 1, 1), max(len(ko_obs), 1))
    phase_for_view = _snowball_phase(runtime, serial_for_view)
    coupon_for_view = _snowball_coupon_pct(runtime, serial_for_view)
    hold_days = max((dt - start_d).days + 1, 0)
    coupon_float_pnl = notional * (coupon_for_view / 100.0) * (hold_days / 365.0)
    ko_line_for_view = _snowball_current_ko_line(runtime, eligible_processed)
    first_ki_txt = _snowball_date_to_text(first_ki_d)
    discount_txt = _snowball_date_to_text(discount_date)

    if discount_triggered and conversion_qty > 0 and conversion_price > 0:
        futures_float = structure_day_pnl(kind, conversion_qty, conversion_price, settle)
        return {
            "qty": 0.0,
            "gen_price": conversion_price,
            "mult": coupon_for_view,
            "status": "雪球折价转期货跟踪",
            "flags": ["SNOWBALL_DISCOUNT_TRACK"],
            "snowball_phase": phase_for_view,
            "snowball_coupon_pct": coupon_for_view,
            "snowball_current_ko_price": ko_line_for_view,
            "snowball_knocked_in": knocked_in,
            "snowball_first_ki_date": first_ki_txt,
            "snowball_discount_date": discount_txt,
            "snowball_conversion_qty": conversion_qty,
            "snowball_conversion_price": conversion_price,
            "snowball_coupon_float_pnl": 0.0,
            "snowball_futures_float_pnl": futures_float,
        }

    ki_hit = price_at_or_below(settle, ki_price) if kind == "ACC" else price_at_or_above(settle, ki_price)
    if ki_hit:
        if not knocked_in:
            st_state["sb_knocked_in"] = True
            knocked_in = True
        if first_ki_d is None:
            st_state["sb_first_ki_date"] = dt
            first_ki_d = dt
            first_ki_txt = _snowball_date_to_text(first_ki_d)

    if bool(runtime["discount_enabled"]) and ki_hit:
        discount_price = max(float(runtime["discount_price"]), 0.0001)
        convert_qty = round(max(notional / discount_price, 0.0), 2)
        st_state["sb_discount_triggered"] = True
        st_state["sb_discount_date"] = dt
        st_state["sb_conversion_qty"] = convert_qty
        st_state["sb_conversion_price"] = discount_price
        futures_float = structure_day_pnl(kind, convert_qty, discount_price, settle) if convert_qty > 0 else 0.0
        return {
            "qty": convert_qty,
            "gen_price": discount_price,
            "mult": coupon_for_view,
            "status": "雪球折价转期货",
            "flags": ["SNOWBALL_DISCOUNT_CONVERT"],
            "snowball_phase": phase_for_view,
            "snowball_coupon_pct": coupon_for_view,
            "snowball_current_ko_price": ko_line_for_view,
            "snowball_knocked_in": knocked_in,
            "snowball_first_ki_date": first_ki_txt,
            "snowball_discount_date": _snowball_date_to_text(dt),
            "snowball_conversion_qty": convert_qty,
            "snowball_conversion_price": discount_price,
            "snowball_coupon_float_pnl": 0.0,
            "snowball_futures_float_pnl": futures_float,
        }

    if obs_processed < len(ko_obs) and ko_obs[obs_processed]["obs_date"] == dt:
        serial_today = int(ko_obs[obs_processed]["serial"])
        ko_price_today = None
        if serial_today > lock_n:
            eligible_today = eligible_processed + 1
            ko_price_today = _snowball_ko_price(runtime, eligible_today)
            ko_hit = price_at_or_above(settle, ko_price_today) if kind == "ACC" else price_at_or_below(settle, ko_price_today)
            eligible_processed = eligible_today
            if ko_hit:
                hold_days = max((dt - start_d).days + 1, 0)
                coupon_hit = _snowball_coupon_pct(runtime, serial_today)
                coupon_pnl = notional * (coupon_hit / 100.0) * (hold_days / 365.0)
                st_state["sb_obs_processed"] = obs_processed + 1
                st_state["sb_eligible_processed"] = eligible_processed
                st_state["sb_ko_date"] = dt
                st_state["sb_ko_coupon_pct"] = coupon_hit
                return {
                    "qty": 0.0,
                    "gen_price": max(entry, 0.0001),
                    "mult": coupon_hit,
                    "status": "雪球敲出",
                    "flags": ["SNOWBALL_KO"],
                    "option_pnl": coupon_pnl,
                    "terminate": True,
                    "snowball_phase": _snowball_phase(runtime, serial_today),
                    "snowball_coupon_pct": coupon_hit,
                    "snowball_current_ko_price": ko_price_today,
                    "snowball_knocked_in": knocked_in,
                    "snowball_first_ki_date": first_ki_txt,
                    "snowball_discount_date": discount_txt,
                    "snowball_conversion_qty": conversion_qty,
                    "snowball_conversion_price": conversion_price,
                    "snowball_coupon_float_pnl": coupon_pnl,
                    "snowball_futures_float_pnl": 0.0,
                }
        obs_processed += 1
        st_state["sb_obs_processed"] = obs_processed
        st_state["sb_eligible_processed"] = eligible_processed
        serial_for_view = min(max(obs_processed + 1, 1), max(len(ko_obs), 1))
        phase_for_view = _snowball_phase(runtime, serial_for_view)
        coupon_for_view = _snowball_coupon_pct(runtime, serial_for_view)
        ko_line_for_view = _snowball_current_ko_line(runtime, eligible_processed)

    if dt >= maturity_settle:
        hold_days = max((dt - start_d).days + 1, 0)
        if not knocked_in:
            serial_ref = max(len(ko_obs), 1)
            coupon_maturity = _snowball_coupon_pct(runtime, serial_ref)
            coupon_pnl = notional * (coupon_maturity / 100.0) * (hold_days / 365.0)
            return {
                "qty": 0.0,
                "gen_price": max(entry, 0.0001),
                "mult": coupon_maturity,
                "status": "雪球到期未敲入未敲出",
                "flags": ["SNOWBALL_MATURITY_COUPON"],
                "option_pnl": coupon_pnl,
                "terminate": True,
                "snowball_phase": _snowball_phase(runtime, serial_ref),
                "snowball_coupon_pct": coupon_maturity,
                "snowball_current_ko_price": ko_line_for_view,
                "snowball_knocked_in": False,
                "snowball_first_ki_date": first_ki_txt,
                "snowball_discount_date": discount_txt,
                "snowball_conversion_qty": conversion_qty,
                "snowball_conversion_price": conversion_price,
                "snowball_coupon_float_pnl": coupon_pnl,
                "snowball_futures_float_pnl": 0.0,
            }

        ref_price = ki_price if bool(runtime["floor_enabled"]) else settle
        if entry > 1e-12:
            if kind == "ACC":
                maturity_loss = ((ref_price - entry) / entry) * notional
            else:
                maturity_loss = ((entry - ref_price) / entry) * notional
        else:
            maturity_loss = 0.0
        maturity_loss = min(maturity_loss, 0.0)
        return {
            "qty": 0.0,
            "gen_price": max(entry, 0.0001),
            "mult": 0.0,
            "status": "雪球到期已敲入",
            "flags": ["SNOWBALL_MATURITY_LOSS"],
            "option_pnl": maturity_loss,
            "terminate": True,
            "snowball_phase": phase_for_view,
            "snowball_coupon_pct": 0.0,
            "snowball_current_ko_price": ko_line_for_view,
            "snowball_knocked_in": True,
            "snowball_first_ki_date": first_ki_txt,
            "snowball_discount_date": discount_txt,
            "snowball_conversion_qty": conversion_qty,
            "snowball_conversion_price": conversion_price,
            "snowball_coupon_float_pnl": 0.0,
            "snowball_futures_float_pnl": 0.0,
        }

    flags: List[str] = ["SNOWBALL_KI_COUPON"] if knocked_in else ["SNOWBALL_OBSERVE"]
    status = "雪球已敲入计息中" if knocked_in else "雪球观察中"
    if missed_obs > 0:
        flags.append("SNOWBALL_PRICE_GAP_WARN")
        if not knocked_in:
            status = "雪球缺价预警"
    return {
        "qty": 0.0,
        "gen_price": max(entry, 0.0001),
        "mult": coupon_for_view,
        "status": status,
        "flags": flags,
        "snowball_phase": phase_for_view,
        "snowball_coupon_pct": coupon_for_view,
        "snowball_current_ko_price": ko_line_for_view,
        "snowball_knocked_in": knocked_in,
        "snowball_first_ki_date": first_ki_txt,
        "snowball_discount_date": discount_txt,
        "snowball_conversion_qty": conversion_qty,
        "snowball_conversion_price": conversion_price,
        "snowball_coupon_float_pnl": coupon_float_pnl,
        "snowball_futures_float_pnl": 0.0,
    }


def _sm_basic_range(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    ko = to_float(struct.get("knock_out_price"))
    multiple = float(pick_first(struct.get("multiple"), 1.0))
    meta = struct.get("meta", {})
    legacy_mode = str(meta.get("_legacy_mode", "")).upper()
    ko_terminate = bool(meta.get("ko_terminate", False))

    # 兼容旧 FIXED_PART（固定倍数）
    if legacy_mode == "FIXED_PART":
        qty = base_qty * max(multiple, 0.0)
        return {
            "qty": qty,
            "gen_price": strike,
            "mult": max(multiple, 0.0),
            "status": "震荡",
            "flags": ["LEGACY_FIXED_PART"],
        }

    # 兼容旧 BASIC_MULT
    if legacy_mode == "BASIC_MULT":
        if kind == "ACC":
            if ko is not None and price_at_or_above(settle, ko):
                return {"qty": 0.0, "gen_price": strike, "mult": 0.0, "status": "敲出不熔断", "flags": ["LEGACY_BASIC_KO"]}
            if price_at_or_below(settle, strike):
                return {
                    "qty": base_qty * max(multiple, 0.0),
                    "gen_price": strike,
                    "mult": max(multiple, 0.0),
                    "status": "敲入",
                    "flags": ["LEGACY_BASIC_KI"],
                }
            return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["LEGACY_BASIC_RANGE"]}
        # DEC
        if price_at_or_below(settle, strike):
            return {"qty": 0.0, "gen_price": strike, "mult": 0.0, "status": "敲出不熔断", "flags": ["LEGACY_BASIC_KO"]}
        if ko is not None and price_at_or_above(settle, ko):
            return {
                "qty": base_qty * max(multiple, 0.0),
                "gen_price": strike,
                "mult": max(multiple, 0.0),
                "status": "敲入",
                "flags": ["LEGACY_BASIC_KI"],
            }
        return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["LEGACY_BASIC_RANGE"]}

    # 新 BASIC_RANGE：区间内固定 1 倍，敲出当日 0，不终止（默认）
    ko_hit = False
    if ko is not None:
        ko_hit = price_at_or_above(settle, ko) if kind == "ACC" else price_at_or_below(settle, ko)
    if ko_hit:
        if ko_terminate:
            st_state["knocked_out"] = True
            st_state["terminated"] = True
        return {
            "qty": 0.0,
            "gen_price": strike,
            "mult": 0.0,
            "status": "敲出不熔断",
            "flags": ["KO_NO_MELT"],
            "terminate": ko_terminate,
        }

    # 当前口径：
    # ACC(累购)：收盘价 <= 行权价 => 敲入多倍
    # DEC(累沽)：收盘价 >= 行权价 => 敲入多倍
    ki_hit = price_at_or_below(settle, strike) if kind == "ACC" else price_at_or_above(settle, strike)
    if ki_hit:
        return {
            "qty": base_qty * max(multiple, 0.0),
            "gen_price": strike,
            "mult": max(multiple, 0.0),
            "status": "敲入",
            "flags": ["KI_MULT"],
        }
    return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}


def _sm_no_ko(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    无敲出累计：
    - 仅行权价触发敲入，不存在敲出/熔断终止。
    - ACC: settle <= strike => 敲入多倍；否则 1 倍
    - DEC: settle >= strike => 敲入多倍；否则 1 倍
    """
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    multiple = max(float(pick_first(struct.get("multiple"), 3.0)), 0.0)

    if kind == "ACC":
        if price_at_or_below(settle, strike):
            return {"qty": base_qty * multiple, "gen_price": strike, "mult": multiple, "status": "敲入", "flags": ["KI_MULT"]}
        return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}

    if price_at_or_above(settle, strike):
        return {"qty": base_qty * multiple, "gen_price": strike, "mult": multiple, "status": "敲入", "flags": ["KI_MULT"]}
    return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}


def _sm_float_ko(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    # FLOAT_KO 口径：
    # - strike_price: 敲入边界（多倍触发）
    # - knock_out_price: 熔断/敲出边界（一次性补齐）
    # - barrier_out: 兼容旧字段，当前与 knock_out_price 同口径
    ko_level = to_float(pick_first(struct.get("knock_out_price"), struct.get("barrier_out")))
    ko_strike = float(pick_first(struct.get("ko_strike_price"), struct.get("entry_price"), strike))
    multiple = max(float(pick_first(struct.get("multiple"), 3.0)), 0.0)
    remaining_days = max(int(day_ctx["remaining_days"]), 0)

    # FLOAT_KO 逻辑：敲出后一次性补齐，并终止后续生成
    if st_state.get("knocked_out", False) or st_state.get("terminated", False):
        return {
            "qty": 0.0,
            "gen_price": strike,
            "mult": 0.0,
            "status": "已熔断终止",
            "flags": ["ALREADY_KO"],
            "terminate": True,
        }

    # 缺字段时降级为 BASIC_RANGE 状态机，避免崩溃
    if ko_level is None and strike is None:
        return _sm_basic_range(struct, settle, day_ctx, st_state)

    # 规则：
    # ACC: settle >= knock_out_price 熔断一次性补齐；settle <= strike_price 敲入多倍；其余 1 倍
    # DEC: settle <= knock_out_price 熔断一次性补齐；settle >= strike_price 敲入多倍；其余 1 倍
    if kind == "ACC":
        if ko_level is not None and price_at_or_above(settle, ko_level):
            qty_once = base_qty * remaining_days
            st_state["knocked_out"] = True
            st_state["terminated"] = True
            return {
                "qty": qty_once,
                "gen_price": ko_strike,
                "mult": 0.0,
                "status": "敲出熔断",
                "flags": ["KO_MELT_ONCE"],
                "knocked_out": True,
                "terminate": True,
            }
        if price_at_or_below(settle, strike):
            return {"qty": base_qty * multiple, "gen_price": strike, "mult": multiple, "status": "敲入", "flags": ["KI_MULT"]}
        return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}

    # DEC
    if ko_level is not None and price_at_or_below(settle, ko_level):
        qty_once = base_qty * remaining_days
        st_state["knocked_out"] = True
        st_state["terminated"] = True
        return {
            "qty": qty_once,
            "gen_price": ko_strike,
            "mult": 0.0,
            "status": "敲出熔断",
            "flags": ["KO_MELT_ONCE"],
            "knocked_out": True,
            "terminate": True,
        }
    if price_at_or_above(settle, strike):
        return {"qty": base_qty * multiple, "gen_price": strike, "mult": multiple, "status": "敲入", "flags": ["KI_MULT"]}
    return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}


def _sm_fixed_subsidy(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    固赔熔断累计：
    - ACC：strike < settle < barrier => 1倍；settle <= strike => 多倍敲入；settle >= barrier => 熔断终止并按剩余观察日给补贴。
    - DEC：barrier < settle < strike => 1倍；settle >= strike => 多倍敲入；settle <= barrier => 熔断终止并按剩余观察日给补贴。
    """
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    barrier = to_float(pick_first(struct.get("barrier_out"), struct.get("knock_out_price")))
    multiple = max(float(pick_first(struct.get("multiple"), 3.0)), 0.0)
    subsidy_per_ton = max(float(pick_first(struct.get("subsidy_per_ton"), 0.0)), 0.0)
    remaining_days = max(int(day_ctx["remaining_days"]), 0)
    remaining_after_today = max(remaining_days - 1, 0)

    ko_hit = False
    if barrier is not None:
        ko_hit = price_at_or_above(settle, barrier) if kind == "ACC" else price_at_or_below(settle, barrier)
    if ko_hit:
        subsidy_qty = base_qty * remaining_after_today
        subsidy_pnl = subsidy_qty * subsidy_per_ton
        st_state["knocked_out"] = True
        st_state["terminated"] = True
        return {
            "qty": 0.0,
            "gen_price": strike,
            "mult": 0.0,
            "status": "敲出熔断",
            "flags": ["KO_SUBSIDY"],
            "knocked_out": True,
            "terminate": True,
            "subsidy_qty": subsidy_qty,
            "subsidy_pnl": subsidy_pnl,
        }

    ki_hit = price_at_or_below(settle, strike) if kind == "ACC" else price_at_or_above(settle, strike)
    if ki_hit:
        return {
            "qty": base_qty * multiple,
            "gen_price": strike,
            "mult": multiple,
            "status": "敲入",
            "flags": ["KI_MULT"],
        }
    return {"qty": base_qty, "gen_price": strike, "mult": 1.0, "status": "震荡", "flags": ["RANGE_BASE"]}


def _sm_premium_subsidy(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    溢价累计（固定赔付类）：
    - ACC: settle <= strike -> 敲入多倍；settle > strike -> 当日不生成，给“当日观察规模=每日基准量”的补贴。
    - DEC: settle >= strike -> 敲入多倍；settle < strike -> 当日不生成，给“当日观察规模=每日基准量”的补贴。
    """
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    multiple = max(float(pick_first(struct.get("multiple"), 3.0)), 0.0)
    subsidy_per_ton = max(float(pick_first(struct.get("subsidy_per_ton"), 0.0)), 0.0)

    ki_hit = price_at_or_below(settle, strike) if kind == "ACC" else price_at_or_above(settle, strike)
    if ki_hit:
        return {
            "qty": base_qty * multiple,
            "gen_price": strike,
            "mult": multiple,
            "status": "敲入",
            "flags": ["KI_MULT"],
        }

    subsidy_qty = base_qty
    subsidy_pnl = subsidy_qty * subsidy_per_ton
    return {
        "qty": 0.0,
        "gen_price": strike,
        "mult": 0.0,
        "status": "不敲入补贴",
        "flags": ["PREM_SUBSIDY"],
        "subsidy_qty": subsidy_qty,
        "subsidy_pnl": subsidy_pnl,
    }


def _sm_range_subsidy(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    区间补贴累计（固定赔付类）：
    - ACC（区间累购）：
      settle <= strike => 敲入多倍；
      strike < settle < barrier => 区间补贴；
      settle >= barrier => 敲出不熔断（当日无补贴，次日继续观察）。
    - DEC（区间累沽）：
      settle >= strike => 敲入多倍；
      barrier < settle < strike => 区间补贴；
      settle <= barrier => 敲出不熔断（当日无补贴，次日继续观察）。
    边界优先级：
    - settle == strike 按“敲入”；
    - settle == barrier 按“敲出无补贴”。
    """
    base_qty = float(day_ctx["base_qty"])
    kind = str(struct["kind"]).upper()
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    barrier = to_float(pick_first(struct.get("barrier_out"), struct.get("knock_out_price")))
    multiple = max(float(pick_first(struct.get("multiple"), 3.0)), 0.0)
    subsidy_per_ton = max(float(pick_first(struct.get("subsidy_per_ton"), 0.0)), 0.0)

    # 缺障碍价时降级到“溢价累计”，避免异常数据导致崩溃。
    if barrier is None:
        return _sm_premium_subsidy(struct, settle, day_ctx, st_state)

    ki_hit = price_at_or_below(settle, strike) if kind == "ACC" else price_at_or_above(settle, strike)
    if ki_hit:
        return {
            "qty": base_qty * multiple,
            "gen_price": strike,
            "mult": multiple,
            "status": "敲入",
            "flags": ["KI_MULT"],
        }

    ko_hit = price_at_or_above(settle, barrier) if kind == "ACC" else price_at_or_below(settle, barrier)
    if ko_hit:
        return {
            "qty": 0.0,
            "gen_price": strike,
            "mult": 0.0,
            "status": "敲出不熔断",
            "flags": ["KO_NO_MELT"],
        }

    subsidy_qty = base_qty
    subsidy_pnl = subsidy_qty * subsidy_per_ton
    return {
        "qty": 0.0,
        "gen_price": strike,
        "mult": 0.0,
        "status": "区间补贴",
        "flags": ["RANGE_SUBSIDY_DAY"],
        "subsidy_qty": subsidy_qty,
        "subsidy_pnl": subsidy_pnl,
    }


def _sm_phoenix_acc_fixed(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    total_days = max(int(pick_first(day_ctx.get("total_days"), 0) or 0), 1)
    observed_days = max(int(pick_first(day_ctx.get("observed_days"), 0) or 0), 0)
    daily_qty = max(float(pick_first(day_ctx.get("base_qty"), struct.get("base_qty_per_day"), 0.0) or 0.0), 0.0)
    params = struct.get("params", {}) if isinstance(struct.get("params"), dict) else {}
    meta = struct.get("meta", {}) if isinstance(struct.get("meta"), dict) else {}
    result = phoenix_acc_fixed_day_event(
        settle,
        day_index=observed_days + 1,
        total_days=total_days,
        daily_qty=daily_qty,
        observed_qty_before=daily_qty * observed_days,
        cumulative_subsidy_before=st_state.get("cum_subsidy_pnl", 0.0),
        cumulative_delivered_qty_before=st_state.get("cum_qty", 0.0),
        kind_value=struct.get("kind"),
        entry_price=pick_first(struct.get("entry_price"), 0.0),
        knock_in_price=pick_first(struct.get("barrier_in"), params.get("knock_in_price")),
        knock_in_exercise_price=pick_first(
            params.get("knock_in_exercise_price"),
            meta.get("knock_in_exercise_price"),
            struct.get("strike_price"),
            struct.get("entry_price"),
        ),
        subsidy_per_ton=pick_first(struct.get("subsidy_per_ton"), params.get("subsidy_per_ton"), 0.0),
        knock_out_price=pick_first(struct.get("knock_out_price"), struct.get("barrier_out")),
        participation_rate=pick_first(struct.get("multiple"), params.get("participation_rate"), params.get("multiple"), 0.0),
        knock_in_qty_mode=pick_first(params.get("knock_in_qty_mode"), meta.get("knock_in_qty_mode"), "all"),
        knock_out_settlement_mode=pick_first(
            params.get("knock_out_settlement_mode"),
            meta.get("knock_out_settlement_mode"),
            "subsidy",
        ),
        knock_out_exercise_price=pick_first(
            params.get("knock_out_exercise_price"),
            meta.get("knock_out_exercise_price"),
            struct.get("ko_strike_price"),
        ),
    )
    event_type = str(result.get("event_type", ""))
    delivered_qty = float(pick_first(result.get("delivered_qty"), 0.0) or 0.0)
    delivered_price = to_float(result.get("delivered_price"))
    delivered_side = str(pick_first(result.get("delivered_side"), "") or "")
    daily_subsidy = float(pick_first(result.get("daily_subsidy"), 0.0) or 0.0)
    subsidy_qty = 0.0
    subsidy_per_ton = max(float(pick_first(struct.get("subsidy_per_ton"), params.get("subsidy_per_ton"), 0.0) or 0.0), 0.0)
    if subsidy_per_ton > 1e-12 and abs(daily_subsidy) > 1e-12:
        subsidy_qty = daily_subsidy / subsidy_per_ton
    flag_map = {
        "normal_subsidy": "PHOENIX_ACC_NORMAL",
        "knock_in_terminate": "PHOENIX_ACC_KNOCK_IN",
        "knock_out_subsidy_terminate": "PHOENIX_ACC_KNOCK_OUT_SUBSIDY",
        "knock_out_delivery_terminate": "PHOENIX_ACC_KNOCK_OUT_DELIVERY",
        "maturity_end": "PHOENIX_ACC_MATURITY",
    }
    gen_price = float(delivered_price) if delivered_price is not None else 0.0
    return {
        "qty": delivered_qty,
        "gen_price": gen_price,
        "mult": (delivered_qty / daily_qty) if daily_qty > 1e-12 else 0.0,
        "status": event_type,
        "flags": [flag_map.get(event_type, "PHOENIX_ACC_NORMAL")],
        "terminate": bool(result.get("terminated_flag", False)),
        "knocked_out": event_type in {"knock_out_subsidy_terminate", "knock_out_delivery_terminate"},
        "subsidy_qty": subsidy_qty,
        "subsidy_pnl": daily_subsidy,
        "phoenix_event_type": event_type,
        "phoenix_terminate_reason": str(pick_first(result.get("terminate_reason"), "") or ""),
        "phoenix_delivered_side": delivered_side,
        "phoenix_delivered_qty": delivered_qty,
        "phoenix_delivered_price": delivered_price,
        "phoenix_daily_subsidy": daily_subsidy,
        "phoenix_cumulative_subsidy": float(pick_first(result.get("cumulative_subsidy"), 0.0) or 0.0),
    }


def _sm_safety_airbag(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    安全气囊（非累计）：
    - 看涨（ACC）：观察期内收盘 <= 障碍价敲入，按行权价一次性转多头线性头寸；
      未敲入到期时，上涨段收益=涨幅*参与率，保护段收益=0。
    - 看跌（DEC）：观察期内收盘 >= 障碍价敲入，按行权价一次性转空头线性头寸；
      未敲入到期时，下跌段收益=跌幅*参与率，保护段收益=0。
    参与率口径为百分比（例如输入 80 表示 80%）。
    """
    base_qty = float(day_ctx["base_qty"])
    total_days = max(int(day_ctx["total_days"]), 0)
    remaining_days = max(int(day_ctx["remaining_days"]), 0)
    kind = str(struct["kind"]).upper()
    entry = float(pick_first(struct.get("entry_price"), struct.get("strike_price"), settle))
    strike = float(pick_first(struct.get("strike_price"), struct.get("entry_price"), settle))
    barrier = to_float(pick_first(struct.get("barrier_out"), struct.get("knock_out_price")))
    participation_pct = max(float(pick_first(struct.get("multiple"), 80.0)), 0.0)
    participation_rate = participation_pct / 100.0
    notional_qty = max(base_qty * total_days, 0.0)

    # 敲入后一次性转线性并终止后续观察生成
    ki_hit = False
    if barrier is not None:
        ki_hit = price_at_or_below(settle, barrier) if kind == "ACC" else price_at_or_above(settle, barrier)
    if ki_hit:
        st_state["knocked_out"] = True
        st_state["terminated"] = True
        return {
            "qty": notional_qty,
            "gen_price": strike,
            "mult": participation_pct,
            "status": "敲入转线性",
            "flags": ["AIRBAG_KI_LINEAR"],
            "knocked_out": True,
            "terminate": True,
        }

    # 非敲入观察期：不生成期货头寸
    is_last_observe_day = remaining_days <= 1
    if not is_last_observe_day:
        return {
            "qty": 0.0,
            "gen_price": strike,
            "mult": participation_pct,
            "status": "未敲入观察",
            "flags": ["AIRBAG_OBSERVE"],
        }

    # 未敲入到期收益（不产生库存头寸，直接记为期权收益）
    option_pnl = 0.0
    if kind == "ACC":
        if settle > entry:
            option_pnl = (settle - entry) * notional_qty * participation_rate
            status = "未敲入到期上涨"
            flags = ["AIRBAG_MATURITY_PAYOFF"]
        else:
            status = "未敲入到期保护"
            flags = ["AIRBAG_MATURITY_ZERO"]
    else:
        if settle < entry:
            option_pnl = (entry - settle) * notional_qty * participation_rate
            status = "未敲入到期下跌"
            flags = ["AIRBAG_MATURITY_PAYOFF"]
        else:
            status = "未敲入到期保护"
            flags = ["AIRBAG_MATURITY_ZERO"]

    return {
        "qty": 0.0,
        "gen_price": strike,
        "mult": participation_pct,
        "status": status,
        "flags": flags,
        "option_pnl": option_pnl,
    }


def _sm_trs(struct: Dict[str, Any], settle: float, day_ctx: Dict[str, Any], st_state: Dict[str, Any]) -> Dict[str, Any]:
    """
    TRS 头寸：
    - 仅在首个有效观察日一次性建仓；
    - 后续交易日不再新增生成量。
    """
    params = struct.get("params", {}) if isinstance(struct.get("params", {}), dict) else {}
    meta = struct.get("meta", {}) if isinstance(struct.get("meta", {}), dict) else {}
    trs_qty = resolve_trs_position_qty_from_legacy(params, meta, struct.get("base_qty_per_day"))
    entry = float(pick_first(struct.get("entry_price"), struct.get("strike_price"), settle, 0.0) or 0.0)
    observed_days = max(int(pick_first(day_ctx.get("observed_days"), 0) or 0), 0)
    if observed_days == 0 and trs_qty > 1e-12:
        return {
            "qty": trs_qty,
            "gen_price": entry,
            "mult": 1.0,
            "status": "TRS建仓",
            "flags": ["TRS_OPEN_ONCE"],
        }
    return {
        "qty": 0.0,
        "gen_price": entry,
        "mult": 0.0,
        "status": "TRS持仓",
        "flags": ["TRS_HOLD"],
    }


def _sm_vanilla_option(
    struct: Dict[str, Any],
    settle: float,
    day_ctx: Dict[str, Any],
    st_state: Dict[str, Any],
) -> Dict[str, Any]:
    qty = max(float(pick_first(to_float(struct.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    premium = max(float(pick_first(to_float(struct.get("premium")), 0.0) or 0.0), 0.0)
    intrinsic = vanilla_intrinsic_value(struct.get("option_type"), struct.get("strike_price"), settle)
    side = normalize_vanilla_side(pick_first(struct.get("side"), vanilla_side_from_kind(struct.get("kind")), "sell"))
    current_float = qty * (intrinsic - premium) if side == "buy" else qty * (premium - intrinsic)
    prev_float = float(pick_first(to_float(st_state.get("vanilla_float_last")), 0.0) or 0.0)
    day_float = current_float - prev_float
    st_state["vanilla_float_last"] = current_float

    remaining_days = max(int(pick_first(day_ctx.get("remaining_days"), 0) or 0), 0)
    is_expiry = remaining_days <= 1
    option_type_cn = vanilla_option_type_cn(struct.get("option_type"))
    side_cn = vanilla_side_cn(side)
    if is_expiry:
        if intrinsic > 1e-12:
            status = f"到期结束-实值{option_type_cn}{side_cn}"
            flags = ["VANILLA_EXPIRED_ITM"]
        else:
            status = f"到期结束-虚值{option_type_cn}{side_cn}"
            flags = ["VANILLA_EXPIRED_OTM"]
    else:
        status = f"存续中-{option_type_cn}{side_cn}"
        flags = ["VANILLA_ACTIVE"]

    return {
        "qty": 0.0,
        "gen_price": premium,
        "mult": 1.0,
        "status": status,
        "flags": flags,
        "option_pnl": day_float,
    }


def _bounds_basic_range(
    struct: Dict[str, Any],
    remaining_days: int,
    observed_days: int,
    observed_qty: float,
    st_state: Dict[str, Any],
) -> Dict[str, float]:
    base = float(struct["base_qty_per_day"])
    multiple = max(float(pick_first(struct.get("multiple"), 1.0)), 0.0)
    legacy_mode = str(struct.get("meta", {}).get("_legacy_mode", "")).upper()
    ko_terminate = bool(struct.get("meta", {}).get("ko_terminate", False))

    if st_state.get("terminated", False) and ko_terminate:
        return {"remaining_min_qty": 0.0, "remaining_max_qty": 0.0}

    if legacy_mode == "FIXED_PART":
        v = remaining_days * base * multiple
        return {"remaining_min_qty": v, "remaining_max_qty": v}
    if legacy_mode == "BASIC_MULT":
        return {"remaining_min_qty": 0.0, "remaining_max_qty": remaining_days * base * multiple}

    # 新 BASIC_RANGE：未来最大按“每日可能敲入多倍”估计上界
    # 例如 remaining_days * base * multiple
    max_mult = max(1.0, multiple)
    return {"remaining_min_qty": 0.0, "remaining_max_qty": remaining_days * base * max_mult}


