def get_structure_spec(code_or_alias: Any) -> StructureSpec:
    code = normalize_strategy_code(code_or_alias)
    return STRUCTURE_REGISTRY.get(code, STRUCTURE_REGISTRY["BASIC_RANGE"])


def resolve_strategy_code_for_display(value: Any) -> str:
    s = str(value or "").strip()
    if not s:
        return ""
    if s in CN_TO_STRATEGY_CODE:
        return CN_TO_STRATEGY_CODE[s]
    return normalize_strategy_code(s)


def normalize_kind_code(value: Any) -> str:
    k_raw = str(value or "").strip()
    k = k_raw.upper()
    if k in {"ACC", "DEC"}:
        return k
    return KIND_ALIAS_TO_CODE.get(k_raw, k)


def normalize_vanilla_option_type(value: Any, default: str = "put") -> str:
    raw = str(value or "").strip()
    norm = VANILLA_OPTION_TYPE_ALIASES.get(raw.lower(), VANILLA_OPTION_TYPE_ALIASES.get(raw, ""))
    if norm in {"call", "put"}:
        return norm
    return default if default in {"call", "put"} else "put"


def normalize_vanilla_side(value: Any, default: str = "sell") -> str:
    raw = str(value or "").strip()
    norm = VANILLA_SIDE_ALIASES.get(raw.lower(), VANILLA_SIDE_ALIASES.get(raw, ""))
    if norm in {"buy", "sell"}:
        return norm
    return default if default in {"buy", "sell"} else "sell"


def vanilla_option_type_cn(value: Any) -> str:
    return VANILLA_OPTION_TYPE_TO_CN.get(normalize_vanilla_option_type(value), "看跌")


def vanilla_side_cn(value: Any) -> str:
    return VANILLA_SIDE_TO_CN.get(normalize_vanilla_side(value), "卖出")


def vanilla_combo_cn(option_type: Any, side: Any) -> str:
    return f"{vanilla_side_cn(side)}{vanilla_option_type_cn(option_type)}"


def normalize_vanilla_structure_name(fallback_name: Any = "") -> str:
    raw = str(fallback_name or "").strip()
    if not raw:
        return ""
    for combo in ("买入看涨", "买入看跌", "卖出看涨", "卖出看跌"):
        if combo in raw:
            return combo
    side_txt = "买入" if "买入" in raw else "卖出" if "卖出" in raw else ""
    option_txt = "看涨" if "看涨" in raw else "看跌" if "看跌" in raw else ""
    if side_txt and option_txt:
        return f"{side_txt}{option_txt}"
    return raw


def vanilla_kind_from_side(side_value: Any) -> str:
    return VANILLA_SIDE_TO_KIND.get(normalize_vanilla_side(side_value), "DEC")


def vanilla_side_from_kind(kind_value: Any) -> str:
    norm_kind = normalize_kind_code(kind_value)
    if norm_kind in VANILLA_KIND_TO_SIDE:
        return VANILLA_KIND_TO_SIDE[norm_kind]
    return normalize_vanilla_side(kind_value, "sell")


def vanilla_intrinsic_value(option_type: Any, strike_price: Any, settle_price: Any) -> float:
    strike = float(pick_first(to_float(strike_price), 0.0) or 0.0)
    settle = float(pick_first(to_float(settle_price), 0.0) or 0.0)
    if normalize_vanilla_option_type(option_type) == "call":
        return max(settle - strike, 0.0)
    return max(strike - settle, 0.0)


def build_vanilla_option_name(
    option_type: Any,
    side: Any,
    underlying: Any = "",
    expiry_date: Any = "",
    strike_price: Any = None,
    premium: Any = None,
) -> str:
    return vanilla_combo_cn(option_type, side)


def _normalize_phoenix_acc_knock_in_qty_mode(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if raw in {"remaining", "剩余", "剩余数量"}:
        return "remaining"
    return "all"


def _normalize_phoenix_acc_knock_out_settlement_mode(value: Any) -> str:
    raw = str(value or "").strip().lower()
    if raw in {"delivery", "给量", "头寸"}:
        return "delivery"
    return "subsidy"


def is_phoenix_acc_strategy_value(value: Any) -> bool:
    raw = str(value or "").strip()
    if raw in {PHOENIX_ACC_BASE_NAME, "凤凰累购", "凤凰累沽"}:
        return True
    return normalize_strategy_code(value) in PHOENIX_ACC_STRATEGY_CODES


def phoenix_acc_strategy_code_for_kind(kind_value: Any) -> str:
    kind_code = normalize_kind_code(kind_value)
    return PHOENIX_ACC_KIND_TO_CODE.get(kind_code, PHOENIX_ACC_CALL_FIXED_CODE)


def resolve_directional_strategy_code(strategy_value: Any, kind_value: Any) -> str:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    if strategy_code in PHOENIX_ACC_STRATEGY_CODES or is_phoenix_acc_strategy_value(strategy_value):
        return phoenix_acc_strategy_code_for_kind(kind_value)
    return strategy_code


def structure_form_state_key(strategy_value: Any) -> str:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    if strategy_code in PHOENIX_ACC_STRATEGY_CODES:
        return "PHOENIX_ACC_FIXED"
    return strategy_code or "BASIC_RANGE"


def validate_phoenix_acc_terms(
    *,
    kind_value: Any,
    entry_price: Any,
    knock_in_price: Any,
    knock_in_exercise_price: Any,
    subsidy_per_ton: Any,
    knock_out_price: Any,
    participation_rate: Any,
    knock_in_qty_mode: Any = "all",
    knock_out_settlement_mode: Any = "subsidy",
    knock_out_exercise_price: Any = None,
) -> Tuple[Dict[str, Any], List[str]]:
    kind_code = normalize_kind_code(kind_value)
    knock_in_qty_mode_n = _normalize_phoenix_acc_knock_in_qty_mode(knock_in_qty_mode)
    knock_out_settlement_mode_n = _normalize_phoenix_acc_knock_out_settlement_mode(knock_out_settlement_mode)
    entry_price_n = to_float(entry_price)
    knock_in_price_n = to_float(knock_in_price)
    knock_in_exercise_price_n = to_float(knock_in_exercise_price)
    knock_out_price_n = to_float(knock_out_price)
    participation_rate_n = to_float(participation_rate)
    subsidy_per_ton_n = pick_first(to_float(subsidy_per_ton), 0.0)
    knock_out_exercise_price_n = to_float(knock_out_exercise_price)

    errors: List[str] = []
    if kind_code not in {"ACC", "DEC"}:
        errors.append("凤凰累计仅支持 kind=ACC/DEC。")
    if entry_price_n is None:
        errors.append("entry_price 必填。")
    if knock_in_price_n is None:
        errors.append("knock_in_price 必填。")
    if knock_in_exercise_price_n is None:
        errors.append("knock_in_exercise_price 必填。")
    if knock_out_price_n is None:
        errors.append("knock_out_price 必填。")
    if participation_rate_n is None:
        errors.append("participation_rate 必填。")
    if knock_in_qty_mode_n not in PHOENIX_ACC_KNOCK_IN_QTY_MODES:
        errors.append("knock_in_qty_mode 仅支持 all / remaining。")
    if knock_out_settlement_mode_n not in PHOENIX_ACC_KNOCK_OUT_SETTLEMENT_MODES:
        errors.append("knock_out_settlement_mode 仅支持 subsidy / delivery。")

    participation_rate_f = float(pick_first(participation_rate_n, 0.0) or 0.0)
    subsidy_per_ton_f = float(pick_first(subsidy_per_ton_n, 0.0) or 0.0)
    if participation_rate_f <= 0:
        errors.append("participation_rate 必须大于 0。")
    if subsidy_per_ton_f < 0:
        errors.append("subsidy_per_ton 不能小于 0。")

    if knock_out_settlement_mode_n == "delivery" and knock_out_exercise_price_n is None:
        errors.append("knock_out_settlement_mode=delivery 时，knock_out_exercise_price 必填。")
    if knock_out_settlement_mode_n != "delivery":
        knock_out_exercise_price_n = None

    if knock_in_price_n is not None and knock_out_price_n is not None:
        if kind_code == "ACC":
            if not (float(knock_in_price_n) < float(knock_out_price_n)):
                errors.append("凤凰累购要求 knock_in_price < knock_out_price。")
        elif kind_code == "DEC":
            if not (float(knock_out_price_n) < float(knock_in_price_n)):
                errors.append("凤凰累沽要求 knock_out_price < knock_in_price。")

    if knock_in_price_n is not None and knock_in_exercise_price_n is not None:
        if kind_code == "ACC" and not (float(knock_in_exercise_price_n) >= float(knock_in_price_n)):
            errors.append("凤凰累购要求 knock_in_exercise_price >= knock_in_price。")
        if kind_code == "DEC" and not (float(knock_in_exercise_price_n) <= float(knock_in_price_n)):
            errors.append("凤凰累沽要求 knock_in_exercise_price <= knock_in_price。")

    return (
        {
            "kind": kind_code,
            "strategy_code": phoenix_acc_strategy_code_for_kind(kind_code),
            "entry_price": entry_price_n,
            "knock_in_price": knock_in_price_n,
            "knock_in_exercise_price": knock_in_exercise_price_n,
            "subsidy_per_ton": subsidy_per_ton_f,
            "knock_out_price": knock_out_price_n,
            "participation_rate": participation_rate_f,
            "knock_in_qty_mode": knock_in_qty_mode_n,
            "knock_out_settlement_mode": knock_out_settlement_mode_n,
            "knock_out_exercise_price": knock_out_exercise_price_n,
        },
        errors,
    )


def phoenix_acc_close_event_type(close: Any, *, kind_value: Any, knock_in_price: float, knock_out_price: float) -> str:
    close_f = float(pick_first(to_float(close), 0.0) or 0.0)
    kind_code = normalize_kind_code(kind_value)
    if kind_code == "ACC":
        if price_at_or_below(close_f, knock_in_price):
            return "knock_in"
        if price_at_or_above(close_f, knock_out_price):
            return "knock_out"
        return "normal"
    if price_at_or_above(close_f, knock_in_price):
        return "knock_in"
    if price_at_or_below(close_f, knock_out_price):
        return "knock_out"
    return "normal"


def phoenix_acc_fixed_day_event(
    close: Any,
    *,
    day_index: Any,
    total_days: Any,
    daily_qty: Any,
    observed_qty_before: Any,
    cumulative_subsidy_before: Any,
    cumulative_delivered_qty_before: Any,
    kind_value: Any,
    entry_price: Any,
    knock_in_price: Any,
    knock_in_exercise_price: Any,
    subsidy_per_ton: Any,
    knock_out_price: Any,
    participation_rate: Any,
    knock_in_qty_mode: Any = "all",
    knock_out_settlement_mode: Any = "subsidy",
    knock_out_exercise_price: Any = None,
) -> Dict[str, Any]:
    terms, errors = validate_phoenix_acc_terms(
        kind_value=kind_value,
        entry_price=entry_price,
        knock_in_price=knock_in_price,
        knock_in_exercise_price=knock_in_exercise_price,
        subsidy_per_ton=subsidy_per_ton,
        knock_out_price=knock_out_price,
        participation_rate=participation_rate,
        knock_in_qty_mode=knock_in_qty_mode,
        knock_out_settlement_mode=knock_out_settlement_mode,
        knock_out_exercise_price=knock_out_exercise_price,
    )
    total_days_i = max(int(pick_first(_int_from_any(total_days, 0), 0) or 0), 1)
    day_index_i = max(int(pick_first(_int_from_any(day_index, 0), 0) or 0), 1)
    daily_qty_f = float(pick_first(to_float(daily_qty), 0.0) or 0.0)
    observed_qty_before_f = float(pick_first(to_float(observed_qty_before), 0.0) or 0.0)
    cumulative_subsidy_before_f = float(pick_first(to_float(cumulative_subsidy_before), 0.0) or 0.0)
    cumulative_delivered_qty_before_f = float(pick_first(to_float(cumulative_delivered_qty_before), 0.0) or 0.0)
    if daily_qty_f <= 0:
        errors.append("daily_qty 必须大于 0。")
    if day_index_i > total_days_i:
        errors.append("day_index 不能大于 total_days。")
    if observed_qty_before_f < 0:
        errors.append("observed_qty_before 不能小于 0。")
    if errors:
        raise ValueError(" | ".join(errors))

    total_qty = daily_qty_f * float(total_days_i)
    observed_before = min(max(observed_qty_before_f, 0.0), total_qty)
    remaining_before = max(total_qty - observed_before, 0.0)
    close_f = float(pick_first(to_float(close), 0.0) or 0.0)
    event_key = phoenix_acc_close_event_type(
        close_f,
        kind_value=terms["kind"],
        knock_in_price=float(terms["knock_in_price"]),
        knock_out_price=float(terms["knock_out_price"]),
    )
    delivered_side = ""
    delivered_qty = 0.0
    delivered_price: Optional[float] = None
    daily_subsidy = 0.0
    terminated_flag = False
    terminate_reason = ""
    event_type = "normal_subsidy"
    cumulative_subsidy = cumulative_subsidy_before_f
    cumulative_delivered_qty = cumulative_delivered_qty_before_f
    observed_after = min(observed_before + daily_qty_f, total_qty)
    remaining_after = max(total_qty - observed_after, 0.0)

    if event_key == "knock_in":
        deliver_base_qty = total_qty if terms["knock_in_qty_mode"] == "all" else remaining_before
        delivered_qty = max(float(deliver_base_qty) * float(terms["participation_rate"]), 0.0)
        delivered_price = float(terms["knock_in_exercise_price"])
        delivered_side = PHOENIX_ACC_DELIVERED_SIDE_BY_KIND.get(str(terms["kind"]), "")
        cumulative_delivered_qty += delivered_qty
        observed_after = total_qty
        remaining_after = 0.0
        terminated_flag = True
        terminate_reason = "knock_in"
        event_type = "knock_in_terminate"
    elif event_key == "knock_out":
        observed_after = total_qty
        remaining_after = 0.0
        terminated_flag = True
        delivered_side = PHOENIX_ACC_DELIVERED_SIDE_BY_KIND.get(str(terms["kind"]), "")
        if terms["knock_out_settlement_mode"] == "delivery":
            delivered_qty = max(float(remaining_before), 0.0)
            delivered_price = float(pick_first(terms["knock_out_exercise_price"], 0.0) or 0.0)
            cumulative_delivered_qty += delivered_qty
            terminate_reason = "knock_out_delivery"
            event_type = "knock_out_delivery_terminate"
        else:
            delivered_side = ""
            daily_subsidy = max(float(remaining_before), 0.0) * float(terms["subsidy_per_ton"])
            cumulative_subsidy += daily_subsidy
            terminate_reason = "knock_out_subsidy"
            event_type = "knock_out_subsidy_terminate"
    elif day_index_i >= total_days_i:
        daily_subsidy = daily_qty_f * float(terms["subsidy_per_ton"])
        cumulative_subsidy += daily_subsidy
        observed_after = total_qty
        remaining_after = 0.0
        terminated_flag = True
        terminate_reason = "maturity"
        event_type = "maturity_end"
    else:
        daily_subsidy = daily_qty_f * float(terms["subsidy_per_ton"])
        cumulative_subsidy += daily_subsidy

    return {
        "close": close_f,
        "day_index": day_index_i,
        "daily_qty": daily_qty_f,
        "observed_qty_before": observed_before,
        "observed_qty_after": observed_after,
        "remaining_qty_before": remaining_before,
        "remaining_qty_after": remaining_after,
        "event_type": event_type,
        "daily_subsidy": daily_subsidy,
        "cumulative_subsidy": cumulative_subsidy,
        "delivered_qty": delivered_qty,
        "delivered_price": delivered_price,
        "delivered_side": delivered_side,
        "cumulative_delivered_qty": cumulative_delivered_qty,
        "terminated_flag": terminated_flag,
        "terminate_reason": terminate_reason,
    }


def simulate_phoenix_acc_fixed_ledger(
    closes: Sequence[Any],
    *,
    kind_value: Any,
    daily_qty: Any,
    entry_price: Any,
    knock_in_price: Any,
    knock_in_exercise_price: Any,
    subsidy_per_ton: Any,
    knock_out_price: Any,
    participation_rate: Any,
    knock_in_qty_mode: Any = "all",
    knock_out_settlement_mode: Any = "subsidy",
    knock_out_exercise_price: Any = None,
) -> List[Dict[str, Any]]:
    close_list = list(closes or [])
    if not close_list:
        raise ValueError("closes 不能为空。")
    rows: List[Dict[str, Any]] = []
    observed_qty_before = 0.0
    cumulative_subsidy_before = 0.0
    cumulative_delivered_qty_before = 0.0
    total_days = len(close_list)
    for day_index, close in enumerate(close_list, start=1):
        row = phoenix_acc_fixed_day_event(
            close,
            day_index=day_index,
            total_days=total_days,
            daily_qty=daily_qty,
            observed_qty_before=observed_qty_before,
            cumulative_subsidy_before=cumulative_subsidy_before,
            cumulative_delivered_qty_before=cumulative_delivered_qty_before,
            kind_value=kind_value,
            entry_price=entry_price,
            knock_in_price=knock_in_price,
            knock_in_exercise_price=knock_in_exercise_price,
            subsidy_per_ton=subsidy_per_ton,
            knock_out_price=knock_out_price,
            participation_rate=participation_rate,
            knock_in_qty_mode=knock_in_qty_mode,
            knock_out_settlement_mode=knock_out_settlement_mode,
            knock_out_exercise_price=knock_out_exercise_price,
        )
        rows.append(row)
        observed_qty_before = float(row["observed_qty_after"])
        cumulative_subsidy_before = float(row["cumulative_subsidy"])
        cumulative_delivered_qty_before = float(row["cumulative_delivered_qty"])
        if bool(row["terminated_flag"]):
            break
    return rows


def _infer_base_name_from_fallback_name(
    fallback_name: str,
    strategy_code: str,
    strategy_value: Any,
) -> str:
    fb = str(fallback_name or "").strip()
    fb = fb.replace("（固定赔付类）", "").replace("(固定赔付类)", "").strip()
    for key_txt, mapped_name in FALLBACK_BASE_NAME_HINTS:
        if key_txt in fb:
            return mapped_name
    if fb:
        return fb
    return STRATEGY_CODE_TO_CN.get(strategy_code, str(strategy_value or "")).strip()


def default_structure_name(strategy_value: Any, kind_value: Any, fallback_name: str = "") -> str:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    kind_code = normalize_kind_code(kind_value)
    side_cn = "累购" if kind_code == "ACC" else "累沽" if kind_code == "DEC" else ""
    base_name = str(STRUCTURE_BASE_NAME_BY_CODE.get(strategy_code, "")).strip()
    if not base_name:
        base_name = _infer_base_name_from_fallback_name(
            fallback_name=fallback_name,
            strategy_code=strategy_code,
            strategy_value=strategy_value,
        )

    if base_name == "安全气囊":
        return "看涨安全气囊" if kind_code == "ACC" else "看跌安全气囊" if kind_code == "DEC" else "安全气囊"
    if base_name == "雪球":
        return "看涨雪球" if kind_code == "ACC" else "看跌雪球" if kind_code == "DEC" else "雪球"
    if base_name == "香草期权":
        fb = normalize_vanilla_structure_name(fallback_name)
        return fb or "香草期权"
    if base_name == "区间补贴累计":
        return "区间累购" if kind_code == "ACC" else "区间累沽" if kind_code == "DEC" else "区间补贴累计"
    if "累计" in base_name and side_cn:
        return base_name.replace("累计", side_cn)
    if ("累购" in base_name or "累沽" in base_name) and side_cn:
        head = base_name.replace("累购", "").replace("累沽", "")
        return f"{head}{side_cn}"
    return base_name


def _trading_days_count_from_text(start_date_v: Any, end_date_v: Any) -> int:
    sd = parse_date_maybe(start_date_v)
    ed = parse_date_maybe(end_date_v)
    if sd is None or ed is None or ed < sd:
        return 1
    return max(1, len(trading_days_between(sd, ed)))


def resolve_structure_trade_day_count(
    start_date_v: Any,
    end_date_v: Any,
    *,
    params_value: Any = None,
    meta_value: Any = None,
) -> int:
    params = parse_json_obj(params_value, {})
    meta = parse_json_obj(meta_value, {})
    stored_days = to_float(pick_first(params.get("n_days"), meta.get("n_days")))
    if stored_days is not None:
        return max(int(round(float(stored_days))), 1)
    return _trading_days_count_from_text(start_date_v, end_date_v)


def resolve_structure_editor_schedule(
    *,
    start_date_value: Any,
    end_date_value: Any,
    trade_days_value: Any,
    fallback_start_date: Any,
    fallback_end_date: Any,
    fallback_trade_days: Any = None,
    end_date_label: str = "结束日期",
) -> Tuple[str, str, int]:
    fallback_start_s = str(pick_first_text(fallback_start_date, default="") or "").strip()
    fallback_end_s = str(pick_first_text(fallback_end_date, fallback_start_s, default=fallback_start_s) or fallback_start_s).strip()
    start_date_s = str(pick_first_text(start_date_value, fallback_start_s, default=fallback_start_s) or fallback_start_s).strip()
    end_date_s = str(pick_first_text(end_date_value, fallback_end_s, default=fallback_end_s) or fallback_end_s).strip()

    start_date_obj = parse_date_maybe(start_date_s)
    if not isinstance(start_date_obj, date):
        raise ValueError("开始日期格式无效")

    end_date_input_obj = parse_date_maybe(end_date_s)
    if not isinstance(end_date_input_obj, date):
        raise ValueError(f"{end_date_label}格式无效")
    if end_date_input_obj < start_date_obj:
        raise ValueError(f"{end_date_label}不能早于开始日期")

    fallback_trade_days_num = to_float(fallback_trade_days)
    old_trade_days = (
        max(int(round(float(fallback_trade_days_num))), 1)
        if fallback_trade_days_num is not None
        else _trading_days_count_from_text(fallback_start_s, fallback_end_s)
    )
    new_trade_days_num = to_float(trade_days_value)
    trade_days = max(int(round(float(new_trade_days_num))), 1) if new_trade_days_num is not None else old_trade_days
    end_date_changed = end_date_s != fallback_end_s
    trade_days_changed = trade_days != old_trade_days

    if trade_days_changed:
        resolved_end_obj = add_trading_days(start_date_obj, trade_days)[0]
        if end_date_changed and resolved_end_obj != end_date_input_obj:
            raise ValueError(f"{end_date_label}与交易日数量不一致，请调整后再保存")
        end_date_obj = resolved_end_obj
    else:
        end_date_obj = end_date_input_obj
        trade_days = _trading_days_count_from_text(start_date_obj, end_date_obj)

    return start_date_obj.strftime(DATE_FMT), end_date_obj.strftime(DATE_FMT), int(trade_days)


def resolve_snowball_notional_amount(params_value: Any) -> float:
    params = parse_json_obj(params_value, {})
    amount = max(float(pick_first(to_float(params.get("sb_notional_amount")), 0.0) or 0.0), 0.0)
    if amount <= 1e-12:
        amount = max(
            float(pick_first(to_float(params.get("sb_notional_wan")), 0.0) or 0.0) * 10000.0,
            0.0,
        )
    return amount


def snowball_scale_qty_from_notional(notional_amount: Any, entry_price: Any) -> float:
    amount = max(float(pick_first(to_float(notional_amount), 0.0) or 0.0), 0.0)
    entry = max(float(pick_first(to_float(entry_price), 0.0) or 0.0), 0.0)
    if amount <= 1e-12 or entry <= 1e-12:
        return 0.0
    return amount / entry


def snowball_notional_amount_from_scale(scale_qty: Any, entry_price: Any) -> float:
    qty = max(float(pick_first(to_float(scale_qty), 0.0) or 0.0), 0.0)
    entry = max(float(pick_first(to_float(entry_price), 0.0) or 0.0), 0.0)
    if qty <= 1e-12 or entry <= 1e-12:
        return 0.0
    return qty * entry


def snowball_editor_merge_notional_params(
    params_value: Any,
    *,
    display_qty: Any,
    old_display_qty: Any,
    entry_price: Any,
) -> Dict[str, Any]:
    params = parse_json_obj(params_value, {})
    out = dict(params)
    display_qty_v = float(pick_first(to_float(display_qty), 0.0) or 0.0)
    old_display_qty_v = float(pick_first(to_float(old_display_qty), 0.0) or 0.0)
    if abs(display_qty_v - old_display_qty_v) <= 1e-9:
        return out
    snowball_notional_amount = snowball_notional_amount_from_scale(display_qty_v, entry_price)
    out["sb_notional_amount"] = float(max(snowball_notional_amount, 0.0))
    out["sb_notional_wan"] = float(max(snowball_notional_amount, 0.0) / 10000.0)
    return out


def structure_display_notional_qty(
    strategy_value: Any,
    base_qty_per_day: Any,
    start_date_v: Any,
    end_date_v: Any,
    entry_price: Any = None,
    params_value: Any = None,
) -> float:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    base_qty = float(pick_first(to_float(base_qty_per_day), 0.0) or 0.0)
    if strategy_code == "SAFETY_AIRBAG":
        return base_qty * float(_trading_days_count_from_text(start_date_v, end_date_v))
    if strategy_code == "SNOWBALL":
        return snowball_scale_qty_from_notional(resolve_snowball_notional_amount(params_value), entry_price)
    return base_qty


def structure_signed_display_notional_qty(
    strategy_value: Any,
    base_qty_per_day: Any,
    start_date_v: Any,
    end_date_v: Any,
    *,
    direction_val: Any,
    entry_price: Any = None,
    params_value: Any = None,
) -> float:
    qty = structure_display_notional_qty(
        strategy_value,
        base_qty_per_day,
        start_date_v,
        end_date_v,
        entry_price=entry_price,
        params_value=params_value,
    )
    return float(pick_first(to_float(signed_value_by_direction(qty, direction_val)), 0.0) or 0.0)


def build_structure_display_notional_qty_map(
    structs_df: pd.DataFrame,
    *,
    strategy_code_filter: Optional[str] = None,
    signed: bool = False,
    reduction_qty_map: Optional[Dict[str, float]] = None,
) -> Dict[str, float]:
    reduce_map = reduction_qty_map if isinstance(reduction_qty_map, dict) else {}
    cache_key = (
        "build_structure_display_notional_qty_map",
        _db_file_version_token(),
        _df_runtime_fingerprint(structs_df),
        str(strategy_code_filter or "").strip().upper(),
        bool(signed),
        tuple(
            sorted(
                (
                    str(k).strip(),
                    round(float(pick_first(to_float(v), 0.0) or 0.0), 8),
                )
                for k, v in reduce_map.items()
                if str(k).strip()
            )
        ),
    )
    cached = _STRUCT_DERIVED_MEMO_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return _copy_cached_runtime_value(cached)
    out: Dict[str, float] = {}
    if structs_df is None or structs_df.empty:
        return out
    filter_code = str(strategy_code_filter or "").strip().upper()
    for _, raw in structs_df.iterrows():
        try:
            resolved = resolve_structure_row(raw)
        except Exception:
            continue
        sid = str(pick_first(resolved.get("structure_id"), "")).strip()
        if not sid:
            continue
        if reduce_map:
            resolved = apply_manual_structure_reduction_to_resolved_row(
                resolved,
                reduce_map.get(sid, 0.0),
            )
        strategy_code = resolve_strategy_code_for_display(resolved.get("strategy_code", ""))
        if filter_code and str(strategy_code).upper() != filter_code:
            continue
        if signed:
            out[sid] = float(
                structure_signed_display_notional_qty(
                    strategy_code,
                    resolved.get("base_qty_per_day"),
                    resolved.get("start_date"),
                    resolved.get("end_date"),
                    direction_val=resolved.get("kind"),
                    entry_price=resolved.get("entry_price"),
                    params_value=resolved.get("params", {}),
                )
            )
        else:
            out[sid] = float(
                structure_display_notional_qty(
                    strategy_code,
                    resolved.get("base_qty_per_day"),
                    resolved.get("start_date"),
                    resolved.get("end_date"),
                    entry_price=resolved.get("entry_price"),
                    params_value=resolved.get("params", {}),
                )
            )
    _memo_cache_put(_STRUCT_DERIVED_MEMO_CACHE, cache_key, out, limit=48)
    return _copy_cached_runtime_value(out)


def report_monitor_display_slot_qty(item: Mapping[str, Any]) -> float:
    if not isinstance(item, Mapping):
        return 0.0
    display_qty = to_float(item.get("display_slot_qty"))
    if display_qty is not None and np.isfinite(float(display_qty)):
        return float(display_qty)
    direction_val = pick_first(item.get("kind"), item.get("side_cn"), item.get("方向"), "")
    open_qty = to_float(item.get("open_position_qty"))
    rem_qty = to_float(item.get("remaining_max_qty"))
    fallback = pick_first(
        open_qty,
        abs(float(rem_qty)) if rem_qty is not None and np.isfinite(float(rem_qty)) else None,
        0.0,
    )
    return float(
        pick_first(
            to_float(signed_value_by_direction(fallback, direction_val)),
            0.0,
        )
        or 0.0
    )


def report_monitor_snowball_coupon_value(item: Mapping[str, Any]) -> float:
    if not isinstance(item, Mapping):
        return 0.0
    return float(
        pick_first(
            to_float(item.get("snowball_coupon_cum_pnl")),
            to_float(item.get("cum_subsidy_pnl")),
            to_float(item.get("snowball_coupon_float_pnl")),
            0.0,
        )
        or 0.0
    )


CUMULATIVE_MONITOR_TITLE = "累计结构监控（含已终止但仍有头寸）"


def report_format_signed_integer(value: Any, *, show_plus: bool = True, suffix: str = "") -> str:
    num = to_float(value)
    if num is None or not np.isfinite(float(num)):
        return "-"
    rounded = int(round(float(num)))
    if rounded == 0:
        base = "0"
    elif rounded > 0 and show_plus:
        base = f"+{rounded:,d}"
    else:
        base = f"{rounded:,d}"
    return f"{base}{suffix}"


def report_cumulative_surviving_side_qty_breakdown(items: Sequence[Mapping[str, Any]], *, include_avg: bool = False) -> Dict[str, Any]:
    long_qty = 0.0
    short_qty = 0.0
    long_avg_qty = 0.0
    short_avg_qty = 0.0
    long_value = 0.0
    short_value = 0.0
    for item in items:
        if not isinstance(item, Mapping):
            continue
        raw_open_qty = to_float(item.get("open_position_qty"))
        signed_open_qty = to_float(item.get("open_position_qty_signed"))
        if raw_open_qty is not None and np.isfinite(float(raw_open_qty)):
            surviving_qty = max(float(raw_open_qty), 0.0)
        elif signed_open_qty is not None and np.isfinite(float(signed_open_qty)):
            surviving_qty = abs(float(signed_open_qty))
        else:
            continue
        kind_txt = str(pick_first(item.get("kind"), "")).strip().upper()
        side_txt = str(pick_first(item.get("side_cn"), "")).strip()
        avg_price = None
        has_avg_price = False
        if include_avg:
            avg_price = to_float(
                pick_first(
                    item.get("open_avg_price"),
                    item.get("open_position_avg_price"),
                    item.get("current_open_avg_price"),
                )
            )
            has_avg_price = avg_price is not None and np.isfinite(float(avg_price))
        if kind_txt == "ACC" or side_txt in {"多单", "看涨"}:
            long_qty += surviving_qty
            if has_avg_price:
                long_avg_qty += surviving_qty
                long_value += surviving_qty * float(avg_price)
            continue
        if kind_txt == "DEC" or side_txt in {"空单", "看跌"}:
            short_qty += surviving_qty
            if has_avg_price:
                short_avg_qty += surviving_qty
                short_value += surviving_qty * float(avg_price)
            continue
        if signed_open_qty is not None and np.isfinite(float(signed_open_qty)):
            if float(signed_open_qty) > 1e-12:
                long_qty += abs(float(signed_open_qty))
                if has_avg_price:
                    long_avg_qty += abs(float(signed_open_qty))
                    long_value += abs(float(signed_open_qty)) * float(avg_price)
            elif float(signed_open_qty) < -1e-12:
                short_qty += abs(float(signed_open_qty))
                if has_avg_price:
                    short_avg_qty += abs(float(signed_open_qty))
                    short_value += abs(float(signed_open_qty)) * float(avg_price)
    out = {
        "long_qty": float(long_qty),
        "short_qty": float(short_qty),
    }
    if include_avg:
        out["long_avg_price"] = float(long_value / long_avg_qty) if long_avg_qty > 1e-12 else None
        out["short_avg_price"] = float(short_value / short_avg_qty) if short_avg_qty > 1e-12 else None
    return out


def report_cumulative_surviving_side_qty_summary_text(items: Sequence[Mapping[str, Any]]) -> str:
    side_qty = report_cumulative_surviving_side_qty_breakdown(items, include_avg=True)
    long_txt = report_format_signed_integer(side_qty.get("long_qty", 0.0), show_plus=False, suffix="吨")
    short_txt = report_format_signed_integer(side_qty.get("short_qty", 0.0), show_plus=False, suffix="吨")
    long_part = f"多单{long_txt}"
    short_part = f"空单{short_txt}"
    long_avg = to_float(side_qty.get("long_avg_price"))
    short_avg = to_float(side_qty.get("short_avg_price"))
    if float(pick_first(to_float(side_qty.get("long_qty")), 0.0) or 0.0) > 1e-12 and long_avg is not None and np.isfinite(float(long_avg)):
        long_part = f"{long_part} 均价{float(long_avg):,.2f}"
    if float(pick_first(to_float(side_qty.get("short_qty")), 0.0) or 0.0) > 1e-12 and short_avg is not None and np.isfinite(float(short_avg)):
        short_part = f"{short_part} 均价{float(short_avg):,.2f}"
    return f"汇总：{long_part}\n　　　{short_part}"


def build_monitor_manual_adjust_trace_text(
    item: Optional[Mapping[str, Any]],
    *,
    show_in_report: bool = False,
) -> str:
    if not show_in_report or not isinstance(item, Mapping):
        return ""
    today_v = to_float(item.get("manual_adjust_today_qty"))
    net_v = to_float(item.get("manual_adjust_net_qty"))
    if today_v is not None and abs(float(today_v)) > 1e-12:
        return f"手调当日 {report_format_signed_integer(today_v, suffix='吨')}"
    if net_v is not None and abs(float(net_v)) > 1e-12:
        return f"手调存量 {report_format_signed_integer(net_v, suffix='吨')}"
    return ""


def report_monitor_filter_structure_bounds_for_display(
    structure_bounds_df: pd.DataFrame,
    *,
    inactive_sid_block: Iterable[Any],
    terminated_with_position_sid_set: Iterable[Any],
) -> pd.DataFrame:
    out = structure_bounds_df.copy()
    if out.empty or "structure_id" not in out.columns:
        return out
    inactive_sid_norm = {
        str(sid).strip()
        for sid in inactive_sid_block
        if str(sid).strip()
    }
    terminated_with_position_norm = {
        str(sid).strip()
        for sid in terminated_with_position_sid_set
        if str(sid).strip()
    }
    sid_ser_report = out["structure_id"].astype(str).str.strip()
    keep_mask = (~sid_ser_report.isin(inactive_sid_norm)) | (sid_ser_report.isin(terminated_with_position_norm))
    return out[keep_mask].copy()


def report_status_is_finished(
    raw_status: Any,
    status_cn: Any,
    *,
    normalized_status: Any = None,
    terminated_with_position: bool = False,
    ) -> bool:
    return structure_status_is_finished(
        raw_status,
        normalized_status=normalized_status,
        terminated_with_position=terminated_with_position,
    )


def sort_cumulative_report_items(items: Sequence[Mapping[str, Any]]) -> List[Mapping[str, Any]]:
    """累计结构排序：累沽在上、累购在下；各分组内未结束在前，已结束按存续吨数绝对值降序。"""
    indexed_items = list(enumerate(items or []))
    if not indexed_items:
        return []

    def _text(v: Any) -> str:
        return str(v).strip() if v is not None else ""

    def _float_or_zero(v: Any) -> float:
        try:
            if v is None or (isinstance(v, str) and not v.strip()):
                return 0.0
            return float(v)
        except Exception:
            return 0.0

    def _group_rank(item: Mapping[str, Any]) -> int:
        kind_txt = _text(item.get("kind")).upper()
        side_txt = _text(item.get("side_cn"))
        if kind_txt == "DEC" or side_txt in {"空单", "看跌", "累沽"}:
            return 0
        if kind_txt == "ACC" or side_txt in {"多单", "看涨", "累购"}:
            return 1
        return 2

    def _is_finished(item: Mapping[str, Any]) -> bool:
        rem_days = item.get("remaining_trading_days")
        if rem_days is not None:
            try:
                if float(rem_days) <= 0.0:
                    return True
            except Exception:
                pass
        status_txt = _text(item.get("status_cn") or item.get("status"))
        return ("结束" in status_txt) or ("终结" in status_txt)

    def _surviving_abs(item: Mapping[str, Any]) -> float:
        for key in ("open_position_qty", "display_slot_qty", "remaining_max_qty"):
            raw_val = item.get(key)
            if raw_val is None:
                continue
            return abs(_float_or_zero(raw_val))
        return 0.0

    sorted_items = sorted(
        indexed_items,
        key=lambda pair: (
            _group_rank(pair[1]),
            0 if not _is_finished(pair[1]) else 1,
            pair[0] if not _is_finished(pair[1]) else 0,
            -_surviving_abs(pair[1]) if _is_finished(pair[1]) else 0.0,
            pair[0],
        ),
    )
    return [item for _, item in sorted_items]


def structure_storage_base_qty(
    strategy_value: Any,
    display_qty: Any,
    start_date_v: Any,
    end_date_v: Any,
) -> float:
    qty = float(pick_first(to_float(display_qty), 0.0) or 0.0)
    if resolve_strategy_code_for_display(strategy_value) == "SAFETY_AIRBAG":
        days = float(_trading_days_count_from_text(start_date_v, end_date_v))
        return qty / days if days > 0 else qty
    return qty


def structure_total_scale_qty(
    strategy_value: Any,
    base_qty_per_day: Any,
    start_date_v: Any,
    end_date_v: Any,
    *,
    params_value: Any = None,
) -> float:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    base_qty = float(pick_first(to_float(base_qty_per_day), 0.0) or 0.0)
    if strategy_code in {"TRS", VANILLA_OPTION_CODE}:
        return base_qty
    if strategy_code == "SNOWBALL":
        return 0.0
    trading_days = float(_trading_days_count_from_text(start_date_v, end_date_v))
    return base_qty * trading_days


def structure_table_total_qty(
    strategy_value: Any,
    base_qty_per_day: Any,
    start_date_v: Any,
    end_date_v: Any,
    *,
    params_value: Any = None,
    meta_value: Any = None,
) -> Optional[float]:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    if strategy_code in {"SNOWBALL", "TRS", VANILLA_OPTION_CODE}:
        return None
    trade_days = resolve_structure_trade_day_count(
        start_date_v,
        end_date_v,
        params_value=params_value,
        meta_value=meta_value,
    )
    base_qty = max(float(pick_first(to_float(base_qty_per_day), 0.0) or 0.0), 0.0)
    return float(base_qty * float(max(trade_days, 1)))


def resolve_structure_editor_base_qty(
    strategy_value: Any,
    *,
    daily_qty_value: Any,
    total_qty_value: Any = None,
    trade_day_count: Any = None,
    old_daily_qty: Any = None,
    old_total_qty: Any = None,
) -> float:
    strategy_code = resolve_strategy_code_for_display(strategy_value)
    trade_days = max(_int_from_any(trade_day_count, 1, min_value=1), 1)
    daily_qty = max(float(pick_first(to_float(daily_qty_value), to_float(old_daily_qty), 0.0) or 0.0), 0.0)
    old_daily = max(float(pick_first(to_float(old_daily_qty), daily_qty, 0.0) or 0.0), 0.0)
    total_qty = to_float(total_qty_value)
    old_total = to_float(old_total_qty)

    if strategy_code == "SNOWBALL":
        return 0.0
    if strategy_code == "SAFETY_AIRBAG":
        total_effective = max(float(pick_first(total_qty, daily_qty, old_total, old_daily, 0.0) or 0.0), 0.0)
        return total_effective / float(trade_days) if trade_days > 0 else total_effective
    if strategy_code in {"TRS", VANILLA_OPTION_CODE}:
        return daily_qty
    if total_qty is None:
        return daily_qty

    total_qty = max(float(total_qty), 0.0)
    total_changed = (old_total is None and total_qty > 1e-9) or (
        old_total is not None and abs(total_qty - float(old_total)) > 1e-9
    )
    daily_changed = abs(daily_qty - old_daily) > 1e-9
    if total_changed and not daily_changed:
        return total_qty / float(trade_days) if trade_days > 0 else total_qty
    if total_changed and daily_changed:
        expected_total = daily_qty * float(trade_days)
        if abs(total_qty - expected_total) > 1e-6:
            raise ValueError("总量（吨）与名义规模（吨）/交易日数量不一致，请调整后再保存")
    return daily_qty


def structure_scale_display_text(struct_row: Dict[str, Any]) -> str:
    if not isinstance(struct_row, dict):
        return ""
    strategy_code = resolve_strategy_code_for_display(pick_first(struct_row.get("strategy_code"), ""))
    if strategy_code == "SNOWBALL":
        notional_amount = structure_scale_sort_value(struct_row)
        return f"{(notional_amount / 10000.0):,.2f} 万名义本金"
    scale_qty = structure_scale_sort_value(struct_row)
    return f"{float(scale_qty):,.2f} 吨"


def structure_scale_sort_value(struct_row: Mapping[str, Any]) -> float:
    if not isinstance(struct_row, Mapping):
        return 0.0
    strategy_code = resolve_strategy_code_for_display(
        pick_first(struct_row.get("strategy_code"), struct_row.get("strategy"), "")
    )
    params_value = struct_row.get("params")
    if not isinstance(params_value, dict):
        params_value = parse_json_obj(struct_row.get("params_json"), {})
    if strategy_code == "SNOWBALL":
        return float(max(resolve_snowball_notional_amount(params_value), 0.0))
    scale_qty = structure_total_scale_qty(
        strategy_code,
        struct_row.get("base_qty_per_day", 0.0),
        struct_row.get("start_date", ""),
        struct_row.get("end_date", ""),
        params_value=params_value,
    )
    return float(max(scale_qty, 0.0))


def trigger_price_label_for_strategy(strategy_value: Any) -> str:
    code = resolve_strategy_code_for_display(strategy_value)
    if code in MELT_TRIGGER_PRICE_STRATEGY_CODES:
        return "熔断价"
    return "敲出价"


def split_trigger_price_value(strategy_value: Any, trigger_price_value: Any) -> Tuple[Optional[float], Optional[float]]:
    px = to_float(trigger_price_value)
    if px is None:
        return None, None
    if abs(px) <= 1e-12:
        return None, None
    code = resolve_strategy_code_for_display(strategy_value)
    if code in MELT_TRIGGER_PRICE_STRATEGY_CODES:
        return None, px
    if code in KNOCK_OUT_TRIGGER_PRICE_STRATEGY_CODES:
        return px, None
    return None, None


def append_trigger_price_display_columns(
    df: pd.DataFrame,
    *,
    strategy_col: str,
    trigger_col: str,
    knock_out_col: str = "敲出价",
    melt_col: str = "熔断价",
) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        out[knock_out_col] = pd.Series(dtype="float64")
        out[melt_col] = pd.Series(dtype="float64")
        return out
    strategy_series = out[strategy_col] if strategy_col in out.columns else pd.Series([""] * len(out), index=out.index)
    trigger_series = out[trigger_col] if trigger_col in out.columns else pd.Series([None] * len(out), index=out.index)
    split_vals = [split_trigger_price_value(strategy_series.loc[idx], trigger_series.loc[idx]) for idx in out.index]
    out[knock_out_col] = [x[0] for x in split_vals]
    out[melt_col] = [x[1] for x in split_vals]
    return out


def resolve_structure_row(row: pd.Series) -> Dict[str, Any]:
    params = parse_json_obj(row.get("params_json"), {})
    meta = parse_json_obj(row.get("meta_json"), {})

    strategy_raw = str(pick_first(row.get("strategy"), row.get("structure_type"), "") or "").strip().upper()
    strategy_code_raw = str(row.get("strategy_code") or "").strip().upper()
    final_code = normalize_strategy_code(strategy_code_raw or strategy_raw)

    if not strategy_code_raw and strategy_raw in {"FIXED_PART", "BASIC_MULT", "TRIGGER_ONCE", "NO_KO"}:
        meta["_legacy_mode"] = strategy_raw

    entry_price = to_float(row.get("entry_price"))
    strike_price = to_float(pick_first(row.get("strike_price"), row.get("gen_price")))
    barrier_in = to_float(row.get("barrier_in"))
    barrier_out = to_float(pick_first(row.get("barrier_out"), row.get("barrier_price")))
    knock_out_price = to_float(pick_first(row.get("knock_out_price"), row.get("melt_price"), barrier_out))
    ko_strike_price = to_float(pick_first(row.get("ko_strike_price"), row.get("melt_strike"), entry_price, strike_price))
    if final_code == "FLOAT_KO":
        if knock_out_price is None:
            knock_out_price = barrier_out
        if barrier_out is None:
            barrier_out = knock_out_price
    default_multiple = (
        80.0
        if final_code == "SAFETY_AIRBAG"
        else 0.0
        if final_code == "SNOWBALL"
        else 1.0
        if final_code == "TRS"
        else 1.0
        if final_code in PHOENIX_ACC_STRATEGY_CODES
        else 3.0
    )
    multiple = resolve_multiplier_from_legacy(params, to_float(row.get("multiple")), default=default_multiple)
    subsidy_per_ton = resolve_subsidy_per_ton_from_legacy(params, meta)
    base_qty_storage = float(pick_first(to_float(row.get("base_qty_per_day")), 0.0) or 0.0)
    trs_position_qty = resolve_trs_position_qty_from_legacy(params, meta, base_qty_storage)
    knock_in_exercise_price = to_float(pick_first(params.get("knock_in_exercise_price"), meta.get("knock_in_exercise_price")))
    knock_in_qty_mode = _normalize_phoenix_acc_knock_in_qty_mode(pick_first(params.get("knock_in_qty_mode"), meta.get("knock_in_qty_mode"), "all"))
    knock_out_settlement_mode = _normalize_phoenix_acc_knock_out_settlement_mode(
        pick_first(params.get("knock_out_settlement_mode"), meta.get("knock_out_settlement_mode"), "subsidy")
    )
    knock_out_exercise_price = to_float(pick_first(params.get("knock_out_exercise_price"), meta.get("knock_out_exercise_price")))
    option_type = normalize_vanilla_option_type(pick_first(row.get("option_type"), params.get("option_type"), meta.get("option_type"), "put"))
    side = normalize_vanilla_side(
        pick_first(
            row.get("side"),
            params.get("side"),
            meta.get("side"),
            vanilla_side_from_kind(row.get("kind")),
            "sell",
        )
    )
    premium = to_float(pick_first(row.get("premium"), params.get("premium"), meta.get("premium")))
    structure_type = str(
        pick_first(
            row.get("structure_type"),
            STRATEGY_CODE_TO_CN.get(final_code, ""),
            row.get("strategy_code"),
            row.get("strategy"),
            "",
        )
        or ""
    ).strip()
    customer_name = str(pick_first(row.get("customer_name"), params.get("customer_name"), meta.get("customer_name"), "") or "").strip()
    counterparty = str(pick_first(row.get("counterparty"), params.get("counterparty"), meta.get("counterparty"), "") or "").strip()
    contract_month = str(pick_first(row.get("contract_month"), params.get("contract_month"), meta.get("contract_month"), "") or "").strip()
    trade_date = str(pick_first(row.get("trade_date"), row.get("start_date"), params.get("trade_date"), "") or "").strip()
    expiry_date = pick_first_text(row.get("expiry_date"), row.get("end_date"), params.get("expiry_date"), default="")
    note = str(pick_first(row.get("note"), params.get("note"), meta.get("note"), "") or "").strip()

    if final_code in PHOENIX_ACC_STRATEGY_CODES:
        params = dict(params) if isinstance(params, dict) else {}
        meta = dict(meta) if isinstance(meta, dict) else {}
        if knock_out_price is None:
            knock_out_price = barrier_out
        if knock_out_price is not None:
            barrier_out = knock_out_price
        if knock_in_exercise_price is None:
            knock_in_exercise_price = to_float(pick_first(row.get("strike_price"), row.get("gen_price"), entry_price))
        if knock_in_exercise_price is not None:
            strike_price = knock_in_exercise_price
        if knock_out_settlement_mode != "delivery":
            knock_out_exercise_price = None
            ko_strike_price = None
        elif knock_out_exercise_price is not None:
            ko_strike_price = knock_out_exercise_price
        params["participation_rate"] = float(pick_first(to_float(params.get("participation_rate")), multiple, 0.0) or 0.0)
        params["knock_in_exercise_price"] = knock_in_exercise_price
        params["knock_in_qty_mode"] = knock_in_qty_mode
        params["knock_out_settlement_mode"] = knock_out_settlement_mode
        if knock_out_exercise_price is None:
            params.pop("knock_out_exercise_price", None)
        else:
            params["knock_out_exercise_price"] = knock_out_exercise_price
        meta["ko_terminate"] = True

    if final_code == "SNOWBALL":
        params = dict(params) if isinstance(params, dict) else {}
        params.setdefault("sb_floor_enabled", True)
        params.setdefault("sb_discount_enabled", False)
        if float(pick_first(to_float(params.get("sb_notional_amount")), 0.0) or 0.0) <= 1e-12:
            notional_wan = float(pick_first(to_float(params.get("sb_notional_wan")), 0.0) or 0.0)
            if notional_wan > 0:
                params["sb_notional_amount"] = notional_wan * 10000.0

        if entry_price is None:
            entry_price = to_float(pick_first(row.get("gen_price"), row.get("strike_price"), 0.0))
        if entry_price is None:
            entry_price = 0.0

        ko_pct = to_float(params.get("sb_ko_pct"))
        ki_pct = to_float(params.get("sb_ki_pct"))
        if knock_out_price is None:
            if ko_pct is not None and entry_price > 1e-12:
                knock_out_price = entry_price * float(ko_pct) / 100.0
            else:
                knock_out_price = entry_price
        if barrier_in is None:
            if ki_pct is not None and entry_price > 1e-12:
                barrier_in = entry_price * float(ki_pct) / 100.0
            else:
                barrier_in = entry_price
        sb_barrier_price = to_float(pick_first(params.get("sb_barrier_price"), row.get("barrier_out"), row.get("barrier_price")))
        barrier_out = sb_barrier_price if sb_barrier_price is not None else knock_out_price
        strike_price = entry_price

    if final_code == "TRS":
        params = dict(params) if isinstance(params, dict) else {}
        params["trs_position_qty"] = max(float(trs_position_qty), 0.0)
        if entry_price is None:
            entry_price = to_float(pick_first(row.get("strike_price"), row.get("gen_price"), 0.0))
        if entry_price is None:
            entry_price = 0.0
        strike_price = entry_price
        barrier_in = None
        barrier_out = None
        knock_out_price = None
        ko_strike_price = None
        multiple = 1.0
        subsidy_per_ton = 0.0
        base_qty_storage = max(float(trs_position_qty), 0.0)

    if final_code == VANILLA_OPTION_CODE:
        params = dict(params) if isinstance(params, dict) else {}
        params["option_type"] = option_type
        params["side"] = side
        if premium is not None:
            params["premium"] = float(premium)
        if expiry_date:
            params["expiry_date"] = expiry_date
        if trade_date:
            params["trade_date"] = trade_date
        if entry_price is None:
            entry_price = to_float(pick_first(row.get("gen_price"), 0.0))
        strike_price = to_float(pick_first(row.get("strike_price"), row.get("gen_price")))
        barrier_in = None
        barrier_out = None
        knock_out_price = None
        ko_strike_price = None
        multiple = 1.0
        subsidy_per_ton = 0.0
        knock_in_exercise_price = None
        knock_in_qty_mode = "all"
        knock_out_settlement_mode = "subsidy"
        knock_out_exercise_price = None
        if not structure_type:
            structure_type = "香草期权"

    start_date = str(pick_first(row.get("start_date"), trade_date, "") or "").strip()
    end_date = str(pick_first(row.get("end_date"), expiry_date, "") or "").strip()
    trade_day_count = resolve_structure_trade_day_count(
        start_date,
        end_date,
        params_value=params,
        meta_value=meta,
    )

    return {
        "structure_id": str(row["structure_id"]),
        "structure_code": resolve_structure_display_code(
            row.get("structure_id", ""),
            row.get("structure_code", ""),
        ),
        "group_id": str(row["group_id"]),
        "name": str(row["name"]),
        "underlying": str(row["underlying"]),
        "risk_party": normalize_risk_party_name(pick_first(row.get("risk_party"), "海证资本")),
        "kind": normalize_kind_code(pick_first(row.get("kind"), vanilla_kind_from_side(side), "ACC")),
        "strategy_code": final_code,
        "structure_type": structure_type or STRATEGY_CODE_TO_CN.get(final_code, ""),
        "base_qty_per_day": float(base_qty_storage),
        "start_date": start_date,
        "end_date": end_date,
        "n_days": int(trade_day_count),
        "trade_date": trade_date,
        "expiry_date": expiry_date,
        "entry_price": entry_price,
        "strike_price": strike_price,
        "barrier_in": barrier_in,
        "barrier_out": barrier_out,
        "knock_out_price": knock_out_price,
        "ko_strike_price": ko_strike_price,
        "multiple": multiple,
        "option_type": option_type,
        "side": side,
        "premium": premium,
        "customer_name": customer_name,
        "counterparty": counterparty,
        "contract_month": contract_month,
        "note": note,
        "subsidy_per_ton": subsidy_per_ton,
        "knock_in_exercise_price": knock_in_exercise_price,
        "knock_in_qty_mode": knock_in_qty_mode,
        "knock_out_settlement_mode": knock_out_settlement_mode,
        "knock_out_exercise_price": knock_out_exercise_price,
        "trs_position_qty": float(trs_position_qty),
        "total_cap_qty": to_float(row.get("total_cap_qty")),
        "daily_cap_qty": to_float(row.get("daily_cap_qty")),
        "params": params,
        "meta": meta,
        "legacy_strategy": strategy_raw,
    }


def build_resolved_structure_scale_maps(
    structs_df: pd.DataFrame,
    *,
    reduction_qty_map: Optional[Dict[str, float]] = None,
) -> Tuple[Dict[str, Dict[str, Any]], Dict[str, str], Dict[str, float]]:
    resolved_map: Dict[str, Dict[str, Any]] = {}
    scale_text_map: Dict[str, str] = {}
    scale_sort_map: Dict[str, float] = {}
    if structs_df is None or structs_df.empty:
        return resolved_map, scale_text_map, scale_sort_map
    reduce_map = reduction_qty_map if isinstance(reduction_qty_map, dict) else {}
    for _, raw in structs_df.iterrows():
        try:
            resolved_rr = resolve_structure_row(raw)
        except Exception:
            continue
        sid_rr = str(pick_first(resolved_rr.get("structure_id"), "")).strip()
        if not sid_rr:
            continue
        if reduce_map:
            resolved_rr = apply_manual_structure_reduction_to_resolved_row(
                resolved_rr,
                reduce_map.get(sid_rr, 0.0),
            )
        resolved_map[sid_rr] = resolved_rr
        scale_text_map[sid_rr] = structure_scale_display_text(resolved_rr)
        scale_sort_map[sid_rr] = structure_scale_sort_value(resolved_rr)
    return resolved_map, scale_text_map, scale_sort_map


def manual_close_structure_option_label(
    structure_id: Any,
    struct_row: Mapping[str, Any],
    *,
    scale_text: Any = "",
    status_text: Any = "",
    remaining_scale_text: Any = "",
    terminated: bool = False,
    termination_label: Any = "",
) -> str:
    sid_opt = str(structure_id).strip()
    meta_row = dict(struct_row) if isinstance(struct_row, Mapping) else {}
    base_label = structure_verbose_label(
        resolve_structure_display_code(sid_opt, meta_row.get("structure_code", "")),
        pick_first(meta_row.get("name"), ""),
        pick_first(meta_row.get("risk_party"), ""),
        pick_first(meta_row.get("kind"), ""),
        pick_first(meta_row.get("underlying"), ""),
        pick_first(
            to_float(pick_first(meta_row.get("entry_price"), meta_row.get("gen_price"))),
            0.0,
        ),
        to_float(meta_row.get("strike_price")),
        strategy_value=pick_first(meta_row.get("strategy_code"), meta_row.get("strategy")),
        knock_in_price=to_float(meta_row.get("barrier_in")),
        barrier_price=resolve_display_barrier_price(
            pick_first(meta_row.get("strategy_code"), meta_row.get("strategy")),
            barrier_out=to_float(pick_first(meta_row.get("barrier_out"), meta_row.get("barrier_price"))),
            barrier_in=to_float(meta_row.get("barrier_in")),
            strike_price=to_float(meta_row.get("strike_price")),
        ),
    )
    suffix_parts: List[str] = []
    scale_text_v = str(pick_first(scale_text, "") or "").strip()
    status_text_v = str(pick_first(status_text, "") or "").strip()
    remaining_scale_text_v = str(pick_first(remaining_scale_text, "") or "").strip()
    if not status_text_v and terminated:
        status_text_v = str(pick_first(termination_label, "") or "").strip() or "已结束"
    if scale_text_v:
        suffix_parts.append(f"结构规模 {scale_text_v}")
    if status_text_v:
        suffix_parts.append(f"状态 {status_text_v}")
    if remaining_scale_text_v and remaining_scale_text_v != scale_text_v:
        suffix_parts.append(f"剩余 {remaining_scale_text_v}")
    if suffix_parts:
        return f"{base_label} | {' | '.join(suffix_parts)}"
    return base_label


def detect_structure_termination_on_prices(
    struct_row: Dict[str, Any],
    prices_df: Optional[pd.DataFrame],
) -> Tuple[bool, str, str]:
    """
    检测结构在“已录价格路径”下是否会出现敲出熔断终止。
    返回：(是否命中, 命中日期, 命中状态中文)
    """
    if prices_df is None or prices_df.empty:
        return False, "", ""
    try:
        sd = datetime.strptime(str(struct_row.get("start_date", "")), DATE_FMT).date()
        ed = datetime.strptime(str(struct_row.get("end_date", "")), DATE_FMT).date()
    except Exception:
        return False, "", ""
    if ed < sd:
        return False, "", ""
    und = str(struct_row.get("underlying", "")).strip()
    if not und:
        return False, "", ""

    psub = prices_df[prices_df["underlying"].astype(str) == und].copy()
    if psub.empty:
        return False, "", ""
    pmap: Dict[str, float] = {}
    for _, rr in psub.iterrows():
        dt_s = str(rr.get("dt", "")).strip()
        if not dt_s:
            continue
        try:
            pmap[dt_s] = float(rr.get("settle"))
        except Exception:
            continue
    if not pmap:
        return False, "", ""

    tdays = trading_days_between(sd, ed)
    if not tdays:
        return False, "", ""
    total_days = len(tdays)
    spec = get_structure_spec(struct_row.get("strategy_code"))
    stt: Dict[str, Any] = {
        "cum_qty": 0.0,
        "cum_pnl": 0.0,
        "cum_subsidy_pnl": 0.0,
        "observed_days": 0,
        "knocked_out": False,
        "terminated": False,
        "manual_closed": False,
    }
    for dt_ in tdays:
        dt_s = dt_.strftime(DATE_FMT)
        if dt_s not in pmap:
            continue
        observed_before = int(stt.get("observed_days", 0))
        remaining_days = max(total_days - observed_before, 0)
        if bool(stt.get("terminated", False)):
            stt["observed_days"] = observed_before + 1
            continue
        day_ctx = {
            "dt": dt_,
            "total_days": total_days,
            "observed_days": observed_before,
            "remaining_days": remaining_days,
            "base_qty": float(pick_first(struct_row.get("base_qty_per_day"), 0.0)),
        }
        sm_res = spec.state_machine(struct_row, float(pmap[dt_s]), day_ctx, stt)
        qty = max(float(sm_res.get("qty", 0.0)), 0.0)
        mult = float(sm_res.get("mult", 0.0))
        status_raw = str(sm_res.get("status", ""))
        if bool(sm_res.get("knocked_out", False)):
            stt["knocked_out"] = True
        term_flag = bool(sm_res.get("terminate", False))
        if term_flag:
            stt["terminated"] = True
        stt["observed_days"] = observed_before + 1
        if term_flag or ("敲出熔断" in status_raw) or ("已熔断终止" in status_raw):
            return True, dt_s, status_to_cn(status_raw, qty, mult)
    return False, "", ""


# ---------------------------
# Fetchers
# ---------------------------
_FETCH_SQL_MEMO_CACHE: Dict[Tuple[str, str, Tuple[int, int, int, int, int]], pd.DataFrame] = {}
_SESSION_SQL_MEMO_CACHE_KEY = "_runtime_sql_query_cache"
_SESSION_LEDGER_MEMO_CACHE_KEY = "_runtime_ledger_cache"


def _session_runtime_cache_bucket(cache_key: str) -> Dict[Any, Any]:
    try:
        bucket = st.session_state.get(cache_key)
        if isinstance(bucket, dict):
            return bucket
        bucket = {}
        st.session_state[cache_key] = bucket
        return bucket
    except Exception:
        return {}


def _clear_session_runtime_cache(cache_key: str) -> None:
    try:
        st.session_state.pop(cache_key, None)
    except Exception:
        pass


def _connection_main_db_path(conn: sqlite3.Connection) -> str:
    try:
        rows = conn.execute("PRAGMA database_list").fetchall()
    except Exception:
        rows = []
    for row in rows:
        if len(row) >= 3 and str(pick_first(row[1], "")).strip() == "main":
            path_s = str(pick_first(row[2], "")).strip()
            if not path_s:
                break
            try:
                return str(Path(path_s).resolve())
            except Exception:
                return path_s
    return ""


def _connection_cache_namespace(conn: sqlite3.Connection) -> str:
    main_path = _connection_main_db_path(conn)
    return main_path if main_path else f"conn:{id(conn)}"


def _db_storage_version_token(db_path_v: Any) -> Tuple[int, int, int, int]:
    path_s = str(db_path_v or "").strip()
    if not path_s:
        return 0, 0, 0, 0
    db_path = Path(path_s)
    wal_path = db_path.with_name(f"{db_path.name}-wal")

    def _path_token(path_obj: Path) -> Tuple[int, int]:
        try:
            stt = path_obj.stat()
            return int(getattr(stt, "st_mtime_ns", 0) or 0), int(getattr(stt, "st_size", 0) or 0)
        except Exception:
            return 0, 0

    db_mtime_ns, db_size = _path_token(db_path)
    wal_mtime_ns, wal_size = _path_token(wal_path)
    return db_mtime_ns, db_size, wal_mtime_ns, wal_size


def _connection_db_version_token(conn: sqlite3.Connection) -> Tuple[int, int, int, int]:
    return _db_storage_version_token(_connection_main_db_path(conn))


def _fetch_sql_query_cached(
    conn: sqlite3.Connection,
    cache_tag: str,
    sql: str,
    *,
    copy_out: bool = True,
) -> pd.DataFrame:
    """
    同一次运行内按连接 + 写入版本号复用查询结果，避免重复读库。
    语义保持：对外仍返回副本，避免下游修改污染缓存。
    """
    change_token = int(pick_first(getattr(conn, "total_changes", 0), 0) or 0)
    main_db_path = _connection_main_db_path(conn)
    cache_ns = main_db_path if main_db_path else _connection_cache_namespace(conn)
    db_token = _connection_db_version_token(conn)
    version_token = (change_token, *db_token)
    ckey = (cache_ns, str(cache_tag), version_token)
    use_session_cache = bool(main_db_path)
    session_cache = _session_runtime_cache_bucket(_SESSION_SQL_MEMO_CACHE_KEY) if use_session_cache else {}
    base_df = session_cache.get(ckey) if use_session_cache else None
    if not isinstance(base_df, pd.DataFrame):
        base_df = _FETCH_SQL_MEMO_CACHE.get(ckey)
    if not isinstance(base_df, pd.DataFrame):
        base_df = pd.read_sql_query(sql, conn)
        _memo_cache_put(_FETCH_SQL_MEMO_CACHE, ckey, base_df, limit=48)
        if use_session_cache:
            _memo_cache_put(session_cache, ckey, base_df, limit=48)
    return base_df.copy() if bool(copy_out) else base_df


