def upsert_probexp_market_input(
    conn: sqlite3.Connection,
    *,
    dt: Any,
    underlying: Any,
    atm_iv: Any,
    skew: Any,
    source: str = "manual",
) -> None:
    dt_s = str(dt or "").strip()
    und_s = _normalize_underlying_symbol(underlying)
    if not dt_s or not und_s:
        return
    iv_v = float(pick_first(to_float(atm_iv), 0.0) or 0.0)
    skew_v = float(pick_first(to_float(skew), 0.0) or 0.0)
    now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    conn.execute(
        """
        INSERT INTO probexp_market_input(dt, underlying, atm_iv, skew, source, updated_at)
        VALUES(?,?,?,?,?,?)
        ON CONFLICT(dt, underlying) DO UPDATE SET
            atm_iv=excluded.atm_iv,
            skew=excluded.skew,
            source=excluded.source,
            updated_at=excluded.updated_at
        """,
        (dt_s, und_s, iv_v, skew_v, str(source or "manual").strip() or "manual", now_s),
    )


def upsert_probexp_calc_log(
    conn: sqlite3.Connection,
    *,
    dt: Any,
    group_id: Any,
    structure_id: Any,
    underlying: Any,
    close_price: Any,
    target_hedge_qty: Any,
    current_position_tons: Any,
    current_position_after_tons: Any,
    target_position_tons: Any,
    suggested_adjust_tons: Any,
    no_trade_band_tons: Any,
    atm_iv: Any,
    skew: Any,
    mc_paths: Any,
    decision_quantile: Any,
    realized_qty: Any,
    remaining_days: Any,
    p10: Any,
    p20: Any,
    p50: Any,
    p80: Any,
    p95: Any,
    p975: Any,
    model_version: str,
) -> None:
    dt_s = str(dt or "").strip()
    gid_s = str(group_id or "").strip()
    sid_s = str(structure_id or "").strip()
    und_s = _normalize_underlying_symbol(underlying)
    if not dt_s or not gid_s or not sid_s or not und_s:
        return
    log_id = f"probexp::{dt_s}::{sid_s}"
    now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    conn.execute(
        """
        INSERT INTO probexp_calc_log(
            log_id, dt, group_id, structure_id, underlying,
            close_price, target_hedge_qty, current_position_tons, current_position_after_tons,
            target_position_tons, suggested_adjust_tons, no_trade_band_tons,
            atm_iv, skew, mc_paths, decision_quantile,
            realized_qty, remaining_days,
            p10, p20, p50, p80, p95, p975,
            model_version, created_at, updated_at
        )
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        ON CONFLICT(dt, structure_id) DO UPDATE SET
            group_id=excluded.group_id,
            underlying=excluded.underlying,
            close_price=excluded.close_price,
            target_hedge_qty=excluded.target_hedge_qty,
            current_position_tons=excluded.current_position_tons,
            current_position_after_tons=excluded.current_position_after_tons,
            target_position_tons=excluded.target_position_tons,
            suggested_adjust_tons=excluded.suggested_adjust_tons,
            no_trade_band_tons=excluded.no_trade_band_tons,
            atm_iv=excluded.atm_iv,
            skew=excluded.skew,
            mc_paths=excluded.mc_paths,
            decision_quantile=excluded.decision_quantile,
            realized_qty=excluded.realized_qty,
            remaining_days=excluded.remaining_days,
            p10=excluded.p10,
            p20=excluded.p20,
            p50=excluded.p50,
            p80=excluded.p80,
            p95=excluded.p95,
            p975=excluded.p975,
            model_version=excluded.model_version,
            updated_at=excluded.updated_at
        """,
        (
            log_id,
            dt_s,
            gid_s,
            sid_s,
            und_s,
            float(pick_first(to_float(close_price), 0.0) or 0.0),
            float(pick_first(to_float(target_hedge_qty), 0.0) or 0.0),
            float(pick_first(to_float(current_position_tons), 0.0) or 0.0),
            float(pick_first(to_float(current_position_after_tons), 0.0) or 0.0),
            float(pick_first(to_float(target_position_tons), 0.0) or 0.0),
            float(pick_first(to_float(suggested_adjust_tons), 0.0) or 0.0),
            float(pick_first(to_float(no_trade_band_tons), 0.0) or 0.0),
            float(pick_first(to_float(atm_iv), 0.0) or 0.0),
            float(pick_first(to_float(skew), 0.0) or 0.0),
            int(pick_first(_int_from_any(mc_paths, 0), 0) or 0),
            str(decision_quantile or "P50").strip() or "P50",
            float(pick_first(to_float(realized_qty), 0.0) or 0.0),
            int(pick_first(_int_from_any(remaining_days, 0), 0) or 0),
            float(pick_first(to_float(p10), 0.0) or 0.0),
            float(pick_first(to_float(p20), 0.0) or 0.0),
            float(pick_first(to_float(p50), 0.0) or 0.0),
            float(pick_first(to_float(p80), 0.0) or 0.0),
            float(pick_first(to_float(p95), 0.0) or 0.0),
            float(pick_first(to_float(p975), 0.0) or 0.0),
            str(model_version or "").strip(),
            now_s,
            now_s,
        ),
    )


def insert_precise_hedge_calc_log(
    conn: sqlite3.Connection,
    *,
    dt: Any,
    group_id: Any,
    structure_id: Any,
    underlying: Any,
    close_price: Any,
    current_position_tons: Any,
    target_center_tons: Any,
    target_lower_tons: Any,
    target_upper_tons: Any,
    recommended_position_tons: Any,
    suggested_adjust_tons: Any,
    current_hit_rate: Any,
    under_prob: Any,
    over_prob: Any,
    history_samples: Any,
    mc_paths: Any,
    atm_iv: Any,
    skew: Any,
    current_zone: Any,
    action_type: Any,
    confidence_level: Any,
    risk_focus: Any,
    fusion_mode: Any,
    frozen_reason: Any,
    state_weighted_optimal: Any,
    history_suggestion: Any,
    mc_suggestion: Any,
    fused_position: Any,
    model_version: str,
    payload_json: Any = "{}",
) -> int:
    dt_s = str(dt or "").strip()
    gid_s = str(group_id or "").strip()
    sid_s = str(structure_id or "").strip()
    und_s = _normalize_underlying_symbol(underlying)
    if not dt_s or not gid_s or not sid_s or not und_s:
        return 0
    now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    row = conn.execute(
        """
        SELECT COALESCE(MAX(version_no), 0)
        FROM precise_hedge_calc_log
        WHERE dt=? AND structure_id=?
        """,
        (dt_s, sid_s),
    ).fetchone()
    version_no = int(pick_first(row[0] if row else 0, 0) or 0) + 1
    save_id = f"precise::{dt_s}::{sid_s}::{version_no}::{uuid4().hex[:8]}"
    payload_text = str(payload_json or "").strip() or "{}"
    conn.execute(
        """
        INSERT INTO precise_hedge_calc_log(
            save_id, dt, group_id, structure_id, underlying, version_no,
            close_price, current_position_tons, target_center_tons, target_lower_tons, target_upper_tons,
            recommended_position_tons, suggested_adjust_tons,
            current_hit_rate, under_prob, over_prob,
            history_samples, mc_paths, atm_iv, skew,
            current_zone, action_type, confidence_level, risk_focus,
            fusion_mode, frozen_reason,
            state_weighted_optimal, history_suggestion, mc_suggestion, fused_position,
            model_version, payload_json, created_at, updated_at
        )
        VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
        """,
        (
            save_id,
            dt_s,
            gid_s,
            sid_s,
            und_s,
            int(version_no),
            float(pick_first(to_float(close_price), 0.0) or 0.0),
            float(pick_first(to_float(current_position_tons), 0.0) or 0.0),
            float(pick_first(to_float(target_center_tons), 0.0) or 0.0),
            float(pick_first(to_float(target_lower_tons), 0.0) or 0.0),
            float(pick_first(to_float(target_upper_tons), 0.0) or 0.0),
            float(pick_first(to_float(recommended_position_tons), 0.0) or 0.0),
            float(pick_first(to_float(suggested_adjust_tons), 0.0) or 0.0),
            float(pick_first(to_float(current_hit_rate), 0.0) or 0.0),
            float(pick_first(to_float(under_prob), 0.0) or 0.0),
            float(pick_first(to_float(over_prob), 0.0) or 0.0),
            int(pick_first(_int_from_any(history_samples, 0), 0) or 0),
            int(pick_first(_int_from_any(mc_paths, 0), 0) or 0),
            float(pick_first(to_float(atm_iv), 0.0) or 0.0),
            float(pick_first(to_float(skew), 0.0) or 0.0),
            str(current_zone or "").strip(),
            str(action_type or "").strip(),
            str(confidence_level or "").strip(),
            str(risk_focus or "").strip(),
            str(fusion_mode or "").strip(),
            str(frozen_reason or "").strip(),
            float(pick_first(to_float(state_weighted_optimal), 0.0) or 0.0),
            float(pick_first(to_float(history_suggestion), 0.0) or 0.0),
            float(pick_first(to_float(mc_suggestion), 0.0) or 0.0),
            float(pick_first(to_float(fused_position), 0.0) or 0.0),
            str(model_version or "").strip(),
            payload_text,
            now_s,
            now_s,
        ),
    )
    return int(version_no)


def compute_spot_inventory_summary(
    spot_lots_df: pd.DataFrame,
    spot_match_df: pd.DataFrame,
    *,
    group_id: Optional[str] = None,
) -> pd.DataFrame:
    lots = spot_lots_df.copy() if spot_lots_df is not None else pd.DataFrame()
    logs = spot_match_df.copy() if spot_match_df is not None else pd.DataFrame()
    if group_id is not None:
        gid_s = str(group_id)
        if not lots.empty and "group_id" in lots.columns:
            lots = lots[lots["group_id"].astype(str) == gid_s].copy()
        if not logs.empty and "group_id" in logs.columns:
            logs = logs[logs["group_id"].astype(str) == gid_s].copy()
    if lots.empty and logs.empty:
        return pd.DataFrame(
            columns=[
                "group_id",
                "spot_name",
                "买入总量",
                "买入总成本",
                "已对冲数量",
                "已结转成本",
                "可用数量",
                "可用成本",
                "可用均价",
                "现货已实现盈亏",
                "对冲总盈亏",
                "最近买入日",
                "最近对冲日",
            ]
        )

    if not lots.empty:
        lots["qty"] = pd.to_numeric(lots.get("qty"), errors="coerce").fillna(0.0)
        lots["buy_price"] = pd.to_numeric(lots.get("buy_price"), errors="coerce").fillna(0.0)
        lots["buy_value"] = lots["qty"] * lots["buy_price"]
        buy_agg = (
            lots.groupby(["group_id", "spot_name"], as_index=False)
            .agg(
                买入总量=("qty", "sum"),
                买入总成本=("buy_value", "sum"),
                最近买入日=("buy_dt", "max"),
            )
        )
    else:
        buy_agg = pd.DataFrame(columns=["group_id", "spot_name", "买入总量", "买入总成本", "最近买入日"])

    if not logs.empty:
        logs["matched_qty"] = pd.to_numeric(logs.get("matched_qty"), errors="coerce").fillna(0.0)
        logs["spot_cost_amount"] = pd.to_numeric(logs.get("spot_cost_amount"), errors="coerce").fillna(0.0)
        logs["spot_pnl"] = pd.to_numeric(logs.get("spot_pnl"), errors="coerce").fillna(0.0)
        logs["total_pnl"] = pd.to_numeric(logs.get("total_pnl"), errors="coerce").fillna(0.0)
        hedge_agg = (
            logs.groupby(["group_id", "spot_name"], as_index=False)
            .agg(
                已对冲数量=("matched_qty", "sum"),
                已结转成本=("spot_cost_amount", "sum"),
                现货已实现盈亏=("spot_pnl", "sum"),
                对冲总盈亏=("total_pnl", "sum"),
                最近对冲日=("match_dt", "max"),
            )
        )
    else:
        hedge_agg = pd.DataFrame(
            columns=[
                "group_id",
                "spot_name",
                "已对冲数量",
                "已结转成本",
                "现货已实现盈亏",
                "对冲总盈亏",
                "最近对冲日",
            ]
        )

    out = buy_agg.merge(hedge_agg, on=["group_id", "spot_name"], how="outer")
    for c in ["买入总量", "买入总成本", "已对冲数量", "已结转成本", "现货已实现盈亏", "对冲总盈亏"]:
        out[c] = pd.to_numeric(out.get(c), errors="coerce").fillna(0.0)
    out["可用数量"] = out["买入总量"] - out["已对冲数量"]
    out["可用成本"] = out["买入总成本"] - out["已结转成本"]
    out["可用数量"] = out["可用数量"].apply(lambda x: 0.0 if abs(float(x)) < 1e-9 else float(x))
    out["可用均价"] = out.apply(
        lambda r: (float(r["可用成本"]) / float(r["可用数量"])) if float(r["可用数量"]) > 1e-12 else 0.0,
        axis=1,
    )
    return out.sort_values(["group_id", "spot_name"]).reset_index(drop=True)


def get_spot_available_snapshot(
    conn: sqlite3.Connection,
    group_id: str,
    spot_name: str,
) -> Tuple[float, float]:
    summ = compute_spot_inventory_summary(fetch_spot_lots(conn), fetch_spot_hedge_logs(conn), group_id=str(group_id))
    if summ.empty:
        return 0.0, 0.0
    sub = summ[summ["spot_name"].astype(str) == str(spot_name)].copy()
    if sub.empty:
        return 0.0, 0.0
    row = sub.iloc[0]
    return float(pick_first(to_float(row.get("可用数量")), 0.0)), float(pick_first(to_float(row.get("可用均价")), 0.0))


def validate_spot_lot_snapshot_consistency(
    spot_lots_df: pd.DataFrame,
    spot_match_df: pd.DataFrame,
    *,
    group_id: str,
) -> Tuple[bool, str]:
    """
    校验现货买入头寸快照是否与已落库的现货对冲流水冲突。
    规则：
    1) 每个现货名称的买入总量 >= 已对冲数量
    2) 每个现货名称的买入总成本 >= 已结转成本
    """
    gid_s = str(group_id).strip()
    if not gid_s:
        return False, "策略组不能为空"

    lots = spot_lots_df.copy() if spot_lots_df is not None else pd.DataFrame()
    logs = spot_match_df.copy() if spot_match_df is not None else pd.DataFrame()
    if not lots.empty and "group_id" in lots.columns:
        lots = lots[lots["group_id"].astype(str) == gid_s].copy()
    if not logs.empty and "group_id" in logs.columns:
        logs = logs[logs["group_id"].astype(str) == gid_s].copy()

    if lots.empty:
        buy_agg = pd.DataFrame(columns=["spot_name", "buy_qty", "buy_cost"])
    else:
        lots["spot_name"] = lots.get("spot_name", "").fillna("").astype(str).str.strip()
        lots["qty"] = pd.to_numeric(lots.get("qty"), errors="coerce").fillna(0.0)
        lots["buy_price"] = pd.to_numeric(lots.get("buy_price"), errors="coerce").fillna(0.0)
        buy_agg = (
            lots.assign(_buy_cost=lots["qty"] * lots["buy_price"])
            .groupby("spot_name", as_index=False)
            .agg(
                buy_qty=("qty", "sum"),
                buy_cost=("_buy_cost", "sum"),
            )
        )

    if logs.empty:
        return True, ""
    logs["spot_name"] = logs.get("spot_name", "").fillna("").astype(str).str.strip()
    logs["matched_qty"] = pd.to_numeric(logs.get("matched_qty"), errors="coerce").fillna(0.0)
    logs["spot_cost_amount"] = pd.to_numeric(logs.get("spot_cost_amount"), errors="coerce").fillna(0.0)
    hedge_agg = (
        logs.groupby("spot_name", as_index=False)
        .agg(
            hedged_qty=("matched_qty", "sum"),
            hedged_cost=("spot_cost_amount", "sum"),
        )
    )

    merged = hedge_agg.merge(buy_agg, on="spot_name", how="left")
    merged["buy_qty"] = pd.to_numeric(merged.get("buy_qty"), errors="coerce").fillna(0.0)
    merged["buy_cost"] = pd.to_numeric(merged.get("buy_cost"), errors="coerce").fillna(0.0)
    merged["qty_gap"] = merged["hedged_qty"] - merged["buy_qty"]
    merged["cost_gap"] = merged["hedged_cost"] - merged["buy_cost"]

    bad_qty = merged[merged["qty_gap"] > 1e-8].copy()
    if not bad_qty.empty:
        r = bad_qty.sort_values("qty_gap", ascending=False).iloc[0]
        return (
            False,
            f"现货【{str(r.get('spot_name', ''))}】买入总量不足：买入 {float(r.get('buy_qty', 0.0)):,.2f}，"
            f"已对冲 {float(r.get('hedged_qty', 0.0)):,.2f}",
        )

    bad_cost = merged[merged["cost_gap"] > 1e-6].copy()
    if not bad_cost.empty:
        r = bad_cost.sort_values("cost_gap", ascending=False).iloc[0]
        return (
            False,
            f"现货【{str(r.get('spot_name', ''))}】买入成本不足：买入成本 {float(r.get('buy_cost', 0.0)):,.2f}，"
            f"已结转成本 {float(r.get('hedged_cost', 0.0)):,.2f}",
        )

    return True, ""


def _json_safe_scalar(v: Any) -> Any:
    try:
        if pd.isna(v):
            return None
    except Exception:
        pass
    if isinstance(v, (date, datetime)):
        return v.strftime(DATE_FMT) if isinstance(v, date) and not isinstance(v, datetime) else v.isoformat(sep=" ")
    if hasattr(v, "item"):
        try:
            v = v.item()
        except Exception:
            pass
    if isinstance(v, (str, int, float, bool)) or v is None:
        return v
    return str(v)


def _normalize_group_ids(group_ids: List[str]) -> List[str]:
    out: List[str] = []
    seen = set()
    for gid in group_ids:
        g = str(gid).strip()
        if not g or g in seen:
            continue
        seen.add(g)
        out.append(g)
    return out


def _chunk_values(vals: List[str], size: int = 500) -> List[List[str]]:
    if size <= 0:
        size = 500
    return [vals[i : i + size] for i in range(0, len(vals), size)]


def _table_columns(conn: sqlite3.Connection, table: str) -> List[str]:
    return [str(r[1]) for r in conn.execute(f"PRAGMA table_info({table})").fetchall()]


def _fetch_rows_by_group_ids(conn: sqlite3.Connection, table: str, group_ids: List[str]) -> List[Dict[str, Any]]:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return []
    cols = _table_columns(conn, table)
    if not cols:
        return []
    ph = ",".join(["?"] * len(gids))
    sql = f"SELECT {','.join(cols)} FROM {table} WHERE group_id IN ({ph})"
    if table == "strategy_group":
        sql += " ORDER BY group_id"
    elif table == "structure":
        sql += " ORDER BY group_id, structure_id"
    elif table == "close_trade":
        sql += " ORDER BY dt, group_id, underlying"
    elif table == "close_trade2":
        sql += " ORDER BY dt, group_id, structure_id, close_id"
    elif table == "spot_position_lot":
        sql += " ORDER BY group_id, spot_name, buy_dt, lot_id"
    elif table == "spot_hedge_match_log":
        sql += " ORDER BY group_id, match_dt, matched_at, match_id"
    rows = conn.execute(sql, tuple(gids)).fetchall()
    out: List[Dict[str, Any]] = []
    for row in rows:
        out.append({c: _json_safe_scalar(v) for c, v in zip(cols, row)})
    return out


def _fetch_price_rows_by_underlying(conn: sqlite3.Connection, underlyings: List[str]) -> List[Dict[str, Any]]:
    unds = [str(x).strip() for x in underlyings if str(x).strip()]
    if not unds:
        return []
    dedup = []
    seen = set()
    for und in unds:
        if und in seen:
            continue
        seen.add(und)
        dedup.append(und)
    cols = _table_columns(conn, "price")
    if not cols:
        return []
    ph = ",".join(["?"] * len(dedup))
    sql = f"SELECT {','.join(cols)} FROM price WHERE underlying IN ({ph}) ORDER BY dt, underlying"
    rows = conn.execute(sql, tuple(dedup)).fetchall()
    out: List[Dict[str, Any]] = []
    for row in rows:
        out.append({c: _json_safe_scalar(v) for c, v in zip(cols, row)})
    return out


def _fetch_close_revert_rows_by_close_ids(conn: sqlite3.Connection, close_ids: List[str]) -> List[Dict[str, Any]]:
    cids = [str(x).strip() for x in close_ids if str(x).strip()]
    if not cids:
        return []
    dedup: List[str] = []
    seen = set()
    for cid in cids:
        if cid in seen:
            continue
        seen.add(cid)
        dedup.append(cid)
    cols = _table_columns(conn, "close_revert_log")
    if not cols:
        return []
    out: List[Dict[str, Any]] = []
    for chunk in _chunk_values(dedup, size=400):
        ph = ",".join(["?"] * len(chunk))
        sql = f"SELECT {','.join(cols)} FROM close_revert_log WHERE close_id IN ({ph}) ORDER BY reverted_at, log_id"
        rows = conn.execute(sql, tuple(chunk)).fetchall()
        for row in rows:
            out.append({c: _json_safe_scalar(v) for c, v in zip(cols, row)})
    return out


def _find_duplicate_keys(
    rows: List[Dict[str, Any]],
    key_cols: List[str],
) -> Tuple[List[str], bool]:
    dup_keys: List[str] = []
    seen = set()
    has_missing_key = False
    for row in rows:
        if not isinstance(row, dict):
            continue
        parts = [str(pick_first(row.get(c), "")).strip() for c in key_cols]
        if any((not x) for x in parts):
            has_missing_key = True
            continue
        key_t = tuple(parts)
        if key_t in seen:
            dup_keys.append(" | ".join(parts))
        else:
            seen.add(key_t)
    # 去重并保序
    uniq = list(dict.fromkeys([x for x in dup_keys if x]))
    return uniq, has_missing_key


def detect_bundle_internal_key_issues(payload: Dict[str, Any]) -> Dict[str, Any]:
    tables = payload.get("tables", {})
    if not isinstance(tables, dict):
        return {"missing_key_tables": [], "duplicate_keys": {}}
    key_map: Dict[str, List[str]] = {
        "strategy_group": ["group_id"],
        "structure": ["structure_id"],
        "close_trade": ["dt", "group_id", "underlying", "side", "qty"],
        "close_trade2": ["close_id"],
        "price": ["dt", "underlying"],
        "close_revert_log": ["log_id"],
        "spot_position_lot": ["lot_id"],
        "spot_hedge_match_log": ["match_id"],
    }
    missing_key_tables: List[str] = []
    duplicate_keys: Dict[str, List[str]] = {}
    for table, key_cols in key_map.items():
        rows = tables.get(table, [])
        if not isinstance(rows, list):
            continue
        dups, has_missing_key = _find_duplicate_keys(rows, key_cols)
        if has_missing_key:
            missing_key_tables.append(table)
        if dups:
            duplicate_keys[table] = dups
    return {
        "missing_key_tables": list(dict.fromkeys(missing_key_tables)),
        "duplicate_keys": duplicate_keys,
    }


def _clone_json_obj(obj: Any) -> Any:
    return json.loads(json.dumps(obj, ensure_ascii=False))


def apply_group_id_rename_to_bundle(payload: Dict[str, Any], rename_map: Dict[str, str]) -> Dict[str, Any]:
    safe_map: Dict[str, str] = {}
    for k, v in (rename_map or {}).items():
        old_gid = str(k).strip()
        new_gid = str(v).strip()
        if not old_gid or not new_gid or old_gid == new_gid:
            continue
        safe_map[old_gid] = new_gid
    if not safe_map:
        return payload

    def _resolve_gid(gid: str) -> str:
        cur = str(gid).strip()
        seen = set()
        while cur in safe_map and cur not in seen:
            seen.add(cur)
            cur = safe_map[cur]
        return cur

    out = _clone_json_obj(payload)
    tables = out.get("tables", {})
    if not isinstance(tables, dict):
        return out

    for table in ["strategy_group", "structure", "close_trade", "close_trade2", "spot_position_lot", "spot_hedge_match_log"]:
        rows = tables.get(table, [])
        if not isinstance(rows, list):
            continue
        for row in rows:
            if not isinstance(row, dict):
                continue
            gid = str(row.get("group_id", "")).strip()
            if gid:
                row["group_id"] = _resolve_gid(gid)

    gids = out.get("group_ids", [])
    if isinstance(gids, list):
        out["group_ids"] = [_resolve_gid(str(x).strip()) for x in gids]
    return out


def is_internal_structure_id(value: Any) -> bool:
    sid = str(pick_first(value, "")).strip().upper()
    return bool(sid) and sid.startswith(STRUCTURE_INTERNAL_ID_PREFIX)


def _next_import_bundle_id(used_ids: set[str], prefix: str = "") -> str:
    while True:
        cand = f"{prefix}{uuid4().hex}" if prefix else uuid4().hex
        if cand not in used_ids:
            used_ids.add(cand)
            return cand


def prepare_strategy_group_bundle_for_import(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    overwrite_group_ids: Optional[List[str]] = None,
) -> Dict[str, Any]:
    out = _clone_json_obj(payload)
    tables = out.get("tables", {})
    if not isinstance(tables, dict):
        return out

    struct_rows = tables.get("structure", [])
    close2_rows = tables.get("close_trade2", [])
    revert_rows = tables.get("close_revert_log", [])
    spot_lot_rows = tables.get("spot_position_lot", [])
    spot_match_rows = tables.get("spot_hedge_match_log", [])
    if not isinstance(struct_rows, list):
        return out

    scope = _fetch_existing_bundle_key_scope(conn, overwrite_group_ids=overwrite_group_ids)

    for row in struct_rows:
        if not isinstance(row, dict):
            continue
        row["structure_code"] = resolve_structure_display_code(
            row.get("structure_id", ""),
            row.get("structure_code", ""),
        )

    structure_id_map: Dict[str, str] = {}
    used_structure_ids = set(scope.get("structure_ids", set()))
    seen_structure_ids: set[str] = set()
    for row in struct_rows:
        if not isinstance(row, dict):
            continue
        old_sid = str(row.get("structure_id", "")).strip()
        if not old_sid:
            continue
        if old_sid in structure_id_map:
            row["structure_id"] = structure_id_map[old_sid]
            continue
        needs_remap = (not is_internal_structure_id(old_sid)) or (old_sid in used_structure_ids) or (old_sid in seen_structure_ids)
        if needs_remap:
            new_sid = _next_import_bundle_id(used_structure_ids, prefix=STRUCTURE_INTERNAL_ID_PREFIX)
            structure_id_map[old_sid] = new_sid
            row["structure_id"] = new_sid
            seen_structure_ids.add(new_sid)
        else:
            used_structure_ids.add(old_sid)
            seen_structure_ids.add(old_sid)

    if structure_id_map:
        for rows in [close2_rows, spot_match_rows]:
            if not isinstance(rows, list):
                continue
            for row in rows:
                if not isinstance(row, dict):
                    continue
                sid = str(row.get("structure_id", "")).strip()
                if sid in structure_id_map:
                    row["structure_id"] = structure_id_map[sid]

    close_id_map: Dict[str, str] = {}
    used_close_ids = set(scope.get("close_ids", set()))
    seen_close_ids: set[str] = set()
    if isinstance(close2_rows, list):
        for row in close2_rows:
            if not isinstance(row, dict):
                continue
            old_close_id = str(row.get("close_id", "")).strip()
            if not old_close_id:
                continue
            if old_close_id in close_id_map:
                row["close_id"] = close_id_map[old_close_id]
                continue
            if old_close_id in used_close_ids or old_close_id in seen_close_ids:
                new_close_id = _next_import_bundle_id(used_close_ids)
                close_id_map[old_close_id] = new_close_id
                row["close_id"] = new_close_id
                seen_close_ids.add(new_close_id)
            else:
                used_close_ids.add(old_close_id)
                seen_close_ids.add(old_close_id)
    if close_id_map and isinstance(revert_rows, list):
        for row in revert_rows:
            if not isinstance(row, dict):
                continue
            close_id = str(row.get("close_id", "")).strip()
            if close_id in close_id_map:
                row["close_id"] = close_id_map[close_id]

    used_log_ids = set(scope.get("revert_log_ids", set()))
    seen_log_ids: set[str] = set()
    if isinstance(revert_rows, list):
        for row in revert_rows:
            if not isinstance(row, dict):
                continue
            old_log_id = str(row.get("log_id", "")).strip()
            if not old_log_id:
                continue
            if old_log_id in used_log_ids or old_log_id in seen_log_ids:
                row["log_id"] = _next_import_bundle_id(used_log_ids)
                seen_log_ids.add(str(row["log_id"]))
            else:
                used_log_ids.add(old_log_id)
                seen_log_ids.add(old_log_id)

    lot_id_map: Dict[str, str] = {}
    used_lot_ids = set(scope.get("spot_lot_ids", set()))
    seen_lot_ids: set[str] = set()
    if isinstance(spot_lot_rows, list):
        for row in spot_lot_rows:
            if not isinstance(row, dict):
                continue
            old_lot_id = str(row.get("lot_id", "")).strip()
            if not old_lot_id:
                continue
            if old_lot_id in lot_id_map:
                row["lot_id"] = lot_id_map[old_lot_id]
                continue
            if old_lot_id in used_lot_ids or old_lot_id in seen_lot_ids:
                new_lot_id = _next_import_bundle_id(used_lot_ids)
                lot_id_map[old_lot_id] = new_lot_id
                row["lot_id"] = new_lot_id
                seen_lot_ids.add(new_lot_id)
            else:
                used_lot_ids.add(old_lot_id)
                seen_lot_ids.add(old_lot_id)
    if lot_id_map and isinstance(spot_match_rows, list):
        for row in spot_match_rows:
            if not isinstance(row, dict):
                continue
            lot_id = str(row.get("spot_lot_id", "")).strip()
            if lot_id in lot_id_map:
                row["spot_lot_id"] = lot_id_map[lot_id]

    used_match_ids = set(scope.get("spot_match_ids", set()))
    seen_match_ids: set[str] = set()
    if isinstance(spot_match_rows, list):
        for row in spot_match_rows:
            if not isinstance(row, dict):
                continue
            old_match_id = str(row.get("match_id", "")).strip()
            if not old_match_id:
                continue
            if old_match_id in used_match_ids or old_match_id in seen_match_ids:
                row["match_id"] = _next_import_bundle_id(used_match_ids)
                seen_match_ids.add(str(row["match_id"]))
            else:
                used_match_ids.add(old_match_id)
                seen_match_ids.add(old_match_id)

    return out


def _safe_filename_stem(stem: str, default_stem: str = "策略组导出") -> str:
    s = str(stem or "").strip()
    for ch in ['\\', '/', ':', '*', '?', '"', '<', '>', '|', '\r', '\n', '\t']:
        s = s.replace(ch, "_")
    s = " ".join(s.split())
    s = s.strip(" .")
    if not s:
        s = default_stem
    if len(s) > 80:
        s = s[:80].rstrip(" .")
    return s or default_stem


def build_group_bundle_filename(group_ids: List[str], group_name_map: Dict[str, str]) -> str:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return "策略组导出.json"
    if len(gids) == 1:
        gid = gids[0]
        gname = str(group_name_map.get(gid, "")).strip()
        base = _safe_filename_stem(gname or gid)
        return f"{base}.json"

    names: List[str] = []
    for gid in gids:
        gname = str(group_name_map.get(gid, "")).strip()
        names.append(_safe_filename_stem(gname or gid, default_stem=gid))
    if len(names) <= 3:
        base = "_".join(names)
    else:
        base = f"{'_'.join(names[:2])}_等{len(names)}组"
    return f"{_safe_filename_stem(base, default_stem='策略组导出')}.json"


def _bundle_tables_sha256(tables: Dict[str, Any]) -> str:
    if not isinstance(tables, dict):
        return ""
    try:
        txt = json.dumps(tables, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except Exception:
        return ""
    return hashlib.sha256(txt.encode("utf-8")).hexdigest()


def build_strategy_group_bundle(conn: sqlite3.Connection, group_ids: List[str]) -> Dict[str, Any]:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        raise ValueError("至少选择一个策略组后再导出")

    groups = _fetch_rows_by_group_ids(conn, "strategy_group", gids)
    found_gids = _normalize_group_ids([str(r.get("group_id", "")).strip() for r in groups])
    missing_gids = [x for x in gids if x not in set(found_gids)]
    if missing_gids:
        raise ValueError(f"以下策略组不存在，无法导出：{', '.join(missing_gids)}")

    structures = _fetch_rows_by_group_ids(conn, "structure", gids)
    closes = _fetch_rows_by_group_ids(conn, "close_trade", gids)
    closes2 = _fetch_rows_by_group_ids(conn, "close_trade2", gids)
    spot_lots = _fetch_rows_by_group_ids(conn, "spot_position_lot", gids)
    spot_matches = _fetch_rows_by_group_ids(conn, "spot_hedge_match_log", gids)
    close_ids = [str(pick_first(r.get("close_id"), "")).strip() for r in closes2 if isinstance(r, dict)]
    revert_logs = _fetch_close_revert_rows_by_close_ids(conn, close_ids)

    und_set = set()
    for row in groups:
        und = str(pick_first(row.get("underlying"), "")).strip()
        if und:
            und_set.add(und)
    for row in structures:
        und = str(pick_first(row.get("underlying"), "")).strip()
        if und:
            und_set.add(und)
    for row in closes:
        und = str(pick_first(row.get("underlying"), "")).strip()
        if und:
            und_set.add(und)
    for row in closes2:
        und = str(pick_first(row.get("underlying"), "")).strip()
        if und:
            und_set.add(und)
    prices = _fetch_price_rows_by_underlying(conn, sorted(list(und_set)))

    tables = {
        "strategy_group": groups,
        "structure": structures,
        "close_trade": closes,
        "close_trade2": closes2,
        "spot_position_lot": spot_lots,
        "spot_hedge_match_log": spot_matches,
        "price": prices,
        "close_revert_log": revert_logs,
    }
    counts = {k: len(v) for k, v in tables.items()}
    schema = {
        "strategy_group": _table_columns(conn, "strategy_group"),
        "structure": _table_columns(conn, "structure"),
        "close_trade": _table_columns(conn, "close_trade"),
        "close_trade2": _table_columns(conn, "close_trade2"),
        "spot_position_lot": _table_columns(conn, "spot_position_lot"),
        "spot_hedge_match_log": _table_columns(conn, "spot_hedge_match_log"),
        "price": _table_columns(conn, "price"),
        "close_revert_log": _table_columns(conn, "close_revert_log"),
    }
    exported_by = str(getpass.getuser() or "unknown").strip() or "unknown"
    tables_sha256 = _bundle_tables_sha256(tables)
    return {
        "format": STRATEGY_GROUP_BUNDLE_FORMAT,
        "version": STRATEGY_GROUP_BUNDLE_VERSION,
        "exported_at": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "exported_by": exported_by,
        "group_ids": found_gids,
        "counts": counts,
        "schema": schema,
        "integrity": {
            "algo": "sha256",
            "tables_sha256": tables_sha256,
        },
        "tables": tables,
    }


def parse_strategy_group_bundle(raw_bytes: bytes) -> Dict[str, Any]:
    if not raw_bytes:
        raise ValueError("导入文件为空")
    try:
        payload = json.loads(raw_bytes.decode("utf-8"))
    except Exception as exc:
        raise ValueError(f"文件不是有效的 UTF-8 JSON：{exc}") from exc
    if not isinstance(payload, dict):
        raise ValueError("导入文件结构错误：顶层必须是对象")

    fmt = str(payload.get("format", "")).strip()
    if fmt != STRATEGY_GROUP_BUNDLE_FORMAT:
        raise ValueError("导入文件格式不匹配，无法识别为策略组导入包")
    raw_version = payload.get("version", 1)
    try:
        version_i = int(raw_version)
    except Exception as exc:
        raise ValueError(f"导入文件 version 字段格式错误：{exc}") from exc
    if version_i <= 0:
        raise ValueError("导入文件 version 字段必须为正整数")
    payload["version"] = version_i
    tables = payload.get("tables")
    if not isinstance(tables, dict):
        raise ValueError("导入文件缺少 tables 节点")

    required_tables = ["strategy_group", "structure", "close_trade", "close_trade2", "price"]
    for table in required_tables:
        if table not in tables:
            raise ValueError(f"导入文件缺少表：{table}")
        if not isinstance(tables.get(table), list):
            raise ValueError(f"导入文件表 {table} 格式错误，必须为数组")
        for i, row in enumerate(tables.get(table, [])):
            if not isinstance(row, dict):
                raise ValueError(f"导入文件表 {table} 第 {i + 1} 行格式错误，必须为对象")
    # 兼容旧导出包：以下可缺省表按空列表处理。
    if "close_revert_log" not in tables:
        tables["close_revert_log"] = []
    elif not isinstance(tables.get("close_revert_log"), list):
        raise ValueError("导入文件表 close_revert_log 格式错误，必须为数组")
    else:
        for i, row in enumerate(tables.get("close_revert_log", [])):
            if not isinstance(row, dict):
                raise ValueError(f"导入文件表 close_revert_log 第 {i + 1} 行格式错误，必须为对象")
    if "spot_position_lot" not in tables:
        tables["spot_position_lot"] = []
    elif not isinstance(tables.get("spot_position_lot"), list):
        raise ValueError("导入文件表 spot_position_lot 格式错误，必须为数组")
    else:
        for i, row in enumerate(tables.get("spot_position_lot", [])):
            if not isinstance(row, dict):
                raise ValueError(f"导入文件表 spot_position_lot 第 {i + 1} 行格式错误，必须为对象")
    if "spot_hedge_match_log" not in tables:
        tables["spot_hedge_match_log"] = []
    elif not isinstance(tables.get("spot_hedge_match_log"), list):
        raise ValueError("导入文件表 spot_hedge_match_log 格式错误，必须为数组")
    else:
        for i, row in enumerate(tables.get("spot_hedge_match_log", [])):
            if not isinstance(row, dict):
                raise ValueError(f"导入文件表 spot_hedge_match_log 第 {i + 1} 行格式错误，必须为对象")

    all_tables = [
        "strategy_group",
        "structure",
        "close_trade",
        "close_trade2",
        "spot_position_lot",
        "spot_hedge_match_log",
        "price",
        "close_revert_log",
    ]
    counts_raw = payload.get("counts", {})
    counts = counts_raw if isinstance(counts_raw, dict) else {}
    for table in all_tables:
        rows = tables.get(table, [])
        if not isinstance(rows, list):
            raise ValueError(f"导入文件表 {table} 格式错误，必须为数组")
        try:
            counts[table] = int(counts.get(table))
        except Exception:
            counts[table] = len(rows)
    payload["counts"] = counts

    gids = payload.get("group_ids")
    if not isinstance(gids, list):
        payload["group_ids"] = _normalize_group_ids(
            [str(r.get("group_id", "")).strip() for r in tables.get("strategy_group", []) if isinstance(r, dict)]
        )
    for row in tables.get("structure", []):
        if not isinstance(row, dict):
            continue
        row["structure_code"] = resolve_structure_display_code(
            row.get("structure_id", ""),
            row.get("structure_code", ""),
        )
    return payload


def inspect_strategy_group_bundle(payload: Dict[str, Any]) -> Dict[str, Any]:
    report: Dict[str, Any] = {
        "version": 0,
        "notes": [],
        "warnings": [],
        "table_stats": [],
        "reference_issues": [],
        "integrity_status": "missing",
    }
    if not isinstance(payload, dict):
        report["warnings"] = ["导入包不是有效对象，无法体检。"]
        return report

    notes: List[str] = []
    warnings: List[str] = []
    raw_version = payload.get("version", 0)
    try:
        version_i = int(raw_version)
    except Exception:
        version_i = 0
        warnings.append("导入包版本号无法识别。")
    report["version"] = version_i
    if version_i > STRATEGY_GROUP_BUNDLE_VERSION:
        warnings.append(
            f"导入包版本 v{version_i} 高于当前程序支持版本 v{STRATEGY_GROUP_BUNDLE_VERSION}，建议先升级程序后再导入。"
        )
    elif version_i < STRATEGY_GROUP_BUNDLE_VERSION and version_i > 0:
        notes.append(
            f"导入包为旧版本 v{version_i}，当前程序会按兼容模式导入（当前版本 v{STRATEGY_GROUP_BUNDLE_VERSION}）。"
        )

    tables = payload.get("tables", {})
    if not isinstance(tables, dict):
        report["warnings"] = warnings + ["导入包缺少 tables 节点。"]
        report["notes"] = notes
        return report
    counts = payload.get("counts", {})
    counts = counts if isinstance(counts, dict) else {}
    table_names = [
        "strategy_group",
        "structure",
        "close_trade",
        "close_trade2",
        "spot_position_lot",
        "spot_hedge_match_log",
        "price",
        "close_revert_log",
    ]

    mismatch_cnt = 0
    table_stats: List[Dict[str, Any]] = []
    for table in table_names:
        rows = tables.get(table, [])
        actual_cnt = len(rows) if isinstance(rows, list) else 0
        declared_cnt_txt = ""
        diff_txt = ""
        try:
            declared_cnt = int(counts.get(table))
            declared_cnt_txt = declared_cnt
            if declared_cnt != actual_cnt:
                mismatch_cnt += 1
                diff_txt = int(actual_cnt - declared_cnt)
        except Exception:
            declared_cnt_txt = ""
        table_stats.append(
            {
                "表": table,
                "声明条数": declared_cnt_txt,
                "实际条数": int(actual_cnt),
                "差异": diff_txt,
            }
        )
    if mismatch_cnt > 0:
        warnings.append(f"导入包 counts 与实际表数据存在 {mismatch_cnt} 个不一致项。")

    group_ids = set(
        _normalize_group_ids(
            [str(r.get("group_id", "")).strip() for r in tables.get("strategy_group", []) if isinstance(r, dict)]
        )
    )
    structure_ids = set(
        _normalize_group_ids(
            [str(r.get("structure_id", "")).strip() for r in tables.get("structure", []) if isinstance(r, dict)]
        )
    )
    structure_gid_map: Dict[str, str] = {
        str(r.get("structure_id", "")).strip(): str(r.get("group_id", "")).strip()
        for r in tables.get("structure", [])
        if isinstance(r, dict) and str(r.get("structure_id", "")).strip()
    }
    close_ids = set(
        _normalize_group_ids(
            [str(r.get("close_id", "")).strip() for r in tables.get("close_trade2", []) if isinstance(r, dict)]
        )
    )
    lot_ids = set(
        _normalize_group_ids(
            [str(r.get("lot_id", "")).strip() for r in tables.get("spot_position_lot", []) if isinstance(r, dict)]
        )
    )

    ref_issues: List[Dict[str, Any]] = []

    for table in ["structure", "close_trade", "close_trade2", "spot_position_lot", "spot_hedge_match_log"]:
        rows = tables.get(table, [])
        if not isinstance(rows, list):
            continue
        bad_gid = sorted(
            list(
                {
                    str(r.get("group_id", "")).strip()
                    for r in rows
                    if isinstance(r, dict)
                    and str(r.get("group_id", "")).strip()
                    and str(r.get("group_id", "")).strip() not in group_ids
                }
            )
        )
        if bad_gid:
            ref_issues.append(
                {
                    "检查项": f"{table}.group_id -> strategy_group",
                    "问题数量": len(bad_gid),
                    "示例": "，".join(bad_gid[:5]),
                }
            )

    close2_rows = tables.get("close_trade2", [])
    if isinstance(close2_rows, list):
        bad_sid = sorted(
            list(
                {
                    str(r.get("structure_id", "")).strip()
                    for r in close2_rows
                    if isinstance(r, dict)
                    and str(r.get("structure_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() != "外部"
                    and str(r.get("structure_id", "")).strip() not in structure_ids
                }
            )
        )
        if bad_sid:
            ref_issues.append(
                {
                    "检查项": "close_trade2.structure_id -> structure",
                    "问题数量": len(bad_sid),
                    "示例": "，".join(bad_sid[:5]),
                }
            )
        bad_sid_gid_mismatch = sorted(
            list(
                {
                    str(r.get("structure_id", "")).strip()
                    for r in close2_rows
                    if isinstance(r, dict)
                    and str(r.get("structure_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() != "外部"
                    and str(r.get("group_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() in structure_gid_map
                    and str(r.get("group_id", "")).strip() != str(structure_gid_map.get(str(r.get("structure_id", "")).strip(), ""))
                }
            )
        )
        if bad_sid_gid_mismatch:
            ref_issues.append(
                {
                    "检查项": "close_trade2.group_id == structure.group_id",
                    "问题数量": len(bad_sid_gid_mismatch),
                    "示例": "，".join(bad_sid_gid_mismatch[:5]),
                }
            )

    revert_rows = tables.get("close_revert_log", [])
    if isinstance(revert_rows, list):
        bad_close = sorted(
            list(
                {
                    str(r.get("close_id", "")).strip()
                    for r in revert_rows
                    if isinstance(r, dict)
                    and str(r.get("close_id", "")).strip()
                    and str(r.get("close_id", "")).strip() not in close_ids
                }
            )
        )
        if bad_close:
            ref_issues.append(
                {
                    "检查项": "close_revert_log.close_id -> close_trade2",
                    "问题数量": len(bad_close),
                    "示例": "，".join(bad_close[:5]),
                }
            )

    spot_match_rows = tables.get("spot_hedge_match_log", [])
    if isinstance(spot_match_rows, list):
        bad_lot = sorted(
            list(
                {
                    str(r.get("spot_lot_id", "")).strip()
                    for r in spot_match_rows
                    if isinstance(r, dict)
                    and str(r.get("spot_lot_id", "")).strip()
                    and str(r.get("spot_lot_id", "")).strip() not in lot_ids
                }
            )
        )
        if bad_lot:
            ref_issues.append(
                {
                    "检查项": "spot_hedge_match_log.spot_lot_id -> spot_position_lot",
                    "问题数量": len(bad_lot),
                    "示例": "，".join(bad_lot[:5]),
                }
            )
        bad_match_sid = sorted(
            list(
                {
                    str(r.get("structure_id", "")).strip()
                    for r in spot_match_rows
                    if isinstance(r, dict)
                    and str(r.get("structure_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() != "外部"
                    and str(r.get("structure_id", "")).strip() not in structure_ids
                }
            )
        )
        if bad_match_sid:
            ref_issues.append(
                {
                    "检查项": "spot_hedge_match_log.structure_id -> structure",
                    "问题数量": len(bad_match_sid),
                    "示例": "，".join(bad_match_sid[:5]),
                }
            )
        bad_match_sid_gid_mismatch = sorted(
            list(
                {
                    str(r.get("structure_id", "")).strip()
                    for r in spot_match_rows
                    if isinstance(r, dict)
                    and str(r.get("structure_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() != "外部"
                    and str(r.get("group_id", "")).strip()
                    and str(r.get("structure_id", "")).strip() in structure_gid_map
                    and str(r.get("group_id", "")).strip() != str(structure_gid_map.get(str(r.get("structure_id", "")).strip(), ""))
                }
            )
        )
        if bad_match_sid_gid_mismatch:
            ref_issues.append(
                {
                    "检查项": "spot_hedge_match_log.group_id == structure.group_id",
                    "问题数量": len(bad_match_sid_gid_mismatch),
                    "示例": "，".join(bad_match_sid_gid_mismatch[:5]),
                }
            )

    if ref_issues:
        warnings.append(f"导入包存在 {len(ref_issues)} 项跨表引用异常。")

    integrity = payload.get("integrity", {})
    expected_hash = ""
    if isinstance(integrity, dict):
        expected_hash = str(pick_first(integrity.get("tables_sha256"), "")).strip().lower()
    if expected_hash:
        actual_hash = _bundle_tables_sha256(tables).strip().lower()
        if actual_hash and actual_hash == expected_hash:
            report["integrity_status"] = "ok"
            notes.append("完整性摘要校验通过（SHA-256）。")
        else:
            report["integrity_status"] = "mismatch"
            warnings.append("完整性摘要校验失败：导入包可能已被修改或损坏。")
    else:
        report["integrity_status"] = "missing"
        notes.append("导入包未携带完整性摘要（旧版本包常见）。")

    report["notes"] = notes
    report["warnings"] = warnings
    report["table_stats"] = table_stats
    report["reference_issues"] = ref_issues
    return report


def _existing_values(conn: sqlite3.Connection, table: str, column: str, values: List[str]) -> List[str]:
    vals = [str(x).strip() for x in values if str(x).strip()]
    if not vals:
        return []
    out = set()
    for chunk in _chunk_values(vals, size=400):
        ph = ",".join(["?"] * len(chunk))
        sql = f"SELECT {column} FROM {table} WHERE {column} IN ({ph})"
        for r in conn.execute(sql, tuple(chunk)).fetchall():
            out.add(str(pick_first(r[0], "")).strip())
    return sorted([x for x in out if x])


def _fetch_close_ids_by_group_ids(conn: sqlite3.Connection, group_ids: List[str]) -> List[str]:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return []
    out: set = set()
    for chunk in _chunk_values(gids, size=300):
        ph = ",".join(["?"] * len(chunk))
        sql = f"SELECT close_id FROM close_trade2 WHERE group_id IN ({ph})"
        for row in conn.execute(sql, tuple(chunk)).fetchall():
            cid = str(pick_first(row[0], "")).strip()
            if cid:
                out.add(cid)
    return sorted(list(out))


def _fetch_revert_log_ids_by_close_ids(conn: sqlite3.Connection, close_ids: List[str]) -> List[str]:
    cids = _normalize_group_ids(close_ids)
    if not cids:
        return []
    out: set = set()
    for chunk in _chunk_values(cids, size=300):
        ph = ",".join(["?"] * len(chunk))
        sql = f"SELECT log_id FROM close_revert_log WHERE close_id IN ({ph})"
        for row in conn.execute(sql, tuple(chunk)).fetchall():
            lid = str(pick_first(row[0], "")).strip()
            if lid:
                out.add(lid)
    return sorted(list(out))


def _fetch_existing_bundle_key_scope(conn: sqlite3.Connection, overwrite_group_ids: Optional[List[str]] = None) -> Dict[str, Any]:
    overwrite_set = set(_normalize_group_ids(overwrite_group_ids or []))

    existing_group_ids: set = set()
    for row in conn.execute("SELECT group_id FROM strategy_group").fetchall():
        gid = str(pick_first(row[0], "")).strip()
        if gid:
            existing_group_ids.add(gid)
    if overwrite_set:
        existing_group_ids = existing_group_ids - overwrite_set

    existing_structure_ids: set = set()
    existing_close_ids: set = set()
    if overwrite_set:
        ph = ",".join(["?"] * len(overwrite_set))
        for row in conn.execute(f"SELECT structure_id FROM structure WHERE group_id NOT IN ({ph})", tuple(overwrite_set)).fetchall():
            sid = str(pick_first(row[0], "")).strip()
            if sid:
                existing_structure_ids.add(sid)
        for row in conn.execute(f"SELECT close_id FROM close_trade2 WHERE group_id NOT IN ({ph})", tuple(overwrite_set)).fetchall():
            cid = str(pick_first(row[0], "")).strip()
            if cid:
                existing_close_ids.add(cid)
    else:
        for row in conn.execute("SELECT structure_id FROM structure").fetchall():
            sid = str(pick_first(row[0], "")).strip()
            if sid:
                existing_structure_ids.add(sid)
        for row in conn.execute("SELECT close_id FROM close_trade2").fetchall():
            cid = str(pick_first(row[0], "")).strip()
            if cid:
                existing_close_ids.add(cid)

    existing_revert_log_ids: set = set()
    for row in conn.execute("SELECT log_id FROM close_revert_log").fetchall():
        lid = str(pick_first(row[0], "")).strip()
        if lid:
            existing_revert_log_ids.add(lid)

    existing_spot_lot_ids: set = set()
    existing_spot_match_ids: set = set()
    if overwrite_set:
        ph = ",".join(["?"] * len(overwrite_set))
        for row in conn.execute(f"SELECT lot_id FROM spot_position_lot WHERE group_id NOT IN ({ph})", tuple(overwrite_set)).fetchall():
            lid = str(pick_first(row[0], "")).strip()
            if lid:
                existing_spot_lot_ids.add(lid)
        for row in conn.execute(f"SELECT match_id FROM spot_hedge_match_log WHERE group_id NOT IN ({ph})", tuple(overwrite_set)).fetchall():
            mid = str(pick_first(row[0], "")).strip()
            if mid:
                existing_spot_match_ids.add(mid)
    else:
        for row in conn.execute("SELECT lot_id FROM spot_position_lot").fetchall():
            lid = str(pick_first(row[0], "")).strip()
            if lid:
                existing_spot_lot_ids.add(lid)
        for row in conn.execute("SELECT match_id FROM spot_hedge_match_log").fetchall():
            mid = str(pick_first(row[0], "")).strip()
            if mid:
                existing_spot_match_ids.add(mid)

    overwrite_close_ids: set = set(_fetch_close_ids_by_group_ids(conn, list(overwrite_set))) if overwrite_set else set()
    if overwrite_close_ids:
        to_drop_log_ids = set(_fetch_revert_log_ids_by_close_ids(conn, list(overwrite_close_ids)))
        existing_revert_log_ids = existing_revert_log_ids - to_drop_log_ids

    return {
        "group_ids": existing_group_ids,
        "structure_ids": existing_structure_ids,
        "close_ids": existing_close_ids,
        "revert_log_ids": existing_revert_log_ids,
        "spot_lot_ids": existing_spot_lot_ids,
        "spot_match_ids": existing_spot_match_ids,
        "overwrite_close_ids": overwrite_close_ids,
    }


def _build_unique_import_id(old_id: str, occupied: set) -> str:
    # 历史上这里会为冲突主键自动追加 _NEW 后缀。
    # 当前口径改为“冲突直接覆盖”，不再自动改名。
    base = str(old_id).strip() or "ID"
    occupied.add(base)
    return base


def auto_remap_bundle_non_group_keys(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    overwrite_group_ids: Optional[List[str]] = None,
) -> Tuple[Dict[str, Any], Dict[str, Dict[str, str]]]:
    # 保留函数签名兼容旧调用方，但当前不再自动改名。
    out = _clone_json_obj(payload)
    return out, {
        "structure_id_map": {},
        "close_id_map": {},
        "revert_log_id_map": {},
        "spot_lot_id_map": {},
        "spot_match_id_map": {},
    }


def detect_strategy_group_bundle_conflicts(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    overwrite_group_ids: Optional[List[str]] = None,
) -> Dict[str, List[str]]:
    tables = payload.get("tables", {})
    group_rows = tables.get("strategy_group", []) if isinstance(tables, dict) else []
    struct_rows = tables.get("structure", []) if isinstance(tables, dict) else []
    close2_rows = tables.get("close_trade2", []) if isinstance(tables, dict) else []
    revert_rows = tables.get("close_revert_log", []) if isinstance(tables, dict) else []
    spot_lot_rows = tables.get("spot_position_lot", []) if isinstance(tables, dict) else []
    spot_match_rows = tables.get("spot_hedge_match_log", []) if isinstance(tables, dict) else []

    incoming_group_ids = _normalize_group_ids([str(r.get("group_id", "")).strip() for r in group_rows if isinstance(r, dict)])
    incoming_structure_ids = _normalize_group_ids([str(r.get("structure_id", "")).strip() for r in struct_rows if isinstance(r, dict)])
    incoming_close_ids = _normalize_group_ids([str(r.get("close_id", "")).strip() for r in close2_rows if isinstance(r, dict)])
    incoming_log_ids = _normalize_group_ids([str(r.get("log_id", "")).strip() for r in revert_rows if isinstance(r, dict)])
    incoming_spot_lot_ids = _normalize_group_ids([str(r.get("lot_id", "")).strip() for r in spot_lot_rows if isinstance(r, dict)])
    incoming_spot_match_ids = _normalize_group_ids([str(r.get("match_id", "")).strip() for r in spot_match_rows if isinstance(r, dict)])

    scope = _fetch_existing_bundle_key_scope(conn, overwrite_group_ids=overwrite_group_ids)
    existing_group_ids = set(scope.get("group_ids", set()))
    existing_structure_ids = set(scope.get("structure_ids", set()))
    existing_close_ids = set(scope.get("close_ids", set()))
    existing_log_ids = set(scope.get("revert_log_ids", set()))
    existing_spot_lot_ids = set(scope.get("spot_lot_ids", set()))
    existing_spot_match_ids = set(scope.get("spot_match_ids", set()))

    return {
        "group_id_conflicts": sorted([x for x in incoming_group_ids if x in existing_group_ids]),
        "structure_id_conflicts": sorted([x for x in incoming_structure_ids if x in existing_structure_ids]),
        "close_id_conflicts": sorted([x for x in incoming_close_ids if x in existing_close_ids]),
        "revert_log_id_conflicts": sorted([x for x in incoming_log_ids if x in existing_log_ids]),
        "spot_lot_id_conflicts": sorted([x for x in incoming_spot_lot_ids if x in existing_spot_lot_ids]),
        "spot_match_id_conflicts": sorted([x for x in incoming_spot_match_ids if x in existing_spot_match_ids]),
    }


def _count_rows_by_group_ids(conn: sqlite3.Connection, table: str, group_ids: List[str]) -> int:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return 0
    ph = ",".join(["?"] * len(gids))
    row = conn.execute(
        f"SELECT COUNT(1) FROM {table} WHERE group_id IN ({ph})",
        tuple(gids),
    ).fetchone()
    return int(pick_first(row[0] if row else 0, 0) or 0)


def summarize_bundle_overwrite_impact(
    conn: sqlite3.Connection,
    overwrite_group_ids: Optional[List[str]] = None,
) -> Dict[str, Any]:
    requested = _normalize_group_ids(overwrite_group_ids or [])
    if not requested:
        return {
            "targets": [],
            "target_count": 0,
            "counts": {},
            "total_delete_rows": 0,
            "revert_rows": 0,
        }

    groups_df = fetch_groups(conn)
    existing_gids = set(groups_df["group_id"].astype(str).tolist()) if not groups_df.empty else set()
    targets = sorted([gid for gid in requested if gid in existing_gids])
    if not targets:
        return {
            "targets": [],
            "target_count": 0,
            "counts": {},
            "total_delete_rows": 0,
            "revert_rows": 0,
        }

    counts = {
        "strategy_group": len(targets),
        "structure": _count_rows_by_group_ids(conn, "structure", targets),
        "close_trade": _count_rows_by_group_ids(conn, "close_trade", targets),
        "close_trade2": _count_rows_by_group_ids(conn, "close_trade2", targets),
        "snowball_conversion": _count_rows_by_group_ids(conn, "snowball_conversion", targets),
        "spot_position_lot": _count_rows_by_group_ids(conn, "spot_position_lot", targets),
        "spot_hedge_match_log": _count_rows_by_group_ids(conn, "spot_hedge_match_log", targets),
        "spot_summary_hidden": _count_rows_by_group_ids(conn, "spot_summary_hidden", targets),
    }
    pref_keys = [_price_auto_underlyings_pref_key(gid) for gid in targets]
    if pref_keys:
        ph_pref = ",".join(["?"] * len(pref_keys))
        pref_row = conn.execute(
            f"SELECT COUNT(1) FROM app_kv WHERE k IN ({ph_pref})",
            tuple(pref_keys),
        ).fetchone()
        counts["app_kv"] = int(pick_first(pref_row[0] if pref_row else 0, 0) or 0)
    else:
        counts["app_kv"] = 0
    ph = ",".join(["?"] * len(targets))
    revert_row = conn.execute(
        f"""
        SELECT COUNT(1)
        FROM close_revert_log l
        WHERE EXISTS (
            SELECT 1
            FROM close_trade2 c
            WHERE c.close_id = l.close_id
              AND c.group_id IN ({ph})
        )
        """,
        tuple(targets),
    ).fetchone()
    revert_cnt = int(pick_first(revert_row[0] if revert_row else 0, 0) or 0)
    counts["close_revert_log"] = revert_cnt
    total_delete = int(sum([int(v) for v in counts.values()]))
    return {
        "targets": targets,
        "target_count": len(targets),
        "counts": counts,
        "total_delete_rows": total_delete,
        "revert_rows": revert_cnt,
    }


def build_bundle_business_constraints(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    overwrite_group_ids: Optional[List[str]] = None,
    price_conflict_policy: str = "insert_only",
) -> Dict[str, Any]:
    blockers: List[str] = []
    high_risks: List[str] = []
    tips: List[str] = []

    internal_issues = detect_bundle_internal_key_issues(payload)
    missing_key_tables = internal_issues.get("missing_key_tables", []) if isinstance(internal_issues, dict) else []
    dup_map = internal_issues.get("duplicate_keys", {}) if isinstance(internal_issues, dict) else {}
    if missing_key_tables:
        blockers.append("导入包存在主键字段缺失，需先修复后再导入。")
    if isinstance(dup_map, dict) and dup_map:
        blockers.append("导入包存在重复主键记录，需先去重后再导入。")

    quality = inspect_strategy_group_bundle(payload)
    ref_issues = quality.get("reference_issues", []) if isinstance(quality, dict) else []
    if isinstance(ref_issues, list) and ref_issues:
        blockers.append(f"导入包存在 {len(ref_issues)} 项跨表引用异常，需先修复后再导入。")

    conflicts = detect_strategy_group_bundle_conflicts(
        conn,
        payload,
        overwrite_group_ids=overwrite_group_ids,
    )
    group_conflicts = conflicts.get("group_id_conflicts", [])
    if group_conflicts:
        blockers.append(f"仍存在策略组编号冲突：{len(group_conflicts)} 项。")

    struct_conflicts = conflicts.get("structure_id_conflicts", [])
    close_conflicts = conflicts.get("close_id_conflicts", [])
    revert_conflicts = conflicts.get("revert_log_id_conflicts", [])
    spot_lot_conflicts = conflicts.get("spot_lot_id_conflicts", [])
    spot_match_conflicts = conflicts.get("spot_match_id_conflicts", [])
    non_group_conflict_total = (
        len(struct_conflicts)
        + len(close_conflicts)
        + len(revert_conflicts)
        + len(spot_lot_conflicts)
        + len(spot_match_conflicts)
    )
    if non_group_conflict_total > 0:
        high_risks.append(
            "导入将直接覆盖同编号记录："
            f"结构ID {len(struct_conflicts)}，平仓ID {len(close_conflicts)}，"
            f"撤回日志ID {len(revert_conflicts)}，现货头寸ID {len(spot_lot_conflicts)}，"
            f"现货对冲流水ID {len(spot_match_conflicts)}。"
        )

    impact = summarize_bundle_overwrite_impact(conn, overwrite_group_ids=overwrite_group_ids)
    if int(pick_first(impact.get("target_count"), 0) or 0) > 0:
        high_risks.append(
            f"覆盖导入将先删除旧数据：策略组 {impact['target_count']} 个，"
            f"预计删除 {int(pick_first(impact.get('total_delete_rows'), 0) or 0)} 条关联记录。"
        )

    price_mode = str(price_conflict_policy).strip().lower()
    if price_mode == "overwrite":
        high_risks.append("已选择“全量覆盖价格”：会覆盖已有价格（含人工维护价格），请谨慎确认。")
    elif price_mode == "overwrite_auto":
        high_risks.append("已选择“覆盖自动来源价格”：自动来源价格会被覆盖，人工锁定价格保留。")

    tips.append("建议先完成导入体检并处理阻断项，再执行最终导入。")
    if int(pick_first(impact.get("target_count"), 0) or 0) > 0:
        tips.append("覆盖导入前建议先导出当前策略组做备份。")

    return {
        "blockers": list(dict.fromkeys([str(x) for x in blockers if str(x).strip()])),
        "high_risks": list(dict.fromkeys([str(x) for x in high_risks if str(x).strip()])),
        "tips": list(dict.fromkeys([str(x) for x in tips if str(x).strip()])),
        "overwrite_impact": impact,
    }


def _insert_rows_by_table_schema(
    conn: sqlite3.Connection,
    table: str,
    rows: List[Dict[str, Any]],
    *,
    price_conflict_policy: str = "insert_only",
) -> int:
    if not rows:
        return 0
    table_cols = _table_columns(conn, table)
    if not table_cols:
        return 0
    vals: List[Tuple[Any, ...]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        vals.append(tuple(_json_safe_scalar(row.get(c)) for c in table_cols))
    if not vals:
        return 0
    ph = ",".join(["?"] * len(table_cols))
    sql = f"INSERT INTO {table}({','.join(table_cols)}) VALUES({ph})"
    if table == "price":
        mode = str(price_conflict_policy).strip().lower()
        if mode == "overwrite":
            sql += """
            ON CONFLICT(dt, underlying) DO UPDATE SET
                settle=excluded.settle,
                source=COALESCE(NULLIF(TRIM(excluded.source), ''), price.source),
                is_locked=COALESCE(excluded.is_locked, price.is_locked),
                updated_at=COALESCE(NULLIF(TRIM(excluded.updated_at), ''), price.updated_at)
            """
        elif mode == "overwrite_auto":
            sql += """
            ON CONFLICT(dt, underlying) DO UPDATE SET
                settle=excluded.settle,
                source=COALESCE(NULLIF(TRIM(excluded.source), ''), price.source),
                is_locked=COALESCE(excluded.is_locked, price.is_locked),
                updated_at=COALESCE(NULLIF(TRIM(excluded.updated_at), ''), price.updated_at)
            WHERE
                COALESCE(price.is_locked, 0) = 0
                AND LOWER(COALESCE(price.source, 'manual')) IN ('akshare', 'auto', 'api')
            """
        else:
            # 默认仅补充缺失价格，避免覆盖目标库已有价格。
            sql += " ON CONFLICT(dt, underlying) DO NOTHING"
    before = conn.total_changes
    conn.executemany(sql, vals)
    return int(conn.total_changes - before)


def _delete_close_revert_rows_by_close_ids(conn: sqlite3.Connection, close_ids: List[str]) -> int:
    cids = _normalize_group_ids(close_ids)
    if not cids:
        return 0
    before = conn.total_changes
    for chunk in _chunk_values(cids, size=300):
        ph = ",".join(["?"] * len(chunk))
        conn.execute(f"DELETE FROM close_revert_log WHERE close_id IN ({ph})", tuple(chunk))
    return int(conn.total_changes - before)


def _delete_rows_by_group_ids(conn: sqlite3.Connection, table: str, group_ids: List[str]) -> int:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return 0
    before = conn.total_changes
    for chunk in _chunk_values(gids, size=300):
        ph = ",".join(["?"] * len(chunk))
        conn.execute(f"DELETE FROM {table} WHERE group_id IN ({ph})", tuple(chunk))
    return int(conn.total_changes - before)


def _delete_group_pref_kv_rows(conn: sqlite3.Connection, group_ids: List[str]) -> int:
    gids = _normalize_group_ids(group_ids)
    if not gids:
        return 0
    keys = [_price_auto_underlyings_pref_key(gid) for gid in gids]
    if not keys:
        return 0
    before = conn.total_changes
    conn.executemany("DELETE FROM app_kv WHERE k=?", [(k,) for k in keys])
    return int(conn.total_changes - before)


def _cleanup_orphan_close_revert_rows(conn: sqlite3.Connection) -> int:
    before = conn.total_changes
    conn.execute(
        """
        DELETE FROM close_revert_log
        WHERE NOT EXISTS (
            SELECT 1
            FROM close_trade2 c
            WHERE c.close_id = close_revert_log.close_id
        )
        """
    )
    return int(conn.total_changes - before)


def delete_strategy_groups_with_dependencies(
    conn: sqlite3.Connection,
    group_ids: List[str],
    *,
    manage_tx: bool = True,
    cleanup_orphan_revert: bool = True,
    cleanup_group_pref_kv: bool = True,
) -> Dict[str, Any]:
    """
    删除策略组并显式清理关联数据。
    说明：
    - 不依赖历史库外键是否完整；
    - close_revert_log 通过 close_id 反查删除；
    - 可选清理无引用撤回日志与策略组偏好配置。
    """
    targets = _normalize_group_ids(group_ids)
    result: Dict[str, Any] = {
        "targets": targets,
        "target_count": 0,
        "strategy_group": 0,
        "structure": 0,
        "close_trade": 0,
        "close_trade2": 0,
        "snowball_conversion": 0,
        "spot_position_lot": 0,
        "spot_hedge_match_log": 0,
        "spot_summary_hidden": 0,
        "close_revert_log": 0,
        "close_revert_orphan": 0,
        "app_kv": 0,
        "total_deleted_rows": 0,
    }
    if not targets:
        return result

    existing_targets: List[str] = []
    for chunk in _chunk_values(targets, size=300):
        ph = ",".join(["?"] * len(chunk))
        rows = conn.execute(
            f"SELECT group_id FROM strategy_group WHERE group_id IN ({ph})",
            tuple(chunk),
        ).fetchall()
        existing_targets.extend([str(r[0]).strip() for r in rows if r and str(r[0]).strip()])
    existing_targets = _normalize_group_ids(existing_targets)
    result["targets"] = existing_targets
    result["target_count"] = len(existing_targets)
    if not existing_targets:
        return result

    close_ids = _fetch_close_ids_by_group_ids(conn, existing_targets)
    try:
        if manage_tx:
            conn.execute("BEGIN IMMEDIATE")
        if close_ids:
            result["close_revert_log"] = _delete_close_revert_rows_by_close_ids(conn, close_ids)
        result["spot_hedge_match_log"] = _delete_rows_by_group_ids(conn, "spot_hedge_match_log", existing_targets)
        result["snowball_conversion"] = _delete_rows_by_group_ids(conn, "snowball_conversion", existing_targets)
        result["close_trade2"] = _delete_rows_by_group_ids(conn, "close_trade2", existing_targets)
        result["close_trade"] = _delete_rows_by_group_ids(conn, "close_trade", existing_targets)
        result["spot_position_lot"] = _delete_rows_by_group_ids(conn, "spot_position_lot", existing_targets)
        result["spot_summary_hidden"] = _delete_rows_by_group_ids(conn, "spot_summary_hidden", existing_targets)
        result["structure"] = _delete_rows_by_group_ids(conn, "structure", existing_targets)
        if cleanup_group_pref_kv:
            result["app_kv"] = _delete_group_pref_kv_rows(conn, existing_targets)
        result["strategy_group"] = _delete_rows_by_group_ids(conn, "strategy_group", existing_targets)
        if cleanup_orphan_revert:
            result["close_revert_orphan"] = _cleanup_orphan_close_revert_rows(conn)
        if manage_tx:
            conn.commit()
    except Exception:
        if manage_tx:
            conn.rollback()
        raise

    result["total_deleted_rows"] = int(
        sum(
            int(pick_first(result.get(k), 0) or 0)
            for k in [
                "strategy_group",
                "structure",
                "close_trade",
                "close_trade2",
                "snowball_conversion",
                "spot_position_lot",
                "spot_hedge_match_log",
                "spot_summary_hidden",
                "close_revert_log",
                "close_revert_orphan",
                "app_kv",
            ]
        )
    )
    return result


def delete_conflicting_bundle_non_group_rows(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    *,
    overwrite_group_ids: Optional[List[str]] = None,
    manage_tx: bool = False,
) -> Dict[str, int]:
    conflicts = detect_strategy_group_bundle_conflicts(
        conn,
        payload,
        overwrite_group_ids=overwrite_group_ids,
    )
    structure_ids = _normalize_group_ids(conflicts.get("structure_id_conflicts", []))
    close_ids = _normalize_group_ids(conflicts.get("close_id_conflicts", []))
    revert_log_ids = _normalize_group_ids(conflicts.get("revert_log_id_conflicts", []))
    spot_lot_ids = _normalize_group_ids(conflicts.get("spot_lot_id_conflicts", []))
    spot_match_ids = _normalize_group_ids(conflicts.get("spot_match_id_conflicts", []))

    result = {
        "structure_related": 0,
        "close_trade2": 0,
        "close_revert_log": 0,
        "spot_position_lot": 0,
        "spot_hedge_match_log": 0,
        "total_deleted_rows": 0,
    }

    try:
        if manage_tx:
            conn.execute("BEGIN IMMEDIATE")

        if structure_ids:
            before = conn.total_changes
            hard_delete_structures_with_related_records(
                conn,
                structure_ids=structure_ids,
                manage_tx=False,
            )
            result["structure_related"] += int(conn.total_changes - before)

        if close_ids:
            result["close_revert_log"] += _delete_close_revert_rows_by_close_ids(conn, close_ids)
            before = conn.total_changes
            for chunk in _chunk_values(close_ids, size=300):
                ph = ",".join(["?"] * len(chunk))
                conn.execute(f"DELETE FROM close_trade2 WHERE close_id IN ({ph})", tuple(chunk))
            result["close_trade2"] += int(conn.total_changes - before)

        if revert_log_ids:
            before = conn.total_changes
            for chunk in _chunk_values(revert_log_ids, size=300):
                ph = ",".join(["?"] * len(chunk))
                conn.execute(f"DELETE FROM close_revert_log WHERE log_id IN ({ph})", tuple(chunk))
            result["close_revert_log"] += int(conn.total_changes - before)

        if spot_lot_ids:
            before = conn.total_changes
            for chunk in _chunk_values(spot_lot_ids, size=300):
                ph = ",".join(["?"] * len(chunk))
                conn.execute(f"DELETE FROM spot_hedge_match_log WHERE spot_lot_id IN ({ph})", tuple(chunk))
            result["spot_hedge_match_log"] += int(conn.total_changes - before)

            before = conn.total_changes
            for chunk in _chunk_values(spot_lot_ids, size=300):
                ph = ",".join(["?"] * len(chunk))
                conn.execute(f"DELETE FROM spot_position_lot WHERE lot_id IN ({ph})", tuple(chunk))
            result["spot_position_lot"] += int(conn.total_changes - before)

        if spot_match_ids:
            before = conn.total_changes
            for chunk in _chunk_values(spot_match_ids, size=300):
                ph = ",".join(["?"] * len(chunk))
                conn.execute(f"DELETE FROM spot_hedge_match_log WHERE match_id IN ({ph})", tuple(chunk))
            result["spot_hedge_match_log"] += int(conn.total_changes - before)

        result["total_deleted_rows"] = int(
            sum(
                int(pick_first(result.get(k), 0) or 0)
                for k in ["structure_related", "close_trade2", "close_revert_log", "spot_position_lot", "spot_hedge_match_log"]
            )
        )
        if manage_tx:
            conn.commit()
    except Exception:
        if manage_tx:
            conn.rollback()
        raise

    return result


def import_strategy_group_bundle(
    conn: sqlite3.Connection,
    payload: Dict[str, Any],
    overwrite_group_ids: Optional[List[str]] = None,
    price_conflict_policy: str = "insert_only",
) -> Tuple[bool, str]:
    payload = prepare_strategy_group_bundle_for_import(
        conn,
        payload,
        overwrite_group_ids=overwrite_group_ids,
    )
    tables = payload.get("tables", {})
    if not isinstance(tables, dict):
        return False, "导入失败：文件内容缺少 tables"
    group_rows = tables.get("strategy_group", [])
    struct_rows = tables.get("structure", [])
    close_rows = tables.get("close_trade", [])
    close2_rows = tables.get("close_trade2", [])
    price_rows = tables.get("price", [])
    revert_rows = tables.get("close_revert_log", [])
    spot_lot_rows = tables.get("spot_position_lot", [])
    spot_match_rows = tables.get("spot_hedge_match_log", [])

    key_issues = detect_bundle_internal_key_issues(payload)
    dup_map = key_issues.get("duplicate_keys", {}) if isinstance(key_issues, dict) else {}
    missing_key_tables = key_issues.get("missing_key_tables", []) if isinstance(key_issues, dict) else []
    if missing_key_tables:
        return False, f"导入失败：文件存在主键字段缺失，请检查表：{', '.join([str(x) for x in missing_key_tables])}"
    if isinstance(dup_map, dict) and dup_map:
        first_table = ""
        first_items: List[str] = []
        for k in [
            "strategy_group",
            "structure",
            "close_trade",
            "close_trade2",
            "price",
            "close_revert_log",
            "spot_position_lot",
            "spot_hedge_match_log",
        ]:
            items = dup_map.get(k, [])
            if items:
                first_table = k
                first_items = [str(x) for x in items[:5]]
                break
        if first_table:
            return False, f"导入失败：文件内存在重复主键（表 {first_table}）：{', '.join(first_items)}"

    incoming_group_ids = _normalize_group_ids([str(r.get("group_id", "")).strip() for r in group_rows if isinstance(r, dict)])
    if not incoming_group_ids:
        return False, "导入失败：文件中未找到有效策略组"
    group_set = set(incoming_group_ids)
    overwrite_set = set(_normalize_group_ids(overwrite_group_ids or []))

    for table_name, rows in [("structure", struct_rows), ("close_trade", close_rows), ("close_trade2", close2_rows)]:
        for i, row in enumerate(rows):
            if not isinstance(row, dict):
                continue
            gid = str(row.get("group_id", "")).strip()
            if gid and gid not in group_set:
                return False, f"导入失败：表 {table_name} 第 {i + 1} 行的策略组编号不在主表中（{gid}）"

    close_id_set = set([str(r.get("close_id", "")).strip() for r in close2_rows if isinstance(r, dict)])
    for i, row in enumerate(revert_rows):
        if not isinstance(row, dict):
            continue
        cid = str(row.get("close_id", "")).strip()
        if cid and cid not in close_id_set:
            return False, f"导入失败：表 close_revert_log 第 {i + 1} 行引用的 close_id 不存在（{cid}）"

    lot_id_set = set([str(r.get("lot_id", "")).strip() for r in spot_lot_rows if isinstance(r, dict)])
    structure_gid_map: Dict[str, str] = {
        str(r.get("structure_id", "")).strip(): str(r.get("group_id", "")).strip()
        for r in struct_rows
        if isinstance(r, dict) and str(r.get("structure_id", "")).strip()
    }
    for i, row in enumerate(close2_rows):
        if not isinstance(row, dict):
            continue
        sid = str(row.get("structure_id", "")).strip()
        if sid and sid != "外部":
            if sid not in structure_gid_map:
                return False, f"导入失败：表 close_trade2 第 {i + 1} 行引用的 structure_id 不存在（{sid}）"
            gid_c = str(row.get("group_id", "")).strip()
            gid_s = str(structure_gid_map.get(sid, "")).strip()
            if gid_c and gid_s and gid_c != gid_s:
                return False, (
                    f"导入失败：表 close_trade2 第 {i + 1} 行策略组与结构不一致（group_id={gid_c}, structure_id={sid}, structure.group_id={gid_s}）"
                )
    for i, row in enumerate(spot_lot_rows):
        if not isinstance(row, dict):
            continue
        gid_l = str(row.get("group_id", "")).strip()
        if gid_l and gid_l not in group_set:
            return False, f"导入失败：表 spot_position_lot 第 {i + 1} 行的策略组编号不在主表中（{gid_l}）"
    for i, row in enumerate(spot_match_rows):
        if not isinstance(row, dict):
            continue
        gid_m = str(row.get("group_id", "")).strip()
        if gid_m and gid_m not in group_set:
            return False, f"导入失败：表 spot_hedge_match_log 第 {i + 1} 行的策略组编号不在主表中（{gid_m}）"
        lot_id = str(row.get("spot_lot_id", "")).strip()
        if lot_id and lot_id not in lot_id_set:
            return False, f"导入失败：表 spot_hedge_match_log 第 {i + 1} 行引用的 lot_id 不存在（{lot_id}）"
        sid_m = str(row.get("structure_id", "")).strip()
        if sid_m and sid_m != "外部":
            if sid_m not in structure_gid_map:
                return False, f"导入失败：表 spot_hedge_match_log 第 {i + 1} 行引用的 structure_id 不存在（{sid_m}）"
            gid_s = str(structure_gid_map.get(sid_m, "")).strip()
            if gid_m and gid_s and gid_m != gid_s:
                return False, (
                    f"导入失败：表 spot_hedge_match_log 第 {i + 1} 行策略组与结构不一致（group_id={gid_m}, structure_id={sid_m}, structure.group_id={gid_s}）"
                )

    conflicts = detect_strategy_group_bundle_conflicts(conn, payload, overwrite_group_ids=list(overwrite_set))
    if conflicts.get("group_id_conflicts"):
        return False, f"导入失败：策略组编号已存在，请先重命名。冲突编号：{', '.join(conflicts['group_id_conflicts'])}"

    existing_group_ids = set(fetch_groups(conn)["group_id"].astype(str).tolist())
    overwrite_targets = sorted([gid for gid in incoming_group_ids if gid in overwrite_set and gid in existing_group_ids])

    try:
        conn.execute("BEGIN IMMEDIATE")
        cnt_old_revert = 0
        cnt_old_deleted = 0
        cnt_conflict_deleted = 0
        if overwrite_targets:
            old_cleanup = delete_strategy_groups_with_dependencies(
                conn,
                overwrite_targets,
                manage_tx=False,
                cleanup_orphan_revert=True,
                cleanup_group_pref_kv=True,
            )
            cnt_old_revert = int(pick_first(old_cleanup.get("close_revert_log"), 0) or 0)
            cnt_old_deleted = int(pick_first(old_cleanup.get("total_deleted_rows"), 0) or 0)
        conflict_cleanup = delete_conflicting_bundle_non_group_rows(
            conn,
            payload,
            overwrite_group_ids=list(overwrite_set),
            manage_tx=False,
        )
        cnt_conflict_deleted = int(pick_first(conflict_cleanup.get("total_deleted_rows"), 0) or 0)
        cnt_group = _insert_rows_by_table_schema(conn, "strategy_group", group_rows)
        cnt_spot_lot = _insert_rows_by_table_schema(conn, "spot_position_lot", spot_lot_rows)
        cnt_struct = _insert_rows_by_table_schema(conn, "structure", struct_rows)
        cnt_close = _insert_rows_by_table_schema(conn, "close_trade", close_rows)
        cnt_close2 = _insert_rows_by_table_schema(conn, "close_trade2", close2_rows)
        cnt_spot_match = _insert_rows_by_table_schema(conn, "spot_hedge_match_log", spot_match_rows)
        cnt_revert = _insert_rows_by_table_schema(conn, "close_revert_log", revert_rows)
        price_mode = str(price_conflict_policy).strip().lower()
        if price_mode not in {"insert_only", "overwrite_auto", "overwrite"}:
            price_mode = "insert_only"
        cnt_price = _insert_rows_by_table_schema(conn, "price", price_rows, price_conflict_policy=price_mode)
        conn.commit()
    except Exception as exc:
        conn.rollback()
        return False, f"导入失败：{humanize_db_write_error(exc)}"

    price_mode_label = BUNDLE_PRICE_IMPORT_POLICY_CODE_TO_LABEL.get(price_mode, BUNDLE_PRICE_IMPORT_POLICY_OPTIONS[0])
    msg = (
        f"导入成功：策略组 {cnt_group} 条，现货头寸 {cnt_spot_lot} 条，结构 {cnt_struct} 条，"
        f"平仓汇总 {cnt_close} 条，平仓明细 {cnt_close2} 条，现货对冲流水 {cnt_spot_match} 条，撤回日志 {cnt_revert} 条，"
        f"价格写入 {cnt_price} 条（策略：{price_mode_label}）"
    )
    if overwrite_targets:
        msg += (
            f"；覆盖策略组 {len(overwrite_targets)} 个"
            f"（已清理旧数据 {cnt_old_deleted} 条，含旧撤回日志 {cnt_old_revert} 条）"
        )
    if cnt_conflict_deleted > 0:
        msg += f"；同编号覆盖清理 {cnt_conflict_deleted} 条关联记录"
    return True, msg


@st.dialog("策略组编号重命名")
def group_bundle_group_id_rename_dialog(
    conn: sqlite3.Connection,
    base_payload: Dict[str, Any],
    bundle_sig: str,
    conflict_group_ids: List[str],
    overwrite_group_ids: Optional[List[str]] = None,
) -> None:
    conflict_ids = _normalize_group_ids(conflict_group_ids)
    if not conflict_ids:
        st.info("当前没有待处理的编号冲突。")
        if st.button("关闭", key=f"group_bundle_rename_close_empty_{bundle_sig}"):
            st.session_state["group_bundle_rename_dialog_open"] = False
            st.rerun()
        return

    groups_now = fetch_groups(conn)
    existing_group_ids = set(groups_now["group_id"].astype(str).tolist()) if not groups_now.empty else set()

    incoming_rows = base_payload.get("tables", {}).get("strategy_group", []) if isinstance(base_payload, dict) else []
    incoming_group_ids = set(
        _normalize_group_ids([str(r.get("group_id", "")).strip() for r in incoming_rows if isinstance(r, dict)])
    )

    map_by_sig = st.session_state.setdefault("group_bundle_rename_map_by_sig", {})
    current_map = map_by_sig.get(bundle_sig, {}) if isinstance(map_by_sig, dict) else {}
    if not isinstance(current_map, dict):
        current_map = {}

    st.caption("检测到策略组编号与当前系统重复，请在下方表格中批量填写新编号后继续导入。")
    seed_rows: List[Dict[str, str]] = []
    for old_gid in conflict_ids:
        default_new = str(current_map.get(old_gid, old_gid)).strip()
        seed_rows.append({"原编号": old_gid, "新编号": default_new})
    rename_df = st.data_editor(
        pd.DataFrame(seed_rows),
        hide_index=True,
        width="stretch",
        num_rows="fixed",
        column_config={
            "原编号": st.column_config.TextColumn("原编号", disabled=True),
            "新编号": st.column_config.TextColumn("新编号"),
        },
        key=f"group_bundle_rename_editor_{bundle_sig}",
    )

    b1, b2 = st.columns(2)
    do_confirm = b1.button("确认重命名并继续", key=f"group_bundle_rename_confirm_{bundle_sig}")
    do_cancel = b2.button("取消", key=f"group_bundle_rename_cancel_{bundle_sig}")

    if do_cancel:
        st.session_state["group_bundle_rename_dialog_open"] = False
        st.rerun()

    if do_confirm:
        rename_map: Dict[str, str] = {}
        errs: List[str] = []
        used_new_ids: set = set()
        if rename_df is None or rename_df.empty:
            st.error("未检测到重命名内容，请填写后再继续。")
            return
        for _, row in rename_df.iterrows():
            old_gid = str(row.get("原编号", "")).strip()
            new_gid = str(row.get("新编号", "")).strip()
            if old_gid not in conflict_ids:
                errs.append(f"发现非法原编号：{old_gid}")
                continue
            if not new_gid:
                errs.append(f"{old_gid} 的新编号不能为空")
                continue
            if new_gid == old_gid:
                errs.append(f"{old_gid} 仍与原编号相同，请修改")
                continue
            if new_gid in used_new_ids:
                errs.append(f"新编号重复：{new_gid}")
                continue
            if new_gid in existing_group_ids:
                errs.append(f"新编号已存在：{new_gid}")
                continue
            if new_gid in incoming_group_ids and new_gid not in conflict_ids:
                errs.append(f"新编号与导入包内其他策略组重复：{new_gid}")
                continue
            used_new_ids.add(new_gid)
            rename_map[old_gid] = new_gid

        if errs:
            st.error("；".join(errs[:5]))
            return

        old_map = map_by_sig.get(bundle_sig, {}) if isinstance(map_by_sig, dict) else {}
        if not isinstance(old_map, dict):
            old_map = {}
        merged_trial_map = {str(k): str(v) for k, v in old_map.items()}
        merged_trial_map.update(rename_map)

        trial_payload = apply_group_id_rename_to_bundle(base_payload, merged_trial_map)
        trial_internal = detect_bundle_internal_key_issues(trial_payload)
        trial_dup = trial_internal.get("duplicate_keys", {}) if isinstance(trial_internal, dict) else {}
        trial_missing = trial_internal.get("missing_key_tables", []) if isinstance(trial_internal, dict) else []
        if trial_missing:
            st.error(f"重命名后主键字段缺失，请检查：{', '.join([str(x) for x in trial_missing])}")
            return
        if isinstance(trial_dup, dict) and trial_dup:
            first_table = ""
            first_items: List[str] = []
            for k in [
                "strategy_group",
                "structure",
                "close_trade",
                "close_trade2",
                "price",
                "close_revert_log",
                "spot_position_lot",
                "spot_hedge_match_log",
            ]:
                items = trial_dup.get(k, [])
                if items:
                    first_table = k
                    first_items = [str(x) for x in items[:5]]
                    break
            if first_table:
                st.error(f"重命名后出现重复主键（表 {first_table}）：{', '.join(first_items)}")
                return

        trial_conflicts = detect_strategy_group_bundle_conflicts(
            conn,
            trial_payload,
            overwrite_group_ids=overwrite_group_ids,
        )
        if trial_conflicts.get("group_id_conflicts"):
            st.error(f"重命名后仍有策略组编号冲突：{', '.join(trial_conflicts['group_id_conflicts'])}")
            return

        if not isinstance(map_by_sig, dict):
            map_by_sig = {}
        old_map2 = map_by_sig.get(bundle_sig, {})
        if not isinstance(old_map2, dict):
            old_map2 = {}
        merged = {str(k): str(v) for k, v in old_map2.items()}
        merged.update(rename_map)
        map_by_sig[bundle_sig] = merged
        st.session_state["group_bundle_rename_map_by_sig"] = map_by_sig
        st.session_state["group_bundle_rename_dialog_open"] = False
        st.success("已应用重命名映射。")
        st.rerun()


def sync_fixed_subsidy_close_records(conn: sqlite3.Connection) -> None:
    """
    为固定赔付类结构同步自动补贴平仓记录（幂等）：
    - FIXED_SUBSIDY: 熔断日一次性补贴 -> 熔断补贴平仓；
    - PREMIUM_SUBSIDY: 不敲入日逐日补贴 -> 溢价补贴平仓；
    - RANGE_SUBSIDY: 区间日逐日补贴（敲入/敲出日无补贴）-> 溢价补贴平仓；
    - 仅写入 quick_batch_id=AUTO_SUBSIDY_BATCH_ID 的自动记录；
    - close_id 采用确定性键，重复运行不会重复插入；
    - 若结构/参数变化，自动记录会更新；失效记录会清理。
    """
    structs_raw = fetch_structures(conn)
    if structs_raw.empty:
        conn.execute("DELETE FROM close_trade2 WHERE quick_batch_id=?", (AUTO_SUBSIDY_BATCH_ID,))
        conn.commit()
        return

    prices = fetch_prices(conn)
    if prices.empty:
        conn.execute("DELETE FROM close_trade2 WHERE quick_batch_id=?", (AUTO_SUBSIDY_BATCH_ID,))
        conn.commit()
        return

    price_map: Dict[Tuple[str, str], float] = {}
    for _, r in prices.iterrows():
        dt = str(r.get("dt", "")).strip()
        und = str(r.get("underlying", "")).strip()
        if not dt or not und:
            continue
        try:
            price_map[(dt, und)] = float(r.get("settle"))
        except Exception:
            continue

    expected_rows: Dict[str, Tuple[Any, ...]] = {}
    manual_close_date_map: Dict[str, date] = {}
    old_manual = fetch_closes2(conn)
    if not old_manual.empty:
        if "close_category" in old_manual.columns:
            man = old_manual[old_manual["close_category"].astype(str).str.strip() == MANUAL_STRUCT_CLOSE_CATEGORY].copy()
        else:
            man = pd.DataFrame()
        if not man.empty:
            for _, rr in man.iterrows():
                sid_m = str(rr.get("structure_id", "")).strip()
                if not sid_m or sid_m == "外部":
                    continue
                try:
                    md = datetime.strptime(str(rr.get("dt", "")), DATE_FMT).date()
                except Exception:
                    continue
                prev = manual_close_date_map.get(sid_m)
                if prev is None or md < prev:
                    manual_close_date_map[sid_m] = md
    for _, raw in structs_raw.iterrows():
        s = resolve_structure_row(raw)
        strategy_code = str(s.get("strategy_code", "")).upper()
        if strategy_code not in {"FIXED_SUBSIDY", "PREMIUM_SUBSIDY", "RANGE_SUBSIDY"}:
            continue

        sid = str(s.get("structure_id", "")).strip()
        gid = str(s.get("group_id", "")).strip()
        und = str(s.get("underlying", "")).strip()
        kind = str(s.get("kind", "")).upper()
        if not sid or not gid or not und or kind not in {"ACC", "DEC"}:
            continue

        try:
            sd = datetime.strptime(str(s.get("start_date", "")), DATE_FMT).date()
            ed = datetime.strptime(str(s.get("end_date", "")), DATE_FMT).date()
        except Exception:
            continue
        if ed < sd:
            continue

        td = trading_days_between(sd, ed)
        manual_close_dt = manual_close_date_map.get(sid)
        if manual_close_dt is not None:
            td = [d for d in td if d < manual_close_dt]
        total_days = len(td)
        if total_days <= 0:
            continue

        base_qty = float(pick_first(s.get("base_qty_per_day"), 0.0) or 0.0)
        subsidy_per_ton = max(float(pick_first(s.get("subsidy_per_ton"), 0.0) or 0.0), 0.0)
        open_price = float(pick_first(s.get("strike_price"), s.get("entry_price"), 0.0) or 0.0)
        side = "SELL" if kind == "ACC" else "BUY"
        strike = float(pick_first(s.get("strike_price"), s.get("entry_price"), 0.0) or 0.0)

        if strategy_code == "FIXED_SUBSIDY":
            barrier = to_float(pick_first(s.get("barrier_out"), s.get("knock_out_price")))
            if barrier is None:
                continue
            observed_days = 0
            for d in td:
                dt_s = d.strftime(DATE_FMT)
                settle = price_map.get((dt_s, und))
                if settle is None:
                    continue

                remaining_days = max(total_days - observed_days, 0)
                ko_hit = price_at_or_above(settle, barrier) if kind == "ACC" else price_at_or_below(settle, barrier)
                if ko_hit:
                    remaining_after_today = max(remaining_days - 1, 0)
                    subsidy_qty = base_qty * remaining_after_today
                    subsidy_pnl = subsidy_qty * subsidy_per_ton
                    if subsidy_qty > 1e-12 or abs(subsidy_pnl) > 1e-12:
                        close_id = f"SUBSIDY::{sid}::{dt_s}"
                        expected_rows[close_id] = (
                            close_id,
                            dt_s,
                            gid,
                            sid,
                            und,
                            side,
                            float(subsidy_qty),
                            float(open_price),
                            float(open_price),
                            float(subsidy_pnl),
                            SUBSIDY_CLOSE_CATEGORY,
                            AUTO_SUBSIDY_BATCH_ID,
                            dt_s,
                            1,
                        )
                    break

                observed_days += 1
            continue

        if strategy_code == "RANGE_SUBSIDY":
            barrier = to_float(pick_first(s.get("barrier_out"), s.get("knock_out_price")))
            if barrier is None:
                continue
            for d in td:
                dt_s = d.strftime(DATE_FMT)
                settle = price_map.get((dt_s, und))
                if settle is None:
                    continue
                settle_v = float(settle)
                # 边界优先级：先判行权价敲入，再判障碍价敲出。
                ki_hit = price_at_or_below(settle_v, strike) if kind == "ACC" else price_at_or_above(settle_v, strike)
                if ki_hit:
                    continue
                ko_hit = price_at_or_above(settle_v, barrier) if kind == "ACC" else price_at_or_below(settle_v, barrier)
                if ko_hit:
                    continue
                subsidy_qty = base_qty
                subsidy_pnl = subsidy_qty * subsidy_per_ton
                if subsidy_qty <= 1e-12 and abs(subsidy_pnl) <= 1e-12:
                    continue
                close_id = f"RANGE_SUBSIDY::{sid}::{dt_s}"
                expected_rows[close_id] = (
                    close_id,
                    dt_s,
                    gid,
                    sid,
                    und,
                    side,
                    float(subsidy_qty),
                    float(open_price),
                    float(open_price),
                    float(subsidy_pnl),
                    PREMIUM_SUBSIDY_CLOSE_CATEGORY,
                    AUTO_SUBSIDY_BATCH_ID,
                    dt_s,
                    1,
                )
            continue

        # PREMIUM_SUBSIDY：不敲入日按“当日观察规模=每日基准量”逐日补贴
        for d in td:
            dt_s = d.strftime(DATE_FMT)
            settle = price_map.get((dt_s, und))
            if settle is None:
                continue
            ki_hit = price_at_or_below(settle, strike) if kind == "ACC" else price_at_or_above(settle, strike)
            if ki_hit:
                continue
            subsidy_qty = base_qty
            subsidy_pnl = subsidy_qty * subsidy_per_ton
            if subsidy_qty <= 1e-12 and abs(subsidy_pnl) <= 1e-12:
                continue
            close_id = f"PREM_SUBSIDY::{sid}::{dt_s}"
            expected_rows[close_id] = (
                close_id,
                dt_s,
                gid,
                sid,
                und,
                side,
                float(subsidy_qty),
                float(open_price),
                float(open_price),
                float(subsidy_pnl),
                PREMIUM_SUBSIDY_CLOSE_CATEGORY,
                AUTO_SUBSIDY_BATCH_ID,
                dt_s,
                1,
            )

    if expected_rows:
        conn.executemany(
            """
            INSERT INTO close_trade2(
                close_id, dt, group_id, structure_id, underlying, side, qty, open_price, close_price, pnl, close_category, quick_batch_id, source_gen_date, is_external
            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(close_id) DO UPDATE SET
                dt=excluded.dt,
                group_id=excluded.group_id,
                structure_id=excluded.structure_id,
                underlying=excluded.underlying,
                side=excluded.side,
                qty=excluded.qty,
                open_price=excluded.open_price,
                close_price=excluded.close_price,
                pnl=excluded.pnl,
                close_category=excluded.close_category,
                quick_batch_id=excluded.quick_batch_id,
                source_gen_date=excluded.source_gen_date,
                is_external=excluded.is_external
            """,
            list(expected_rows.values()),
        )
        keep_ids = list(expected_rows.keys())
        ph = ",".join(["?"] * len(keep_ids))
        conn.execute(
            f"DELETE FROM close_trade2 WHERE quick_batch_id=? AND close_id NOT IN ({ph})",
            (AUTO_SUBSIDY_BATCH_ID, *keep_ids),
        )
    else:
        conn.execute("DELETE FROM close_trade2 WHERE quick_batch_id=?", (AUTO_SUBSIDY_BATCH_ID,))

    conn.commit()


def sync_snowball_conversion_records(conn: sqlite3.Connection, as_of_date: Optional[str] = None) -> None:
    """
    同步雪球“折价转期货”映射表（幂等）：
    - 数据来源为全量重算后的结构日度结果；
    - 每个结构保留首次触发折价转期货事件；
    - 采用 upsert + 失效清理，保证重算覆盖。
    """
    structs_raw = fetch_structures(conn)
    prices = fetch_prices(conn)
    if structs_raw.empty or prices.empty:
        conn.execute("DELETE FROM snowball_conversion")
        conn.commit()
        return

    struct_rows, _, _ = compute_ledgers_cached(conn, as_of_date=as_of_date)
    if struct_rows.empty:
        conn.execute("DELETE FROM snowball_conversion")
        conn.commit()
        return

    struct_notional_map: Dict[str, float] = {}
    for _, rr in structs_raw.iterrows():
        try:
            r_res = resolve_structure_row(rr)
        except Exception:
            continue
        if str(r_res.get("strategy_code", "")).upper() != "SNOWBALL":
            continue
        sid = str(r_res.get("structure_id", "")).strip()
        if not sid:
            continue
        p = r_res.get("params", {}) if isinstance(r_res.get("params", {}), dict) else {}
        struct_notional_map[sid] = max(float(pick_first(to_float(p.get("sb_notional_amount")), 0.0) or 0.0), 0.0)

    sb_rows = struct_rows[
        struct_rows["strategy_code"].astype(str).str.upper().eq("SNOWBALL")
    ].copy()
    if sb_rows.empty:
        conn.execute("DELETE FROM snowball_conversion")
        conn.commit()
        return

    sb_rows["flags"] = sb_rows.get("flags", "").fillna("").astype(str)
    sb_rows["status"] = sb_rows.get("status", "").fillna("").astype(str)
    conv_mask = sb_rows["flags"].str.contains("SNOWBALL_DISCOUNT_CONVERT", na=False) | sb_rows["status"].str.contains(
        "雪球折价转期货", na=False
    )
    conv_rows = sb_rows[conv_mask].copy()
    if conv_rows.empty:
        conn.execute("DELETE FROM snowball_conversion")
        conn.commit()
        return

    conv_rows = conv_rows.sort_values(["date", "structure_id"]).groupby("structure_id", as_index=False).first()
    calc_date_s = str(as_of_date or "")
    if not calc_date_s:
        date_ser = conv_rows["date"].astype(str).dropna()
        calc_date_s = str(date_ser.max()) if not date_ser.empty else ""
    now_s = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    expected_rows: Dict[str, Tuple[Any, ...]] = {}
    for _, rr in conv_rows.iterrows():
        sid = str(rr.get("structure_id", "")).strip()
        gid = str(rr.get("group_id", "")).strip()
        und = str(rr.get("underlying", "")).strip()
        kind = str(rr.get("kind", "")).strip().upper()
        dt_s = str(rr.get("date", "")).strip()
        if not sid or not gid or not und or not dt_s or kind not in {"ACC", "DEC"}:
            continue

        conv_qty = max(
            float(
                pick_first(
                    to_float(rr.get("snowball_conversion_qty")),
                    to_float(rr.get("generated_qty")),
                    0.0,
                )
                or 0.0
            ),
            0.0,
        )
        conv_qty = round(conv_qty, 2)
        conv_price = max(
            float(
                pick_first(
                    to_float(rr.get("snowball_conversion_price")),
                    to_float(rr.get("gen_price")),
                    0.0,
                )
                or 0.0
            ),
            0.0,
        )
        if conv_qty <= 1e-12 or conv_price <= 1e-12:
            continue
        notional_amount = struct_notional_map.get(sid, 0.0)
        if notional_amount <= 1e-12:
            notional_amount = conv_qty * conv_price
        conversion_id = f"SNOWBALL_CONV::{sid}::{dt_s}"
        source_status = str(pick_first(rr.get("status"), "雪球折价转期货")).strip() or "雪球折价转期货"
        expected_rows[conversion_id] = (
            conversion_id,
            sid,
            gid,
            und,
            kind,
            dt_s,
            float(conv_qty),
            float(conv_price),
            float(notional_amount),
            source_status,
            calc_date_s,
            now_s,
        )

    if expected_rows:
        conn.executemany(
            """
            INSERT INTO snowball_conversion(
                conversion_id, structure_id, group_id, underlying, kind, trigger_date,
                conversion_qty, conversion_price, notional_amount, source_status, source_calc_date, updated_at
            ) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)
            ON CONFLICT(conversion_id) DO UPDATE SET
                structure_id=excluded.structure_id,
                group_id=excluded.group_id,
                underlying=excluded.underlying,
                kind=excluded.kind,
                trigger_date=excluded.trigger_date,
                conversion_qty=excluded.conversion_qty,
                conversion_price=excluded.conversion_price,
                notional_amount=excluded.notional_amount,
                source_status=excluded.source_status,
                source_calc_date=excluded.source_calc_date,
                updated_at=excluded.updated_at
            """,
            list(expected_rows.values()),
        )
        keep_ids = list(expected_rows.keys())
        ph = ",".join(["?"] * len(keep_ids))
        conn.execute(
            f"DELETE FROM snowball_conversion WHERE conversion_id NOT IN ({ph})",
            tuple(keep_ids),
        )
    else:
        conn.execute("DELETE FROM snowball_conversion")
    conn.commit()


# ---------------------------
# Compute Engine (registry-driven)
# ---------------------------
def _clone_resolved_structure_row(resolved_row: Mapping[str, Any]) -> Dict[str, Any]:
    out = dict(resolved_row) if isinstance(resolved_row, Mapping) else {}
    if not out:
        return out
    if isinstance(out.get("params"), dict):
        out["params"] = dict(out.get("params", {}))
    if isinstance(out.get("meta"), dict):
        out["meta"] = dict(out.get("meta", {}))
    return out


def _prepare_ledger_runtime_structures(structs: pd.DataFrame) -> List[Dict[str, Any]]:
    runtime_rows: List[Dict[str, Any]] = []
    if structs is None or structs.empty:
        return runtime_rows
    for _, raw in structs.iterrows():
        resolved = resolve_structure_row(raw)
        sid = str(resolved.get("structure_id", "")).strip()
        sd = datetime.strptime(str(resolved["start_date"]), DATE_FMT).date()
        ed = datetime.strptime(str(resolved["end_date"]), DATE_FMT).date()
        trade_days = trading_days_between(sd, ed)
        strategy_code = str(resolved.get("strategy_code", "")).upper()
        runtime_rows.append(
            {
                "sid": sid,
                "resolved": resolved,
                "trade_days": trade_days,
                "total_days": int(len(trade_days)),
                "spec": get_structure_spec(strategy_code),
                "strategy_code": strategy_code,
                "is_trs": strategy_code == "TRS",
                "underlying": str(resolved.get("underlying", "")),
                "group_underlying_key": (
                    str(resolved.get("group_id", "")),
                    str(resolved.get("underlying", "")),
                ),
            }
        )
    return runtime_rows


def compute_ledgers(
    conn: sqlite3.Connection,
    as_of_date: Optional[str] = None,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    # 计算核心路径：读缓存原表（不复制），降低大表内存拷贝开销。
    groups = fetch_groups(conn, copy=False)
    structs = fetch_structures(conn, copy=False)
    prices = fetch_prices(conn, copy=False)
    closes = fetch_closes(conn, copy=False)
    closes2 = fetch_closes2(conn, copy=False)

    if structs.empty or prices.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    runtime_structs = _prepare_ledger_runtime_structures(structs)
    if not runtime_structs:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    known_sid_set = {str(rr["sid"]) for rr in runtime_structs if str(rr["sid"]).strip()}
    trs_sid_set = {str(rr["sid"]) for rr in runtime_structs if bool(rr.get("is_trs")) and str(rr["sid"]).strip()}

    dt_vals = prices["dt"].astype(str).tolist() if "dt" in prices.columns else []
    und_vals = prices["underlying"].astype(str).tolist() if "underlying" in prices.columns else []
    settle_vals = pd.to_numeric(prices.get("settle"), errors="coerce").tolist()
    price_map: Dict[Tuple[str, str], float] = {}
    for dt_s, und_s, settle_v in zip(dt_vals, und_vals, settle_vals):
        if pd.isna(settle_v):
            continue
        price_map[(str(dt_s), str(und_s))] = float(settle_v)

    price_dates_series = pd.to_datetime(prices.get("dt"), errors="coerce").dropna().dt.date
    all_date_set: set[date] = set(price_dates_series.tolist())
    if not closes.empty and "dt" in closes.columns:
        close_dates = pd.to_datetime(closes.get("dt"), errors="coerce").dropna().dt.date
        all_date_set |= set(close_dates.tolist())
    if not closes2.empty and "dt" in closes2.columns:
        close2_dates = pd.to_datetime(closes2.get("dt"), errors="coerce").dropna().dt.date
        all_date_set |= set(close2_dates.tolist())
    all_dates_raw = sorted(all_date_set)
    all_dates = [d for d in all_dates_raw if is_trading_day(d)]
    if as_of_date:
        try:
            cutoff = datetime.strptime(str(as_of_date), DATE_FMT).date()
            all_dates = [d for d in all_dates if d <= cutoff]
        except Exception:
            pass
    if not all_dates:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    all_dates_set = set(all_dates)
    runtime_structs_by_date: Dict[date, List[Dict[str, Any]]] = {}
    for runtime_row in runtime_structs:
        for trade_dt in runtime_row.get("trade_days", []):
            if trade_dt in all_dates_set:
                runtime_structs_by_date.setdefault(trade_dt, []).append(runtime_row)

    close_map_by_dt: Dict[str, Dict[Tuple[str, str], List[Dict[str, Any]]]] = {}
    if not closes.empty:
        for rr in closes.itertuples(index=False):
            dt_s = str(getattr(rr, "dt", ""))
            gid_s = str(getattr(rr, "group_id", ""))
            und_s = str(getattr(rr, "underlying", ""))
            rec = {"side": str(getattr(rr, "side", "")), "qty": float(getattr(rr, "qty", 0.0))}
            close_map_by_dt.setdefault(dt_s, {}).setdefault((gid_s, und_s), []).append(rec)

    close2_day_map_by_dt: Dict[str, Dict[Tuple[str, str], float]] = {}
    close2_pos_map_by_dt: Dict[str, Dict[Tuple[str, str], List[Dict[str, Any]]]] = {}
    manual_close_date_map: Dict[str, date] = {}
    manual_reduce_day_map_by_dt: Dict[str, Dict[str, float]] = {}
    if not closes2.empty:
        for rr in closes2.itertuples(index=False):
            dt_s = str(pick_first(getattr(rr, "dt", ""), ""))
            gid_s = str(pick_first(getattr(rr, "group_id", ""), ""))
            und_s = str(pick_first(getattr(rr, "underlying", ""), ""))
            pnl_v = float(pick_first(getattr(rr, "pnl", 0.0), 0.0) or 0.0)
            sid_s = str(pick_first(getattr(rr, "structure_id", ""), "")).strip()
            close_category_s = str(pick_first(getattr(rr, "close_category", ""), "")).strip()
            gk = (gid_s, und_s)

            # 结构已从主表删除时，close_trade2 可能留下历史“孤儿”记录。
            # 这些记录仍可在平仓明细页展示，但不应再参与核心台账口径。
            if sid_s and sid_s != "外部" and sid_s not in known_sid_set:
                continue

            if close_category_s == MANUAL_STRUCT_CLOSE_CATEGORY:
                sid_m = sid_s
                if sid_m and sid_m != "外部":
                    try:
                        d_m = datetime.strptime(dt_s, DATE_FMT).date()
                        prev_m = manual_close_date_map.get(sid_m)
                        if prev_m is None or d_m < prev_m:
                            manual_close_date_map[sid_m] = d_m
                    except Exception:
                        pass
            elif close_category_s == MANUAL_STRUCT_REDUCTION_CATEGORY:
                if sid_s and sid_s != "外部":
                    qty_reduce = max(float(pick_first(to_float(getattr(rr, "qty", 0.0)), 0.0) or 0.0), 0.0)
                    if qty_reduce > 1e-12:
                        manual_reduce_day_map_by_dt.setdefault(dt_s, {})
                        manual_reduce_day_map_by_dt[dt_s][sid_s] = (
                            manual_reduce_day_map_by_dt[dt_s].get(sid_s, 0.0) + qty_reduce
                        )
            if sid_s in trs_sid_set:
                # TRS 不进入结构/套保监控汇总，相关平仓记录不参与 group_state 计算。
                continue
            close2_day_map_by_dt.setdefault(dt_s, {})
            close2_day_map_by_dt[dt_s][gk] = close2_day_map_by_dt[dt_s].get(gk, 0.0) + pnl_v
            is_external = int(pick_first(getattr(rr, "is_external", 0), 0) or 0)
            side = str(pick_first(getattr(rr, "side", ""), "")).upper()
            qty = float(pick_first(getattr(rr, "qty", 0.0), 0.0) or 0.0)
            px = to_float(getattr(rr, "close_price", None))
            if is_external == 0 and side in {"BUY", "SELL"} and qty > 0:
                rec2 = {"side": side, "qty": qty, "price": px}
                close2_pos_map_by_dt.setdefault(dt_s, {}).setdefault(gk, []).append(rec2)

    s_state: Dict[str, Dict[str, Any]] = {
        str(runtime_row["sid"]): {
            "cum_qty": 0.0,
            "cum_pnl": 0.0,
            "cum_subsidy_pnl": 0.0,
            "observed_days": 0,
            "knocked_out": False,
            "terminated": False,
            "manual_closed": False,
        }
        for runtime_row in runtime_structs
    }

    g_state: Dict[Tuple[str, str], Dict[str, float]] = {}
    g_close_pnl: Dict[Tuple[str, str], float] = {}
    g_subsidy_pnl: Dict[Tuple[str, str], float] = {}
    g_snowball_subsidy_pnl: Dict[Tuple[str, str], float] = {}

    def ensure_g(group_id: str, underlying: str) -> Dict[str, float]:
        k = (group_id, underlying)
        if k not in g_state:
            g_state[k] = {
                "long_qty": 0.0,
                "long_value": 0.0,
                "short_qty": 0.0,
                "short_value": 0.0,
                "pos_qty": 0.0,
                "avg_entry": 0.0,
                "realized": 0.0,
                "unrealized": 0.0,
                "total": 0.0,
            }
            g_close_pnl[k] = 0.0
            g_subsidy_pnl[k] = 0.0
            g_snowball_subsidy_pnl[k] = 0.0
        return g_state[k]

    def _apply_manual_trade(gs: Dict[str, float], dpos: float, trade_px: float, calc_realized: bool = True) -> None:
        """
        手工交易（close_trade）口径：
        - 仅手工交易才会触发已实现盈亏；
        - 结构每日生成不参与自动对冲平仓。
        """
        eps = 1e-12
        if abs(dpos) < eps:
            return

        if dpos > 0:
            qty = dpos
            short_qty = float(gs.get("short_qty", 0.0))
            short_val = float(gs.get("short_value", 0.0))
            close_qty = min(short_qty, qty)
            if close_qty > eps and short_qty > eps:
                short_avg = short_val / short_qty
                if calc_realized:
                    gs["realized"] += close_qty * (short_avg - trade_px)
                short_qty -= close_qty
                short_val -= close_qty * short_avg
                qty -= close_qty
            if qty > eps:
                gs["long_qty"] = float(gs.get("long_qty", 0.0)) + qty
                gs["long_value"] = float(gs.get("long_value", 0.0)) + qty * trade_px
            gs["short_qty"] = max(short_qty, 0.0)
            gs["short_value"] = max(short_val, 0.0)
        else:
            qty = -dpos
            long_qty = float(gs.get("long_qty", 0.0))
            long_val = float(gs.get("long_value", 0.0))
            close_qty = min(long_qty, qty)
            if close_qty > eps and long_qty > eps:
                long_avg = long_val / long_qty
                if calc_realized:
                    gs["realized"] += close_qty * (trade_px - long_avg)
                long_qty -= close_qty
                long_val -= close_qty * long_avg
                qty -= close_qty
            if qty > eps:
                gs["short_qty"] = float(gs.get("short_qty", 0.0)) + qty
                gs["short_value"] = float(gs.get("short_value", 0.0)) + qty * trade_px
            gs["long_qty"] = max(long_qty, 0.0)
            gs["long_value"] = max(long_val, 0.0)

        if float(gs.get("long_qty", 0.0)) < eps:
            gs["long_qty"] = 0.0
            gs["long_value"] = 0.0
        if float(gs.get("short_qty", 0.0)) < eps:
            gs["short_qty"] = 0.0
            gs["short_value"] = 0.0

    structure_rows: List[Dict[str, Any]] = []
    group_rows: List[Dict[str, Any]] = []
    bounds_rows: List[Dict[str, Any]] = []
    group_name_map = (
        {
            str(getattr(rr, "group_id", "")): str(getattr(rr, "group_name", ""))
            for rr in groups.itertuples(index=False)
        }
        if not groups.empty
        else {}
    )
    manual_reduce_cum_qty_map: Dict[str, float] = {}

    for dt_ in all_dates:
        dt = dt_.strftime(DATE_FMT)
        for sid_reduce, qty_reduce in manual_reduce_day_map_by_dt.get(dt, {}).items():
            sid_reduce_s = str(sid_reduce).strip()
            if not sid_reduce_s:
                continue
            manual_reduce_cum_qty_map[sid_reduce_s] = (
                manual_reduce_cum_qty_map.get(sid_reduce_s, 0.0)
                + max(float(pick_first(to_float(qty_reduce), 0.0) or 0.0), 0.0)
            )
        day_close_map = close_map_by_dt.get(dt, {})
        day_close2_pos_map = close2_pos_map_by_dt.get(dt, {})
        day_close2_pnl_map = close2_day_map_by_dt.get(dt, {})
        gen_by_group: Dict[Tuple[str, str], Dict[str, float]] = {}
        day_struct_signed_qty: Dict[Tuple[str, str], float] = {}
        day_struct_abs_qty: Dict[Tuple[str, str], float] = {}
        day_struct_subsidy_pnl: Dict[Tuple[str, str], float] = {}
        day_struct_snowball_subsidy_pnl: Dict[Tuple[str, str], float] = {}
        day_struct_option_pnl: Dict[Tuple[str, str], float] = {}
        day_struct_sum: Dict[Tuple[str, str], float] = {}

        # 结构通用主循环：策略逻辑交给 spec.state_machine
        for runtime_row in runtime_structs_by_date.get(dt_, []):
            sid = str(runtime_row["sid"])
            manual_close_d = manual_close_date_map.get(sid)
            if manual_close_d is not None and dt_ >= manual_close_d:
                s_state[sid]["manual_closed"] = True
                continue

            und = str(runtime_row["underlying"])
            pk = (dt, und)
            if pk not in price_map:
                continue

            settle = price_map[pk]
            stt = s_state[sid]
            observed_before = int(stt["observed_days"])
            total_days = int(runtime_row["total_days"])
            remaining_days = max(total_days - observed_before, 0)

            struct_row = _clone_resolved_structure_row(runtime_row["resolved"])
            if manual_reduce_cum_qty_map:
                struct_row = apply_manual_structure_reduction_to_resolved_row(
                    struct_row,
                    manual_reduce_cum_qty_map.get(sid, 0.0),
                )
            spec = runtime_row["spec"]

            day_ctx = {
                "dt": dt_,
                "total_days": total_days,
                "observed_days": observed_before,
                "remaining_days": remaining_days,
                "base_qty": float(struct_row["base_qty_per_day"]),
            }

            # 熔断终止后的结构：仍计 observed_days，但不再生成行
            if stt.get("terminated", False):
                stt["observed_days"] = observed_before + 1
                continue

            sm_res = spec.state_machine(struct_row, settle, day_ctx, stt)
            qty = max(float(sm_res.get("qty", 0.0)), 0.0)
            mult = float(sm_res.get("mult", 0.0))
            status = str(sm_res.get("status", ""))
            flags = [str(x) for x in sm_res.get("flags", []) if str(x)]
            gen_price = float(pick_first(sm_res.get("gen_price"), struct_row.get("strike_price"), settle))
            phoenix_event_type = pick_first_text(sm_res.get("phoenix_event_type"))
            phoenix_terminate_reason = pick_first_text(sm_res.get("phoenix_terminate_reason"))
            phoenix_delivered_side = pick_first_text(sm_res.get("phoenix_delivered_side"))

            if bool(sm_res.get("knocked_out", False)):
                stt["knocked_out"] = True
            if bool(sm_res.get("terminate", False)):
                stt["terminated"] = True

            day_pnl = structure_day_pnl(struct_row["kind"], qty, gen_price, settle)
            day_subsidy_pnl = float(pick_first(sm_res.get("subsidy_pnl"), 0.0) or 0.0)
            day_option_pnl = float(pick_first(sm_res.get("option_pnl"), 0.0) or 0.0)
            day_snowball_coupon_pnl = 0.0
            if str(struct_row.get("strategy_code", "")).upper() == "SNOWBALL":
                coupon_float_now = float(pick_first(to_float(sm_res.get("snowball_coupon_float_pnl")), 0.0) or 0.0)
                coupon_float_prev = float(pick_first(to_float(stt.get("sb_coupon_float_last")), 0.0) or 0.0)
                day_snowball_coupon_pnl = max(coupon_float_now - coupon_float_prev, 0.0)
                stt["sb_coupon_float_last"] = max(coupon_float_now, 0.0)
                day_subsidy_pnl += day_snowball_coupon_pnl
                # 雪球正向票息按补贴口径计入；负向到期亏损仍保留在 option_pnl 口径。
                if day_option_pnl > 0:
                    day_option_pnl = 0.0
            day_pnl += day_option_pnl
            stt["cum_qty"] += qty
            stt["cum_pnl"] += day_pnl
            stt["cum_subsidy_pnl"] += day_subsidy_pnl
            stt["observed_days"] = observed_before + 1
            observed_days_now = int(stt["observed_days"])
            observed_generated_qty = float(stt["cum_qty"])
            remaining_days_now = max(total_days - observed_days_now, 0)
            raw_status = pick_first_text(phoenix_event_type, status)
            normalized_status = normalize_structure_status(raw_status)
            status_cn = status_to_cn(raw_status, qty, mult)

            structure_rows.append(
                {
                    "date": dt,
                    "settle": settle,
                    "group_id": struct_row["group_id"],
                    "structure_id": struct_row["structure_id"],
                    "name": struct_row["name"],
                    "underlying": struct_row["underlying"],
                    "risk_party": struct_row["risk_party"],
                    "kind": struct_row["kind"],
                    "strategy_code": struct_row["strategy_code"],
                    "entry_price": struct_row["entry_price"],
                    "strike_price": struct_row["strike_price"],
                    "trade_date": struct_row.get("trade_date"),
                    "expiry_date": struct_row.get("expiry_date"),
                    "option_type": struct_row.get("option_type"),
                    "side": struct_row.get("side"),
                    "premium": struct_row.get("premium"),
                    "customer_name": struct_row.get("customer_name"),
                    "counterparty": struct_row.get("counterparty"),
                    "contract_month": struct_row.get("contract_month"),
                    "note": struct_row.get("note"),
                    "barrier_in": struct_row["barrier_in"],
                    "barrier_out": struct_row["barrier_out"],
                    "knock_out_price": struct_row["knock_out_price"],
                    "ko_strike_price": struct_row["ko_strike_price"],
                    "status": status_cn,
                    "raw_status": raw_status,
                    "normalized_status": normalized_status,
                    "status_cn": status_cn,
                    "multiplier": mult,
                    "generated_qty": qty,
                    "cum_qty": stt["cum_qty"],
                    "day_pnl": day_pnl,
                    "cum_pnl": stt["cum_pnl"],
                    "day_subsidy_pnl": day_subsidy_pnl,
                    "cum_subsidy_pnl": stt["cum_subsidy_pnl"],
                    "day_option_pnl": day_option_pnl,
                    "gen_price": gen_price,
                    "total_trading_days": total_days,
                    "observed_trading_days": observed_days_now,
                    "remaining_trading_days": remaining_days_now,
                    "observed_generated_qty": observed_generated_qty,
                    "flags": "|".join(flags),
                    "event_type": phoenix_event_type,
                    "terminate_reason": phoenix_terminate_reason,
                    "delivered_side": phoenix_delivered_side,
                    "snowball_phase": str(pick_first(sm_res.get("snowball_phase"), "")),
                    "snowball_coupon_pct": float(pick_first(sm_res.get("snowball_coupon_pct"), 0.0) or 0.0),
                    "snowball_current_ko_price": to_float(sm_res.get("snowball_current_ko_price")),
                    "snowball_knocked_in": 1 if _bool_from_any(sm_res.get("snowball_knocked_in"), False) else 0,
                    "snowball_first_ki_date": str(pick_first(sm_res.get("snowball_first_ki_date"), "")),
                    "snowball_discount_date": str(pick_first(sm_res.get("snowball_discount_date"), "")),
                    "snowball_conversion_qty": float(pick_first(sm_res.get("snowball_conversion_qty"), 0.0) or 0.0),
                    "snowball_conversion_price": float(pick_first(sm_res.get("snowball_conversion_price"), 0.0) or 0.0),
                    "snowball_coupon_float_pnl": float(pick_first(sm_res.get("snowball_coupon_float_pnl"), 0.0) or 0.0),
                    "snowball_futures_float_pnl": float(pick_first(sm_res.get("snowball_futures_float_pnl"), 0.0) or 0.0),
                }
            )

            # TRS 仅进入头寸仓库与风险敞口，不进入结构/套保监控的日度汇总口径。
            if not bool(runtime_row.get("is_trs")):
                gk = runtime_row["group_underlying_key"]
                acc = gen_by_group.setdefault(gk, {"signed_qty": 0.0, "signed_value": 0.0})
                sq = kind_to_signed(struct_row["kind"], qty)
                acc["signed_qty"] += sq
                acc["signed_value"] += sq * gen_price
                day_struct_signed_qty[gk] = day_struct_signed_qty.get(gk, 0.0) + sq
                day_struct_abs_qty[gk] = day_struct_abs_qty.get(gk, 0.0) + abs(qty)
                day_struct_subsidy_pnl[gk] = day_struct_subsidy_pnl.get(gk, 0.0) + day_subsidy_pnl
                day_struct_snowball_subsidy_pnl[gk] = (
                    day_struct_snowball_subsidy_pnl.get(gk, 0.0) + day_snowball_coupon_pnl
                )
                day_struct_option_pnl[gk] = day_struct_option_pnl.get(gk, 0.0) + day_option_pnl
                day_struct_sum[gk] = day_struct_sum.get(gk, 0.0) + day_pnl

                ensure_g(struct_row["group_id"], struct_row["underlying"])

        for gid, und in day_close_map.keys():
            ensure_g(gid, und)
        for gid, und in day_close2_pos_map.keys():
            ensure_g(gid, und)
        for gid, und in day_close2_pnl_map.keys():
            ensure_g(gid, und)

        # apply generation（不自动平仓：仅累计进仓库）
        for (gid, und), gen in gen_by_group.items():
            gs = ensure_g(gid, und)
            dpos = gen["signed_qty"]
            if abs(dpos) < 1e-12:
                continue
            trade_px = gen["signed_value"] / dpos
            if dpos > 0:
                gs["long_qty"] = float(gs.get("long_qty", 0.0)) + dpos
                gs["long_value"] = float(gs.get("long_value", 0.0)) + dpos * trade_px
            else:
                q = -dpos
                gs["short_qty"] = float(gs.get("short_qty", 0.0)) + q
                gs["short_value"] = float(gs.get("short_value", 0.0)) + q * trade_px

        # apply close_trade at settle（手工平仓口径）
        for (gid, und), clist in day_close_map.items():
            pk = (dt, und)
            if pk not in price_map:
                continue
            settle = price_map[pk]
            gs = ensure_g(gid, und)

            for c in clist:
                dpos = close_to_signed(c["side"], c["qty"])
                if abs(dpos) < 1e-12:
                    continue
                trade_px = settle
                _apply_manual_trade(gs, dpos, trade_px, calc_realized=True)

        # apply close_trade2 的结构平仓数量（仅改仓位，不重复计算已实现盈亏）
        for (gid, und), clist in day_close2_pos_map.items():
            pk = (dt, und)
            settle = to_float(price_map.get(pk))
            gs = ensure_g(gid, und)
            for c in clist:
                dpos = close_to_signed(c["side"], c["qty"])
                if abs(dpos) < 1e-12:
                    continue
                trade_px_raw = to_float(c.get("price"))
                if trade_px_raw is None:
                    trade_px_raw = settle
                trade_px = float(pick_first(trade_px_raw, 0.0))
                _apply_manual_trade(gs, dpos, trade_px, calc_realized=False)

        # MTM
        for (gid, und), gs in g_state.items():
            pk = (dt, und)
            if pk not in price_map:
                continue
            settle = price_map[pk]
            long_qty = float(gs.get("long_qty", 0.0))
            long_val = float(gs.get("long_value", 0.0))
            short_qty = float(gs.get("short_qty", 0.0))
            short_val = float(gs.get("short_value", 0.0))

            long_avg = (long_val / long_qty) if long_qty > 1e-12 else 0.0
            short_avg = (short_val / short_qty) if short_qty > 1e-12 else 0.0

            gs["pos_qty"] = long_qty - short_qty
            if abs(gs["pos_qty"]) > 1e-12:
                gs["avg_entry"] = (long_val - short_val) / gs["pos_qty"]
            else:
                gs["avg_entry"] = 0.0

            gs["unrealized"] = long_qty * (settle - long_avg) + short_qty * (short_avg - settle)
            gs["total"] = gs["realized"] + gs["unrealized"]

        for (gid, und), _ in g_state.items():
            g_close_pnl[(gid, und)] = (
                g_close_pnl.get((gid, und), 0.0)
                + day_close2_pnl_map.get((gid, und), 0.0)
                + day_struct_option_pnl.get((gid, und), 0.0)
            )

        for (gid, und), gs in sorted(g_state.items()):
            pk = (dt, und)
            if pk not in price_map:
                continue
            settle = price_map[pk]
            g_subsidy_pnl[(gid, und)] = g_subsidy_pnl.get((gid, und), 0.0) + day_struct_subsidy_pnl.get((gid, und), 0.0)
            g_snowball_subsidy_pnl[(gid, und)] = (
                g_snowball_subsidy_pnl.get((gid, und), 0.0) + day_struct_snowball_subsidy_pnl.get((gid, und), 0.0)
            )

            gen_signed = gen_by_group.get((gid, und), {}).get("signed_qty", 0.0)
            close_signed = 0.0
            for c in day_close_map.get((gid, und), []):
                close_signed += close_to_signed(c["side"], c["qty"])

            group_rows.append(
                {
                    "date": dt,
                    "group_id": gid,
                    "group_name": group_name_map.get(gid, ""),
                    "underlying": und,
                    "settle": settle,
                    "generated_signed_qty": gen_signed,
                    "struct_gen_signed_qty": day_struct_signed_qty.get((gid, und), 0.0),
                    "struct_gen_abs_qty": day_struct_abs_qty.get((gid, und), 0.0),
                    "close_signed_qty": close_signed,
                    "net_pos_qty": gs["pos_qty"],
                    "avg_entry": gs["avg_entry"],
                    "realized_pnl": gs["realized"],
                    "unrealized_pnl": gs["unrealized"],
                    "day_subsidy_pnl": day_struct_subsidy_pnl.get((gid, und), 0.0),
                    "subsidy_pnl": g_subsidy_pnl.get((gid, und), 0.0),
                    "close_pnl": g_close_pnl.get((gid, und), 0.0),
                    "floating_pnl": gs["unrealized"],
                    # close_pnl 已包含自动生成的“熔断补贴平仓”记录；雪球票息按补贴口径单独并入总盈亏。
                    "total_pnl": (
                        gs["realized"]
                        + gs["unrealized"]
                        + g_close_pnl.get((gid, und), 0.0)
                        + g_snowball_subsidy_pnl.get((gid, und), 0.0)
                    ),
                    "structure_day_pnl_sum": day_struct_sum.get((gid, und), 0.0),
                }
            )

    # bounds（默认由 spec.bounds 驱动）
    bounds_reduce_asof_date = parse_date_maybe(as_of_date) if as_of_date else None
    if bounds_reduce_asof_date is None and all_dates:
        bounds_reduce_asof_date = all_dates[-1]
    manual_reduce_qty_map_bounds = build_manual_structure_reduction_qty_map(
        closes2,
        as_of_date=bounds_reduce_asof_date,
    )
    for runtime_row in runtime_structs:
        sid = str(runtime_row["sid"])
        struct_row = _clone_resolved_structure_row(runtime_row["resolved"])
        if manual_reduce_qty_map_bounds:
            struct_row = apply_manual_structure_reduction_to_resolved_row(
                struct_row,
                manual_reduce_qty_map_bounds.get(sid, 0.0),
            )
        spec = runtime_row["spec"]
        stt = s_state.get(
            sid,
            {"cum_qty": 0.0, "observed_days": 0, "terminated": False, "knocked_out": False, "manual_closed": False},
        )

        total_days = int(runtime_row["total_days"])
        observed_days = int(stt.get("observed_days", 0))
        remaining_days = max(total_days - observed_days, 0)
        # 熔断终止后，剩余交易日口径固定为 0（已一次性补齐后续头寸）
        if bool(stt.get("terminated", False)) or bool(stt.get("knocked_out", False)):
            remaining_days = 0
        if bool(stt.get("sb_discount_triggered", False)):
            remaining_days = 0
        if bool(stt.get("manual_closed", False)):
            remaining_days = 0
        observed_generated_qty = float(stt.get("cum_qty", 0.0))

        bres = spec.bounds(struct_row, remaining_days, observed_days, observed_generated_qty, stt)
        rem_min_abs = max(float(bres.get("remaining_min_qty", 0.0)), 0.0)
        rem_max_abs = max(float(bres.get("remaining_max_qty", 0.0)), 0.0)
        if rem_min_abs > rem_max_abs:
            rem_min_abs, rem_max_abs = rem_max_abs, rem_min_abs

        exposure_min_qty = observed_generated_qty + rem_min_abs
        exposure_max_qty = observed_generated_qty + rem_max_abs

        bounds_rows.append(
            {
                "level": "STRUCTURE",
                "group_id": struct_row["group_id"],
                "structure_id": struct_row["structure_id"],
                "name": struct_row["name"],
                "underlying": struct_row["underlying"],
                "kind": struct_row["kind"],
                "strategy_code": struct_row["strategy_code"],
                "total_trading_days": total_days,
                "observed_trading_days": observed_days,
                "remaining_trading_days": remaining_days,
                "observed_generated_qty": observed_generated_qty,
                "remaining_min_qty": rem_min_abs,
                "remaining_max_qty": rem_max_abs,
                "exposure_min_qty": exposure_min_qty,
                "exposure_max_qty": exposure_max_qty,
            }
        )

    struct_bounds_df = pd.DataFrame(bounds_rows)
    gb: List[Dict[str, Any]] = []
    if not struct_bounds_df.empty:
        for (gid, und), sub in struct_bounds_df.groupby(["group_id", "underlying"]):
            observed_generated_signed_sum = 0.0
            remaining_min_signed_sum = 0.0
            remaining_max_signed_sum = 0.0
            exposure_min_signed_sum = 0.0
            exposure_max_signed_sum = 0.0
            for _, r in sub.iterrows():
                sgn = 1.0 if str(r.get("kind", "")).upper() == "ACC" else -1.0
                observed_generated_signed_sum += sgn * float(r.get("observed_generated_qty", 0.0))
                remaining_min_signed_sum += sgn * float(r.get("remaining_min_qty", 0.0))
                remaining_max_signed_sum += sgn * float(r.get("remaining_max_qty", 0.0))
                exposure_min_signed_sum += sgn * float(r.get("exposure_min_qty", 0.0))
                exposure_max_signed_sum += sgn * float(r.get("exposure_max_qty", 0.0))
            gb.append(
                {
                    "level": "GROUP",
                    "group_id": gid,
                    "structure_id": "",
                    "name": "GROUP_SUM",
                    "underlying": und,
                    "kind": "NET",
                    "strategy_code": "SUM",
                    "total_trading_days": "-",
                    "observed_trading_days": "-",
                    "remaining_trading_days": "-",
                    "observed_generated_signed_sum": observed_generated_signed_sum,
                    "remaining_min_signed_sum": remaining_min_signed_sum,
                    "remaining_max_signed_sum": remaining_max_signed_sum,
                    "exposure_min_signed_sum": exposure_min_signed_sum,
                    "exposure_max_signed_sum": exposure_max_signed_sum,
                    # 兼容旧列名（仍提供，避免 UI 断裂）
                    "observed_generated_qty": observed_generated_signed_sum,
                    "remaining_min_qty": remaining_min_signed_sum,
                    "remaining_max_qty": remaining_max_signed_sum,
                    "exposure_min_qty": exposure_min_signed_sum,
                    "exposure_max_qty": exposure_max_signed_sum,
                }
            )

    bounds_df = pd.concat([struct_bounds_df, pd.DataFrame(gb)], ignore_index=True)
    return pd.DataFrame(structure_rows), pd.DataFrame(group_rows), bounds_df


_LEDGER_MEMO_CACHE: Dict[
    Tuple[str, str, Tuple[int, int, int, int, int]],
    Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame],
] = {}
_LEDGER_MEMO_CACHE_MAX = 48
_SPECIAL_HISTORY_FILE_MEMO_CACHE: Dict[str, pd.DataFrame] = {}
_SPECIAL_HISTORY_FETCH_MEMO_CACHE: Dict[Tuple[str, str, str], Dict[str, Any]] = {}
_PROBEXP_MC_RESULT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_WINRATE_MC_RESULT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_WINRATE_HISTORY_RESULT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_WINRATE_ACC_HISTORY_RESULT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_SPECIAL_SNAPSHOT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_SPECIAL_PAGE_UI_MEMO_CACHE: Dict[str, Any] = {}
_SPECIAL_PAGE_PREWARM_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_AK_REALTIME_QUOTE_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_SPECIAL_HISTORY_META_FILE_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_STRUCT_DERIVED_MEMO_CACHE: Dict[Any, Any] = {}
_MONITOR_UI_MEMO_CACHE: Dict[str, pd.DataFrame] = {}
_MONITOR_SCOPE_META_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_MONITOR_GAP_SCOPE_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_OPEN_LOT_MEMO_CACHE: Dict[Any, pd.DataFrame] = {}
_PRICE_GAP_MEMO_CACHE: Dict[Any, pd.DataFrame] = {}
_MONITOR_REPORT_MEMO_CACHE: Dict[str, Dict[str, Any]] = {}
_REPORT_IMAGE_MEMO_CACHE: Dict[str, bytes] = {}
_SPECIAL_CACHE_LIMIT = 24
_CORE_SYNC_LAST_TOKEN_PROCESS: Optional[Tuple[int, int, int, int]] = None


def compute_ledgers_cached(
    conn: sqlite3.Connection,
    as_of_date: Optional[str] = None,
    *,
    copy_out: bool = True,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    """
    统一计算入口：同一次运行内对同连接+同截止日复用结果，避免重复重算。
    使用 conn.total_changes + 数据文件版本号 作为写入版本号，确保跨进程写入后自动失效。
    """
    as_of_key = str(as_of_date or "").strip()
    change_token = int(pick_first(getattr(conn, "total_changes", 0), 0) or 0)
    main_db_path = _connection_main_db_path(conn)
    cache_ns = main_db_path if main_db_path else _connection_cache_namespace(conn)
    db_token = _connection_db_version_token(conn)
    version_token = (change_token, *db_token)
    key = (cache_ns, as_of_key, version_token)
    use_session_cache = bool(main_db_path)
    session_cache = _session_runtime_cache_bucket(_SESSION_LEDGER_MEMO_CACHE_KEY) if use_session_cache else {}
    payload = session_cache.get(key) if use_session_cache else None
    if not (
        isinstance(payload, tuple)
        and len(payload) == 3
        and all(isinstance(item, pd.DataFrame) for item in payload)
    ):
        payload = _LEDGER_MEMO_CACHE.get(key)
    if not (
        isinstance(payload, tuple)
        and len(payload) == 3
        and all(isinstance(item, pd.DataFrame) for item in payload)
    ):
        payload = compute_ledgers(conn, as_of_date=as_of_key or None)
        _memo_cache_put(_LEDGER_MEMO_CACHE, key, payload, limit=_LEDGER_MEMO_CACHE_MAX)
        if use_session_cache:
            _memo_cache_put(session_cache, key, payload, limit=_LEDGER_MEMO_CACHE_MAX)
    s_df, g_df, b_df = payload
    if not bool(copy_out):
        return s_df, g_df, b_df
    return s_df.copy(), g_df.copy(), b_df.copy()


@dataclass
class SpecialPagePerfCollector:
    page_name: str
    started_at: float
    checkpoint_at: float
    rows: List[Dict[str, Any]]

    def checkpoint(self, step: str, *, category: str = "render", note: str = "") -> None:
        now = time.perf_counter()
        self.rows.append(
            {
                "页面": str(self.page_name),
                "步骤": str(step),
                "类别": str(category),
                "耗时(ms)": float((now - self.checkpoint_at) * 1000.0),
                "累计(ms)": float((now - self.started_at) * 1000.0),
                "说明": str(note or ""),
            }
        )
        self.checkpoint_at = now

    def record_duration(self, step: str, elapsed_s: float, *, category: str = "compute", note: str = "") -> None:
        now = time.perf_counter()
        self.rows.append(
            {
                "页面": str(self.page_name),
                "步骤": str(step),
                "类别": str(category),
                "耗时(ms)": float(max(elapsed_s, 0.0) * 1000.0),
                "累计(ms)": float((now - self.started_at) * 1000.0),
                "说明": str(note or ""),
            }
        )
        self.checkpoint_at = now

    def to_frame(self) -> pd.DataFrame:
        if not self.rows:
            return pd.DataFrame(columns=["页面", "步骤", "类别", "耗时(ms)", "累计(ms)", "说明"])
        return pd.DataFrame(self.rows)


def special_page_perf_start(page_name: str) -> SpecialPagePerfCollector:
    now = time.perf_counter()
    return SpecialPagePerfCollector(page_name=str(page_name), started_at=now, checkpoint_at=now, rows=[])


