def probexp_is_accumulator_structure(struct_row: Mapping[str, Any]) -> bool:
    strategy_code = resolve_strategy_code_for_display(struct_row.get("strategy_code", ""))
    fallback_name = str(pick_first(struct_row.get("name"), "")).strip()
    name_norm = default_structure_name(strategy_code, struct_row.get("kind", ""), fallback_name=fallback_name)
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    meta_tags = [
        meta.get("tag"),
        meta.get("tags"),
        meta.get("label"),
        meta.get("structure_label"),
        struct_row.get("label"),
        struct_row.get("structure"),
    ]
    text_pool = " ".join(
        [
            str(strategy_code or ""),
            str(fallback_name or ""),
            str(name_norm or ""),
            str(STRATEGY_CODE_TO_CN.get(strategy_code, "") or ""),
            " ".join(str(x) for x in meta_tags if x is not None),
        ]
    )
    return (strategy_code in ACCUMULATOR_STRATEGY_CODES) or any(token in text_pool for token in ["累计", "累购", "累沽"])


def probexp_infer_initial_target_qty(struct_row: Mapping[str, Any], total_days: int) -> float:
    params = struct_row.get("params", {}) if isinstance(struct_row.get("params", {}), dict) else {}
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    total_cap = pick_first(
        to_float(struct_row.get("total_cap_qty")),
        to_float(params.get("total_cap_qty")),
        to_float(meta.get("total_cap_qty")),
    )
    if total_cap is not None and float(total_cap) > 1e-12:
        return float(total_cap)
    base_qty = max(float(pick_first(to_float(struct_row.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    return base_qty * max(int(total_days), 0)


def probexp_underlying_product_code(underlying: Any) -> str:
    txt = _normalize_underlying_symbol(underlying)
    if not txt:
        return ""
    txt = txt.split(".", 1)[0]
    m = re.match(r"^([A-Z]{1,4})", txt)
    return str(m.group(1)).upper() if m else txt.upper()


def probexp_underlying_series(underlying: Any) -> str:
    txt = _normalize_underlying_symbol(underlying)
    if not txt:
        return ""
    txt = txt.split(".", 1)[0]
    m = re.match(r"^([A-Z]{1,4}\d{3,4})", txt)
    return str(m.group(1)).upper() if m else txt.upper()


def probexp_extract_contract_series(contract_text: Any) -> str:
    txt = str(pick_first(contract_text, "") or "").strip().upper()
    if not txt:
        return ""
    m = re.search(r"([A-Z]{1,4}\d{3,4})", txt)
    return str(m.group(1)).upper() if m else ""


def probexp_extract_strike_from_contract(contract_text: Any) -> Optional[float]:
    txt = str(pick_first(contract_text, "") or "").strip().upper()
    if not txt:
        return None
    patterns = [
        r"[CP][\-_]?(\d+(?:\.\d+)?)$",
        r"-(\d+(?:\.\d+)?)$",
    ]
    for pattern in patterns:
        m = re.search(pattern, txt)
        if m:
            return to_float(m.group(1))
    return None


def probexp_underlying_exp_month(underlying: Any, rep_date: Any) -> str:
    series = probexp_underlying_series(underlying)
    product = probexp_underlying_product_code(underlying)
    if (not series) or (not product):
        return ""
    suffix = series[len(product) :]
    if (not suffix.isdigit()) or len(suffix) not in (3, 4):
        return ""
    if len(suffix) == 4:
        yy = int(suffix[:2])
        mm = int(suffix[2:])
        if 1 <= mm <= 12:
            return f"{2000 + yy:04d}{mm:02d}"
        return ""
    rep_date_obj = parse_date_maybe(rep_date)
    ref_year = rep_date_obj.year if isinstance(rep_date_obj, date) else date.today().year
    year_digit = int(suffix[0])
    mm = int(suffix[1:])
    if not 1 <= mm <= 12:
        return ""
    target_month = ref_year * 12 + (rep_date_obj.month if isinstance(rep_date_obj, date) else date.today().month)
    candidate_years = [yy for yy in range(ref_year - 5, ref_year + 6) if yy % 10 == year_digit]
    if not candidate_years:
        candidate_years = [ref_year]
    best_year = min(
        candidate_years,
        key=lambda yy: (
            abs((yy * 12 + mm) - target_month),
            0 if (yy * 12 + mm) >= target_month - 1 else 1,
            yy,
        ),
    )
    return f"{best_year:04d}{mm:02d}"


def probexp_is_month_contract(symbol: Any) -> bool:
    route = parse_futures_symbol(symbol)
    return bool(route.ok and str(route.input_type) == "specific_contract" and str(route.contract_code or "").strip())


def probexp_normalize_month_contract_symbol(symbol: Any, rep_date: Any) -> str:
    route = parse_futures_symbol(symbol)
    if (not route.ok) or str(route.input_type) != "specific_contract":
        return ""
    product_code = str(route.product_code or "").strip().upper()
    exp_month = probexp_underlying_exp_month(str(route.contract_code or route.normalized_input or ""), rep_date)
    if product_code and exp_month:
        return f"{product_code}{exp_month[-4:]}"
    return str(route.contract_code or "").strip().upper()


def probexp_collect_candidate_month_contracts(
    structure_candidates: Any,
    *,
    rep_date: Any,
    product_code: str = "",
) -> List[str]:
    items: List[Any] = []
    if structure_candidates is None:
        return []
    if isinstance(structure_candidates, pd.DataFrame):
        items = structure_candidates.to_dict("records")
    elif isinstance(structure_candidates, Mapping):
        if any(k in structure_candidates for k in ["resolved", "underlying", "structure_id"]):
            items = [structure_candidates]
        else:
            items = list(structure_candidates.values())
    elif isinstance(structure_candidates, Iterable) and not isinstance(structure_candidates, (str, bytes)):
        items = list(structure_candidates)
    else:
        items = [structure_candidates]

    target_product = str(product_code or "").strip().upper()
    out: List[str] = []
    for item in items:
        raw_underlying = ""
        if isinstance(item, pd.Series):
            item = item.to_dict()
        if isinstance(item, Mapping):
            resolved = item.get("resolved") if isinstance(item.get("resolved"), Mapping) else {}
            raw_underlying = str(
                pick_first(
                    resolved.get("underlying") if isinstance(resolved, Mapping) else "",
                    item.get("underlying"),
                )
                or ""
            ).strip()
        else:
            raw_underlying = str(pick_first(item, "") or "").strip()
        contract_code = probexp_normalize_month_contract_symbol(raw_underlying, rep_date)
        if not contract_code:
            continue
        if target_product and probexp_underlying_product_code(contract_code) != target_product:
            continue
        out.append(contract_code)
    return sorted(list(dict.fromkeys([str(x).strip().upper() for x in out if str(x).strip()])))


def probexp_resolve_iv_contract_underlying(
    resolved_underlying: Any,
    *,
    api_symbol_input: Any = "",
    structure_candidates: Any = None,
    selected_sid: Any = "",
    rep_date: Any = "",
) -> Dict[str, Any]:
    base_hint = _normalize_underlying_symbol(resolved_underlying) or _normalize_underlying_symbol(api_symbol_input) or "I.DCE"
    selected_sid_text = str(pick_first(selected_sid, "") or "").strip()

    resolved_contract = probexp_normalize_month_contract_symbol(resolved_underlying, rep_date)
    if resolved_contract:
        return {
            "ok": True,
            "iv_underlying": resolved_contract,
            "contract_code": resolved_contract,
            "resolution_source": "resolved_underlying",
            "resolution_source_label": "当前分析结构 underlying",
            "reason": f"来源：当前分析结构 underlying -> {resolved_contract}",
            "selected_sid": selected_sid_text,
        }

    api_contract = probexp_normalize_month_contract_symbol(api_symbol_input, rep_date)
    if api_contract:
        return {
            "ok": True,
            "iv_underlying": api_contract,
            "contract_code": api_contract,
            "resolution_source": "history_symbol_input",
            "resolution_source_label": "历史价格代码输入",
            "reason": f"来源：历史价格代码输入 -> {api_contract}",
            "selected_sid": selected_sid_text,
        }

    target_product = (
        probexp_underlying_product_code(resolved_underlying)
        or probexp_underlying_product_code(api_symbol_input)
    )
    candidate_contracts = probexp_collect_candidate_month_contracts(
        structure_candidates,
        rep_date=rep_date,
        product_code=target_product,
    )
    if len(candidate_contracts) == 1:
        picked = str(candidate_contracts[0]).strip().upper()
        return {
            "ok": True,
            "iv_underlying": picked,
            "contract_code": picked,
            "resolution_source": "structure_candidates",
            "resolution_source_label": "当前结构集唯一具体月份合约",
            "reason": f"来源：当前结构集唯一具体月份合约 -> {picked}",
            "selected_sid": selected_sid_text,
            "candidate_contracts": candidate_contracts,
        }

    if len(candidate_contracts) > 1:
        return {
            "ok": False,
            "iv_underlying": "",
            "contract_code": "",
            "resolution_source": "ambiguous_structure_candidates",
            "resolution_source_label": "当前结构集存在多个具体月份合约",
            "reason": (
                f"当前 underlying 为主力/连续语义（如 {base_hint}），当前结构集存在多个具体月份合约："
                f"{'、'.join(candidate_contracts)}，请输入或绑定具体月份合约（如 I2609）。"
            ),
            "selected_sid": selected_sid_text,
            "candidate_contracts": candidate_contracts,
        }

    return {
        "ok": False,
        "iv_underlying": "",
        "contract_code": "",
        "resolution_source": "no_specific_contract",
        "resolution_source_label": "未能解析具体月份合约",
        "reason": f"当前 underlying 为主力/连续语义（如 {base_hint}），未能解析具体期权月份，请输入或绑定具体月份合约（如 I2609）。",
        "selected_sid": selected_sid_text,
        "candidate_contracts": [],
    }


def probexp_fetch_json_via_http(url: str, *, timeout: float = 10.0) -> Any:
    req = urllib_request.Request(
        url,
        headers={
            "User-Agent": (
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/135.0.0.0 Safari/537.36"
            ),
            "Accept": "application/json,text/plain,*/*",
        },
    )
    with urllib_request.urlopen(req, timeout=timeout) as resp:
        charset = resp.headers.get_content_charset() or "utf-8"
        raw = resp.read()
    return json.loads(raw.decode(charset, errors="replace"))


def probexp_extract_openvlab_dto_atm_iv(
    payload: Mapping[str, Any],
    *,
    underlying_series: str,
    current_close: float,
) -> Dict[str, Any]:
    out = {
        "ok": False,
        "atm_iv": None,
        "contract": "",
        "strike": None,
        "skew": None,
        "reason": "OpenVlab 期权链未返回可用 ATM IV",
    }
    result = payload.get("result") if isinstance(payload, Mapping) else None
    context = result.get("context") if isinstance(result, Mapping) else None
    chain_map = context.get("c") if isinstance(context, Mapping) else None
    if not isinstance(chain_map, Mapping) or not chain_map:
        return out
    series_key = str(underlying_series or "").upper().strip()
    chain = chain_map.get(series_key) if series_key else None
    if not isinstance(chain, Mapping):
        for key, value in chain_map.items():
            if str(key).upper().strip() == series_key:
                chain = value
                break
    if not isinstance(chain, Mapping):
        if len(chain_map) == 1:
            chain = next(iter(chain_map.values()))
        else:
            return out
    strikes_map = chain.get("s") if isinstance(chain, Mapping) else None
    if not isinstance(strikes_map, Mapping) or not strikes_map:
        return out
    rows: List[Dict[str, Any]] = []
    for strike_txt, pair in strikes_map.items():
        if not isinstance(pair, Mapping):
            continue
        strike = to_float(strike_txt)
        if strike is None:
            strike = to_float(pair.get("strike"))
        if strike is None:
            continue
        iv_list: List[float] = []
        contracts: List[str] = []
        oi_sum = 0.0
        vol_sum = 0.0
        for side_key in ["c", "p"]:
            leg = pair.get(side_key)
            if not isinstance(leg, Mapping):
                continue
            leg_iv = to_float(leg.get("iv"))
            if leg_iv is not None and float(leg_iv) > 1e-12:
                iv_list.append(float(leg_iv))
            leg_contract = str(pick_first(leg.get("cc"), "") or "").strip()
            if leg_contract:
                contracts.append(leg_contract)
            oi_sum += float(pick_first(to_float(leg.get("o")), 0.0) or 0.0)
            vol_sum += float(pick_first(to_float(leg.get("v")), 0.0) or 0.0)
        if not iv_list:
            continue
        rows.append(
            {
                "strike": float(strike),
                "atm_gap": abs(float(strike) - float(current_close)),
                "atm_iv": float(np.mean(iv_list)),
                "oi": float(oi_sum),
                "vol": float(vol_sum),
                "score": float(oi_sum + vol_sum),
                "contract": " / ".join(contracts[:2]),
            }
        )
    if not rows:
        return out
    work = pd.DataFrame(rows)
    min_gap = float(work["atm_gap"].min())
    atm_pool = work[np.isclose(work["atm_gap"], min_gap, atol=1e-9)].copy()
    if atm_pool.empty:
        atm_pool = work.sort_values(["atm_gap", "score", "oi", "vol"], ascending=[True, False, False, False]).head(1).copy()
    atm_pool = atm_pool.sort_values(["score", "oi", "vol"], ascending=[False, False, False]).copy()
    pick_row = atm_pool.iloc[0]
    atm_iv = float(pd.to_numeric(atm_pool.get("atm_iv"), errors="coerce").fillna(0.0).mean())
    if atm_iv <= 1e-12:
        return out
    return {
        "ok": True,
        "atm_iv": float(atm_iv),
        "contract": str(pick_first(pick_row.get("contract"), "") or "").strip(),
        "strike": float(pick_first(to_float(pick_row.get("strike")), 0.0) or 0.0),
        "skew": None,
        "reason": "",
    }


def probexp_fetch_openvlab_atm_iv(
    *,
    underlying: Any,
    rep_date: str,
    current_close: Any,
) -> Dict[str, Any]:
    empty = {
        "ok": False,
        "atm_iv": None,
        "source": "",
        "reason": "OpenVlab 自动 IV 暂不可用",
        "contract": "",
        "strike": None,
        "skew": None,
    }
    current_close_num = to_float(current_close)
    if current_close_num is None or float(current_close_num) <= 1e-12:
        out = dict(empty)
        out["reason"] = "缺少当前价格"
        return out
    product_code = probexp_underlying_product_code(underlying)
    exp_month = probexp_underlying_exp_month(underlying, rep_date)
    underlying_series = probexp_underlying_series(underlying)
    if (not product_code) or (not exp_month):
        out = dict(empty)
        out["reason"] = "OpenVlab 未能解析当前结构的合约月份"
        return out
    contract_code = f"{product_code}{exp_month[-4:]}"
    cache_key = (f"{product_code}|{exp_month}", str(rep_date))
    cached = _PROBEXP_OPENVLAB_IV_CACHE.get(cache_key)
    if isinstance(cached, dict):
        return dict(cached)
    indicator_url = f"{PROBEXP_OPENVLAB_BASE_URL}/api/get-indicators/{urllib_parse.quote(product_code)}/{urllib_parse.quote(exp_month)}"
    dto_url = f"{PROBEXP_OPENVLAB_BASE_URL}/api/dto/{urllib_parse.quote(product_code)}?{urllib_parse.urlencode({'exps': exp_month})}"
    last_reason = ""
    try:
        payload = probexp_fetch_json_via_http(indicator_url, timeout=10.0)
        result = payload.get("result") if isinstance(payload, Mapping) else None
        atm_iv = to_float(result.get("atmv")) if isinstance(result, Mapping) else None
        skew = to_float(result.get("skew")) if isinstance(result, Mapping) else None
        if atm_iv is not None and float(atm_iv) > 1e-12:
            out = {
                "ok": True,
                "atm_iv": float(atm_iv),
                "source": f"OpenVlab-{contract_code}",
                "reason": "",
                "contract": contract_code,
                "strike": None,
                "skew": float(skew) if skew is not None else None,
            }
            _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
            return out
        last_reason = f"OpenVlab 指标接口未返回可用 ATM IV（{contract_code}）"
    except (urllib_error.URLError, TimeoutError, json.JSONDecodeError, ValueError) as exc:
        last_reason = f"OpenVlab 指标接口获取失败（{contract_code}）：{exc}"
    except Exception as exc:
        last_reason = f"OpenVlab 指标接口获取失败（{contract_code}）：{exc}"
    try:
        payload = probexp_fetch_json_via_http(dto_url, timeout=10.0)
        dto_rec = probexp_extract_openvlab_dto_atm_iv(
            payload,
            underlying_series=underlying_series or contract_code,
            current_close=float(current_close_num),
        )
        if bool(dto_rec.get("ok")):
            out = {
                "ok": True,
                "atm_iv": float(pick_first(to_float(dto_rec.get("atm_iv")), 0.0) or 0.0),
                "source": f"OpenVlab-{contract_code}",
                "reason": "",
                "contract": str(pick_first(dto_rec.get("contract"), contract_code) or contract_code),
                "strike": to_float(dto_rec.get("strike")),
                "skew": to_float(dto_rec.get("skew")),
            }
            _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
            return out
        dto_reason = str(pick_first(dto_rec.get("reason"), "") or "").strip()
        if dto_reason:
            last_reason = dto_reason
    except (urllib_error.URLError, TimeoutError, json.JSONDecodeError, ValueError) as exc:
        if not last_reason:
            last_reason = f"OpenVlab 期权链接口获取失败（{contract_code}）：{exc}"
    except Exception as exc:
        if not last_reason:
            last_reason = f"OpenVlab 期权链接口获取失败（{contract_code}）：{exc}"
    out = dict(empty)
    out["reason"] = last_reason or f"OpenVlab 自动 IV 暂不可用（{contract_code}）"
    _PROBEXP_OPENVLAB_IV_CACHE[cache_key] = dict(out)
    return out


def probexp_signed_tons(value: Any, direction_val: Any) -> float:
    signed_val = to_float(signed_value_by_direction(value, direction_val))
    return float(pick_first(signed_val, 0.0) or 0.0)


def probexp_normalize_directional_input(value: Any, direction_val: Any) -> Tuple[float, bool]:
    raw = float(pick_first(to_float(value), 0.0) or 0.0)
    normalized = probexp_signed_tons(raw, direction_val)
    corrected = abs(normalized - raw) > 1e-9
    return normalized, corrected


def probexp_format_position_tons(value: Any, *, zero_text: str = "0 吨") -> str:
    num = float(pick_first(to_float(value), 0.0) or 0.0)
    if abs(num) <= 1e-12:
        return str(zero_text)
    return f"{num:,.0f} 吨"


def probexp_split_metric_value_text(value: Any) -> Tuple[str, str]:
    txt = str(pick_first(value, "") or "").strip()
    if not txt:
        return "--", ""
    if " " in txt:
        main_text, unit_text = txt.rsplit(" ", 1)
        main_text = str(main_text).strip()
        unit_text = str(unit_text).strip()
        if main_text and unit_text and len(unit_text) <= 12:
            return main_text, unit_text
    return txt, ""


def probexp_calc_snapshot_font_px(
    value_text: Any,
    *,
    max_px: int = 31,
    min_px: int = 18,
    target_chars: float = 7.4,
) -> int:
    raw = str(pick_first(value_text, "") or "").strip()
    if not raw:
        return int(max_px)
    effective_len = 0.0
    for ch in raw:
        if ch.isdigit():
            effective_len += 0.92
        elif ch in ",.%+-":
            effective_len += 0.62
        elif ord(ch) > 127:
            effective_len += 1.10
        else:
            effective_len += 0.88
    if effective_len <= float(target_chars):
        return int(max_px)
    scaled = float(max_px) * float(target_chars) / float(max(effective_len, 1.0))
    return int(max(float(min_px), min(float(max_px), scaled)))


def probexp_render_snapshot_metric_card(
    title: str,
    value: Any,
    *,
    min_height_px: int = 118,
) -> None:
    title_html = html.escape(str(title or ""))
    main_text, unit_text = probexp_split_metric_value_text(value)
    value_font_px = probexp_calc_snapshot_font_px(main_text)
    unit_font_px = max(int(round(float(value_font_px) * 0.56)), 13)
    value_html = html.escape(main_text or "--")
    unit_html = html.escape(unit_text)
    value_block = (
        f'<span style="font-size:{int(value_font_px)}px; line-height:1.02; font-weight:800; color:#f3f7ff; '
        'letter-spacing:-0.02em; overflow-wrap:anywhere; word-break:break-word; font-variant-numeric:tabular-nums;">'
        f"{value_html}</span>"
    )
    if unit_text:
        value_block += (
            f'<span style="font-size:{unit_font_px}px; font-weight:700; color:#d5e5fb; letter-spacing:0.01em;">'
            f"{unit_html}</span>"
        )
    st.markdown(
        (
            f'<div style="min-height:{int(min_height_px)}px; border:1px solid #21486e; border-radius:14px; '
            'padding:14px 16px; background:linear-gradient(180deg, rgba(16,34,63,0.98) 0%, rgba(13,28,55,0.98) 100%); '
            'box-shadow:inset 0 1px 0 rgba(255,255,255,0.03); display:flex; flex-direction:column; justify-content:space-between;">'
            f'<div style="font-size:0.92rem; font-weight:700; color:#dbe9ff; margin-bottom:10px;">{title_html}</div>'
            '<div style="display:flex; flex-wrap:wrap; align-items:baseline; gap:4px 8px; max-width:100%;">'
            f"{value_block}"
            "</div></div>"
        ),
        unsafe_allow_html=True,
    )


def probexp_render_snapshot_price_input(
    title: str,
    *,
    state_key: str,
    default_value: Any,
    min_value: float = 0.01,
    step: float = 0.5,
    format: str = "%.2f",
) -> float:
    if state_key not in st.session_state:
        st.session_state[state_key] = float(pick_first(to_float(default_value), min_value) or min_value)
    css_token = re.sub(r"[^0-9A-Za-z_-]+", "_", str(state_key or "snapshot_price")).strip("_") or "snapshot_price"
    anchor_class = f"otc-snapshot-price-card-{css_token}"
    title_html = html.escape(str(title or ""))
    st.markdown(
        (
            "<style>"
            f"div.element-container:has(.{anchor_class}) {{ margin-bottom:0 !important; }}"
            f"div.element-container:has(.{anchor_class}) + div[data-testid=\"stNumberInput\"] {{ "
            "margin-top:0 !important; margin-bottom:0.15rem !important; "
            "padding:0 16px 14px 16px; border:1px solid #21486e; border-top:none; border-radius:0 0 14px 14px; "
            "background:linear-gradient(180deg, rgba(16,34,63,0.98) 0%, rgba(13,28,55,0.98) 100%); "
            "box-shadow:inset 0 1px 0 rgba(255,255,255,0.03);"
            "} "
            f"div.element-container:has(.{anchor_class}) + div[data-testid=\"stNumberInput\"] input {{ "
            "text-align:center; font-size:1.08rem !important; font-weight:760 !important; letter-spacing:0.015em; "
            "min-height:2.62rem; background:rgba(26, 36, 54, 0.86) !important;"
            "} "
            f"div.element-container:has(.{anchor_class}) + div[data-testid=\"stNumberInput\"] button {{ min-height:2.62rem; }}"
            "</style>"
            f'<div class="{anchor_class}" style="border:1px solid #21486e; border-bottom:none; border-radius:14px 14px 0 0; '
            'padding:12px 16px 8px; background:linear-gradient(180deg, rgba(16,34,63,0.98) 0%, rgba(13,28,55,0.98) 100%); '
            'box-shadow:inset 0 1px 0 rgba(255,255,255,0.03);">'
            f'<div style="font-size:0.92rem; font-weight:700; color:#dbe9ff; text-align:center;">{title_html}</div>'
            "</div>"
        ),
        unsafe_allow_html=True,
    )
    return float(
        st.number_input(
            title,
            min_value=float(min_value),
            step=float(step),
            format=str(format),
            key=state_key,
            label_visibility="collapsed",
        )
    )


def probexp_humanize_auto_iv_reason(reason: Any, *, exchange: str = "", symbol: str = "") -> str:
    txt = str(pick_first(reason, "") or "").strip()
    ex = str(exchange or "").upper().strip()
    sym = str(symbol or "").strip()
    if not txt:
        return "自动 IV 源暂不可用"
    if "OpenVlab" in txt:
        return txt
    if ("Expecting value" in txt) or ("JSONDecodeError" in txt):
        if ex == "DCE":
            return f"{sym or '该品种'}自动 IV 源返回空响应或被交易所拦截，已回退到已保存值或默认值"
        return f"{sym or '该品种'}自动 IV 源返回空响应，已回退到已保存值或默认值"
    if ("412" in txt) or ("403" in txt):
        return f"{sym or '该品种'}自动 IV 源暂时拒绝访问，已回退到已保存值或默认值"
    if "已回退到已保存值或默认值" in txt:
        return txt
    if "缺少当前价格" in txt or "监控日期无效" in txt:
        return txt
    if "暂无" in txt or "未配置" in txt or "不可用" in txt:
        return txt
    if "期权行情为空" in txt or "缺少有效 IV 数据" in txt:
        return f"{sym or '该品种'}当日未取到可用 IV，已回退到已保存值或默认值"
    return f"{sym or '该品种'}自动 IV 获取失败，已回退到已保存值或默认值"


def probexp_build_gap_snapshot(
    *,
    struct_row_raw: Any,
    prices_df: pd.DataFrame,
    close2_df: pd.DataFrame,
    rep_date: str,
) -> Dict[str, Any]:
    empty = {
        "remaining_oscillation_scale": 0.0,
        "remaining_knockin_max_scale": 0.0,
        "remaining_subsidy_scale": 0.0,
        "remaining_observe_days": 0,
        "missing_dates": "",
    }
    if struct_row_raw is None:
        return empty
    try:
        sub_structs = pd.DataFrame([dict(struct_row_raw)])
    except Exception:
        return empty
    if sub_structs.empty:
        return empty
    prices_asof = prices_df.copy() if prices_df is not None else pd.DataFrame()
    rep_date_obj = parse_date_maybe(rep_date)
    if (not prices_asof.empty) and isinstance(rep_date_obj, date):
        dt_asof_series = pd.to_datetime(prices_asof["dt"], errors="coerce").dt.date
        prices_asof = prices_asof[dt_asof_series <= rep_date_obj].copy()
    try:
        gap_df = compute_price_gap_table(
            sub_structs,
            prices_asof,
            close2_df,
            as_of_date=rep_date_obj,
        )
    except Exception:
        return empty
    if gap_df.empty:
        return empty
    rr = gap_df.iloc[-1]
    return {
        "remaining_oscillation_scale": float(
            pick_first(to_float(rr.get("剩余震荡最小头寸规模")), 0.0) or 0.0
        ),
        "remaining_knockin_max_scale": float(
            pick_first(to_float(rr.get("剩余震荡最大头寸规模")), 0.0) or 0.0
        ),
        "remaining_subsidy_scale": float(
            pick_first(to_float(rr.get("剩余震荡最大补贴规模")), 0.0) or 0.0
        ),
        "remaining_observe_days": int(
            pick_first(_int_from_any(rr.get("剩余观察交易日"), 0), 0) or 0
        ),
        "missing_dates": str(pick_first(rr.get("缺失日期列表"), "") or "").strip(),
    }


def probexp_build_structure_stock_qty_map(
    *,
    struct_asof: pd.DataFrame,
    close2_df: pd.DataFrame,
    adjustment_df: Optional[pd.DataFrame] = None,
    rep_gid: str,
    rep_date: str,
    rep_und: str,
    rep_und_all: bool,
) -> Dict[str, float]:
    if struct_asof is None or struct_asof.empty:
        return {}
    wh_cut = struct_asof.copy()
    if "date" in wh_cut.columns:
        dt_ser = pd.to_datetime(wh_cut["date"], errors="coerce").dt.date
        rep_date_obj = parse_date_maybe(rep_date)
        if isinstance(rep_date_obj, date):
            wh_cut = wh_cut[dt_ser.notna() & (dt_ser <= rep_date_obj)].copy()
    if wh_cut.empty:
        return {}

    c2_group = pd.DataFrame()
    if close2_df is not None and not close2_df.empty:
        c2_group = close2_df[close2_df["group_id"].astype(str) == str(rep_gid)].copy()
        if not rep_und_all and str(rep_und).strip():
            c2_group = c2_group[c2_group["underlying"].astype(str) == str(rep_und)].copy()
        if not c2_group.empty and "dt" in c2_group.columns:
            c2_group["dt"] = c2_group["dt"].astype(str)
            c2_group = c2_group[c2_group["dt"] <= str(rep_date)].copy()
    try:
        wh_open = build_open_lot_rows(
            wh_cut,
            c2_group,
            str(rep_date),
            adjustment_df,
        )
    except Exception:
        return {}
    if wh_open is None or wh_open.empty:
        return {}
    return (
        wh_open.groupby(wh_open["structure_id"].astype(str))["open_qty"]
        .sum()
        .astype(float)
        .to_dict()
    )


def probexp_fetch_auto_atm_iv(
    *,
    underlying: Any,
    rep_date: str,
    current_close: Any,
) -> Dict[str, Any]:
    empty = {
        "ok": False,
        "atm_iv": None,
        "source": "",
        "reason": "自动 IV 源暂不可用",
        "contract": "",
        "strike": None,
    }
    current_close_num = to_float(current_close)
    if current_close_num is None or float(current_close_num) <= 1e-12:
        out = dict(empty)
        out["reason"] = "缺少当前价格"
        return out
    rep_date_obj = parse_date_maybe(rep_date)
    if not isinstance(rep_date_obj, date):
        out = dict(empty)
        out["reason"] = "监控日期无效"
        return out
    und_norm = _normalize_underlying_symbol(underlying)
    product_code = probexp_underlying_product_code(und_norm)
    underlying_series = probexp_underlying_series(und_norm)
    openvlab_rec = probexp_fetch_openvlab_atm_iv(
        underlying=underlying,
        rep_date=rep_date,
        current_close=current_close,
    )
    if bool(openvlab_rec.get("ok")):
        return openvlab_rec
    openvlab_reason = str(pick_first(openvlab_rec.get("reason"), "") or "").strip()
    ak_mod = _ensure_akshare_imported()
    if ak_mod is None:
        out = dict(empty)
        out["reason"] = openvlab_reason or "AKShare 不可用"
        return out
    meta = (
        PROBEXP_AK_OPTION_SYMBOL_MAP.get(und_norm)
        or PROBEXP_AK_OPTION_SYMBOL_MAP.get(product_code)
        or {}
    )
    if not meta:
        out = dict(empty)
        out["reason"] = openvlab_reason or f"暂未配置 {und_norm or product_code or '该品种'} 的 AKShare IV 映射"
        return out
    api_mode = str(meta.get("api", "hist") or "hist").strip().lower()
    exchange = str(meta.get("exchange", "")).upper().strip()
    symbol = str(meta.get("symbol", "")).strip()
    cache_key = (f"{exchange}|{api_mode}|{symbol}", rep_date_obj.strftime("%Y%m%d"))
    if cache_key in _PROBEXP_AK_IV_CACHE:
        table_rec = _PROBEXP_AK_IV_CACHE[cache_key]
    else:
        table_rec = {"ok": False, "df": pd.DataFrame(), "reason": "AKShare 未返回数据"}
        try:
            fetch_name = ""
            if exchange == "DCE":
                fetch_name = "option_hist_dce"
            elif exchange == "CZCE":
                fetch_name = "option_hist_czce"
            elif exchange == "GFEX":
                fetch_name = "option_hist_gfex" if api_mode == "hist" else "option_vol_gfex"
            elif exchange == "SHFE":
                fetch_name = "option_vol_shfe" if api_mode == "vol" else "option_hist_shfe"
            if fetch_name:
                fetch_fn = getattr(ak_mod, fetch_name, None)
                if callable(fetch_fn):
                    try:
                        raw_df = fetch_fn(symbol=symbol, trade_date=rep_date_obj.strftime("%Y%m%d"))
                    except TypeError:
                        raw_df = fetch_fn(symbol, rep_date_obj.strftime("%Y%m%d"))
                    if isinstance(raw_df, pd.DataFrame) and not raw_df.empty:
                        table_rec = {"ok": True, "df": raw_df.copy(), "reason": "", "api": fetch_name}
                    else:
                        table_rec["reason"] = "AKShare 期权行情为空"
                else:
                    table_rec["reason"] = f"当前 AKShare 未提供 {fetch_name} 接口"
            else:
                table_rec["reason"] = f"暂未接入 {exchange or '未知交易所'} 的期权 IV 接口"
        except Exception as exc:
            table_rec["reason"] = probexp_humanize_auto_iv_reason(
                str(exc),
                exchange=exchange,
                symbol=symbol,
            )
        _PROBEXP_AK_IV_CACHE[cache_key] = table_rec

    if not bool(table_rec.get("ok")):
        out = dict(empty)
        ak_reason = probexp_humanize_auto_iv_reason(
            table_rec.get("reason"),
            exchange=exchange,
            symbol=symbol,
        )
        out["reason"] = openvlab_reason or ak_reason
        return out

    df = table_rec.get("df")
    if not isinstance(df, pd.DataFrame) or df.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权行情为空", exchange=exchange, symbol=symbol)
        return out

    work = df.copy()
    contract_col = _pick_ak_col(df, ["合约", "合约代码", "合约名称", "contract", "symbol", "期权合约代码", "合约系列"])
    iv_col = _pick_ak_col(df, ["隐含波动率(%)", "隐含波动率", "IV", "iv", "implied_volatility"])
    oi_col = _pick_ak_col(df, ["持仓量", "open_interest", "持仓"])
    vol_col = _pick_ak_col(df, ["成交量", "成交量(手)", "volume"])
    if not iv_col:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    work[iv_col] = pd.to_numeric(work[iv_col], errors="coerce")
    if oi_col:
        work[oi_col] = pd.to_numeric(work[oi_col], errors="coerce").fillna(0.0)
    else:
        work["__oi__"] = 0.0
        oi_col = "__oi__"
    if vol_col:
        work[vol_col] = pd.to_numeric(work[vol_col], errors="coerce").fillna(0.0)
    else:
        work["__vol__"] = 0.0
        vol_col = "__vol__"

    if contract_col:
        work["__contract__"] = work[contract_col].astype(str).fillna("")
        work["__series__"] = work["__contract__"].map(probexp_extract_contract_series)
    else:
        work["__contract__"] = ""
        work["__series__"] = ""

    if api_mode == "vol":
        work = work.dropna(subset=[iv_col]).copy()
        if work.empty:
            out = dict(empty)
            out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
            return out
        if underlying_series:
            exact_series = work[work["__series__"].astype(str).str.upper() == underlying_series].copy()
            if not exact_series.empty:
                work = exact_series
        work = work.sort_values([oi_col, vol_col], ascending=[False, False]).copy()
        pick_row = work.iloc[0]
        atm_iv = float(pd.to_numeric(pick_row.get(iv_col), errors="coerce"))
        if str(iv_col).strip() == "隐含波动率" and atm_iv <= 3.0:
            atm_iv *= 100.0
        if atm_iv <= 1e-12:
            out = dict(empty)
            out["reason"] = probexp_humanize_auto_iv_reason("AKShare 返回的 ATM IV 无效", exchange=exchange, symbol=symbol)
            return out
        contract_name = str(pick_first(pick_row.get(contract_col) if contract_col else None, pick_row.get("__series__"), "") or "").strip()
        return {
            "ok": True,
            "atm_iv": float(atm_iv),
            "source": f"AKShare-{symbol}",
            "reason": "",
            "contract": contract_name,
            "strike": None,
        }

    strike_col = _pick_ak_col(df, ["行权价", "执行价", "strike", "strike_price"])
    if strike_col:
        work[strike_col] = pd.to_numeric(work[strike_col], errors="coerce")
    else:
        work["__strike__"] = work["__contract__"].map(probexp_extract_strike_from_contract)
        strike_col = "__strike__"

    work = work.dropna(subset=[strike_col, iv_col]).copy()
    if work.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    if underlying_series:
        same_series = work[work["__series__"].astype(str).str.upper() == underlying_series].copy()
        if not same_series.empty:
            work = same_series
    work["__atm_gap__"] = (pd.to_numeric(work[strike_col], errors="coerce") - float(current_close_num)).abs()
    work = work.dropna(subset=["__atm_gap__"]).copy()
    if work.empty:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 期权表缺少有效 IV 数据", exchange=exchange, symbol=symbol)
        return out
    min_gap = float(work["__atm_gap__"].min())
    atm_pool = work[np.isclose(work["__atm_gap__"], min_gap, atol=1e-9)].copy()
    if atm_pool.empty:
        atm_pool = work.sort_values(["__atm_gap__", oi_col, vol_col], ascending=[True, False, False]).head(1).copy()
    best_series = ""
    if underlying_series and (atm_pool["__series__"].astype(str).str.upper() == underlying_series).any():
        best_series = underlying_series
    elif "__series__" in atm_pool.columns and (atm_pool["__series__"].astype(str).str.strip() != "").any():
        series_score = (
            atm_pool.assign(
                __score__=pd.to_numeric(atm_pool.get(oi_col), errors="coerce").fillna(0.0)
                + pd.to_numeric(atm_pool.get(vol_col), errors="coerce").fillna(0.0)
            )
            .groupby("__series__", as_index=False)["__score__"]
            .sum()
            .sort_values(["__score__", "__series__"], ascending=[False, True])
        )
        if not series_score.empty:
            best_series = str(series_score.iloc[0]["__series__"]).strip().upper()
    if best_series:
        atm_pool = atm_pool[atm_pool["__series__"].astype(str).str.upper() == best_series].copy()
    atm_pool = atm_pool.sort_values([oi_col, vol_col], ascending=[False, False]).copy()
    pick_row = atm_pool.iloc[0]
    atm_iv = float(pd.to_numeric(atm_pool.get(iv_col), errors="coerce").fillna(0.0).mean())
    if str(iv_col).strip() == "隐含波动率" and atm_iv <= 3.0:
        atm_iv *= 100.0
    if contract_col:
        contract_values = [str(x).strip() for x in atm_pool[contract_col].astype(str).dropna().tolist() if str(x).strip()]
        contract_name = " / ".join(contract_values[:2])
    else:
        contract_name = ""
    strike_used = to_float(pick_row.get(strike_col))
    if atm_iv <= 1e-12:
        out = dict(empty)
        out["reason"] = probexp_humanize_auto_iv_reason("AKShare 返回的 ATM IV 无效", exchange=exchange, symbol=symbol)
        return out
    return {
        "ok": True,
        "atm_iv": float(atm_iv),
        "source": f"AKShare-{symbol}",
        "reason": "",
        "contract": contract_name,
        "strike": strike_used,
    }


def probexp_fetch_auto_atm_iv_with_timeout(
    *,
    underlying: Any,
    rep_date: str,
    current_close: Any,
    timeout_sec: float = PROBEXP_AUTO_IV_TIMEOUT_SEC,
) -> Dict[str, Any]:
    timeout_val = max(float(pick_first(to_float(timeout_sec), PROBEXP_AUTO_IV_TIMEOUT_SEC) or PROBEXP_AUTO_IV_TIMEOUT_SEC), 0.1)
    executor = ThreadPoolExecutor(max_workers=1)
    future = executor.submit(
        probexp_fetch_auto_atm_iv,
        underlying=underlying,
        rep_date=rep_date,
        current_close=current_close,
    )
    try:
        result = future.result(timeout=timeout_val)
        if isinstance(result, dict):
            return dict(result)
        return {
            "ok": False,
            "atm_iv": None,
            "skew": None,
            "source": "",
            "reason": "自动 IV 返回结果无效，已回退到已保存值或默认值。",
            "contract": "",
            "strike": None,
        }
    except FuturesTimeoutError:
        future.cancel()
        return {
            "ok": False,
            "atm_iv": None,
            "skew": None,
            "source": "",
            "reason": f"自动 IV 获取超过 {timeout_val:.0f} 秒，已回退到已保存值或默认值。",
            "contract": "",
            "strike": None,
        }
    except Exception as exc:
        return {
            "ok": False,
            "atm_iv": None,
            "skew": None,
            "source": "",
            "reason": probexp_humanize_auto_iv_reason(str(exc)),
            "contract": "",
            "strike": None,
        }
    finally:
        try:
            executor.shutdown(wait=False, cancel_futures=True)
        except TypeError:
            executor.shutdown(wait=False)


