def precise_hedge_exact_target_position(
    *,
    target_hedge_qty: float,
    observed_qty: float,
    future_qty: float,
    direction_sign: float,
) -> float:
    signed_generated_total = float(direction_sign) * (float(observed_qty) + float(future_qty))
    exact_target_position = float(target_hedge_qty) - signed_generated_total
    return float(probexp_clip_target_position_to_direction(exact_target_position, direction_sign))


def precise_hedge_normalize_target_interval(
    target_center: Any,
    target_lower: Any,
    target_upper: Any,
    direction_sign: Any,
) -> Dict[str, float]:
    center_val = float(pick_first(to_float(target_center), 0.0) or 0.0)
    low_val = float(pick_first(to_float(target_lower), center_val) or center_val)
    high_val = float(pick_first(to_float(target_upper), center_val) or center_val)
    low_num = min(low_val, high_val)
    high_num = max(low_val, high_val)
    sign_val = float(pick_first(to_float(direction_sign), 1.0) or 1.0)
    dir_low, dir_high = sorted([sign_val * low_num, sign_val * high_num])
    dir_center = float(sign_val * center_val)
    return {
        "target_center": center_val,
        "target_lower": low_num,
        "target_upper": high_num,
        "dir_center": dir_center,
        "dir_lower": float(dir_low),
        "dir_upper": float(dir_high),
        "direction_sign": sign_val,
    }


def precise_hedge_default_target_bounds(target_center: Any, kind_value: Any) -> Tuple[float, float]:
    center_val = float(pick_first(to_float(target_center), 0.0) or 0.0)
    kind_code = normalize_kind_code(kind_value)
    if kind_code == "DEC":
        return float(center_val * 1.5), float(center_val * 0.8)
    return float(center_val * 0.8), float(center_val * 1.5)


def precise_hedge_pick_path_scoring_indices(path_count: int, n_days: int) -> Dict[str, Any]:
    path_count_val = max(int(path_count), 0)
    n_days_val = max(int(n_days), 0)
    if path_count_val <= 0 or n_days_val <= 0:
        return {
            "indices": np.asarray([], dtype=int),
            "basis": "无路径",
            "sampled": False,
            "coverage": 0.0,
            "sample_count": 0,
        }
    total_cells = int(path_count_val) * int(n_days_val)
    if total_cells <= int(PRECISE_HEDGE_PATH_SCORING_CELL_CAP):
        indices = np.arange(path_count_val, dtype=int)
        return {
            "indices": indices,
            "basis": "全部路径",
            "sampled": False,
            "coverage": 1.0,
            "sample_count": int(indices.size),
        }
    max_paths = max(
        int(PRECISE_HEDGE_PATH_SCORING_CELL_CAP // max(n_days_val, 1)),
        int(PRECISE_HEDGE_PATH_SCORING_MIN_PATHS),
    )
    sample_count = int(min(path_count_val, max_paths))
    if sample_count >= path_count_val:
        indices = np.arange(path_count_val, dtype=int)
        return {
            "indices": indices,
            "basis": "全部路径",
            "sampled": False,
            "coverage": 1.0,
            "sample_count": int(indices.size),
        }
    indices = np.unique(np.linspace(0, max(path_count_val - 1, 0), num=sample_count, dtype=int))
    return {
        "indices": indices.astype(int, copy=False),
        "basis": "代表路径子样本",
        "sampled": True,
        "coverage": float(indices.size) / float(path_count_val),
        "sample_count": int(indices.size),
    }


def precise_hedge_build_path_interval_metrics(
    cum_exec_step_paths: Any,
    *,
    observed_qty: float,
    candidate_position: float,
    direction_sign: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
) -> Dict[str, float]:
    arr = np.asarray(cum_exec_step_paths, dtype=float)
    if arr.ndim == 1:
        arr = arr.reshape(1, -1)
    if arr.ndim != 2:
        arr = np.zeros((0, 0), dtype=float)
    arr = np.where(np.isfinite(arr), arr, np.nan)
    if arr.size <= 0 or arr.shape[1] <= 0:
        return {
            "hit_rate": 0.0,
            "under_prob": 0.0,
            "over_prob": 0.0,
            "mean_abs_gap": 0.0,
            "mean_interval_excess": 0.0,
            "avg_under_gap": 0.0,
            "avg_over_gap": 0.0,
            "tail_gap_p90": 0.0,
            "tail_gap_p95": 0.0,
            "interval_gap_p95": 0.0,
            "interval_gap_cvar95": 0.0,
            "bias_mean": 0.0,
            "near_hit_rate": 0.0,
            "near_under_prob": 0.0,
            "near_over_prob": 0.0,
            "final_hit_rate": 0.0,
            "final_under_prob": 0.0,
            "final_over_prob": 0.0,
            "path_max_gap_p95": 0.0,
            "path_max_gap_cvar95": 0.0,
            "daily_interval_gap_p95": 0.0,
            "daily_interval_gap_cvar95": 0.0,
            "point_count": 0.0,
            "path_count": 0.0,
            "near_days": 0.0,
        }
    normalized = precise_hedge_normalize_target_interval(target_center, target_lower, target_upper, direction_sign)
    dir_center = float(normalized["dir_center"])
    dir_low = float(normalized["dir_lower"])
    dir_high = float(normalized["dir_upper"])
    dir_total = float(normalized["direction_sign"]) * (
        float(candidate_position) + float(direction_sign) * (float(observed_qty) + arr)
    )
    center_gap = dir_total - dir_center
    under_mask = dir_total < (dir_low - 1e-12)
    over_mask = dir_total > (dir_high + 1e-12)
    hit_mask = (~under_mask) & (~over_mask)
    interval_gap = np.zeros(dir_total.shape, dtype=float)
    if bool(np.any(under_mask)):
        interval_gap[under_mask] = dir_low - dir_total[under_mask]
    if bool(np.any(over_mask)):
        interval_gap[over_mask] = dir_total[over_mask] - dir_high
    n_days = int(arr.shape[1])
    near_days = int(max(1, min(n_days, int(np.ceil(n_days / 3.0)), int(PRECISE_HEDGE_PATH_NEAR_TERM_DAY_CAP))))
    near_slice = slice(0, near_days)
    final_total = dir_total[:, -1]
    final_under_mask = final_total < (dir_low - 1e-12)
    final_over_mask = final_total > (dir_high + 1e-12)
    final_hit_mask = (~final_under_mask) & (~final_over_mask)
    path_max_gap = np.max(interval_gap, axis=1)
    path_gap_p95 = float(np.quantile(path_max_gap, 0.95)) if path_max_gap.size > 0 else 0.0
    path_tail = path_max_gap[path_max_gap >= max(path_gap_p95 - 1e-12, 0.0)]
    daily_gap_p95 = float(np.quantile(interval_gap, 0.95)) if interval_gap.size > 0 else 0.0
    daily_tail = interval_gap[interval_gap >= max(daily_gap_p95 - 1e-12, 0.0)]
    return {
        "hit_rate": float(np.mean(hit_mask)),
        "under_prob": float(np.mean(under_mask)),
        "over_prob": float(np.mean(over_mask)),
        "mean_abs_gap": float(np.mean(np.abs(center_gap))),
        "mean_interval_excess": float(np.mean(interval_gap)),
        "avg_under_gap": float(np.mean(dir_low - dir_total[under_mask])) if bool(np.any(under_mask)) else 0.0,
        "avg_over_gap": float(np.mean(dir_total[over_mask] - dir_high)) if bool(np.any(over_mask)) else 0.0,
        "tail_gap_p90": float(np.quantile(path_max_gap, 0.90)) if path_max_gap.size > 0 else 0.0,
        "tail_gap_p95": float(path_gap_p95),
        "interval_gap_p95": float(path_gap_p95),
        "interval_gap_cvar95": float(np.mean(path_tail)) if path_tail.size > 0 else 0.0,
        "bias_mean": float(np.mean(center_gap)),
        "near_hit_rate": float(np.mean(hit_mask[:, near_slice])) if near_days > 0 else 0.0,
        "near_under_prob": float(np.mean(under_mask[:, near_slice])) if near_days > 0 else 0.0,
        "near_over_prob": float(np.mean(over_mask[:, near_slice])) if near_days > 0 else 0.0,
        "final_hit_rate": float(np.mean(final_hit_mask)),
        "final_under_prob": float(np.mean(final_under_mask)),
        "final_over_prob": float(np.mean(final_over_mask)),
        "path_max_gap_p95": float(path_gap_p95),
        "path_max_gap_cvar95": float(np.mean(path_tail)) if path_tail.size > 0 else 0.0,
        "daily_interval_gap_p95": float(daily_gap_p95),
        "daily_interval_gap_cvar95": float(np.mean(daily_tail)) if daily_tail.size > 0 else 0.0,
        "point_count": float(dir_total.size),
        "path_count": float(dir_total.shape[0]),
        "near_days": float(near_days),
    }


def precise_hedge_classify_path_profile(
    *,
    total_days: int,
    oscillation_days: Any,
    knockin_days: Any,
    knockout_days: Any,
    first_ki_step: Any,
    first_ko_step: Any,
) -> str:
    total_days_val = max(int(total_days), 0)
    osc_days = int(pick_first(_int_from_any(oscillation_days, 0), 0) or 0)
    ki_days = int(pick_first(_int_from_any(knockin_days, 0), 0) or 0)
    ko_days = int(pick_first(_int_from_any(knockout_days, 0), 0) or 0)
    first_ki = int(pick_first(_int_from_any(first_ki_step, -1), -1) or -1)
    first_ko = int(pick_first(_int_from_any(first_ko_step, -1), -1) or -1)
    early_cut = max(2, int(np.ceil(total_days_val * 0.35))) if total_days_val > 0 else 2
    stable_cut = max(2, int(np.ceil(total_days_val * 0.65))) if total_days_val > 0 else 2
    if ko_days > 0 and first_ko > 0 and first_ko <= early_cut:
        return "早敲出收缩型"
    if ki_days > 0 and first_ki > 0 and first_ki <= early_cut:
        return "早敲入放量型"
    if ki_days > 0 and first_ki > early_cut:
        return "后段敲入放量型"
    if osc_days >= stable_cut and ko_days <= 0:
        return "长震荡平滑型"
    if ko_days > 0:
        return "后段敲出收缩型"
    return "长震荡平滑型"


def precise_hedge_get_path_profile_note(profile_label: Any) -> str:
    label_text = str(pick_first(profile_label, "") or "").strip()
    for name, note, _ in PRECISE_HEDGE_PATH_PROFILE_META:
        if str(name) == label_text:
            return str(note)
    return ""


def precise_hedge_build_interval_metrics(
    final_total_paths: Any,
    *,
    direction_sign: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
) -> Dict[str, float]:
    arr = np.asarray(final_total_paths, dtype=float)
    arr = arr[np.isfinite(arr)]
    normalized = precise_hedge_normalize_target_interval(target_center, target_lower, target_upper, direction_sign)
    if arr.size <= 0:
        return {
            "hit_rate": 0.0,
            "under_prob": 0.0,
            "over_prob": 0.0,
            "mean_abs_gap": 0.0,
            "mean_interval_excess": 0.0,
            "avg_under_gap": 0.0,
            "avg_over_gap": 0.0,
            "tail_gap_p90": 0.0,
            "tail_gap_p95": 0.0,
            "interval_gap_p95": 0.0,
            "interval_gap_cvar95": 0.0,
            "bias_mean": 0.0,
        }
    arr_dir = normalized["direction_sign"] * arr
    dir_center = float(normalized["dir_center"])
    dir_low = float(normalized["dir_lower"])
    dir_high = float(normalized["dir_upper"])
    center_gap = arr_dir - dir_center
    under_mask = arr_dir < (dir_low - 1e-12)
    over_mask = arr_dir > (dir_high + 1e-12)
    hit_mask = (~under_mask) & (~over_mask)
    interval_gap = np.zeros(arr_dir.shape, dtype=float)
    if bool(np.any(under_mask)):
        interval_gap[under_mask] = dir_low - arr_dir[under_mask]
    if bool(np.any(over_mask)):
        interval_gap[over_mask] = arr_dir[over_mask] - dir_high
    interval_gap_p95 = float(np.quantile(interval_gap, 0.95)) if interval_gap.size > 0 else 0.0
    tail_mask = interval_gap >= max(interval_gap_p95 - 1e-12, 0.0)
    tail_vals = interval_gap[tail_mask]
    return {
        "hit_rate": float(np.mean(hit_mask)),
        "under_prob": float(np.mean(under_mask)),
        "over_prob": float(np.mean(over_mask)),
        "mean_abs_gap": float(np.mean(np.abs(center_gap))),
        "mean_interval_excess": float(np.mean(interval_gap)),
        "avg_under_gap": float(np.mean(dir_low - arr_dir[under_mask])) if bool(np.any(under_mask)) else 0.0,
        "avg_over_gap": float(np.mean(arr_dir[over_mask] - dir_high)) if bool(np.any(over_mask)) else 0.0,
        "tail_gap_p90": float(np.quantile(np.abs(center_gap), 0.90)),
        "tail_gap_p95": float(np.quantile(np.abs(center_gap), 0.95)),
        "interval_gap_p95": interval_gap_p95,
        "interval_gap_cvar95": float(np.mean(tail_vals)) if tail_vals.size > 0 else 0.0,
        "bias_mean": float(np.mean(center_gap)),
    }


def _precise_hedge_metric_chunk_size(base_cell_count: int) -> int:
    base_cells = max(int(base_cell_count), 1)
    return max(int(PRECISE_HEDGE_SCAN_METRIC_CHUNK_CELL_CAP // base_cells), 1)


def _precise_hedge_tail_cvar_from_rows(values: np.ndarray, thresholds: np.ndarray) -> np.ndarray:
    out = np.zeros(int(values.shape[0]), dtype=float)
    if values.ndim != 2 or values.shape[0] != int(thresholds.size):
        return out
    for idx in range(values.shape[0]):
        threshold = max(float(thresholds[idx]) - 1e-12, 0.0)
        tail_vals = values[idx][values[idx] >= threshold]
        out[idx] = float(np.mean(tail_vals)) if tail_vals.size > 0 else 0.0
    return out


def precise_hedge_build_interval_metrics_batch(
    final_total_base_paths: Any,
    *,
    candidate_positions: Sequence[float],
    direction_sign: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
) -> Dict[str, np.ndarray]:
    candidate_arr = np.asarray(candidate_positions, dtype=float).reshape(-1)
    out = {
        "hit_rate": np.zeros(candidate_arr.size, dtype=float),
        "under_prob": np.zeros(candidate_arr.size, dtype=float),
        "over_prob": np.zeros(candidate_arr.size, dtype=float),
        "mean_abs_gap": np.zeros(candidate_arr.size, dtype=float),
        "mean_interval_excess": np.zeros(candidate_arr.size, dtype=float),
        "avg_under_gap": np.zeros(candidate_arr.size, dtype=float),
        "avg_over_gap": np.zeros(candidate_arr.size, dtype=float),
        "tail_gap_p90": np.zeros(candidate_arr.size, dtype=float),
        "tail_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "interval_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "interval_gap_cvar95": np.zeros(candidate_arr.size, dtype=float),
        "bias_mean": np.zeros(candidate_arr.size, dtype=float),
    }
    if candidate_arr.size <= 0:
        return out
    base = np.asarray(final_total_base_paths, dtype=float).reshape(-1)
    base = base[np.isfinite(base)]
    if base.size <= 0:
        return out
    normalized = precise_hedge_normalize_target_interval(target_center, target_lower, target_upper, direction_sign)
    dir_center = float(normalized["dir_center"])
    dir_low = float(normalized["dir_lower"])
    dir_high = float(normalized["dir_upper"])
    direction_scale = float(normalized["direction_sign"])
    base_dir = direction_scale * base
    chunk_size = _precise_hedge_metric_chunk_size(base_dir.size)
    for start in range(0, candidate_arr.size, chunk_size):
        end = min(start + chunk_size, int(candidate_arr.size))
        candidate_chunk = candidate_arr[start:end]
        dir_total = base_dir[np.newaxis, :] + direction_scale * candidate_chunk[:, np.newaxis]
        center_gap = dir_total - dir_center
        under_mask = dir_total < (dir_low - 1e-12)
        over_mask = dir_total > (dir_high + 1e-12)
        under_gap = np.where(under_mask, dir_low - dir_total, 0.0)
        over_gap = np.where(over_mask, dir_total - dir_high, 0.0)
        interval_gap = under_gap + over_gap
        under_prob = np.mean(under_mask, axis=1)
        over_prob = np.mean(over_mask, axis=1)
        hit_rate = 1.0 - under_prob - over_prob
        abs_center_gap = np.abs(center_gap)
        interval_gap_p95 = np.quantile(interval_gap, 0.95, axis=1)
        out["hit_rate"][start:end] = hit_rate
        out["under_prob"][start:end] = under_prob
        out["over_prob"][start:end] = over_prob
        out["mean_abs_gap"][start:end] = np.mean(abs_center_gap, axis=1)
        out["mean_interval_excess"][start:end] = np.mean(interval_gap, axis=1)
        under_count = np.sum(under_mask, axis=1)
        over_count = np.sum(over_mask, axis=1)
        out["avg_under_gap"][start:end] = np.divide(
            np.sum(under_gap, axis=1),
            under_count,
            out=np.zeros(end - start, dtype=float),
            where=under_count > 0,
        )
        out["avg_over_gap"][start:end] = np.divide(
            np.sum(over_gap, axis=1),
            over_count,
            out=np.zeros(end - start, dtype=float),
            where=over_count > 0,
        )
        out["tail_gap_p90"][start:end] = np.quantile(abs_center_gap, 0.90, axis=1)
        out["tail_gap_p95"][start:end] = np.quantile(abs_center_gap, 0.95, axis=1)
        out["interval_gap_p95"][start:end] = interval_gap_p95
        out["interval_gap_cvar95"][start:end] = _precise_hedge_tail_cvar_from_rows(interval_gap, interval_gap_p95)
        out["bias_mean"][start:end] = np.mean(center_gap, axis=1)
    return out


def precise_hedge_build_path_interval_metrics_batch(
    cum_exec_step_paths: Any,
    *,
    observed_qty: float,
    candidate_positions: Sequence[float],
    direction_sign: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
) -> Dict[str, np.ndarray]:
    candidate_arr = np.asarray(candidate_positions, dtype=float).reshape(-1)
    out = {
        "hit_rate": np.zeros(candidate_arr.size, dtype=float),
        "under_prob": np.zeros(candidate_arr.size, dtype=float),
        "over_prob": np.zeros(candidate_arr.size, dtype=float),
        "mean_abs_gap": np.zeros(candidate_arr.size, dtype=float),
        "mean_interval_excess": np.zeros(candidate_arr.size, dtype=float),
        "avg_under_gap": np.zeros(candidate_arr.size, dtype=float),
        "avg_over_gap": np.zeros(candidate_arr.size, dtype=float),
        "tail_gap_p90": np.zeros(candidate_arr.size, dtype=float),
        "tail_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "interval_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "interval_gap_cvar95": np.zeros(candidate_arr.size, dtype=float),
        "bias_mean": np.zeros(candidate_arr.size, dtype=float),
        "near_hit_rate": np.zeros(candidate_arr.size, dtype=float),
        "near_under_prob": np.zeros(candidate_arr.size, dtype=float),
        "near_over_prob": np.zeros(candidate_arr.size, dtype=float),
        "final_hit_rate": np.zeros(candidate_arr.size, dtype=float),
        "final_under_prob": np.zeros(candidate_arr.size, dtype=float),
        "final_over_prob": np.zeros(candidate_arr.size, dtype=float),
        "path_max_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "path_max_gap_cvar95": np.zeros(candidate_arr.size, dtype=float),
        "daily_interval_gap_p95": np.zeros(candidate_arr.size, dtype=float),
        "daily_interval_gap_cvar95": np.zeros(candidate_arr.size, dtype=float),
        "point_count": np.zeros(candidate_arr.size, dtype=float),
        "path_count": np.zeros(candidate_arr.size, dtype=float),
        "near_days": np.zeros(candidate_arr.size, dtype=float),
    }
    if candidate_arr.size <= 0:
        return out
    arr = np.asarray(cum_exec_step_paths, dtype=float)
    if arr.ndim == 1:
        arr = arr.reshape(1, -1)
    if arr.ndim != 2:
        arr = np.zeros((0, 0), dtype=float)
    arr = np.where(np.isfinite(arr), arr, np.nan)
    if arr.size <= 0 or arr.shape[1] <= 0:
        return out
    normalized = precise_hedge_normalize_target_interval(target_center, target_lower, target_upper, direction_sign)
    dir_center = float(normalized["dir_center"])
    dir_low = float(normalized["dir_lower"])
    dir_high = float(normalized["dir_upper"])
    direction_scale = float(normalized["direction_sign"])
    base_dir = direction_scale * (float(direction_sign) * (float(observed_qty) + arr))
    n_days = int(arr.shape[1])
    near_days = int(max(1, min(n_days, int(np.ceil(n_days / 3.0)), int(PRECISE_HEDGE_PATH_NEAR_TERM_DAY_CAP))))
    near_slice = slice(0, near_days)
    chunk_size = _precise_hedge_metric_chunk_size(arr.size)
    for start in range(0, candidate_arr.size, chunk_size):
        end = min(start + chunk_size, int(candidate_arr.size))
        candidate_chunk = candidate_arr[start:end]
        dir_total = base_dir[np.newaxis, :, :] + direction_scale * candidate_chunk[:, np.newaxis, np.newaxis]
        center_gap = dir_total - dir_center
        under_mask = dir_total < (dir_low - 1e-12)
        over_mask = dir_total > (dir_high + 1e-12)
        under_gap = np.where(under_mask, dir_low - dir_total, 0.0)
        over_gap = np.where(over_mask, dir_total - dir_high, 0.0)
        interval_gap = under_gap + over_gap
        under_prob = np.mean(under_mask, axis=(1, 2))
        over_prob = np.mean(over_mask, axis=(1, 2))
        final_under_prob = np.mean(under_mask[:, :, -1], axis=1)
        final_over_prob = np.mean(over_mask[:, :, -1], axis=1)
        near_under_prob = np.mean(under_mask[:, :, near_slice], axis=(1, 2)) if near_days > 0 else np.zeros(end - start, dtype=float)
        near_over_prob = np.mean(over_mask[:, :, near_slice], axis=(1, 2)) if near_days > 0 else np.zeros(end - start, dtype=float)
        path_max_gap = np.max(interval_gap, axis=2)
        path_gap_p95 = np.quantile(path_max_gap, 0.95, axis=1)
        flat_interval_gap = interval_gap.reshape(end - start, -1)
        daily_gap_p95 = np.quantile(flat_interval_gap, 0.95, axis=1)
        out["hit_rate"][start:end] = 1.0 - under_prob - over_prob
        out["under_prob"][start:end] = under_prob
        out["over_prob"][start:end] = over_prob
        out["mean_abs_gap"][start:end] = np.mean(np.abs(center_gap), axis=(1, 2))
        out["mean_interval_excess"][start:end] = np.mean(interval_gap, axis=(1, 2))
        under_count = np.sum(under_mask, axis=(1, 2))
        over_count = np.sum(over_mask, axis=(1, 2))
        out["avg_under_gap"][start:end] = np.divide(
            np.sum(under_gap, axis=(1, 2)),
            under_count,
            out=np.zeros(end - start, dtype=float),
            where=under_count > 0,
        )
        out["avg_over_gap"][start:end] = np.divide(
            np.sum(over_gap, axis=(1, 2)),
            over_count,
            out=np.zeros(end - start, dtype=float),
            where=over_count > 0,
        )
        out["tail_gap_p90"][start:end] = np.quantile(path_max_gap, 0.90, axis=1)
        out["tail_gap_p95"][start:end] = path_gap_p95
        out["interval_gap_p95"][start:end] = path_gap_p95
        out["interval_gap_cvar95"][start:end] = _precise_hedge_tail_cvar_from_rows(path_max_gap, path_gap_p95)
        out["bias_mean"][start:end] = np.mean(center_gap, axis=(1, 2))
        out["near_hit_rate"][start:end] = 1.0 - near_under_prob - near_over_prob
        out["near_under_prob"][start:end] = near_under_prob
        out["near_over_prob"][start:end] = near_over_prob
        out["final_hit_rate"][start:end] = 1.0 - final_under_prob - final_over_prob
        out["final_under_prob"][start:end] = final_under_prob
        out["final_over_prob"][start:end] = final_over_prob
        out["path_max_gap_p95"][start:end] = path_gap_p95
        out["path_max_gap_cvar95"][start:end] = _precise_hedge_tail_cvar_from_rows(path_max_gap, path_gap_p95)
        out["daily_interval_gap_p95"][start:end] = daily_gap_p95
        out["daily_interval_gap_cvar95"][start:end] = _precise_hedge_tail_cvar_from_rows(flat_interval_gap, daily_gap_p95)
        out["point_count"][start:end] = float(dir_total.shape[1] * dir_total.shape[2])
        out["path_count"][start:end] = float(dir_total.shape[1])
        out["near_days"][start:end] = float(near_days)
    return out


def precise_hedge_apply_magnitude_adjust(position: Any, adjust_pct: float, direction_sign: Any) -> float:
    pos_val = float(pick_first(to_float(position), 0.0) or 0.0)
    sign_val = float(pick_first(to_float(direction_sign), 1.0) or 1.0)
    if abs(pos_val) <= 1e-12:
        return 0.0
    adjusted_abs = max(abs(pos_val) * (1.0 + float(adjust_pct)), 0.0)
    adjusted_pos = (1.0 if sign_val >= 0.0 else -1.0) * adjusted_abs
    return float(probexp_clip_target_position_to_direction(adjusted_pos, sign_val))


def precise_hedge_parse_bucket_range(bucket_label: Any) -> Optional[Tuple[float, float]]:
    txt = str(pick_first(bucket_label, "") or "").strip()
    if not txt:
        return None
    parts = re.split(r"\s*-\s*", txt)
    if len(parts) != 2:
        return None
    lo = to_float(parts[0].replace(",", ""))
    hi = to_float(parts[1].replace(",", ""))
    if lo is None or hi is None:
        return None
    lo_num = float(min(lo, hi))
    hi_num = float(max(lo, hi))
    return lo_num, hi_num


def precise_hedge_find_bucket_row(
    bucket_df: pd.DataFrame,
    entry_price: Any,
    *,
    bucket_col: str = "价格区间",
) -> Optional[pd.Series]:
    if bucket_df is None or bucket_df.empty:
        return None
    entry_val = to_float(entry_price)
    if entry_val is None:
        return None
    best_row: Optional[pd.Series] = None
    best_dist = float("inf")
    for _, row in bucket_df.iterrows():
        parsed = precise_hedge_parse_bucket_range(row.get(bucket_col))
        if parsed is None:
            continue
        lo_num, hi_num = parsed
        if lo_num - 1e-12 <= float(entry_val) <= hi_num + 1e-12:
            return row
        center = (lo_num + hi_num) * 0.5
        dist = abs(float(entry_val) - center)
        if dist < best_dist:
            best_dist = dist
            best_row = row
    return best_row


def precise_hedge_describe_bucket_match(
    bucket_row: Mapping[str, Any],
    entry_price: Any,
    *,
    bucket_col: str = "价格区间",
) -> Dict[str, Any]:
    bucket_label = str(pick_first(bucket_row.get(bucket_col), "") or "").strip() if isinstance(bucket_row, Mapping) else ""
    entry_val = to_float(entry_price)
    out = {
        "bucket_label": bucket_label,
        "entry_price": entry_val,
        "matched": bool(bucket_label),
        "exact": False,
        "boundary_gap": None,
    }
    if not bucket_label or entry_val is None:
        return out
    parsed = precise_hedge_parse_bucket_range(bucket_label)
    if parsed is None:
        return out
    lo_num, hi_num = parsed
    if lo_num - 1e-12 <= float(entry_val) <= hi_num + 1e-12:
        out["exact"] = True
        out["boundary_gap"] = 0.0
        return out
    out["boundary_gap"] = float(min(abs(float(entry_val) - lo_num), abs(float(entry_val) - hi_num)))
    return out


def precise_hedge_find_time_row(time_df: pd.DataFrame, label_col: str, label_value: str) -> Optional[pd.Series]:
    if time_df is None or time_df.empty or label_col not in time_df.columns:
        return None
    sub = time_df[time_df[label_col].astype(str) == str(label_value)].copy()
    if sub.empty:
        return None
    return sub.iloc[0]


def precise_hedge_infer_bias_signal(
    *,
    knockin_prob: Any,
    stable_prob: Any,
    knockout_prob: Any,
    positive_adjust_pct: float,
) -> Dict[str, Any]:
    ki_prob = float(pick_first(to_float(knockin_prob), 0.0) or 0.0)
    stable_prob_val = float(pick_first(to_float(stable_prob), 0.0) or 0.0)
    ko_prob = float(pick_first(to_float(knockout_prob), 0.0) or 0.0)
    dominant = max(
        [("发生敲入", ki_prob), ("震荡/中性", stable_prob_val), ("发生敲出", ko_prob)],
        key=lambda item: item[1],
    )[0]
    margin = max(ki_prob, ko_prob) - stable_prob_val
    if (ko_prob > ki_prob + 0.05) and (ko_prob >= stable_prob_val or margin > 0.03):
        return {
            "stance": "偏高套保",
            "adjust_pct": float(abs(positive_adjust_pct)),
            "dominant_state": dominant,
            "reason": "历史上更容易提前敲出，未来继续生成偏少，当前仓位宜略高。",
        }
    if (ki_prob > ko_prob + 0.05) and (ki_prob >= stable_prob_val or margin > 0.03):
        return {
            "stance": "偏轻套保",
            "adjust_pct": -float(abs(positive_adjust_pct)),
            "dominant_state": dominant,
            "reason": "历史上更容易敲入放大生成，未来继续生成偏多，当前仓位宜略轻。",
        }
    return {
        "stance": "中性",
        "adjust_pct": 0.0,
        "dominant_state": dominant,
        "reason": "历史概率分布没有明显偏向，维持基准仓位即可。",
    }


def precise_hedge_build_scan_table(
    *,
    future_qty_paths: Any,
    cum_exec_step_paths: Any = None,
    observed_qty: float,
    direction_sign: float,
    current_position: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
    step_tons: float,
    scan_steps: int,
    named_positions: Mapping[str, float],
) -> pd.DataFrame:
    future_qty = np.asarray(future_qty_paths, dtype=float)
    future_qty = future_qty[np.isfinite(future_qty)]
    if future_qty.size <= 0:
        return pd.DataFrame()
    cum_exec_matrix = np.asarray(cum_exec_step_paths, dtype=float)
    if cum_exec_matrix.ndim == 1:
        cum_exec_matrix = cum_exec_matrix.reshape(1, -1)
    use_path_metrics = (
        isinstance(cum_exec_matrix, np.ndarray)
        and cum_exec_matrix.ndim == 2
        and cum_exec_matrix.size > 0
        and cum_exec_matrix.shape[1] > 0
    )
    signed_generated_total_paths = float(direction_sign) * (float(observed_qty) + future_qty)
    step_val = max(float(step_tons), 100.0)
    scan_span = max(int(scan_steps), 2)
    ref_positions = [float(current_position)] + [float(v) for v in named_positions.values()]
    min_ref = min(ref_positions)
    max_ref = max(ref_positions)
    lo = min_ref - step_val * scan_span
    hi = max_ref + step_val * scan_span
    grid_start = np.floor(lo / step_val) * step_val
    grid_end = np.ceil(hi / step_val) * step_val
    candidate_positions = list(np.arange(grid_start, grid_end + step_val * 0.5, step_val))
    candidate_positions.extend(ref_positions)
    normalized_candidates: List[float] = []
    for pos in candidate_positions:
        clipped = float(probexp_clip_target_position_to_direction(pos, direction_sign))
        normalized_candidates.append(round(clipped, 6))
    normalized_candidates = sorted(set(normalized_candidates))
    candidate_arr = np.asarray(normalized_candidates, dtype=float)
    final_metric_batch = precise_hedge_build_interval_metrics_batch(
        signed_generated_total_paths,
        candidate_positions=candidate_arr,
        direction_sign=float(direction_sign),
        target_center=float(target_center),
        target_lower=float(target_lower),
        target_upper=float(target_upper),
    )
    path_metric_batch = (
        precise_hedge_build_path_interval_metrics_batch(
            cum_exec_matrix,
            observed_qty=float(observed_qty),
            candidate_positions=candidate_arr,
            direction_sign=float(direction_sign),
            target_center=float(target_center),
            target_lower=float(target_lower),
            target_upper=float(target_upper),
        )
        if use_path_metrics
        else {}
    )
    rows: List[Dict[str, Any]] = []
    for idx, candidate_pos in enumerate(normalized_candidates):
        final_metrics = {
            key: float(arr[idx])
            for key, arr in final_metric_batch.items()
        }
        metrics = (
            {
                key: float(arr[idx])
                for key, arr in path_metric_batch.items()
            }
            if use_path_metrics
            else final_metrics
        )
        matched_tags = [
            str(name)
            for name, pos in named_positions.items()
            if abs(float(candidate_pos) - float(pos)) <= max(step_val * 0.2, 1e-6)
        ]
        rows.append(
            {
                "候选仓位": float(candidate_pos),
                "标签": " / ".join(matched_tags),
                "区间命中率": float(metrics["hit_rate"]),
                "路径覆盖率": float(metrics["hit_rate"]),
                "近端覆盖率": float(metrics.get("near_hit_rate", metrics["hit_rate"])),
                "终点命中率": float(metrics.get("final_hit_rate", final_metrics["hit_rate"])),
                "欠保概率": float(metrics["under_prob"]),
                "超保概率": float(metrics["over_prob"]),
                "近端欠保概率": float(metrics.get("near_under_prob", metrics["under_prob"])),
                "近端超保概率": float(metrics.get("near_over_prob", metrics["over_prob"])),
                "终点欠保概率": float(metrics.get("final_under_prob", final_metrics["under_prob"])),
                "终点超保概率": float(metrics.get("final_over_prob", final_metrics["over_prob"])),
                "平均绝对偏差": float(metrics["mean_abs_gap"]),
                "区间外平均偏差": float(metrics["mean_interval_excess"]),
                "尾部偏差P95": float(metrics["tail_gap_p95"]),
                "区间外CVaR95": float(metrics["interval_gap_cvar95"]),
                "路径尾部最大偏差P95": float(metrics.get("path_max_gap_p95", metrics["tail_gap_p95"])),
                "路径尾部最大偏差CVaR95": float(metrics.get("path_max_gap_cvar95", metrics["interval_gap_cvar95"])),
                "偏差均值": float(metrics["bias_mean"]),
                "评分口径": "全路径" if use_path_metrics else "终点",
                "仓位调整": probexp_describe_adjustment(current_position, candidate_pos),
            }
        )
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out["_偏差平衡"] = (out["欠保概率"] - out["超保概率"]).abs()
    out = out.sort_values(
        ["路径覆盖率", "近端覆盖率", "平均绝对偏差", "路径尾部最大偏差P95", "终点命中率", "_偏差平衡", "候选仓位"],
        ascending=[False, False, True, True, False, True, True],
    ).reset_index(drop=True)
    out["排名"] = np.arange(1, len(out) + 1)
    return out


def precise_hedge_clip_position_array_to_direction(position_paths: Any, direction_sign: Any) -> np.ndarray:
    arr = np.asarray(position_paths, dtype=float)
    sign_val = float(pick_first(to_float(direction_sign), 1.0) or 1.0)
    if arr.size <= 0:
        return np.asarray([], dtype=float)
    if sign_val >= 0.0:
        return np.where(arr > 0.0, arr, 0.0)
    return np.where(arr < 0.0, arr, 0.0)


def precise_hedge_build_distribution_stats(values: Any) -> Dict[str, float]:
    arr = np.asarray(values, dtype=float)
    arr = arr[np.isfinite(arr)]
    if arr.size <= 0:
        return {
            "mean": 0.0,
            "std": 0.0,
            "p10": 0.0,
            "p25": 0.0,
            "p50": 0.0,
            "p75": 0.0,
            "p90": 0.0,
            "p70": 0.0,
            "p80": 0.0,
            "min": 0.0,
            "max": 0.0,
        }
    return {
        "mean": float(np.mean(arr)),
        "std": float(np.std(arr)),
        "p10": float(np.quantile(arr, 0.10)),
        "p25": float(np.quantile(arr, 0.25)),
        "p50": float(np.quantile(arr, 0.50)),
        "p75": float(np.quantile(arr, 0.75)),
        "p90": float(np.quantile(arr, 0.90)),
        "p70": float(np.quantile(arr, 0.70)),
        "p80": float(np.quantile(arr, 0.80)),
        "min": float(np.min(arr)),
        "max": float(np.max(arr)),
    }


def precise_hedge_build_execution_distribution_summaries(
    mc_result: Mapping[str, Any],
    *,
    observed_qty: Any = None,
    runtime_state_seed: Optional[Mapping[str, Any]] = None,
) -> Tuple[Dict[str, float], Dict[str, float], Dict[str, Any]]:
    runtime_seed = runtime_state_seed_to_dict(
        runtime_state_seed
        if isinstance(runtime_state_seed, Mapping)
        else (mc_result.get("runtime_state_seed", {}) if isinstance(mc_result.get("runtime_state_seed", {}), Mapping) else {})
    )
    observed_qty_val = float(
        pick_first(
            to_float(observed_qty),
            runtime_seed.get("cum_qty"),
            0.0,
        )
        or 0.0
    )
    future_qty = np.asarray(mc_result.get("future_qty_paths"), dtype=float)
    future_qty = future_qty[np.isfinite(future_qty)]
    cum_exec_paths = np.asarray(mc_result.get("cum_exec_paths"), dtype=float)
    cum_exec_paths = cum_exec_paths[np.isfinite(cum_exec_paths)]
    cumulative_exec_paths = (
        cum_exec_paths
        if cum_exec_paths.size > 0
        else np.asarray(float(observed_qty_val) + future_qty, dtype=float)
    )
    distribution_summary = precise_hedge_build_distribution_stats(cumulative_exec_paths)
    future_qty_summary = precise_hedge_build_distribution_stats(future_qty)
    distribution_summary["distribution_name"] = "最终累计执行量"
    distribution_summary["distribution_note"] = "口径为当前已累计数量叠加 future_qty_paths 后得到的最终累计执行量分布。"
    distribution_summary["observed_qty"] = float(observed_qty_val)
    distribution_summary["future_qty_mean"] = float(future_qty_summary.get("mean", 0.0))
    distribution_summary["future_qty_p50"] = float(future_qty_summary.get("p50", 0.0))
    distribution_summary["future_qty_p90"] = float(future_qty_summary.get("p90", 0.0))
    diagnostics = {
        "observed_qty": float(observed_qty_val),
        "future_path_count": int(future_qty.size),
        "cum_exec_path_count": int(cumulative_exec_paths.size),
        "future_unique_count": int(np.unique(future_qty).size) if future_qty.size > 0 else 0,
        "cum_exec_unique_count": int(np.unique(cumulative_exec_paths).size) if cumulative_exec_paths.size > 0 else 0,
        "used_cum_exec_paths": bool(cum_exec_paths.size > 0),
    }
    diagnostics["is_degenerate"] = bool(diagnostics["cum_exec_unique_count"] <= 1 and diagnostics["cum_exec_path_count"] > 0)
    return distribution_summary, future_qty_summary, diagnostics


def precise_hedge_build_customer_qty_quantile_table(
    distribution_summary: Mapping[str, Any],
    future_qty_summary: Mapping[str, Any],
) -> pd.DataFrame:
    rows: List[Dict[str, Any]] = []
    quantiles = [
        ("P10", "偏低成交情景", "p10"),
        ("P25", "略低成交情景", "p25"),
        ("P50", "中性预估", "p50"),
        ("P75", "略高成交情景", "p75"),
        ("P90", "偏高成交情景", "p90"),
    ]
    for label, scenario, key in quantiles:
        rows.append(
            {
                "分位线": label,
                "情景说明": scenario,
                "未来预计新增成交量": float(pick_first(to_float(future_qty_summary.get(key)), 0.0) or 0.0),
                "预计最终累计成交量": float(pick_first(to_float(distribution_summary.get(key)), 0.0) or 0.0),
            }
        )
    return pd.DataFrame(rows)


def precise_hedge_build_customer_path_state_overview(
    metrics: Mapping[str, Any],
    state_rows_df: Optional[pd.DataFrame] = None,
) -> Dict[str, Any]:
    path_count = int(round(float(pick_first(to_float(metrics.get("path_count")), 0.0) or 0.0)))
    hit_rate = float(pick_first(to_float(metrics.get("hit_rate")), 0.0) or 0.0)
    overview: Dict[str, Any] = {
        "path_count": int(max(path_count, 0)),
        "in_target_path_equiv": int(round(max(path_count, 0) * max(min(hit_rate, 1.0), 0.0))),
        "in_target_rate": float(max(min(hit_rate, 1.0), 0.0)),
        "knock_in_paths": 0,
        "knock_in_rate": 0.0,
        "knock_out_paths": 0,
        "knock_out_rate": 0.0,
        "neutral_paths": 0,
        "neutral_rate": 0.0,
    }
    if not isinstance(state_rows_df, pd.DataFrame) or state_rows_df.empty:
        return overview
    work = state_rows_df.copy()
    if "情景" not in work.columns or "当前路径数" not in work.columns:
        return overview
    work["当前路径数"] = pd.to_numeric(work["当前路径数"], errors="coerce").fillna(0.0)
    total_paths = int(round(float(work["当前路径数"].sum())))
    if total_paths > 0:
        overview["path_count"] = int(total_paths)
        overview["in_target_path_equiv"] = int(round(total_paths * overview["in_target_rate"]))
    for _, row in work.iterrows():
        scenario = str(row.get("情景", ""))
        count = int(round(float(pick_first(row.get("当前路径数"), 0.0) or 0.0)))
        if "敲入" in scenario:
            overview["knock_in_paths"] += count
        elif "敲出" in scenario:
            overview["knock_out_paths"] += count
        else:
            overview["neutral_paths"] += count
    if overview["path_count"] > 0:
        total = float(overview["path_count"])
        overview["knock_in_rate"] = float(overview["knock_in_paths"]) / total
        overview["knock_out_rate"] = float(overview["knock_out_paths"]) / total
        overview["neutral_rate"] = float(overview["neutral_paths"]) / total
    return overview


def precise_hedge_build_customer_path_metric_text(
    metrics: Mapping[str, Any],
    qty_quantile_df: Optional[pd.DataFrame] = None,
    path_state_overview: Optional[Mapping[str, Any]] = None,
    *,
    basis: str = "路径过程",
) -> str:
    hit_rate = float(pick_first(to_float(metrics.get("hit_rate")), 0.0) or 0.0)
    under_prob = float(pick_first(to_float(metrics.get("under_prob")), 0.0) or 0.0)
    over_prob = float(pick_first(to_float(metrics.get("over_prob")), 0.0) or 0.0)
    mean_gap = float(pick_first(to_float(metrics.get("mean_abs_gap")), 0.0) or 0.0)
    if under_prob > over_prob + 0.03:
        risk_text = "更容易出现套少了的情况"
    elif over_prob > under_prob + 0.03:
        risk_text = "更容易出现套多了的情况"
    else:
        risk_text = "套少和套多的情况比较接近"

    p50_future = None
    p50_final = None
    if isinstance(qty_quantile_df, pd.DataFrame) and not qty_quantile_df.empty and "分位线" in qty_quantile_df.columns:
        p50_rows = qty_quantile_df[qty_quantile_df["分位线"].astype(str) == "P50"].copy()
        if not p50_rows.empty:
            p50_future = to_float(p50_rows.iloc[0].get("未来预计新增成交量"))
            p50_final = to_float(p50_rows.iloc[0].get("预计最终累计成交量"))

    qty_text = ""
    if p50_future is not None or p50_final is not None:
        qty_text = (
            f" 按 P50 中性预估，未来还会新增成交约 {probexp_format_tons(p50_future)}，"
            f"最终累计成交约 {probexp_format_position_tons(p50_final)}。"
        )
    path_text = ""
    if isinstance(path_state_overview, Mapping) and int(pick_first(path_state_overview.get("path_count"), 0) or 0) > 0:
        path_count = int(pick_first(path_state_overview.get("path_count"), 0) or 0)
        in_target_paths = int(pick_first(path_state_overview.get("in_target_path_equiv"), 0) or 0)
        ki_paths = int(pick_first(path_state_overview.get("knock_in_paths"), 0) or 0)
        ko_paths = int(pick_first(path_state_overview.get("knock_out_paths"), 0) or 0)
        neutral_paths = int(pick_first(path_state_overview.get("neutral_paths"), 0) or 0)
        path_text = (
            f"本次用 {path_count:,} 条代表路径逐日看过程，平均每天约 {in_target_paths:,} 条路径在目标区间内"
            f"（约 {hit_rate * 100.0:.1f}%）；其中敲入状态约 {ki_paths:,} 条"
            f"（{float(pick_first(path_state_overview.get('knock_in_rate'), 0.0) or 0.0) * 100.0:.1f}%），"
            f"敲出状态约 {ko_paths:,} 条"
            f"（{float(pick_first(path_state_overview.get('knock_out_rate'), 0.0) or 0.0) * 100.0:.1f}%），"
            f"其余震荡/未敲入未敲出约 {neutral_paths:,} 条。"
        )
    else:
        path_text = f"{basis}口径下，按当前建议仓位，约 {hit_rate * 100.0:.1f}% 的观察点落在目标范围内。"
    return (
        f"{path_text}"
        f" 从每日过程看，约 {under_prob * 100.0:.1f}% 的观察点会套少，约 {over_prob * 100.0:.1f}% 会套多，"
        f"平均离目标中心约 {probexp_format_tons(mean_gap)}，这个吨数是不带方向的偏离幅度，"
        f"不是多空正负号；整体看{risk_text}。"
        f"{qty_text}"
    )


def precise_hedge_prepare_param_scan_candidate_df(
    existing_df: Any,
    *,
    default_entry: Any,
    default_strike: Any,
    default_barrier: Any,
    default_multiple: Any,
) -> pd.DataFrame:
    columns = ["入场价", "时间(BD)", "参与率K", "行权价", "障碍价"]
    alias_map: Dict[str, Tuple[str, ...]] = {
        "入场价": ("入场价", "entry_price", "入场"),
        "时间(BD)": ("时间(BD)", "时间", "期限", "term"),
        "参与率K": ("参与率K", "参与率", "K", "multiple"),
        "行权价": ("行权价", "行权", "strike_price", "执行价"),
        "障碍价": ("障碍价", "障碍", "barrier_out", "敲出价"),
    }
    if isinstance(existing_df, pd.DataFrame) and not existing_df.empty:
        work = existing_df.copy()
        for col_name in columns:
            if col_name not in work.columns:
                for alias in alias_map.get(col_name, ()):
                    if alias in work.columns:
                        work[col_name] = work[alias]
                        break
            if col_name not in work.columns:
                work[col_name] = np.nan
        return work[columns].copy()
    entry_val = float(pick_first(to_float(default_entry), 0.0) or 0.0)
    strike_val = float(pick_first(to_float(default_strike), entry_val) or entry_val)
    barrier_val = float(pick_first(to_float(default_barrier), strike_val) or strike_val)
    multiple_val = float(pick_first(to_float(default_multiple), 3.0) or 3.0)
    multiple_val = float(np.clip(multiple_val, 2.0, 4.0))
    seed_rows = [
        {"入场价": entry_val, "时间(BD)": 20, "参与率K": multiple_val, "行权价": strike_val, "障碍价": barrier_val},
        {"入场价": entry_val, "时间(BD)": 25, "参与率K": multiple_val, "行权价": strike_val, "障碍价": barrier_val},
        {"入场价": entry_val, "时间(BD)": 20, "参与率K": min(max(multiple_val + 1.0, 2.0), 4.0), "行权价": strike_val, "障碍价": barrier_val},
        {"入场价": entry_val, "时间(BD)": 25, "参与率K": min(max(multiple_val + 1.0, 2.0), 4.0), "行权价": strike_val, "障碍价": barrier_val},
    ]
    return pd.DataFrame(seed_rows, columns=columns)


def precise_hedge_collect_param_scan_candidate_rows(candidate_df: Any) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    rows: List[Dict[str, Any]] = []
    issues: List[Dict[str, Any]] = []
    if not isinstance(candidate_df, pd.DataFrame) or candidate_df.empty:
        return rows, issues
    work = precise_hedge_prepare_param_scan_candidate_df(
        candidate_df,
        default_entry=0.0,
        default_strike=0.0,
        default_barrier=0.0,
        default_multiple=3.0,
    )
    seen_keys: set[Tuple[float, int, float, float, float]] = set()
    for row_idx, row in work.iterrows():
        entry_val = to_float(row.get("入场价"))
        term_num = to_float(row.get("时间(BD)"))
        term_val = int(round(float(term_num))) if term_num is not None and np.isfinite(term_num) else None
        k_val = to_float(row.get("参与率K"))
        strike_val = to_float(row.get("行权价"))
        barrier_val = to_float(row.get("障碍价"))
        raw_values = [entry_val, term_val, k_val, strike_val, barrier_val]
        if all(v is None or (isinstance(v, float) and (not np.isfinite(v))) for v in raw_values):
            continue
        display_row = int(row_idx) + 1
        if entry_val is None or float(entry_val) <= 0.0:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "入场价必须大于 0"})
            continue
        if term_val is None or int(term_val) <= 0:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "时间(BD)必须是正整数"})
            continue
        if k_val is None or float(k_val) < 2.0 - 1e-12 or float(k_val) > 4.0 + 1e-12:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "参与率K 必须位于 2 到 4 之间"})
            continue
        if strike_val is None or float(strike_val) <= 0.0:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "行权价必须大于 0"})
            continue
        if barrier_val is None or float(barrier_val) <= 0.0:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "障碍价必须大于 0"})
            continue
        dedupe_key = (
            round(float(entry_val), 6),
            int(term_val),
            round(float(k_val), 4),
            round(float(strike_val), 6),
            round(float(barrier_val), 6),
        )
        if dedupe_key in seen_keys:
            issues.append({"类别": "候选结构", "行号": display_row, "原因": "与前面行完全重复，已跳过"})
            continue
        seen_keys.add(dedupe_key)
        rows.append(
            {
                "入场价": float(entry_val),
                "时间": int(term_val),
                "参与率K": float(k_val),
                "行权价": float(strike_val),
                "障碍价": float(barrier_val),
                "输入行号": display_row,
            }
        )
    return rows, issues


def special_accumulator_vectorized_evaluate(
    *,
    struct_row: Mapping[str, Any],
    price_matrix: Any,
    state_seed: Optional[Mapping[str, Any]] = None,
    quantile_meta: Optional[List[Tuple[str, float, str, str]]] = None,
    sample_idx: Optional[np.ndarray] = None,
    target_lower: Any = None,
    target_upper: Any = None,
    capture_full_cum_paths: bool = False,
) -> Dict[str, Any]:
    prices = np.asarray(price_matrix, dtype=np.float32)
    if prices.ndim != 2:
        raise RuntimeError("参数扫描价格路径矩阵维度无效")
    seed = runtime_state_seed_from_any(state_seed)
    sample_idx_arr = (
        np.asarray(sample_idx, dtype=int).reshape(-1)
        if isinstance(sample_idx, np.ndarray)
        else np.asarray(sample_idx if sample_idx is not None else [], dtype=int).reshape(-1)
    )
    if prices.size <= 0 or prices.shape[1] <= 0:
        path_count = int(prices.shape[0]) if prices.ndim == 2 else 0
        zero_paths = np.zeros(path_count, dtype=float)
        zero_scenarios = np.full(path_count, WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT, dtype=np.int8)
        zero_total_paths = np.full(path_count, float(seed.cum_qty), dtype=float)
        sample_cum_qty_paths = np.zeros((int(sample_idx_arr.size), 0), dtype=np.float32)
        scoring_meta = precise_hedge_pick_path_scoring_indices(path_count, 0)
        scoring_idx_arr = np.asarray(scoring_meta.get("indices"), dtype=int).reshape(-1)
        step_quantiles: Dict[str, np.ndarray] = {}
        for label, _, _, _ in quantile_meta or []:
            step_quantiles[str(label)] = np.zeros(0, dtype=float)
        zero_step_probs = np.zeros(0, dtype=float)
        return {
            "future_qty_paths": zero_paths,
            "final_future_qty": zero_paths,
            "final_total_qty": zero_total_paths,
            "scenario_ids": zero_scenarios,
            "scenario_prob_by_id": {
                WINRATE_ACCUMULATOR_SCENARIO_KI: 0.0,
                WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT: 1.0 if path_count > 0 else 0.0,
                WINRATE_ACCUMULATOR_SCENARIO_KO: 0.0,
            },
            "mean_future_qty": 0.0,
            "std_future_qty": 0.0,
            "path_count": path_count,
            "sample_cum_qty_paths": sample_cum_qty_paths,
            "sample_daily_exec_paths": np.zeros((int(sample_idx_arr.size), 0), dtype=np.float32),
            "sample_state_code_paths": np.zeros((int(sample_idx_arr.size), 0), dtype=np.int8),
            "step_quantiles": step_quantiles,
            "terminated_by_ko_flags": np.zeros(path_count, dtype=bool),
            "structure_survival_flags": np.ones(path_count, dtype=bool),
            "structure_survival_prob": 1.0 if path_count > 0 else 0.0,
            "has_knockin_flags": np.zeros(path_count, dtype=bool),
            "knockin_prob": 0.0,
            "has_knockout_flags": np.zeros(path_count, dtype=bool),
            "knockout_prob": 0.0,
            "termination_step": np.full(path_count, -1, dtype=int),
            "first_ki_step_paths": np.full(path_count, -1, dtype=int),
            "first_ko_step_paths": np.full(path_count, -1, dtype=int),
            "oscillation_days_paths": np.zeros(path_count, dtype=np.int16),
            "knockin_days_paths": np.zeros(path_count, dtype=np.int16),
            "knockout_days_paths": np.zeros(path_count, dtype=np.int16),
            "step_under_target_prob": zero_step_probs,
            "step_over_target_prob": zero_step_probs.copy(),
            "cum_exec_paths": zero_total_paths,
            "path_scoring_cum_qty_paths": np.zeros((int(scoring_idx_arr.size), 0), dtype=np.float32),
            "path_scoring_future_qty_paths": np.zeros(int(scoring_idx_arr.size), dtype=float),
            "path_scoring_scenario_ids": np.full(int(scoring_idx_arr.size), WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT, dtype=np.int8),
            "path_scoring_first_ki_steps": np.full(int(scoring_idx_arr.size), -1, dtype=int),
            "path_scoring_first_ko_steps": np.full(int(scoring_idx_arr.size), -1, dtype=int),
            "path_scoring_oscillation_days": np.zeros(int(scoring_idx_arr.size), dtype=np.int16),
            "path_scoring_knockin_days": np.zeros(int(scoring_idx_arr.size), dtype=np.int16),
            "path_scoring_knockout_days": np.zeros(int(scoring_idx_arr.size), dtype=np.int16),
            "path_scoring_basis": str(pick_first(scoring_meta.get("basis"), "无路径")),
            "path_scoring_sampled": bool(scoring_meta.get("sampled", False)),
            "path_scoring_coverage": float(pick_first(scoring_meta.get("coverage"), 0.0) or 0.0),
            "path_scoring_count": int(pick_first(scoring_meta.get("sample_count"), 0) or 0),
            "full_cum_exec_step_paths": np.zeros((path_count, 0), dtype=np.float32) if capture_full_cum_paths else np.zeros((0, 0), dtype=np.float32),
        }
    if (not np.isfinite(prices).all()) or float(np.min(prices)) <= 0.0:
        raise RuntimeError("参数扫描价格路径存在无效值")

    path_count = int(prices.shape[0])
    n_days = int(prices.shape[1])
    code = resolve_strategy_code_for_display(struct_row.get("strategy_code", ""))
    kind = normalize_kind_code(struct_row.get("kind", ""))
    is_acc = kind == "ACC"
    base_qty = max(float(pick_first(to_float(struct_row.get("base_qty_per_day")), 0.0) or 0.0), 0.0)
    strike = float(pick_first(to_float(struct_row.get("strike_price")), to_float(struct_row.get("entry_price")), 0.0) or 0.0)
    barrier_out = to_float(struct_row.get("barrier_out"))
    knock_out_price = to_float(struct_row.get("knock_out_price"))
    multiple = max(float(pick_first(to_float(struct_row.get("multiple")), 3.0) or 0.0), 0.0)
    meta = struct_row.get("meta", {}) if isinstance(struct_row.get("meta", {}), dict) else {}
    legacy_mode = str(meta.get("_legacy_mode", "")).upper()
    ko_terminate = bool(meta.get("ko_terminate", False))

    future_qty = np.zeros(path_count, dtype=float)
    active = np.ones(path_count, dtype=bool)
    has_ki = np.full(path_count, bool(seed.has_knockin_history), dtype=bool)
    has_ko = np.full(path_count, bool(seed.has_knockout_history), dtype=bool)
    terminated_by_ko = np.zeros(path_count, dtype=bool)
    termination_step = np.full(path_count, -1, dtype=int)
    sample_cum_qty_paths = np.zeros((int(sample_idx_arr.size), n_days), dtype=np.float32)
    sample_daily_exec_paths = np.zeros((int(sample_idx_arr.size), n_days), dtype=np.float32)
    sample_state_code_paths = np.zeros((int(sample_idx_arr.size), n_days), dtype=np.int8)
    sample_slot_by_path = np.full(path_count, -1, dtype=int)
    if sample_idx_arr.size > 0:
        sample_slot_by_path[sample_idx_arr] = np.arange(sample_idx_arr.size, dtype=int)
    scoring_meta = precise_hedge_pick_path_scoring_indices(path_count, n_days)
    scoring_idx_arr = np.asarray(scoring_meta.get("indices"), dtype=int).reshape(-1)
    path_scoring_cum_qty_paths = np.zeros((int(scoring_idx_arr.size), n_days), dtype=np.float32)
    full_cum_exec_step_paths = np.zeros((path_count, n_days), dtype=np.float32) if capture_full_cum_paths else np.zeros((0, 0), dtype=np.float32)
    oscillation_days_paths = np.zeros(path_count, dtype=np.int16)
    knockin_days_paths = np.zeros(path_count, dtype=np.int16)
    knockout_days_paths = np.zeros(path_count, dtype=np.int16)
    first_ki_step_paths = np.full(path_count, -1, dtype=np.int16)
    first_ko_step_paths = np.full(path_count, -1, dtype=np.int16)
    step_quantiles: Dict[str, np.ndarray] = {}
    for label, _, _, _ in quantile_meta or []:
        step_quantiles[str(label)] = np.zeros(n_days, dtype=float)
    step_under_target_prob = np.zeros(n_days, dtype=float)
    step_over_target_prob = np.zeros(n_days, dtype=float)
    target_lower_val = to_float(target_lower)
    target_upper_val = to_float(target_upper)
    remaining_cap_init = special_seed_remaining_cap(seed)
    remaining_cap_path = (
        np.full(path_count, float(remaining_cap_init), dtype=float)
        if remaining_cap_init is not None
        else None
    )

    for step in range(n_days):
        active_idx = np.where(active)[0]
        if active_idx.size == 0:
            break
        px_next = np.asarray(prices[active_idx, step], dtype=float)
        qty = np.zeros(int(active_idx.size), dtype=float)
        deactivate_mask = np.zeros(int(active_idx.size), dtype=bool)
        ki_hit = np.zeros(int(active_idx.size), dtype=bool)
        ko_hit = np.zeros(int(active_idx.size), dtype=bool)

        if code == "BASIC_RANGE" and legacy_mode == "FIXED_PART":
            qty[:] = base_qty * multiple
        elif code == "BASIC_RANGE" and legacy_mode == "BASIC_MULT":
            if is_acc:
                if knock_out_price is not None:
                    ko_hit = price_array_at_or_above(px_next, float(knock_out_price))
                ki_hit = price_array_at_or_below(px_next, strike)
                qty[ko_hit] = 0.0
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
                qty[(~ko_hit) & (~ki_hit)] = base_qty
            else:
                ko_hit = price_array_at_or_below(px_next, strike)
                if knock_out_price is not None:
                    ki_hit = price_array_at_or_above(px_next, float(knock_out_price))
                qty[ko_hit] = 0.0
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
                qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "NO_KO":
            ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
            qty[ki_hit] = base_qty * multiple
            qty[~ki_hit] = base_qty
        elif code == "FLOAT_KO":
            ki_level = strike
            ko_level = knock_out_price if knock_out_price is not None else barrier_out
            if ko_level is None:
                ko_level = barrier_out
            if ko_level is not None:
                ko_hit = (
                    price_array_at_or_above(px_next, float(ko_level))
                    if is_acc
                    else price_array_at_or_below(px_next, float(ko_level))
                )
            ki_hit = price_array_at_or_below(px_next, float(ki_level)) if is_acc else price_array_at_or_above(px_next, float(ki_level))
            qty[ko_hit] = base_qty * float(max(n_days - step, 0))
            deactivate_mask = ko_hit.copy()
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "FIXED_SUBSIDY":
            ko_level = barrier_out if barrier_out is not None else knock_out_price
            if ko_level is not None:
                ko_hit = (
                    price_array_at_or_above(px_next, float(ko_level))
                    if is_acc
                    else price_array_at_or_below(px_next, float(ko_level))
                )
            ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
            deactivate_mask = ko_hit.copy()
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
        elif code == "PREMIUM_SUBSIDY":
            ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
            qty[ki_hit] = base_qty * multiple
        elif code == "RANGE_SUBSIDY":
            if barrier_out is None:
                ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
                qty[ki_hit] = base_qty * multiple
            else:
                ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
                ko_hit = (
                    price_array_at_or_above(px_next, float(barrier_out))
                    if is_acc
                    else price_array_at_or_below(px_next, float(barrier_out))
                )
                qty[(~ko_hit) & ki_hit] = base_qty * multiple
        else:
            if knock_out_price is not None:
                ko_hit = (
                    price_array_at_or_above(px_next, float(knock_out_price))
                    if is_acc
                    else price_array_at_or_below(px_next, float(knock_out_price))
                )
            ki_hit = price_array_at_or_below(px_next, strike) if is_acc else price_array_at_or_above(px_next, strike)
            qty[ko_hit] = 0.0
            qty[(~ko_hit) & ki_hit] = base_qty * multiple
            qty[(~ko_hit) & (~ki_hit)] = base_qty
            if ko_terminate:
                deactivate_mask = ko_hit.copy()

        qty_exec = qty
        if remaining_cap_path is not None:
            cap_now = np.asarray(remaining_cap_path[active_idx], dtype=float)
            qty_exec = np.minimum(np.maximum(qty_exec, 0.0), np.maximum(cap_now, 0.0))
            remaining_cap_path[active_idx] = np.maximum(cap_now - qty_exec, 0.0)
        oscillation_mask = (~ko_hit) & (~ki_hit)
        if bool(np.any(oscillation_mask)):
            oscillation_days_paths[active_idx[oscillation_mask]] += 1
        if bool(np.any(ki_hit)):
            ki_idx = active_idx[ki_hit]
            knockin_days_paths[ki_idx] += 1
            first_ki_mask = first_ki_step_paths[ki_idx] < 0
            if bool(np.any(first_ki_mask)):
                first_ki_step_paths[ki_idx[first_ki_mask]] = int(step) + 1
        if bool(np.any(ko_hit)):
            ko_idx = active_idx[ko_hit]
            knockout_days_paths[ko_idx] += 1
            first_ko_mask = first_ko_step_paths[ko_idx] < 0
            if bool(np.any(first_ko_mask)):
                first_ko_step_paths[ko_idx[first_ko_mask]] = int(step) + 1
        future_qty[active_idx] += qty_exec
        if bool(np.any(ki_hit)):
            has_ki[active_idx[ki_hit]] = True
        if bool(np.any(ko_hit)):
            has_ko[active_idx[ko_hit]] = True
        if bool(np.any(deactivate_mask)):
            deactivated_idx = active_idx[deactivate_mask]
            terminated_by_ko[deactivated_idx] = True
            termination_step[deactivated_idx] = int(step)
            active[deactivated_idx] = False
        if target_lower_val is not None:
            step_under_target_prob[step] = float(np.mean((float(seed.cum_qty) + future_qty) < float(target_lower_val))) if path_count > 0 else 0.0
        if target_upper_val is not None:
            step_over_target_prob[step] = float(np.mean((float(seed.cum_qty) + future_qty) > float(target_upper_val))) if path_count > 0 else 0.0
        if sample_idx_arr.size > 0:
            sample_cum_qty_paths[:, step] = future_qty[sample_idx_arr].astype(np.float32, copy=False)
            state_codes = np.full(int(sample_idx_arr.size), 3, dtype=np.int8)
            sample_active_mask = sample_slot_by_path[active_idx] >= 0
            if bool(np.any(sample_active_mask)):
                sample_active_idx = active_idx[sample_active_mask]
                sample_slots = sample_slot_by_path[sample_active_idx]
                state_codes[sample_slots] = 0
                state_codes[sample_slots[ki_hit[sample_active_mask]]] = 1
                state_codes[sample_slots[ko_hit[sample_active_mask]]] = 2
                sample_daily_exec_paths[sample_slots, step] = qty_exec[sample_active_mask].astype(np.float32, copy=False)
            sample_state_code_paths[:, step] = state_codes
        if scoring_idx_arr.size > 0:
            path_scoring_cum_qty_paths[:, step] = future_qty[scoring_idx_arr].astype(np.float32, copy=False)
        if capture_full_cum_paths:
            full_cum_exec_step_paths[:, step] = future_qty.astype(np.float32, copy=False)
        for label, qv, _, _ in quantile_meta or []:
            step_quantiles[str(label)][step] = float(np.quantile(future_qty, qv))

    scenario_ids = np.full(path_count, WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT, dtype=np.int8)
    if ko_terminate:
        ko_first_mask = has_ko & terminated_by_ko
        scenario_ids[ko_first_mask] = WINRATE_ACCUMULATOR_SCENARIO_KO
        scenario_ids[has_ki & (~ko_first_mask)] = WINRATE_ACCUMULATOR_SCENARIO_KI
        scenario_ids[(~has_ki) & has_ko & (~ko_first_mask)] = WINRATE_ACCUMULATOR_SCENARIO_KO
    else:
        scenario_ids[has_ki] = WINRATE_ACCUMULATOR_SCENARIO_KI
        scenario_ids[(~has_ki) & has_ko] = WINRATE_ACCUMULATOR_SCENARIO_KO
    structure_survival_flags = ~terminated_by_ko
    final_total_qty = float(seed.cum_qty) + future_qty
    scenario_prob_by_id = {
        WINRATE_ACCUMULATOR_SCENARIO_KI: float(np.mean(scenario_ids == WINRATE_ACCUMULATOR_SCENARIO_KI)) if path_count > 0 else 0.0,
        WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT: float(np.mean(scenario_ids == WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT)) if path_count > 0 else 0.0,
        WINRATE_ACCUMULATOR_SCENARIO_KO: float(np.mean(scenario_ids == WINRATE_ACCUMULATOR_SCENARIO_KO)) if path_count > 0 else 0.0,
    }
    return {
        "future_qty_paths": future_qty,
        "final_future_qty": future_qty,
        "final_total_qty": final_total_qty,
        "scenario_ids": scenario_ids,
        "scenario_prob_by_id": scenario_prob_by_id,
        "mean_future_qty": float(np.mean(future_qty)) if future_qty.size > 0 else 0.0,
        "std_future_qty": float(np.std(future_qty)) if future_qty.size > 0 else 0.0,
        "path_count": path_count,
        "sample_cum_qty_paths": sample_cum_qty_paths,
        "sample_daily_exec_paths": sample_daily_exec_paths,
        "sample_state_code_paths": sample_state_code_paths,
        "step_quantiles": step_quantiles,
        "terminated_by_ko_flags": terminated_by_ko,
        "termination_step": termination_step,
        "first_ki_step_paths": first_ki_step_paths.astype(int, copy=False),
        "first_ko_step_paths": first_ko_step_paths.astype(int, copy=False),
        "oscillation_days_paths": oscillation_days_paths.astype(np.int16, copy=False),
        "knockin_days_paths": knockin_days_paths.astype(np.int16, copy=False),
        "knockout_days_paths": knockout_days_paths.astype(np.int16, copy=False),
        "step_under_target_prob": step_under_target_prob,
        "step_over_target_prob": step_over_target_prob,
        "structure_survival_flags": structure_survival_flags,
        "structure_survival_prob": float(np.mean(structure_survival_flags)) if path_count > 0 else 0.0,
        "has_knockin_flags": has_ki,
        "knockin_prob": float(np.mean(has_ki)) if path_count > 0 else 0.0,
        "has_knockout_flags": has_ko,
        "knockout_prob": float(np.mean(has_ko)) if path_count > 0 else 0.0,
        "cum_exec_paths": final_total_qty,
        "path_scoring_cum_qty_paths": path_scoring_cum_qty_paths,
        "path_scoring_future_qty_paths": future_qty[scoring_idx_arr].astype(float, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=float),
        "path_scoring_scenario_ids": scenario_ids[scoring_idx_arr].astype(np.int8, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=np.int8),
        "path_scoring_first_ki_steps": first_ki_step_paths[scoring_idx_arr].astype(int, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=int),
        "path_scoring_first_ko_steps": first_ko_step_paths[scoring_idx_arr].astype(int, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=int),
        "path_scoring_oscillation_days": oscillation_days_paths[scoring_idx_arr].astype(np.int16, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=np.int16),
        "path_scoring_knockin_days": knockin_days_paths[scoring_idx_arr].astype(np.int16, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=np.int16),
        "path_scoring_knockout_days": knockout_days_paths[scoring_idx_arr].astype(np.int16, copy=False) if scoring_idx_arr.size > 0 else np.asarray([], dtype=np.int16),
        "path_scoring_basis": str(pick_first(scoring_meta.get("basis"), "无路径")),
        "path_scoring_sampled": bool(scoring_meta.get("sampled", False)),
        "path_scoring_coverage": float(pick_first(scoring_meta.get("coverage"), 0.0) or 0.0),
        "path_scoring_count": int(pick_first(scoring_meta.get("sample_count"), 0) or 0),
        "full_cum_exec_step_paths": full_cum_exec_step_paths,
    }


def precise_hedge_evaluate_accumulator_price_matrix(
    *,
    struct_row: Mapping[str, Any],
    price_matrix: Any,
    state_seed: Optional[Mapping[str, Any]] = None,
) -> Dict[str, Any]:
    return special_accumulator_vectorized_evaluate(
        struct_row=struct_row,
        price_matrix=price_matrix,
        state_seed=state_seed,
    )

def precise_hedge_build_param_scan_scores(
    *,
    mean_final: Any,
    std_final: Any,
    hit_rate: Any,
    under_prob: Any,
    over_prob: Any,
    feasibility_score: Any,
    target_center: Any,
    target_lower: Any,
    target_upper: Any,
    p10: Any = None,
    p50: Any = None,
    p90: Any = None,
    direction_sign: Any = 1.0,
) -> Dict[str, Any]:
    mean_val = float(pick_first(to_float(mean_final), 0.0) or 0.0)
    std_val = max(float(pick_first(to_float(std_final), 0.0) or 0.0), 0.0)
    hit_val = float(np.clip(float(pick_first(to_float(hit_rate), 0.0) or 0.0), 0.0, 1.0))
    under_val = float(np.clip(float(pick_first(to_float(under_prob), 0.0) or 0.0), 0.0, 1.0))
    over_val = float(np.clip(float(pick_first(to_float(over_prob), 0.0) or 0.0), 0.0, 1.0))
    feasibility_val = float(np.clip(float(pick_first(to_float(feasibility_score), 0.0) or 0.0), 0.0, 1.0))
    target_center_val = float(pick_first(to_float(target_center), 0.0) or 0.0)
    target_lower_val = float(pick_first(to_float(target_lower), target_center_val) or target_center_val)
    target_upper_val = float(pick_first(to_float(target_upper), target_center_val) or target_center_val)
    band_scale = max(abs(float(target_upper_val) - float(target_lower_val)) * 0.5, abs(float(target_center_val)) * 0.05, 1000.0)
    direction_sign_val = float(pick_first(to_float(direction_sign), 1.0) or 1.0)
    normalized = precise_hedge_normalize_target_interval(
        target_center_val,
        target_lower_val,
        target_upper_val,
        direction_sign_val,
    )
    p10_val = to_float(p10)
    p50_val = to_float(p50)
    p90_val = to_float(p90)
    if p10_val is not None and p90_val is not None:
        span_val = max(float(p90_val) - float(p10_val), 0.0)
    elif p50_val is not None:
        span_val = max(float(std_val) * 1.349, abs(float(p50_val) - float(mean_val)) * 2.0)
    else:
        span_val = max(float(std_val) * 1.349, 0.0)
    deviation_score = 1.0 / (1.0 + abs(float(mean_val) - float(target_center_val)) / max(float(band_scale), 1.0))
    dispersion_score = 1.0 / (1.0 + float(std_val) / max(float(band_scale), 1.0))
    stability_score = 1.0 / (1.0 + float(span_val) / max(float(band_scale) * 1.5, 1.0))
    balance_score = float(np.clip(1.0 - abs(float(under_val) - float(over_val)), 0.0, 1.0))
    mean_dir = float(direction_sign_val) * float(mean_val)
    dir_center = float(normalized.get("dir_center", target_center_val))
    dir_upper = float(normalized.get("dir_upper", target_upper_val))
    upper_span = max(abs(float(dir_upper) - float(dir_center)), float(band_scale) * 0.25, 1.0)
    upper_bias_score = float(np.clip((float(mean_dir) - float(dir_center)) / float(upper_span), 0.0, 1.0))
    upper_proximity_score = 1.0 / (1.0 + abs(float(mean_dir) - float(dir_upper)) / max(float(band_scale), 1.0))
    upper_exposure_score = float(np.clip(0.65 * upper_proximity_score + 0.35 * upper_bias_score, 0.0, 1.0))
    components = {
        "deviation": float(np.clip(deviation_score, 0.0, 1.0)),
        "hit": float(hit_val),
        "under": float(1.0 - under_val),
        "over": float(1.0 - over_val),
        "dispersion": float(np.clip(dispersion_score, 0.0, 1.0)),
        "feasibility": float(feasibility_val),
        "stability": float(np.clip(stability_score, 0.0, 1.0)),
        "balance": float(balance_score),
        "upper_exposure": float(np.clip(upper_exposure_score, 0.0, 1.0)),
    }
    scores: Dict[str, float] = {}
    for pref_label, weight_map in PRECISE_HEDGE_PARAM_SCAN_SCORE_WEIGHT_MAP.items():
        total_score = 0.0
        for metric_name, weight_val in weight_map.items():
            total_score += float(components.get(metric_name, 0.0)) * float(weight_val)
        scores[str(pref_label)] = float(total_score * 100.0)
    recommendation_scores: Dict[str, float] = {}
    for bucket_label, weight_map in PRECISE_HEDGE_PARAM_SCAN_BUCKET_WEIGHT_MAP.items():
        total_score = 0.0
        for metric_name, weight_val in weight_map.items():
            total_score += float(components.get(metric_name, 0.0)) * float(weight_val)
        recommendation_scores[str(bucket_label)] = float(total_score * 100.0)
    return {
        "components": components,
        "scores": scores,
        "recommendation_scores": recommendation_scores,
        "band_scale": float(band_scale),
        "p90_p10_span": float(span_val),
    }


def precise_hedge_rank_candidate_rows(
    scan_df: pd.DataFrame,
    score_col: str,
    *,
    sort_cols: Optional[Sequence[str]] = None,
    ascending: Optional[Sequence[bool]] = None,
    exclude_combo_ids: Optional[Sequence[str]] = None,
) -> pd.DataFrame:
    if scan_df is None or scan_df.empty or score_col not in scan_df.columns:
        return pd.DataFrame()
    work = scan_df.copy()
    exclude_keys = {str(x) for x in exclude_combo_ids or [] if str(x)}
    if exclude_keys and "_combo_id" in work.columns:
        work = work[~work["_combo_id"].astype(str).isin(exclude_keys)].copy()
    if work.empty:
        return work
    default_sort_cols = [score_col, "目标区间命中率", "与目标头寸绝对偏差", "标准差", "输入行号", "入场价", "时间", "参与率K"]
    default_ascending = [False, False, True, True, True, True, True, True]
    cols = list(sort_cols) if sort_cols is not None else default_sort_cols
    asc = list(ascending) if ascending is not None else default_ascending
    usable_cols: List[str] = []
    usable_asc: List[bool] = []
    for idx, col_name in enumerate(cols):
        if col_name in work.columns:
            usable_cols.append(str(col_name))
            usable_asc.append(bool(asc[idx]) if idx < len(asc) else True)
    if not usable_cols:
        return work.reset_index(drop=True)
    return work.sort_values(usable_cols, ascending=usable_asc).reset_index(drop=True)


def precise_hedge_pick_structure_scan_row(
    scan_df: pd.DataFrame,
    score_col: str,
    *,
    sort_cols: Optional[Sequence[str]] = None,
    ascending: Optional[Sequence[bool]] = None,
    exclude_combo_ids: Optional[Sequence[str]] = None,
) -> Dict[str, Any]:
    work = precise_hedge_rank_candidate_rows(
        scan_df,
        score_col,
        sort_cols=sort_cols,
        ascending=ascending,
        exclude_combo_ids=exclude_combo_ids,
    )
    if work.empty:
        return {}
    return work.iloc[0].to_dict()


def precise_hedge_pick_bucket_row(
    scan_df: pd.DataFrame,
    *,
    bucket_label: str,
    used_combo_ids: Optional[Sequence[str]] = None,
) -> Dict[str, Any]:
    score_col = str(PRECISE_HEDGE_PARAM_SCAN_BUCKET_SCORE_COL_MAP.get(bucket_label, ""))
    sort_spec_map: Dict[str, Tuple[List[str], List[bool]]] = {
        "稳健型": (
            [score_col, "欠保概率", "稳定性评分", "标准差", "目标区间命中率", "与目标头寸绝对偏差", "输入行号", "入场价", "时间", "参与率K"],
            [False, True, False, True, False, True, True, True, True, True],
        ),
        "平衡型": (
            [score_col, "目标区间命中率", "与目标头寸绝对偏差", "区间均衡评分", "标准差", "输入行号", "入场价", "时间", "参与率K"],
            [False, False, True, False, True, True, True, True, True],
        ),
        "激进型": (
            [score_col, "上沿贴近评分", "目标区间命中率", "与目标头寸绝对偏差", "超保概率", "标准差", "输入行号", "入场价", "时间", "参与率K"],
            [False, False, False, True, True, True, True, True, True, True],
        ),
    }
    sort_cols, ascending = sort_spec_map.get(
        str(bucket_label),
        ([score_col, "目标区间命中率", "与目标头寸绝对偏差", "标准差"], [False, False, True, True]),
    )
    primary_pick = precise_hedge_pick_structure_scan_row(
        scan_df,
        score_col,
        sort_cols=sort_cols,
        ascending=ascending,
    )
    if not primary_pick:
        return {}
    picked = precise_hedge_pick_structure_scan_row(
        scan_df,
        score_col,
        sort_cols=sort_cols,
        ascending=ascending,
        exclude_combo_ids=used_combo_ids,
    )
    dedupe_note = ""
    if not picked:
        picked = dict(primary_pick)
        if used_combo_ids:
            dedupe_note = "有效候选不足，无法完全去重，沿用最接近的现有方案。"
    elif used_combo_ids and str(pick_first(picked.get("_combo_id"), "")) != str(pick_first(primary_pick.get("_combo_id"), "")):
        dedupe_note = "与另一档头部候选接近，已向次优方案去重。"
    out = dict(picked)
    out["去重说明"] = str(dedupe_note)
    out["推荐评分列"] = str(score_col)
    out["推荐评分"] = float(pick_first(to_float(out.get(score_col)), 0.0) or 0.0)
    return out


def precise_hedge_describe_structure_scan_reason(
    row: Mapping[str, Any],
    *,
    label: str,
    preference: str,
    dedupe_note: str = "",
) -> str:
    hit_text = probexp_format_pct(row.get("目标区间命中率"))
    under_text = probexp_format_pct(row.get("欠保概率"))
    over_text = probexp_format_pct(row.get("超保概率"))
    gap_text = probexp_format_tons(row.get("与目标头寸绝对偏差"))
    std_text = probexp_format_tons(row.get("标准差"))
    mean_text = probexp_format_tons(row.get("平均最终头寸"), signed=True)
    message = ""
    if str(label) == "稳健型":
        message = (
            f"这组方案优先减少套少了的情况，当前套少了约 {under_text}，离散度约 {std_text}，"
            f"同时把落在目标内的比例维持在 {hit_text}，平均偏离目标 {gap_text}。"
        )
    elif str(label) == "平衡型":
        message = (
            f"这组方案更看重整体均衡，落在目标内的比例 {hit_text}，平均偏离目标 {gap_text}，"
            f"套少了 {under_text}、套多了 {over_text} 相对更平衡，离散度约 {std_text}。"
        )
    elif str(label) == "激进型":
        message = (
            f"这组方案更靠近目标上沿，平均最终头寸 {mean_text}，落在目标内的比例 {hit_text}，"
            f"平均偏离目标 {gap_text}，在接受一定波动 {std_text} 的前提下，套多了约 {over_text}。"
        )
    elif str(label) == "综合最优":
        if str(preference) == "偏防欠保":
            message = f"按当前“减少套少”口径排序后，套少了 {under_text}，落在目标内 {hit_text}，平均偏离目标 {gap_text}。"
        elif str(preference) == "偏防超保":
            message = f"按当前“减少套多”口径排序后，套多了 {over_text}，落在目标内 {hit_text}，平均偏离目标 {gap_text}。"
        else:
            message = f"按当前综合口径排序后，落在目标内 {hit_text}，平均偏离目标 {gap_text}，套少了 {under_text}、套多了 {over_text}。"
    elif str(label) == "偏防欠保":
        message = f"这组方案优先减少套少了的情况，当前套少了约 {under_text}，落在目标内 {hit_text}，离散度约 {std_text}。"
    elif str(label) == "偏防超保":
        message = f"这组方案优先减少套多了的情况，当前套多了约 {over_text}，落在目标内 {hit_text}，平均偏离目标 {gap_text}。"
    else:
        message = f"落在目标内 {hit_text}，套少了 {under_text}，套多了 {over_text}，平均偏离目标 {gap_text}。"
    dedupe_text = str(dedupe_note).strip()
    if dedupe_text:
        message = f"{message} {dedupe_text}"
    return message


def precise_hedge_build_recommendation_buckets(
    scan_df: pd.DataFrame,
    *,
    preference: str,
) -> Dict[str, Dict[str, Any]]:
    recommendation_map: Dict[str, Dict[str, Any]] = {}
    used_combo_ids: set[str] = set()
    for bucket_label in PRECISE_HEDGE_PARAM_SCAN_BUCKET_SCORE_COL_MAP.keys():
        picked = precise_hedge_pick_bucket_row(
            scan_df,
            bucket_label=str(bucket_label),
            used_combo_ids=sorted(used_combo_ids),
        )
        if not picked:
            continue
        combo_id = str(pick_first(picked.get("_combo_id"), ""))
        if combo_id:
            used_combo_ids.add(combo_id)
        scan_row_payload = dict(picked)
        item = dict(scan_row_payload)
        item["推荐档位"] = str(bucket_label)
        item["参数组合"] = {
            "入场价": float(pick_first(to_float(scan_row_payload.get("入场价")), 0.0) or 0.0),
            "时间": int(pick_first(_int_from_any(scan_row_payload.get("时间"), 0), 0) or 0),
            "参与率K": float(pick_first(to_float(scan_row_payload.get("参与率K")), 0.0) or 0.0),
            "行权价": float(pick_first(to_float(scan_row_payload.get("行权价")), 0.0) or 0.0),
            "障碍价": float(pick_first(to_float(scan_row_payload.get("障碍价")), 0.0) or 0.0),
        }
        item["命中率"] = float(pick_first(to_float(scan_row_payload.get("目标区间命中率")), 0.0) or 0.0)
        item["欠保概率"] = float(pick_first(to_float(scan_row_payload.get("欠保概率")), 0.0) or 0.0)
        item["超保概率"] = float(pick_first(to_float(scan_row_payload.get("超保概率")), 0.0) or 0.0)
        item["平均偏差"] = float(pick_first(to_float(scan_row_payload.get("与目标头寸绝对偏差")), 0.0) or 0.0)
        item["推荐理由"] = precise_hedge_describe_structure_scan_reason(
            scan_row_payload,
            label=str(bucket_label),
            preference=str(preference),
            dedupe_note=str(pick_first(scan_row_payload.get("去重说明"), "")),
        )
        item["scan_row"] = dict(scan_row_payload)
        recommendation_map[str(bucket_label)] = item
    return recommendation_map


def precise_hedge_render_structure_scan_card(
    title: str,
    row: Mapping[str, Any],
    *,
    empty_reason: str = "暂无可用推荐。",
) -> None:
    st.markdown(f"##### {str(title)}")
    if not isinstance(row, Mapping) or not row:
        st.caption(str(empty_reason).strip() or "暂无可用推荐。")
        return
    display_row = (
        row.get("scan_row", {})
        if isinstance(row.get("scan_row", {}), Mapping)
        else row
    )
    if not isinstance(display_row, Mapping) or not display_row:
        st.caption(str(empty_reason).strip() or "暂无可用推荐。")
        return
    st.caption(
        f"入场价 {probexp_format_price(display_row.get('入场价'), digits=2)} | "
        f"时间 {int(pick_first(_int_from_any(display_row.get('时间'), 0), 0) or 0)} 天 | "
        f"参与率K {float(pick_first(to_float(display_row.get('参与率K')), 0.0) or 0.0):.2f}"
    )
    st.caption(
        f"行权价 {probexp_format_price(display_row.get('行权价'), digits=2)} | "
        f"障碍价 {probexp_format_price(display_row.get('障碍价'), digits=2)}"
    )
    st.caption(
        f"平均最终头寸 {probexp_format_position_tons(display_row.get('平均最终头寸'))} | "
        f"落在目标内 {probexp_format_pct(display_row.get('目标区间命中率'))}"
    )
    st.caption(
        f"套少了 {probexp_format_pct(display_row.get('欠保概率'))} | "
        f"套多了 {probexp_format_pct(display_row.get('超保概率'))}"
    )
    st.caption(
        f"平均偏离目标 {probexp_format_tons(display_row.get('与目标头寸绝对偏差'))} | "
        f"标准差 {probexp_format_tons(display_row.get('标准差'))}"
    )
    reason_text = str(pick_first(row.get("推荐理由"), display_row.get("推荐理由"), "")).strip()
    if reason_text:
        st.info(reason_text)


def precise_hedge_run_structure_param_scan(
    *,
    resolved: Mapping[str, Any],
    current_price: Any,
    direction_sign: Any,
    target_center: Any,
    target_lower: Any,
    target_upper: Any,
    candidate_df: Any,
    preference: str,
    atm_iv_pct: Any,
    skew: Any,
    paths: Any,
    base_issues: Optional[Sequence[Mapping[str, Any]]] = None,
    seed_hint: str = "",
    perf: Optional[SpecialPagePerfCollector] = None,
) -> Dict[str, Any]:
    direction_sign_val = float(pick_first(to_float(direction_sign), 1.0) or 1.0)
    direction_kind = "ACC" if direction_sign_val >= 0.0 else "DEC"
    current_price_val = float(pick_first(to_float(current_price), 0.0) or 0.0)
    if current_price_val <= 1e-12:
        raise RuntimeError("当前价格无效，无法执行参数扫描。")
    pref_label = str(preference).strip()
    if pref_label not in PRECISE_HEDGE_PARAM_SCAN_PREFERENCE_OPTIONS:
        pref_label = "偏中性"
    score_col_map = {
        "偏中性": "偏中性评分",
        "偏防欠保": "偏防欠保评分",
        "偏防超保": "偏防超保评分",
    }
    active_score_col = str(score_col_map.get(pref_label, "偏中性评分"))

    target_center_signed, target_center_corrected = probexp_normalize_directional_input(target_center, direction_kind)
    target_lower_signed, target_lower_corrected = probexp_normalize_directional_input(target_lower, direction_kind)
    target_upper_signed, target_upper_corrected = probexp_normalize_directional_input(target_upper, direction_kind)
    target_interval = precise_hedge_normalize_target_interval(
        target_center_signed,
        target_lower_signed,
        target_upper_signed,
        direction_sign_val,
    )
    input_adjust_notes: List[str] = []
    if target_center_corrected or target_lower_corrected or target_upper_corrected:
        input_adjust_notes.append("参数扫描目标区间已按结构方向自动纠正为同向口径。")

    skipped_rows: List[Dict[str, Any]] = [dict(row) for row in base_issues or [] if isinstance(row, Mapping)]
    combos, candidate_issues = precise_hedge_collect_param_scan_candidate_rows(candidate_df)
    skipped_rows.extend(candidate_issues)

    base_signature_payload = {
        "seed_hint": seed_hint,
        "input_mode": "candidate_rows",
        "preference": pref_label,
        "target_center": float(target_center_signed),
        "target_lower": float(target_interval["target_lower"]),
        "target_upper": float(target_interval["target_upper"]),
        "combo_count": int(len(combos)),
    }
    if not combos:
        skipped_df = pd.DataFrame(skipped_rows)
        skipped_reason_df = (
            skipped_df.groupby("原因", dropna=False).size().reset_index(name="数量").sort_values(["数量", "原因"], ascending=[False, True])
            if not skipped_df.empty and "原因" in skipped_df.columns
            else pd.DataFrame()
        )
        empty_result = {
            "scan_df": pd.DataFrame(),
            "recommendations": {},
            "recommendation_map": {},
            "recommendation_buckets": {},
            "skipped_df": skipped_df,
            "skipped_reason_df": skipped_reason_df,
            "evaluated_count": 0,
            "combo_count": 0,
            "unique_eval_count": 0,
            "shared_term_count": 0,
            "preference": pref_label,
            "active_score_col": active_score_col,
            "target_center": float(target_center_signed),
            "target_lower": float(target_interval["target_lower"]),
            "target_upper": float(target_interval["target_upper"]),
            "target_interval": target_interval,
            "input_mode": "candidate_rows",
            "band_scale": max(
                abs(float(target_interval["target_upper"]) - float(target_interval["target_lower"])) * 0.5,
                abs(float(target_center_signed)) * 0.05,
                1000.0,
            ),
            "input_adjust_notes": input_adjust_notes,
        }
        return _attach_special_page_result_meta(
            empty_result,
            page_name=f"{PRECISE_HEDGE_PAGE_LABEL}:结构参数优化",
            input_signature=_special_page_input_signature(base_signature_payload),
        )

    atm_iv_val = float(pick_first(to_float(atm_iv_pct), 0.0) or 0.0)
    skew_val = float(pick_first(to_float(skew), 0.0) or 0.0)
    path_count = int(_int_from_any(paths, PROBEXP_MC_PATHS_DEFAULT, min_value=2000, max_value=PROBEXP_MC_PATHS_MAX))
    price_matrix_cache: Dict[int, np.ndarray] = {}
    eval_cache: Dict[str, Dict[str, Any]] = {}
    rows: List[Dict[str, Any]] = []

    with special_page_perf_step(perf, "结构参数优化-参数扫描", category="compute"):
        for combo in combos:
            term_val = int(combo["时间"])
            eval_key = "|".join(
                [
                    str(term_val),
                    f"{float(combo['参与率K']):.4f}",
                    f"{float(combo['行权价']):.6f}",
                    f"{float(combo['障碍价']):.6f}",
                ]
            )
            if eval_key not in eval_cache:
                if term_val not in price_matrix_cache:
                    price_sim = winrate_simulate_price_paths(
                        start_price=float(current_price_val),
                        n_days=int(term_val),
                        atm_iv_pct=float(atm_iv_val),
                        skew=float(skew_val),
                        paths=int(path_count),
                        trading_days_per_year=252,
                        seed_hint=f"{seed_hint}|term={term_val}",
                    )
                    price_matrix_cache[int(term_val)] = np.asarray(price_sim.get("price_paths"), dtype=np.float32)
                runtime_struct = dict(resolved or {})
                runtime_struct["strategy_code"] = resolve_strategy_code_for_display(runtime_struct.get("strategy_code", ""))
                runtime_struct["kind"] = normalize_kind_code(runtime_struct.get("kind", ""))
                runtime_struct["entry_price"] = float(combo["入场价"])
                runtime_struct["strike_price"] = float(combo["行权价"])
                runtime_struct["barrier_out"] = float(combo["障碍价"])
                runtime_struct["knock_out_price"] = float(combo["障碍价"])
                runtime_struct["ko_strike_price"] = float(
                    pick_first(to_float(runtime_struct.get("ko_strike_price")), combo["入场价"]) or combo["入场价"]
                )
                runtime_struct["multiple"] = float(combo["参与率K"])
                runtime_struct["base_qty_per_day"] = float(
                    pick_first(to_float(runtime_struct.get("base_qty_per_day")), 0.0) or 0.0
                )
                eval_payload = precise_hedge_evaluate_accumulator_price_matrix(
                    struct_row=runtime_struct,
                    price_matrix=price_matrix_cache[int(term_val)],
                )
                future_qty_paths = np.asarray(eval_payload.get("future_qty_paths"), dtype=float)
                final_total_paths = float(direction_sign_val) * future_qty_paths
                final_stats = precise_hedge_build_distribution_stats(final_total_paths)
                metrics = precise_hedge_build_interval_metrics(
                    final_total_paths,
                    direction_sign=float(direction_sign_val),
                    target_center=float(target_center_signed),
                    target_lower=float(target_interval["target_lower"]),
                    target_upper=float(target_interval["target_upper"]),
                )
                eval_cache[eval_key] = {
                    "mean_final": float(final_stats.get("mean", 0.0)),
                    "std_final": float(final_stats.get("std", 0.0)),
                    "p10": float(final_stats.get("p10", 0.0)),
                    "p25": float(final_stats.get("p25", 0.0)),
                    "p50": float(final_stats.get("p50", 0.0)),
                    "p75": float(final_stats.get("p75", 0.0)),
                    "p90": float(final_stats.get("p90", 0.0)),
                    "metrics": metrics,
                }
            eval_payload = eval_cache[eval_key]
            score_payload = precise_hedge_build_param_scan_scores(
                mean_final=eval_payload.get("mean_final"),
                std_final=eval_payload.get("std_final"),
                hit_rate=((eval_payload.get("metrics", {}) if isinstance(eval_payload.get("metrics", {}), dict) else {}).get("hit_rate")),
                under_prob=((eval_payload.get("metrics", {}) if isinstance(eval_payload.get("metrics", {}), dict) else {}).get("under_prob")),
                over_prob=((eval_payload.get("metrics", {}) if isinstance(eval_payload.get("metrics", {}), dict) else {}).get("over_prob")),
                feasibility_score=1.0,
                target_center=float(target_center_signed),
                target_lower=float(target_interval["target_lower"]),
                target_upper=float(target_interval["target_upper"]),
                p10=eval_payload.get("p10"),
                p50=eval_payload.get("p50"),
                p90=eval_payload.get("p90"),
                direction_sign=float(direction_sign_val),
            )
            metrics = eval_payload.get("metrics", {}) if isinstance(eval_payload.get("metrics", {}), dict) else {}
            score_components = score_payload.get("components", {}) if isinstance(score_payload.get("components", {}), dict) else {}
            rec_scores = score_payload.get("recommendation_scores", {}) if isinstance(score_payload.get("recommendation_scores", {}), dict) else {}
            combo_id = "|".join(
                [
                    f"{float(combo['入场价']):.6f}",
                    str(int(combo["时间"])),
                    f"{float(combo['参与率K']):.4f}",
                    f"{float(combo['行权价']):.6f}",
                    f"{float(combo['障碍价']):.6f}",
                ]
            )
            rows.append(
                {
                    "输入行号": int(pick_first(combo.get("输入行号"), 0) or 0),
                    "入场价": float(combo["入场价"]),
                    "时间": int(combo["时间"]),
                    "参与率K": float(combo["参与率K"]),
                    "行权价": float(combo["行权价"]),
                    "障碍价": float(combo["障碍价"]),
                    "可行性评分": 100.0,
                    "平均最终头寸": float(pick_first(eval_payload.get("mean_final"), 0.0) or 0.0),
                    "P10": float(pick_first(eval_payload.get("p10"), 0.0) or 0.0),
                    "P25": float(pick_first(eval_payload.get("p25"), 0.0) or 0.0),
                    "P50": float(pick_first(eval_payload.get("p50"), 0.0) or 0.0),
                    "P75": float(pick_first(eval_payload.get("p75"), 0.0) or 0.0),
                    "P90": float(pick_first(eval_payload.get("p90"), 0.0) or 0.0),
                    "标准差": float(pick_first(eval_payload.get("std_final"), 0.0) or 0.0),
                    "分布跨度P90-P10": float(pick_first(score_payload.get("p90_p10_span"), 0.0) or 0.0),
                    "与目标头寸绝对偏差": abs(float(pick_first(eval_payload.get("mean_final"), 0.0) or 0.0) - float(target_center_signed)),
                    "目标区间命中率": float(pick_first(metrics.get("hit_rate"), 0.0) or 0.0),
                    "欠保概率": float(pick_first(metrics.get("under_prob"), 0.0) or 0.0),
                    "超保概率": float(pick_first(metrics.get("over_prob"), 0.0) or 0.0),
                    "稳定性评分": float(pick_first(to_float(score_components.get("stability")), 0.0) or 0.0) * 100.0,
                    "区间均衡评分": float(pick_first(to_float(score_components.get("balance")), 0.0) or 0.0) * 100.0,
                    "上沿贴近评分": float(pick_first(to_float(score_components.get("upper_exposure")), 0.0) or 0.0) * 100.0,
                    "偏中性评分": float(pick_first((score_payload.get("scores", {}) if isinstance(score_payload.get("scores", {}), dict) else {}).get("偏中性"), 0.0) or 0.0),
                    "偏防欠保评分": float(pick_first((score_payload.get("scores", {}) if isinstance(score_payload.get("scores", {}), dict) else {}).get("偏防欠保"), 0.0) or 0.0),
                    "偏防超保评分": float(pick_first((score_payload.get("scores", {}) if isinstance(score_payload.get("scores", {}), dict) else {}).get("偏防超保"), 0.0) or 0.0),
                    "稳健型评分": float(pick_first(rec_scores.get("稳健型"), 0.0) or 0.0),
                    "平衡型评分": float(pick_first(rec_scores.get("平衡型"), 0.0) or 0.0),
                    "激进型评分": float(pick_first(rec_scores.get("激进型"), 0.0) or 0.0),
                    "_combo_id": combo_id,
                }
            )

    scan_df = pd.DataFrame(rows)
    if scan_df.empty:
        skipped_df = pd.DataFrame(skipped_rows)
        skipped_reason_df = (
            skipped_df.groupby("原因", dropna=False).size().reset_index(name="数量").sort_values(["数量", "原因"], ascending=[False, True])
            if not skipped_df.empty and "原因" in skipped_df.columns
            else pd.DataFrame()
        )
        empty_result = {
            "scan_df": scan_df,
            "recommendations": {},
            "recommendation_map": {},
            "recommendation_buckets": {},
            "skipped_df": skipped_df,
            "skipped_reason_df": skipped_reason_df,
            "evaluated_count": 0,
            "combo_count": int(len(combos)),
            "unique_eval_count": int(len(eval_cache)),
            "shared_term_count": int(len(price_matrix_cache)),
            "preference": pref_label,
            "active_score_col": active_score_col,
            "target_center": float(target_center_signed),
            "target_lower": float(target_interval["target_lower"]),
            "target_upper": float(target_interval["target_upper"]),
            "target_interval": target_interval,
            "input_mode": "candidate_rows",
            "band_scale": max(
                abs(float(target_interval["target_upper"]) - float(target_interval["target_lower"])) * 0.5,
                abs(float(target_center_signed)) * 0.05,
                1000.0,
            ),
            "input_adjust_notes": input_adjust_notes,
        }
        return _attach_special_page_result_meta(
            empty_result,
            page_name=f"{PRECISE_HEDGE_PAGE_LABEL}:结构参数优化",
            input_signature=_special_page_input_signature(base_signature_payload),
        )

    scan_df["综合评分"] = pd.to_numeric(scan_df.get(active_score_col), errors="coerce").fillna(0.0)
    scan_df = scan_df.sort_values(
        [active_score_col, "目标区间命中率", "与目标头寸绝对偏差", "标准差", "输入行号", "入场价", "时间", "参与率K"],
        ascending=[False, False, True, True, True, True, True, True],
    ).reset_index(drop=True)
    scan_df["排名"] = np.arange(1, len(scan_df) + 1)
    recommendations: Dict[str, Dict[str, Any]] = {}
    recommendation_specs = [
        ("综合最优", active_score_col),
        ("偏防欠保", "偏防欠保评分"),
        ("偏防超保", "偏防超保评分"),
    ]
    label_map: Dict[str, List[str]] = {}
    recommendation_map = precise_hedge_build_recommendation_buckets(
        scan_df,
        preference=pref_label,
    )
    bucket_label_map: Dict[str, List[str]] = {}
    for card_title, score_col in recommendation_specs:
        picked = precise_hedge_pick_structure_scan_row(scan_df, score_col)
        if not picked:
            continue
        picked["推荐理由"] = precise_hedge_describe_structure_scan_reason(
            picked,
            label=card_title,
            preference=pref_label,
        )
        recommendations[str(card_title)] = picked
        combo_id = str(pick_first(picked.get("_combo_id"), ""))
        if combo_id:
            label_map.setdefault(combo_id, []).append(str(card_title))
    for bucket_label, picked in recommendation_map.items():
        combo_id = str(pick_first((picked.get("scan_row", {}) if isinstance(picked.get("scan_row", {}), dict) else {}).get("_combo_id"), picked.get("_combo_id"), ""))
        if combo_id:
            bucket_label_map.setdefault(combo_id, []).append(str(bucket_label))
            label_map.setdefault(combo_id, []).append(str(bucket_label))
    scan_df["推荐分层"] = scan_df["_combo_id"].map(lambda x: " / ".join(bucket_label_map.get(str(x), [])))
    scan_df["推荐标签"] = scan_df["_combo_id"].map(lambda x: " / ".join(dict.fromkeys(label_map.get(str(x), []))))

    skipped_df = pd.DataFrame(skipped_rows)
    skipped_reason_df = (
        skipped_df.groupby("原因", dropna=False).size().reset_index(name="数量").sort_values(["数量", "原因"], ascending=[False, True])
        if not skipped_df.empty and "原因" in skipped_df.columns
        else pd.DataFrame()
    )
    result_payload = {
        "scan_df": scan_df,
        "recommendations": recommendations,
        "recommendation_map": recommendation_map,
        "recommendation_buckets": recommendation_map,
        "skipped_df": skipped_df,
        "skipped_reason_df": skipped_reason_df,
        "evaluated_count": int(len(scan_df)),
        "combo_count": int(len(combos)),
        "unique_eval_count": int(len(eval_cache)),
        "shared_term_count": int(len(price_matrix_cache)),
        "preference": pref_label,
        "active_score_col": active_score_col,
        "target_center": float(target_center_signed),
        "target_lower": float(target_interval["target_lower"]),
        "target_upper": float(target_interval["target_upper"]),
        "target_interval": target_interval,
        "input_mode": "candidate_rows",
        "band_scale": max(
            abs(float(target_interval["target_upper"]) - float(target_interval["target_lower"])) * 0.5,
            abs(float(target_center_signed)) * 0.05,
            1000.0,
        ),
        "input_adjust_notes": input_adjust_notes,
    }
    base_signature_payload.update(
        {
            "evaluated_count": int(len(scan_df)),
            "shared_term_count": int(len(price_matrix_cache)),
            "unique_eval_count": int(len(eval_cache)),
        }
    )
    return _attach_special_page_result_meta(
        result_payload,
        page_name=f"{PRECISE_HEDGE_PAGE_LABEL}:结构参数优化",
        input_signature=_special_page_input_signature(base_signature_payload),
    )


def precise_hedge_build_state_layer(
    *,
    history_result: Mapping[str, Any],
    mc_result: Mapping[str, Any],
    template: Mapping[str, Any],
    snapshot: Mapping[str, Any],
    current_position: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
    step_tons: float,
    scan_steps: int,
) -> Dict[str, Any]:
    future_qty = np.asarray(mc_result.get("future_qty_paths"), dtype=float)
    future_qty = future_qty[np.isfinite(future_qty)]
    scenario_ids = np.asarray(mc_result.get("scenario_ids"), dtype=int).reshape(-1)
    if scenario_ids.size != future_qty.size:
        scenario_ids = np.full(future_qty.size, WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT, dtype=np.int8)
    path_scoring_cum_qty_paths = np.asarray(mc_result.get("path_scoring_cum_qty_paths"), dtype=float)
    if path_scoring_cum_qty_paths.ndim == 1:
        path_scoring_cum_qty_paths = path_scoring_cum_qty_paths.reshape(1, -1)
    if path_scoring_cum_qty_paths.ndim != 2:
        path_scoring_cum_qty_paths = np.zeros((0, 0), dtype=float)
    path_scoring_scenario_ids = np.asarray(mc_result.get("path_scoring_scenario_ids"), dtype=int).reshape(-1)
    if path_scoring_cum_qty_paths.shape[0] != path_scoring_scenario_ids.size:
        path_scoring_cum_qty_paths = np.zeros((0, 0), dtype=float)
        path_scoring_scenario_ids = np.asarray([], dtype=int)
    history_sample_df = history_result.get("sample_df") if isinstance(history_result.get("sample_df"), pd.DataFrame) else pd.DataFrame()
    history_cum_exec_matrix = np.asarray(history_result.get("cum_exec_path_matrix"), dtype=float)
    if history_cum_exec_matrix.ndim == 1:
        history_cum_exec_matrix = history_cum_exec_matrix.reshape(1, -1)
    if history_cum_exec_matrix.ndim != 2 or history_cum_exec_matrix.shape[0] != len(history_sample_df):
        history_cum_exec_matrix = np.zeros((0, 0), dtype=float)
    direction_sign = float(pick_first(snapshot.get("direction_sign"), 1.0) or 1.0)
    observed_qty = float(pick_first(snapshot.get("observed_qty"), 0.0) or 0.0)
    total_hist = int(len(history_sample_df)) if isinstance(history_sample_df, pd.DataFrame) else 0
    prob_source = "Monte Carlo 显式状态拆分（历史样本对照）"
    scenario_meta = [
        (
            WINRATE_ACCUMULATOR_SCENARIO_KI,
            "敲入情景",
            "按真实敲入路径单独统计，代表未来生成偏多的风险场景。",
        ),
        (
            WINRATE_ACCUMULATOR_SCENARIO_NO_EVENT,
            "震荡/中性情景",
            "按真实未敲入且未敲出路径单独统计，代表结构按常规节奏继续生成。",
        ),
        (
            WINRATE_ACCUMULATOR_SCENARIO_KO,
            "敲出情景",
            "按真实敲出路径单独统计，代表未来生成偏少或提前结束的风险场景。",
        ),
    ]
    rows: List[Dict[str, Any]] = []
    weighted_position_raw = 0.0
    state_result_map: Dict[str, Dict[str, Any]] = {}
    for scenario_id, scenario_label, note in scenario_meta:
        mc_mask = scenario_ids == int(scenario_id)
        state_future_qty = future_qty[mc_mask]
        mc_prob = float(np.mean(mc_mask)) if future_qty.size > 0 else 0.0
        state_path_cum_qty = np.zeros((0, 0), dtype=float)
        if path_scoring_cum_qty_paths.size > 0 and path_scoring_scenario_ids.size == path_scoring_cum_qty_paths.shape[0]:
            state_path_cum_qty = path_scoring_cum_qty_paths[path_scoring_scenario_ids == int(scenario_id)]
        hist_future_qty = np.asarray([], dtype=float)
        hist_prob = 0.0
        hist_path_cum_qty = np.zeros((0, 0), dtype=float)
        if isinstance(history_sample_df, pd.DataFrame) and (not history_sample_df.empty):
            hist_sub = history_sample_df[history_sample_df["scenario_id"].astype(int) == int(scenario_id)].copy()
            hist_prob = (float(len(hist_sub)) / float(total_hist)) if total_hist > 0 else 0.0
            if "future_qty" in hist_sub.columns:
                hist_future_qty = pd.to_numeric(hist_sub["future_qty"], errors="coerce").dropna().to_numpy(dtype=float)
            if history_cum_exec_matrix.size > 0 and "sample_index" in hist_sub.columns:
                hist_indices = [int(x) - 1 for x in pd.to_numeric(hist_sub["sample_index"], errors="coerce").dropna().astype(int).tolist() if int(x) > 0]
                hist_indices = [idx for idx in hist_indices if 0 <= idx < history_cum_exec_matrix.shape[0]]
                if hist_indices:
                    hist_path_cum_qty = history_cum_exec_matrix[np.asarray(hist_indices, dtype=int)]
        working_future_qty = state_future_qty if state_future_qty.size > 0 else hist_future_qty
        working_path_cum_qty = state_path_cum_qty if state_path_cum_qty.size > 0 else hist_path_cum_qty
        generation_stats = precise_hedge_build_distribution_stats(working_future_qty)
        raw_position_paths = float(target_center) - float(direction_sign) * (float(observed_qty) + working_future_qty)
        position_paths = precise_hedge_clip_position_array_to_direction(raw_position_paths, direction_sign)
        position_stats = precise_hedge_build_distribution_stats(position_paths)
        named_positions = {
            f"{scenario_label} 仓位P50": float(position_stats.get("p50", 0.0)),
            f"{scenario_label} 仓位P80": float(position_stats.get("p80", 0.0)),
        }
        state_scan_df = precise_hedge_build_scan_table(
            future_qty_paths=working_future_qty,
            cum_exec_step_paths=working_path_cum_qty,
            observed_qty=float(observed_qty),
            direction_sign=float(direction_sign),
            current_position=float(current_position),
            target_center=float(target_center),
            target_lower=float(target_lower),
            target_upper=float(target_upper),
            step_tons=float(step_tons),
            scan_steps=int(scan_steps),
            named_positions=named_positions,
        )
        suggested_pos = float(
            pick_first(
                state_scan_df.iloc[0].get("候选仓位") if isinstance(state_scan_df, pd.DataFrame) and not state_scan_df.empty else None,
                position_stats.get("p50"),
                0.0,
            )
            or 0.0
        )
        state_metrics = (
            precise_hedge_build_path_interval_metrics(
                working_path_cum_qty,
                observed_qty=float(observed_qty),
                candidate_position=float(suggested_pos),
                direction_sign=float(direction_sign),
                target_center=float(target_center),
                target_lower=float(target_lower),
                target_upper=float(target_upper),
            )
            if working_path_cum_qty.size > 0
            else precise_hedge_build_interval_metrics(
                float(suggested_pos) + float(direction_sign) * (float(observed_qty) + working_future_qty),
                direction_sign=float(direction_sign),
                target_center=float(target_center),
                target_lower=float(target_lower),
                target_upper=float(target_upper),
            )
        )
        weighted_position_raw += float(mc_prob) * float(suggested_pos)
        rows.append(
            {
                "情景": scenario_label,
                "历史概率": float(hist_prob),
                "MonteCarlo概率": float(mc_prob),
                "当前权重概率": float(mc_prob),
                "历史样本数": int(hist_future_qty.size),
                "当前路径数": int(state_future_qty.size),
                "最终生成均值(吨)": float(generation_stats.get("mean", 0.0)),
                "最终生成P50(吨)": float(generation_stats.get("p50", 0.0)),
                "最终生成P70(吨)": float(generation_stats.get("p70", 0.0)),
                "最终生成P80(吨)": float(generation_stats.get("p80", 0.0)),
                "最终生成标准差(吨)": float(generation_stats.get("std", 0.0)),
                "推荐仓位均值(吨)": float(position_stats.get("mean", 0.0)),
                "推荐仓位P50(吨)": float(position_stats.get("p50", 0.0)),
                "推荐仓位P70(吨)": float(position_stats.get("p70", 0.0)),
                "推荐仓位P80(吨)": float(position_stats.get("p80", 0.0)),
                "推荐仓位标准差(吨)": float(position_stats.get("std", 0.0)),
                "建议仓位(吨)": float(suggested_pos),
                "较状态P50偏移(吨)": float(suggested_pos - float(position_stats.get("p50", 0.0))),
                "较状态P80偏移(吨)": float(suggested_pos - float(position_stats.get("p80", 0.0))),
                "命中率": float(state_metrics.get("hit_rate", 0.0)),
                "欠保概率": float(state_metrics.get("under_prob", 0.0)),
                "超保概率": float(state_metrics.get("over_prob", 0.0)),
                "平均绝对偏差": float(state_metrics.get("mean_abs_gap", 0.0)),
                "尾部偏差P95": float(state_metrics.get("tail_gap_p95", 0.0)),
                "近端覆盖率": float(state_metrics.get("near_hit_rate", 0.0)),
                "终点命中率": float(state_metrics.get("final_hit_rate", 0.0)),
                "说明": note,
            }
        )
        state_result_map[str(scenario_label)] = {
            "scenario_id": int(scenario_id),
            "mc_prob": float(mc_prob),
            "hist_prob": float(hist_prob),
            "future_qty_paths": working_future_qty,
            "cum_exec_step_paths": working_path_cum_qty,
            "position_paths": position_paths,
            "scan_df": state_scan_df,
            "metrics": state_metrics,
            "suggested_position": float(suggested_pos),
        }
    weighted_position = float(probexp_clip_target_position_to_direction(weighted_position_raw, direction_sign))
    return {
        "rows_df": pd.DataFrame(rows),
        "weighted_position": weighted_position,
        "prob_source": prob_source,
        "state_result_map": state_result_map,
    }


def precise_hedge_build_path_schedule_df(
    *,
    cum_exec_step_paths: Any,
    observed_qty: float,
    candidate_position: float,
    direction_sign: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
) -> pd.DataFrame:
    arr = np.asarray(cum_exec_step_paths, dtype=float)
    if arr.ndim == 1:
        arr = arr.reshape(1, -1)
    if arr.ndim != 2 or arr.size <= 0 or arr.shape[1] <= 0:
        return pd.DataFrame()
    cum_total = float(observed_qty) + arr
    q10 = np.quantile(cum_total, 0.10, axis=0)
    q50 = np.quantile(cum_total, 0.50, axis=0)
    q80 = np.quantile(cum_total, 0.80, axis=0)
    normalized = precise_hedge_normalize_target_interval(target_center, target_lower, target_upper, direction_sign)
    dir_total = float(normalized["direction_sign"]) * (
        float(candidate_position) + float(direction_sign) * cum_total
    )
    dir_low = float(normalized["dir_lower"])
    dir_high = float(normalized["dir_upper"])
    under_mask = dir_total < (dir_low - 1e-12)
    over_mask = dir_total > (dir_high + 1e-12)
    hit_mask = (~under_mask) & (~over_mask)
    interval_gap = np.zeros(dir_total.shape, dtype=float)
    if bool(np.any(under_mask)):
        interval_gap[under_mask] = dir_low - dir_total[under_mask]
    if bool(np.any(over_mask)):
        interval_gap[over_mask] = dir_total[over_mask] - dir_high
    rows: List[Dict[str, Any]] = []
    for step in range(arr.shape[1]):
        rows.append(
            {
                "第几天": int(step + 1),
                "累计执行P10(吨)": float(q10[step]),
                "累计执行P50(吨)": float(q50[step]),
                "累计执行P80(吨)": float(q80[step]),
                "路径覆盖率": float(np.mean(hit_mask[:, step])),
                "欠保概率": float(np.mean(under_mask[:, step])),
                "超保概率": float(np.mean(over_mask[:, step])),
                "路径偏差P95": float(np.quantile(interval_gap[:, step], 0.95)) if interval_gap.shape[0] > 0 else 0.0,
            }
        )
    return pd.DataFrame(rows)


def precise_hedge_build_path_profile_report(
    *,
    mc_result: Mapping[str, Any],
    snapshot: Mapping[str, Any],
    current_position: float,
    target_center: float,
    target_lower: float,
    target_upper: float,
    step_tons: float,
    scan_steps: int,
) -> Dict[str, Any]:
    path_cum_qty = np.asarray(mc_result.get("path_scoring_cum_qty_paths"), dtype=float)
    if path_cum_qty.ndim == 1:
        path_cum_qty = path_cum_qty.reshape(1, -1)
    if path_cum_qty.ndim != 2 or path_cum_qty.size <= 0 or path_cum_qty.shape[1] <= 0:
        return {
            "rows_df": pd.DataFrame(),
            "weighted_position": 0.0,
            "dominant_profile": "",
            "summary_lines": [],
            "schedule_df": pd.DataFrame(),
            "path_basis_note": "当前缺少可用于路径分型的路径矩阵。",
        }
    direction_sign = float(pick_first(snapshot.get("direction_sign"), 1.0) or 1.0)
    observed_qty = float(pick_first(snapshot.get("observed_qty"), 0.0) or 0.0)
    first_ki_steps = np.asarray(mc_result.get("path_scoring_first_ki_steps"), dtype=int).reshape(-1)
    first_ko_steps = np.asarray(mc_result.get("path_scoring_first_ko_steps"), dtype=int).reshape(-1)
    oscillation_days = np.asarray(mc_result.get("path_scoring_oscillation_days"), dtype=int).reshape(-1)
    knockin_days = np.asarray(mc_result.get("path_scoring_knockin_days"), dtype=int).reshape(-1)
    knockout_days = np.asarray(mc_result.get("path_scoring_knockout_days"), dtype=int).reshape(-1)
    future_qty = np.asarray(mc_result.get("path_scoring_future_qty_paths"), dtype=float).reshape(-1)
    if (
        future_qty.size != path_cum_qty.shape[0]
        or first_ki_steps.size != path_cum_qty.shape[0]
        or first_ko_steps.size != path_cum_qty.shape[0]
        or oscillation_days.size != path_cum_qty.shape[0]
    ):
        return {
            "rows_df": pd.DataFrame(),
            "weighted_position": 0.0,
            "dominant_profile": "",
            "summary_lines": [],
            "schedule_df": pd.DataFrame(),
            "path_basis_note": "路径矩阵与路径摘要长度不一致，暂无法做路径分型。",
        }
    total_days = int(path_cum_qty.shape[1])
    profile_labels = np.asarray(
        [
            precise_hedge_classify_path_profile(
                total_days=total_days,
                oscillation_days=oscillation_days[idx],
                knockin_days=knockin_days[idx],
                knockout_days=knockout_days[idx],
                first_ki_step=first_ki_steps[idx],
                first_ko_step=first_ko_steps[idx],
            )
            for idx in range(path_cum_qty.shape[0])
        ],
        dtype=object,
    )
    rows: List[Dict[str, Any]] = []
    weighted_position_raw = 0.0
    result_map: Dict[str, Dict[str, Any]] = {}
    total_paths = int(path_cum_qty.shape[0])
    for profile_label, note, _ in PRECISE_HEDGE_PATH_PROFILE_META:
        mask = profile_labels == str(profile_label)
        count = int(np.sum(mask))
        if count <= 0:
            continue
        sub_cum_qty = path_cum_qty[mask]
        sub_future_qty = future_qty[mask]
        scan_df = precise_hedge_build_scan_table(
            future_qty_paths=sub_future_qty,
            cum_exec_step_paths=sub_cum_qty,
            observed_qty=float(observed_qty),
            direction_sign=float(direction_sign),
            current_position=float(current_position),
            target_center=float(target_center),
            target_lower=float(target_lower),
            target_upper=float(target_upper),
            step_tons=float(step_tons),
            scan_steps=int(scan_steps),
            named_positions={"当前持仓": float(current_position)},
        )
        suggested_position = float(
            pick_first(
                scan_df.iloc[0].get("候选仓位") if isinstance(scan_df, pd.DataFrame) and not scan_df.empty else None,
                current_position,
                0.0,
            )
            or 0.0
        )
        metrics = precise_hedge_build_path_interval_metrics(
            sub_cum_qty,
            observed_qty=float(observed_qty),
            candidate_position=float(suggested_position),
            direction_sign=float(direction_sign),
            target_center=float(target_center),
            target_lower=float(target_lower),
            target_upper=float(target_upper),
        )
        ki_sub = first_ki_steps[mask]
        ko_sub = first_ko_steps[mask]
        positive_ki = ki_sub[ki_sub > 0]
        positive_ko = ko_sub[ko_sub > 0]
        prob = float(count) / float(total_paths) if total_paths > 0 else 0.0
        weighted_position_raw += prob * float(suggested_position)
        rows.append(
            {
                "路径类型": str(profile_label),
                "当前权重概率": float(prob),
                "路径数": int(count),
                "末端生成P50(吨)": float(np.quantile(sub_future_qty, 0.50)) if sub_future_qty.size > 0 else 0.0,
                "平均震荡日": float(np.mean(oscillation_days[mask])) if count > 0 else 0.0,
                "首次敲入中位日": float(np.median(positive_ki)) if positive_ki.size > 0 else np.nan,
                "首次敲出中位日": float(np.median(positive_ko)) if positive_ko.size > 0 else np.nan,
                "路径最优仓位(吨)": float(suggested_position),
                "路径覆盖率": float(metrics.get("hit_rate", 0.0)),
                "近端覆盖率": float(metrics.get("near_hit_rate", 0.0)),
                "终点命中率": float(metrics.get("final_hit_rate", 0.0)),
                "路径尾部最大偏差P95": float(metrics.get("path_max_gap_p95", 0.0)),
                "说明": str(note),
            }
        )
        result_map[str(profile_label)] = {
            "prob": float(prob),
            "path_count": int(count),
            "cum_exec_step_paths": sub_cum_qty,
            "future_qty_paths": sub_future_qty,
            "scan_df": scan_df,
            "metrics": metrics,
            "suggested_position": float(suggested_position),
        }
    rows_df = pd.DataFrame(rows)
    if not rows_df.empty:
        rows_df = rows_df.sort_values(["当前权重概率", "路径覆盖率", "路径数"], ascending=[False, False, False]).reset_index(drop=True)
    dominant_profile = str(pick_first(rows_df.iloc[0].get("路径类型") if not rows_df.empty else "", ""))
    dominant_note = precise_hedge_get_path_profile_note(dominant_profile)
    weighted_position = float(probexp_clip_target_position_to_direction(weighted_position_raw, direction_sign))
    schedule_df = precise_hedge_build_path_schedule_df(
        cum_exec_step_paths=path_cum_qty,
        observed_qty=float(observed_qty),
        candidate_position=float(weighted_position),
        direction_sign=float(direction_sign),
        target_center=float(target_center),
        target_lower=float(target_lower),
        target_upper=float(target_upper),
    )
    path_basis_note = (
        f"路径评分基于 {str(pick_first(mc_result.get('path_scoring_basis'), '无路径'))} "
        f"{int(pick_first(mc_result.get('path_scoring_count'), path_cum_qty.shape[0]) or path_cum_qty.shape[0]):,} 条路径。"
    )
    if bool(mc_result.get("path_scoring_sampled", False)):
        path_basis_note += f" 覆盖原始 Monte Carlo 路径约 {float(pick_first(mc_result.get('path_scoring_coverage'), 0.0) or 0.0) * 100.0:.1f}%。"
    summary_lines = []
    if dominant_profile:
        summary_lines.append(f"当前最主导的数量路径是“{dominant_profile}”。{dominant_note}")
    if not rows_df.empty:
        summary_lines.append(
            f"按路径分型加权后的参考仓位约为 {probexp_format_position_tons(weighted_position)}，"
            f"更强调未来每天累计数量怎么走，而不是只看终点。"
        )
    if path_basis_note:
        summary_lines.append(path_basis_note)
    return {
        "rows_df": rows_df,
        "weighted_position": float(weighted_position),
        "dominant_profile": dominant_profile,
        "summary_lines": summary_lines,
        "schedule_df": schedule_df,
        "path_basis_note": path_basis_note,
        "result_map": result_map,
    }


def precise_hedge_pick_scan_row(scan_df: pd.DataFrame, candidate_position: float) -> Dict[str, Any]:
    if scan_df is None or scan_df.empty:
        return {}
    sub = scan_df[np.isclose(scan_df["候选仓位"].astype(float), float(candidate_position), atol=1e-6)].copy()
    if sub.empty:
        return {}
    return sub.iloc[0].to_dict()


def precise_hedge_describe_weight_stance(candidate_position: Any, neutral_position: Any, tolerance_tons: float) -> str:
    candidate_abs = abs(float(pick_first(to_float(candidate_position), 0.0) or 0.0))
    neutral_abs = abs(float(pick_first(to_float(neutral_position), 0.0) or 0.0))
    tol = max(float(pick_first(to_float(tolerance_tons), 0.0) or 0.0), 1.0)
    if candidate_abs > neutral_abs + tol:
        return "偏保守"
    if candidate_abs < neutral_abs - tol:
        return "偏轻"
    return "偏中性"


def precise_hedge_resolve_price_zone(
    *,
    price: Any,
    direction_sign: float,
    ki_level: Optional[float],
    ko_level: Optional[float],
    buffer_pct: float,
) -> Dict[str, str]:
    price_val = float(pick_first(to_float(price), 0.0) or 0.0)
    ki_val = to_float(ki_level)
    ko_val = to_float(ko_level)
    buf = float(np.clip(float(buffer_pct), 0.005, 0.05))
    if direction_sign >= 0.0:
        if ki_val is not None and price_at_or_below(price_val, ki_val):
            return {"zone_key": "ki_danger", "zone_label": "敲入危险区", "zone_hint": "价格已进入或穿越敲入侧。"}
        if ko_val is not None and price_at_or_above(price_val, ko_val):
            return {"zone_key": "ko_danger", "zone_label": "敲出危险区", "zone_hint": "价格已进入或穿越敲出/熔断侧。"}
        if ki_val is not None and price_at_or_below(price_val, float(ki_val) * (1.0 + buf)):
            return {"zone_key": "ki_sensitive", "zone_label": "敲入敏感区", "zone_hint": "价格靠近敲入侧，需更重视欠保风险。"}
        if ko_val is not None and price_at_or_above(price_val, float(ko_val) * (1.0 - buf)):
            return {"zone_key": "ko_sensitive", "zone_label": "敲出敏感区", "zone_hint": "价格靠近敲出侧，需更重视超保风险。"}
        return {"zone_key": "neutral", "zone_label": "中性区", "zone_hint": "价格位于两条触发线之间，可优先维持基准仓位。"}
    if ki_val is not None and price_at_or_above(price_val, ki_val):
        return {"zone_key": "ki_danger", "zone_label": "敲入危险区", "zone_hint": "价格已进入或穿越敲入侧。"}
    if ko_val is not None and price_at_or_below(price_val, ko_val):
        return {"zone_key": "ko_danger", "zone_label": "敲出危险区", "zone_hint": "价格已进入或穿越敲出/熔断侧。"}
    if ki_val is not None and price_at_or_above(price_val, float(ki_val) * (1.0 - buf)):
        return {"zone_key": "ki_sensitive", "zone_label": "敲入敏感区", "zone_hint": "价格靠近敲入侧，需更重视欠保风险。"}
    if ko_val is not None and price_at_or_below(price_val, float(ko_val) * (1.0 + buf)):
        return {"zone_key": "ko_sensitive", "zone_label": "敲出敏感区", "zone_hint": "价格靠近敲出侧，需更重视超保风险。"}
    return {"zone_key": "neutral", "zone_label": "中性区", "zone_hint": "价格位于两条触发线之间，可优先维持基准仓位。"}


def precise_hedge_build_action_plan(
    *,
    resolved: Mapping[str, Any],
    snapshot: Mapping[str, Any],
    current_position: float,
    state_weighted_position: float,
    knockin_position: float,
    stable_position: float,
    knockout_position: float,
    target_center: float,
    scan_step_tons: float,
    state_prob_map: Mapping[str, float],
    risk_focus_text: str,
) -> Dict[str, Any]:
    direction_sign = float(pick_first(snapshot.get("direction_sign"), 1.0) or 1.0)
    current_close = float(pick_first(snapshot.get("current_close"), 0.0) or 0.0)
    entry_price = float(
        pick_first(
            to_float(resolved.get("entry_price")),
            to_float(resolved.get("strike_price")),
            current_close,
            0.0,
        )
        or 0.0
    )
    ki_level = to_float(pick_first(resolved.get("strike_price"), resolved.get("barrier_in"), resolved.get("entry_price")))
    ko_level = to_float(pick_first(resolved.get("knock_out_price"), resolved.get("barrier_out")))
    span_candidates = [abs(float(entry_price) - float(ki_level)) if ki_level is not None else 0.0]
    if ko_level is not None:
        span_candidates.append(abs(float(entry_price) - float(ko_level)))
        if ki_level is not None:
            span_candidates.append(abs(float(ki_level) - float(ko_level)))
    span_ref = max([x for x in span_candidates if np.isfinite(x)] + [abs(current_close) * 0.03, 1.0])
    buffer_pct = float(np.clip(span_ref / max(abs(entry_price), 1.0) * 0.18, 0.01, 0.03))
    no_trade_band = max(float(scan_step_tons) * 0.5, abs(float(target_center)) * 0.02, 500.0)

    def _blend_position(base_pos: float, alt_pos: float, alpha: float) -> float:
        blended = float(base_pos) + float(alpha) * (float(alt_pos) - float(base_pos))
        return float(probexp_clip_target_position_to_direction(blended, direction_sign))

    zone_map = {
        "ki_danger": float(knockin_position),
        "ki_sensitive": _blend_position(float(state_weighted_position), float(knockin_position), 0.55),
        "neutral": float(state_weighted_position),
        "ko_sensitive": _blend_position(float(state_weighted_position), float(knockout_position), 0.55),
        "ko_danger": float(knockout_position),
    }

    def _build_action(target_pos: float) -> Dict[str, Any]:
        diff_val = float(target_pos) - float(current_position)
        if abs(diff_val) <= no_trade_band:
            action_type = "维持"
            action_text = f"维持（当前持仓与目标仓位偏差 {abs(diff_val):,.0f} 吨，小于阈值 {no_trade_band:,.0f} 吨）"
        else:
            action_type = "加仓" if abs(float(target_pos)) > abs(float(current_position)) else "减仓"
            action_text = probexp_describe_adjustment(current_position, target_pos)
        return {
            "target_position": float(target_pos),
            "adjust_tons": float(diff_val),
            "action_type": action_type,
            "action_text": action_text,
        }

    current_zone = precise_hedge_resolve_price_zone(
        price=current_close,
        direction_sign=float(direction_sign),
        ki_level=ki_level,
        ko_level=ko_level,
        buffer_pct=float(buffer_pct),
    )
    current_target_position = float(zone_map.get(str(current_zone.get("zone_key", "neutral")), state_weighted_position))
    current_action = _build_action(current_target_position)

    state_probs_text = (
        f"当前状态概率：敲入 {probexp_format_pct(state_prob_map.get('敲入情景'))}，"
        f"中性 {probexp_format_pct(state_prob_map.get('震荡/中性情景'))}，"
        f"敲出 {probexp_format_pct(state_prob_map.get('敲出情景'))}。"
    )
    current_reason = (
        f"{str(current_zone.get('zone_hint', ''))}"
        f" 基准仓位使用状态加权综合最优仓位 {probexp_format_position_tons(state_weighted_position)}，"
        f"当前主风险判断为“{str(risk_focus_text)}”。 {state_probs_text}"
    ).strip()

    def _condition_text(zone_key: str) -> str:
        if zone_key == "ki_danger":
            if ki_level is None:
                return "敲入危险区"
            return f"价格进入敲入侧（{('<= ' if direction_sign >= 0 else '>= ')}{float(ki_level):,.2f}）"
        if zone_key == "ki_sensitive":
            if ki_level is None:
                return "接近敲入侧"
            level = float(ki_level) * (1.0 + buffer_pct if direction_sign >= 0 else 1.0 - buffer_pct)
            return f"价格接近敲入侧（{('<= ' if direction_sign >= 0 else '>= ')}{level:,.2f}）"
        if zone_key == "ko_sensitive":
            if ko_level is None:
                return "接近敲出侧"
            level = float(ko_level) * (1.0 - buffer_pct if direction_sign >= 0 else 1.0 + buffer_pct)
            return f"价格接近敲出侧（{('>= ' if direction_sign >= 0 else '<= ')}{level:,.2f}）"
        if zone_key == "ko_danger":
            if ko_level is None:
                return "敲出危险区"
            return f"价格进入敲出侧（{('>= ' if direction_sign >= 0 else '<= ')}{float(ko_level):,.2f}）"
        if ki_level is not None and ko_level is not None:
            left = float(ki_level) * (1.0 + buffer_pct if direction_sign >= 0 else 1.0 - buffer_pct)
            right = float(ko_level) * (1.0 - buffer_pct if direction_sign >= 0 else 1.0 + buffer_pct)
            lo_text = min(left, right)
            hi_text = max(left, right)
            return f"价格位于中性区（{lo_text:,.2f} ~ {hi_text:,.2f}）"
        return "价格位于中性区"

    threshold_rows: List[Dict[str, Any]] = []
    for zone_key, zone_label in [
        ("ki_danger", "敲入危险区"),
        ("neutral", "中性区"),
        ("ko_danger", "敲出危险区"),
    ]:
        target_pos = float(zone_map.get(zone_key, state_weighted_position))
        action_rec = _build_action(target_pos)
        threshold_rows.append(
            {
                "区域": zone_label,
                "价格条件": _condition_text(zone_key),
                "目标仓位(吨)": float(target_pos),
                "建议调整(吨)": float(action_rec.get("adjust_tons", 0.0)),
                "动作": str(action_rec.get("action_type", "维持")),
                "说明": (
                    "敲入侧用敲入状态最优仓位。"
                    if zone_key == "ki_danger"
                    else ("敲出侧用敲出状态最优仓位。" if zone_key == "ko_danger" else "中性区优先使用状态加权综合最优仓位。")
                ),
            }
        )

    price_step = max(abs(current_close) * 0.01, span_ref * 0.25, 1.0)
    if current_close - price_step <= 0.0:
        price_step = max(abs(current_close) * 0.005, 1.0)
    scenario_rows: List[Dict[str, Any]] = []
    for label, scenario_price in [
        ("下移一档", max(current_close - price_step, 0.01)),
        ("当前价格", current_close),
        ("上移一档", current_close + price_step),
    ]:
        zone_rec = precise_hedge_resolve_price_zone(
            price=scenario_price,
            direction_sign=float(direction_sign),
            ki_level=ki_level,
            ko_level=ko_level,
            buffer_pct=float(buffer_pct),
        )
        scenario_target = float(zone_map.get(str(zone_rec.get("zone_key", "neutral")), state_weighted_position))
        action_rec = _build_action(scenario_target)
        scenario_rows.append(
            {
                "价格情景": label,
                "价格": float(scenario_price),
                "区域": str(zone_rec.get("zone_label", "中性区")),
                "目标仓位(吨)": float(scenario_target),
                "动作": str(action_rec.get("action_type", "维持")),
                "建议调整(吨)": float(action_rec.get("adjust_tons", 0.0)),
                "解释": str(zone_rec.get("zone_hint", "")),
            }
        )

    return {
        "reference_target_position": float(state_weighted_position),
        "current_target_position": float(current_target_position),
        "no_trade_band": float(no_trade_band),
        "current_zone": current_zone,
        "current_action": current_action,
        "current_reason": current_reason,
        "threshold_df": pd.DataFrame(threshold_rows),
        "scenario_df": pd.DataFrame(scenario_rows),
        "price_step": float(price_step),
        "buffer_pct": float(buffer_pct),
    }


def precise_hedge_build_entry_bucket_sensitivity(
    *,
    history_result: Mapping[str, Any],
    state_layer: Mapping[str, Any],
    entry_price: Any,
    neutral_position: float,
    direction_sign: float,
    scan_step_tons: float,
) -> Dict[str, Any]:
    bucket_df = history_result.get("bucket_df") if isinstance(history_result.get("bucket_df"), pd.DataFrame) else pd.DataFrame()
    if bucket_df is None or bucket_df.empty:
        return {"table_df": pd.DataFrame(), "current_bucket": {}}
    state_result_map = state_layer.get("state_result_map", {}) if isinstance(state_layer.get("state_result_map", {}), dict) else {}
    ki_state = state_result_map.get("敲入情景", {}) if isinstance(state_result_map.get("敲入情景", {}), dict) else {}
    stable_state = state_result_map.get("震荡/中性情景", {}) if isinstance(state_result_map.get("震荡/中性情景", {}), dict) else {}
    ko_state = state_result_map.get("敲出情景", {}) if isinstance(state_result_map.get("敲出情景", {}), dict) else {}
    ki_pos = float(pick_first(ki_state.get("suggested_position"), neutral_position) or neutral_position)
    stable_pos = float(pick_first(stable_state.get("suggested_position"), neutral_position) or neutral_position)
    ko_pos = float(pick_first(ko_state.get("suggested_position"), neutral_position) or neutral_position)
    tol = max(float(scan_step_tons) * 0.5, 100.0)
    rows: List[Dict[str, Any]] = []
    for _, row in bucket_df.iterrows():
        ki_prob = float(pick_first(row.get("发生敲入概率"), 0.0) or 0.0)
        stable_prob = float(pick_first(row.get("未敲入且未敲出概率"), 0.0) or 0.0)
        ko_prob = float(pick_first(row.get("发生敲出概率"), 0.0) or 0.0)
        bucket_position_raw = ki_prob * ki_pos + stable_prob * stable_pos + ko_prob * ko_pos
        bucket_position = float(probexp_clip_target_position_to_direction(bucket_position_raw, direction_sign))
        weighted_hit = (
            ki_prob * float(pick_first((ki_state.get("metrics", {}) if isinstance(ki_state.get("metrics", {}), dict) else {}).get("hit_rate"), 0.0) or 0.0)
            + stable_prob * float(pick_first((stable_state.get("metrics", {}) if isinstance(stable_state.get("metrics", {}), dict) else {}).get("hit_rate"), 0.0) or 0.0)
            + ko_prob * float(pick_first((ko_state.get("metrics", {}) if isinstance(ko_state.get("metrics", {}), dict) else {}).get("hit_rate"), 0.0) or 0.0)
        )
        weighted_under = (
            ki_prob * float(pick_first((ki_state.get("metrics", {}) if isinstance(ki_state.get("metrics", {}), dict) else {}).get("under_prob"), 0.0) or 0.0)
            + stable_prob * float(pick_first((stable_state.get("metrics", {}) if isinstance(stable_state.get("metrics", {}), dict) else {}).get("under_prob"), 0.0) or 0.0)
            + ko_prob * float(pick_first((ko_state.get("metrics", {}) if isinstance(ko_state.get("metrics", {}), dict) else {}).get("under_prob"), 0.0) or 0.0)
        )
        weighted_over = (
            ki_prob * float(pick_first((ki_state.get("metrics", {}) if isinstance(ki_state.get("metrics", {}), dict) else {}).get("over_prob"), 0.0) or 0.0)
            + stable_prob * float(pick_first((stable_state.get("metrics", {}) if isinstance(stable_state.get("metrics", {}), dict) else {}).get("over_prob"), 0.0) or 0.0)
            + ko_prob * float(pick_first((ko_state.get("metrics", {}) if isinstance(ko_state.get("metrics", {}), dict) else {}).get("over_prob"), 0.0) or 0.0)
        )
        weighted_mae = (
            ki_prob * float(pick_first((ki_state.get("metrics", {}) if isinstance(ki_state.get("metrics", {}), dict) else {}).get("mean_abs_gap"), 0.0) or 0.0)
            + stable_prob * float(pick_first((stable_state.get("metrics", {}) if isinstance(stable_state.get("metrics", {}), dict) else {}).get("mean_abs_gap"), 0.0) or 0.0)
            + ko_prob * float(pick_first((ko_state.get("metrics", {}) if isinstance(ko_state.get("metrics", {}), dict) else {}).get("mean_abs_gap"), 0.0) or 0.0)
        )
        bias = precise_hedge_infer_bias_signal(
            knockin_prob=ki_prob,
            stable_prob=stable_prob,
            knockout_prob=ko_prob,
            positive_adjust_pct=PRECISE_HEDGE_BUCKET_ADJUST_PCT,
        )
        parsed = precise_hedge_parse_bucket_range(row.get("价格区间"))
        bucket_center = float((parsed[0] + parsed[1]) * 0.5) if parsed is not None else float(len(rows))
        rows.append(
            {
                "入场价区间": str(pick_first(row.get("价格区间"), "")),
                "样本数": int(pick_first(row.get("样本数"), 0) or 0),
                "敲入概率": float(ki_prob),
                "中性概率": float(stable_prob),
                "敲出概率": float(ko_prob),
                "建议仓位(吨)": float(bucket_position),
                "命中率": float(weighted_hit),
                "欠保概率": float(weighted_under),
                "超保概率": float(weighted_over),
                "平均绝对偏差": float(weighted_mae),
                "建议倾向": precise_hedge_describe_weight_stance(bucket_position, neutral_position, tol),
                "区间修正": str(pick_first(bias.get("stance"), "中性")),
                "解释": str(pick_first(bias.get("reason"), "")),
                "_bucket_center": float(bucket_center),
            }
        )
    out = pd.DataFrame(rows)
    if out.empty:
        return {"table_df": out, "current_bucket": {}}
    out = out.sort_values(["_bucket_center"]).reset_index(drop=True)
    current_bucket_row = precise_hedge_find_bucket_row(bucket_df, entry_price)
    current_bucket_label = str(pick_first(current_bucket_row.get("价格区间"), "")) if current_bucket_row is not None else ""
    out["当前入场区间"] = out["入场价区间"].astype(str) == str(current_bucket_label)
    current_bucket_show = out[out["当前入场区间"]].head(1)
    current_bucket = current_bucket_show.iloc[0].to_dict() if not current_bucket_show.empty else {}
    return {
        "table_df": out.drop(columns=["_bucket_center"], errors="ignore"),
        "current_bucket": current_bucket,
        "current_bucket_label": current_bucket_label,
    }


def precise_hedge_render_bucket_sensitivity_chart(
    bucket_df: pd.DataFrame,
    *,
    current_bucket_label: str = "",
    figure_size: Tuple[float, float] = (11.8, 4.8),
) -> None:
    _setup_matplotlib_cjk_font()
    if not isinstance(bucket_df, pd.DataFrame) or bucket_df.empty or "入场价区间" not in bucket_df.columns:
        st.caption("暂无入场价敏感度图。")
        return
    show = bucket_df.copy()
    for col_name in ["建议仓位(吨)", "欠保概率", "超保概率"]:
        if col_name in show.columns:
            show[col_name] = pd.to_numeric(show[col_name], errors="coerce")
            show.loc[~np.isfinite(show[col_name]), col_name] = np.nan
    show = show[show["建议仓位(吨)"].notna()].copy()
    if show.empty:
        st.caption("暂无入场价敏感度图。")
        return
    show["欠保概率_pct"] = pd.to_numeric(show.get("欠保概率"), errors="coerce").fillna(0.0) * 100.0
    show["超保概率_pct"] = pd.to_numeric(show.get("超保概率"), errors="coerce").fillna(0.0) * 100.0
    show["欠保概率_pct"] = show["欠保概率_pct"].clip(lower=0.0, upper=100.0)
    show["超保概率_pct"] = show["超保概率_pct"].clip(lower=0.0, upper=100.0)
    show["入场价区间"] = show["入场价区间"].astype(str).map(lambda s: str(s).replace("\n", " ").strip())
    highlight_bucket_text = str(current_bucket_label).strip()
    fig_w = float(np.clip(float(pick_first(figure_size[0], 11.8) or 11.8), 8.8, 14.5))
    fig_h = float(np.clip(float(pick_first(figure_size[1], 4.8) or 4.8), 4.4, 6.0))
    fig, ax1 = plt.subplots(figsize=(fig_w, fig_h), dpi=130)
    fig.patch.set_facecolor("#071a34")
    ax1.set_facecolor("#0c274c")
    x = np.arange(len(show), dtype=float)
    bucket_labels = show["入场价区间"].astype(str).tolist()
    bar_colors = ["#68b7ff" if str(lbl).strip() != highlight_bucket_text else "#8e3341" for lbl in bucket_labels]
    edge_colors = ["#dcecff" if str(lbl).strip() != highlight_bucket_text else "#ffb3b3" for lbl in bucket_labels]
    line_widths = [0.28 if str(lbl).strip() != highlight_bucket_text else 1.05 for lbl in bucket_labels]
    bars = ax1.bar(x, show["建议仓位(吨)"].tolist(), color=bar_colors, width=0.72, alpha=0.88, edgecolor=edge_colors, linewidth=line_widths)
    value_arr = pd.to_numeric(show["建议仓位(吨)"], errors="coerce").fillna(0.0).to_numpy(dtype=float)
    finite_value_arr = value_arr[np.isfinite(value_arr)]
    label_offset = 80.0
    if finite_value_arr.size > 0:
        value_span = float(np.nanmax(finite_value_arr) - np.nanmin(finite_value_arr))
        label_offset = max(float(value_span) * 0.04, float(np.nanmax(np.abs(finite_value_arr))) * 0.02, 80.0)
    for bar, val in zip(bars, value_arr.tolist()):
        if not np.isfinite(float(val)):
            continue
        ax1.text(
            bar.get_x() + bar.get_width() / 2.0,
            float(val) + np.sign(float(val) if abs(float(val)) > 1e-12 else 1.0) * float(label_offset),
            f"{float(val):,.0f}",
            ha="center",
            va="bottom" if float(val) >= 0 else "top",
            color="#eef6ff",
            fontsize=8.0,
            fontweight="bold",
            path_effects=[mpl_patheffects.withStroke(linewidth=2.0, foreground="#0c274c")],
            clip_on=True,
        )
    ax2 = ax1.twinx()
    ax2.plot(x, show["欠保概率_pct"].tolist(), color="#ff7f79", marker="o", linewidth=1.9, markersize=5.0, label="欠保概率")
