def empty_structure_editor_view() -> pd.DataFrame:
    return pd.DataFrame(columns=STRUCT_EDITOR_EMPTY_COLUMNS)


def prepare_structure_editor_view(show: pd.DataFrame) -> Tuple[pd.DataFrame, bool, bool]:
    out = show.copy() if isinstance(show, pd.DataFrame) else pd.DataFrame()
    if out.empty:
        return empty_structure_editor_view(), False, False

    if "风险子" in out.columns:
        out["风险子"] = out["风险子"].apply(lambda x: normalize_risk_party_name(x, default="海证资本"))
        out["风险子"] = out["风险子"].apply(lambda x: x if x in RISK_PARTY_OPTIONS else "海证资本")

    if "交易日数量" in out.columns:
        out["交易日数量"] = pd.to_numeric(out["交易日数量"], errors="coerce").fillna(1).astype("Int64")
    if "总量（吨）" in out.columns:
        out["总量（吨）"] = pd.to_numeric(out["总量（吨）"], errors="coerce")

    out["参与倍数"] = pd.to_numeric(out["参与倍数"], errors="coerce")
    airbag_rate_existing = (
        pd.to_numeric(out["参与率（%）"], errors="coerce")
        if "参与率（%）" in out.columns
        else pd.Series(np.nan, index=out.index, dtype="float64")
    )
    show_has_airbag = False
    show_only_airbag = False
    if "策略类型" in out.columns:
        strategy_codes_series = out["策略类型"].astype(str).apply(resolve_strategy_code_for_display)
        snowball_mask_editor = strategy_codes_series == "SNOWBALL"
        trs_mask_editor = strategy_codes_series == "TRS"
        airbag_mask_editor = strategy_codes_series == "SAFETY_AIRBAG"
        out.loc[(strategy_codes_series != "SAFETY_AIRBAG") & (~snowball_mask_editor) & (~trs_mask_editor), "参与倍数"] = (
            out.loc[(strategy_codes_series != "SAFETY_AIRBAG") & (~snowball_mask_editor) & (~trs_mask_editor), "参与倍数"].fillna(3.0)
        )
        out.loc[snowball_mask_editor, "参与倍数"] = 0.0
        out.loc[trs_mask_editor, "参与倍数"] = 1.0
        show_has_airbag = bool(airbag_mask_editor.any())
        show_only_airbag = bool(show_has_airbag and (~airbag_mask_editor).sum() == 0)
        if show_has_airbag:
            if "总量（吨）" not in out.columns:
                out["总量（吨）"] = pd.Series(np.nan, index=out.index, dtype="float64")
            out["参与率（%）"] = pd.NA
            out.loc[airbag_mask_editor, "总量（吨）"] = pd.to_numeric(
                out.loc[airbag_mask_editor, "总量（吨）"],
                errors="coerce",
            ).where(
                pd.to_numeric(out.loc[airbag_mask_editor, "总量（吨）"], errors="coerce").notna(),
                pd.to_numeric(out.loc[airbag_mask_editor, "名义规模（吨）"], errors="coerce"),
            )
            # 安全气囊展示列优先保留已存/已编辑的参与率，只有缺失时才回退默认值。
            out.loc[airbag_mask_editor, "参与率（%）"] = (
                airbag_rate_existing.loc[airbag_mask_editor]
                .where(airbag_rate_existing.loc[airbag_mask_editor].notna(), out.loc[airbag_mask_editor, "参与倍数"])
                .fillna(80.0)
            )
            out.loc[airbag_mask_editor, "参与倍数"] = pd.NA
    else:
        out["参与倍数"] = out["参与倍数"].fillna(3.0)

    out["删除"] = False
    return out, show_has_airbag, show_only_airbag


def hide_empty_structure_editor_columns(show: pd.DataFrame) -> pd.DataFrame:
    if show is None or show.empty:
        return show
    hideable_cols = [c for c in show.columns if c not in STRUCT_EDITOR_ALWAYS_KEEP_COLUMNS]
    return hide_empty_display_columns(show, hideable_cols)


def apply_structure_editor_filters(
    show: pd.DataFrame,
    gid: str,
    show_has_airbag: bool,
    show_only_airbag: bool,
) -> pd.DataFrame:
    out = show.copy()
    if show_only_airbag:
        out = out.drop(columns=["参与倍数"], errors="ignore")
    out = rename_subsidy_display_column(out, strategy_col="策略类型")
    if show_has_airbag:
        return hide_empty_structure_editor_columns(out)
    out = out.drop(columns=["参与率（%）"], errors="ignore")
    numeric_cols = [c for c in STRUCT_EDITOR_FILTER_NUMERIC_COLS if c in out.columns]
    filtered = apply_table_filters(
        out,
        f"struct_table_{gid}",
        keyword_cols=["结构编号", "结构", "风险子", "品种"],
        category_cols=["方向", "策略类型", "风险子", "品种"],
        date_cols=["开始日期", "结束日期"],
        numeric_cols=numeric_cols,
        title="结构表筛选",
        expanded=False,
    )
    return hide_empty_structure_editor_columns(filtered)


def structure_editor_direction_options(show: pd.DataFrame) -> List[str]:
    dir_opts_editor = ["看涨", "看跌"]
    if show.empty or "策略类型" not in show.columns:
        return dir_opts_editor
    sc_editor = show["策略类型"].astype(str).apply(resolve_strategy_code_for_display)
    has_airbag_editor = bool(sc_editor.eq("SAFETY_AIRBAG").any())
    has_non_airbag_editor = bool((~sc_editor.eq("SAFETY_AIRBAG")).any())
    if has_airbag_editor and not has_non_airbag_editor:
        return ["看涨", "看跌"]
    if has_non_airbag_editor and not has_airbag_editor:
        return ["看涨", "看跌"]
    return dir_opts_editor


